#!/usr/bin/env node
'use strict';

// =========================
// ALL REQUIRES FIRST — before any class or function uses them
// This fixes: ReferenceError: Cannot access 'path' before initialization
// =========================
const fs      = require('fs');
const path    = require('path');
const https   = require('https');
const crypto  = require('crypto');
const { exec, execSync } = require('child_process');
const { promisify }      = require('util');
const zlib    = require('zlib');
const execAsync = promisify(exec);

// Third-party modules
const express   = require('express');
const WebSocket = require('ws');
const axios     = require('axios');
const dotenv    = require('dotenv');

// Load environment variables immediately
try {
  if (fs.existsSync('.env')) dotenv.config();
} catch (_) { /* no .env file — use Render env vars */ }

// =========================
// RENDER SAFE BOOTSTRAP
// =========================
// Force IPv4 (avoids broken IPv6 paths on cloud/Render)
require('dns').setDefaultResultOrder('ipv4first');

// Prevent crashes — early handlers before anything else initialises
process.on('uncaughtException', (err) => {
  console.error('UNCAUGHT EXCEPTION:', err.message, err.stack?.split('\n')[1] || '');
});
process.on('unhandledRejection', (err) => {
  console.error('UNHANDLED REJECTION:', err?.message || err);
});

// Keep process alive on Render (prevents idle sleep between setIntervals)
setInterval(() => {}, 1 << 30);

// =========================
// KEEPALIVE SERVER (RENDER REQUIRED)
// =========================
const app  = express();
const PORT = parseInt(process.env.PORT || '10000', 10);

app.get('/', (_req, _res) => {
  _res.send('✅ Signal Engine Running');
});

// UptimeRobot / Render ping endpoint
app.get('/ping', (_req, _res) => {
  _res.status(200).send('pong');
});

// ── Health / telemetry endpoint — exposes circuit-breaker + cycle stats
// so external monitors can see if the engine is alive and progressing.
// (Defined here, but `_cycleTelemetry` and `signalBucket` are populated below;
// the response handler accesses them lazily at request time.)
app.get('/status', (_req, res) => {
  try {
    res.json({
      ok: true,
      uptimeSec: Math.round(process.uptime()),
      memoryMB:  Math.round(process.memoryUsage().rss / 1024 / 1024),
      telemetry: typeof _cycleTelemetry !== 'undefined' ? _cycleTelemetry : null,
      bucketSize: typeof signalBucket  !== 'undefined' ? signalBucket.length : 0,
      lastSignal: typeof lastSignal    !== 'undefined' ? lastSignal          : null,
      emergencyHalt: process.env.EMERGENCY_HALT === '1',
    });
  } catch (e) {
    res.status(500).json({ ok: false, error: e.message });
  }
});

app.listen(PORT, () => {
  console.log(`🚀 Server running on port ${PORT}`);
});


/**
 * =========================================================
 * INTEGRATED SIGNAL ENGINE (RENDER SAFE - COMPLETE)
 * Version: 6.0.0 (Integrated with Billion_render.js)
 * Description:
 * - Conflict-free signals
 * - Integrated decision engine
 * - Plug-ready for AI/HFT modules
 * - Algorithm sanity fixes
 * - Normalized confidence, TP/SL, and pricing logic
 * - Defensive guards against runaway values
 * - Unified execution engine
 * - All v1-v6 upgrade modules integrated
 * - Novel algorithm suite (7 engines)
 * - 5 unprecedented scientific engines
 * - Multi-timeframe consensus engine
 * - Institutional context engine (v2-v5 layers)
 * =========================================================
 */



/* =========================
   CORE UTILITIES
   (defined early so all downstream code can use them immediately)
   ⚠️  SINGLE DEFINITIONS — do NOT re-declare these anywhere else in the file.
       Each utility exists exactly once here and is referenced everywhere below.
========================= */
const clamp      = (v, min, max) => Math.max(min, Math.min(max, v));
const safeNumber = (v, fallback = 0) => Number.isFinite(Number(v)) ? Number(v) : fallback;
const floor      = (v) => Math.floor(v);
const abs        = (v) => Math.abs(v);
const sqrt       = (v) => Math.sqrt(v);

/* =========================
   DEBUG / LOG CONTROL
   Set DEBUG=true in your .env (or Render env vars) to enable verbose logs.
   Leaving it off keeps Render free-tier log memory safe.
========================= */
const DEBUG = process.env.DEBUG === 'true';
const dbg   = (...args) => { if (DEBUG) console.log(...args); };

/* =========================
   ENGINE STATE (scoped — not bare globals)
   Replacing bare `let signalDir` / `let riskLevel` with a single context
   object prevents silent corruption when async scan cycles overlap.
========================= */
const _engineState = {
  signalDir: null,   // 'BUY' | 'SELL' | null
  riskLevel: null,   // 'HIGH' | 'MEDIUM' | 'LOW' | null
};
// Convenience read-only accessors used by external consumers / exports
Object.defineProperty(globalThis, 'signalDir', { get: () => _engineState.signalDir });
Object.defineProperty(globalThis, 'riskLevel', { get: () => _engineState.riskLevel });

// =========================
// FIX 2 — UNIFIED SIGNAL STRUCTURE
// =========================
// All signal output flows through this single builder so every
// emitted signal is guaranteed to have the same shape.
function buildSignal({ symbol, direction, confidence, entry, stopLoss, takeProfit, timeframe, reason }) {
  return {
    symbol:      symbol || 'UNKNOWN',  // ✅ FIX: symbol now carried through so resolveFinalSignal
    direction,                         //         can group by symbol for per-symbol conflict resolution
    confidence:  Math.max(0, Math.min(100, safeNumber(confidence))),
    entry:       safeNumber(entry),      // ✅ NaN-safe: undefined/null/NaN → 0
    stopLoss:    safeNumber(stopLoss),   // ✅ NaN-safe
    takeProfit:  safeNumber(takeProfit), // ✅ NaN-safe
    timeframe,
    reason,
    timestamp:   Date.now()
  };
}

// =========================
// FIX 3 — SIGNAL BUCKET (collects every candidate signal)
// =========================
// Every internal strategy pushes signals here via captureSignal().
// Only the highest-confidence survivor is emitted after the full
// scan cycle completes — preventing conflicting BUY/SELL outputs.
const signalBucket = [];

// Hard cap on the candidate bucket — prevents unbounded growth if the
// resolver fails to drain it (memory safety for long-running Render
// processes). Configurable via env; default 200 is more than enough for
// any single scan cycle across 30+ symbols.
const SIGNAL_BUCKET_MAX = parseInt(process.env.SIGNAL_BUCKET_MAX || '200', 10);

function captureSignal(signal) {
  if (!signal || !signal.direction || signal.direction === 'NEUTRAL') return;
  // EMERGENCY_HALT — operator kill switch. Set process.env.EMERGENCY_HALT=1
  // (or _engineState.emergencyHalt = true) to refuse all new signals.
  if (process.env.EMERGENCY_HALT === '1' || _engineState.emergencyHalt === true) {
    console.log('🛑 EMERGENCY_HALT active — captureSignal refused');
    return;
  }
  // Memory-safety cap — hard ceiling prevents unbounded bucket growth
  if (signalBucket.length >= SIGNAL_BUCKET_MAX) {
    console.log(`⚠️  signalBucket cap reached (${SIGNAL_BUCKET_MAX}) — dropping new candidate ${signal.symbol||''} ${signal.direction}`);
    return;
  }
  // Normalize confidence to 0–100 range no matter what was passed in
  signal.confidence = normalizeConfidence(signal.confidence);

  // ── DECISION ENGINE V2 (BOOSTER + CONTRADICTION SKIPPER) ─────────────
  // V2 is now INTEGRATED into the consensus build, not a separate gate:
  //   • SKIP only on hard contradictions (hidden flow strongly opposes,
  //     quantum probability flips the direction)
  //   • Otherwise BOOST the certainty (up to +20 by default) when
  //     positive factors confirm the direction, and propagate the boost
  //     back to the consensus object so the user's formal high-quality
  //     gate (cert 90 / avg 50 / conv 50 / pillars 4) sees the new value.
  //
  // MODE (env DECISION_ENGINE_MODE):
  //   • 'enforce'  (default) — apply boost; SKIP drops the candidate
  //   • 'advisory'           — boost still applied, but SKIPs become logs
  //   • 'off'                — completely bypass V2 (no boost, no skip)
  const _decMode = (process.env.DECISION_ENGINE_MODE || 'enforce').toLowerCase();
  if (_decMode !== 'off' && (signal._consensus || signal._instCtx)) {
    try {
      const _decIn  = adaptForDecisionEngine(signal, signal._consensus, signal._instCtx, signal._btcDom);
      const _decOut = decideSignalV2(_decIn);

      if (_decOut.action === 'SKIP') {
        // Hidden flow blocks are absolute — bypass advisory mode entirely.
        // The user requirement is that a contradicting hidden flow NEVER fires,
        // regardless of any mode flag.
        if (_decOut.hiddenBlocked) {
          console.log(`🛑 V2 HIDDEN BLOCK ${signal.symbol||''} ${signal.direction} — ${_decOut.reason}`);
          return;
        }
        if (_decMode === 'advisory') {
          console.log(`📝 V2 [ADVISORY] would SKIP ${signal.symbol||''} ${signal.direction} (${_decOut.reason}) — signal kept`);
          signal.decisionAdvisory = { action: 'SKIP', reason: _decOut.reason };
        } else {
          console.log(`🛑 V2 SKIP ${signal.symbol||''} ${signal.direction} — ${_decOut.reason}`);
          return; // hard contradiction — never trade this
        }
      } else {
        // BOOST/PENALTY verdict: apply NET delta to signal AND propagate
        // back to the consensus so the formal high-quality gate sees the
        // adjusted certainty. A 90% raw signal with a soft contradiction
        // becomes ~70% here BEFORE the 90% gate runs — exactly per spec.
        const _origCert = signal.confidence;
        signal.confidence       = _decOut.certainty;       // adjusted, clamped 0..100
        signal.decisionStatus   = _decOut.status;          // CONFIRMED | STRONG | STANDARD
        signal.decisionBoost    = _decOut.boost;           // raw boost amount
        signal.decisionPenalty  = _decOut.penalty;         // raw penalty amount
        signal.decisionNetDelta = _decOut.netDelta;        // boost − penalty
        signal.decisionRaw      = _decOut.rawBoosted;      // raw value (may exceed 100 or go below 0)
        signal.decisionReason   = _decOut.reason || '';

        // Propagate net delta back to the consensus object so downstream
        // checks (isHighQualitySignal, Telegram cards, etc.) see the
        // adjusted certaintyScore — this is what makes V2 truly
        // "integrated into the consensus build" rather than a separate gate.
        if (signal._consensus && _decOut.netDelta !== 0) {
          const _prev = safeNumber(signal._consensus.certaintyScore, _origCert);
          signal._consensus.certaintyScore = Math.max(0, Math.min(100, _prev + _decOut.netDelta));
          signal._consensus.decisionBoost   = _decOut.boost;
          signal._consensus.decisionPenalty = _decOut.penalty;
          signal._consensus.decisionRaw     = _decOut.rawBoosted;
        }
        // Log whenever V2 changed the certainty — boost, soft penalty, OR hard
        // contradiction cap. Without this, a 99% → 60% cap from hidden-flow
        // contradiction would happen silently because soft `penalty` is 0.
        if (_decOut.boost > 0 || _decOut.penalty > 0 || _decOut.contradictionCap !== null || _decOut.netDelta !== 0) {
          const sign = _decOut.netDelta >= 0 ? `+${_decOut.netDelta}` : `${_decOut.netDelta}`;
          const tag  = _decOut.contradictionCap !== null ? 'CAP'
                     : _decOut.penalty > 0                ? 'ADJUST'
                     : 'BOOST';
          console.log(`⚡ V2 ${tag} ${signal.symbol||''} ${signal.direction} ${_decOut.baseCert}% ${sign} → ${_decOut.certainty}%${_decOut.rawBoosted > 100 ? ` (raw ${_decOut.rawBoosted}%)` : ''} [${_decOut.status}] — ${_decOut.reason}`);
        }
      }
      // Drop the heavy context refs before going into the bucket so we do
      // not retain large objects between scan cycles.
      delete signal._consensus;
      delete signal._instCtx;
    } catch (e) {
      // fail open — never block a signal due to engine error
      console.warn('decisionEngineV2 error (signal kept):', e.message);
    }
  }

  signalBucket.push(signal);
}

// =========================
// CONFIDENCE NORMALIZER
// =========================
// Accepts any numeric form (0–1 fraction or 0–100 integer) and
// always returns a clean integer in the 0–100 range.
function normalizeConfidence(raw) {
  if (raw == null || isNaN(Number(raw))) return 0;
  const n = Number(raw);
  // Values ≤ 1 are treated as fractions (e.g. 0.72 → 72)
  const pct = n <= 1 ? n * 100 : n;
  return Math.round(Math.max(0, Math.min(100, pct)));
}

// =========================
// QUALITY-GATE THRESHOLDS (USER REQUESTED — RARE / HIGH-QUALITY ONLY)
// =========================
// A signal is allowed to fire ONLY when ALL four gates pass:
//   1. Certainty           >= SIGNAL_CERT_MIN  (default 90)
//   2. Average confidence  >= SIGNAL_AVG_MIN   (default 50)
//   3. Conviction          >= SIGNAL_CONV_MIN  (default 50)
//   4. Institutional pillars confirmed = SIGNAL_PILLAR_MIN (default 4 — full)
// Defaults can be overridden via env vars.
function _qualityThresholds() {
  return {
    certMin:   parseFloat(process.env.SIGNAL_CERT_MIN   || process.env.SIGNAL_THRESHOLD || '75'),
    avgMin:    parseFloat(process.env.SIGNAL_AVG_MIN    || '45'),
    // ✅ USER REQUEST: conviction default lowered from 50 → 40 so good
    // setups aren't blocked by a slightly weak conviction reading.
    convMin:   parseFloat(process.env.SIGNAL_CONV_MIN   || '45'),
    pillarMin: parseInt  (process.env.SIGNAL_PILLAR_MIN || '3', 10),
  };
}
function getInstPillarsConfirmed(instCtx, dir) {
  // ✅ FIX (post-deploy "0/4 pillars on every asset" bug):
  //
  // The previous version of this function looked for field names that do
  // NOT exist on the institutional context object that getInstContext /
  // buildInstitutionalContextFull actually produces. The real shape is:
  //
  //   { wyckoff, struct, trap, liq, kz }     ← `struct` & `kz`, NOT
  //                                            `structure` & `session`
  //
  // It also checked for `.aligned` booleans on each sub-object which the
  // engine never sets anywhere. Worst of all, it received no `dir`, so it
  // had no way to reproduce the real alignment logic from
  // formatInstitutionalContext. As a result it ALWAYS returned 0, every
  // signal failed the `pillars >= SIGNAL_PILLAR_MIN (4)` gate inside
  // isHighQualitySignal, and every asset card displayed 0/4 pillars.
  //
  // This rewrite mirrors formatInstitutionalContext exactly so the gate
  // and the displayed pillar count are guaranteed to agree.

  if (!instCtx) return 0;

  // 1) Honour any explicit numeric field if a downstream layer set one.
  const cand = [
    instCtx.pillarsConfirmed, instCtx.alignmentScore, instCtx.alignedPillars,
    instCtx.confluence, instCtx.confluenceScore, instCtx.pillars,
  ];
  for (const c of cand) {
    if (typeof c === 'number' && Number.isFinite(c)) return Math.max(0, Math.min(4, c));
  }

  // 2) Real derivation — uses the SAME logic as formatInstitutionalContext.
  //    Tolerate the legacy field names too (`structure`, `session`) just in
  //    case some auxiliary code path produces them.
  const wyckoff = instCtx.wyckoff;
  const struct  = instCtx.struct  || instCtx.structure;
  const trap    = instCtx.trap;
  const kz      = instCtx.kz      || instCtx.session;

  const hasDir = dir === 'BUY' || dir === 'SELL';

  // Wyckoff: bias matches signal direction or is NEUTRAL (does not oppose)
  const wyA = hasDir
    ? !!(wyckoff && (wyckoff.bias === dir || wyckoff.bias === 'NEUTRAL'))
    : !!(wyckoff && wyckoff.phase);

  // Structure: direction matches or NEUTRAL
  const stA = hasDir
    ? !!(struct && (struct.direction === dir || struct.direction === 'NEUTRAL'))
    : !!struct;

  // Trap pillar: no trap, or trap not triggered, or trap aligned with dir
  const trA = hasDir
    ? (!trap || !trap.trapped || trap.direction === dir)
    : !!trap;

  // Killzone / session: active
  const kzA = !!(kz && kz.active);

  let ag = 0;
  if (wyA) ag++;
  if (stA) ag++;
  if (trA) ag++;
  if (kzA) ag++;
  return ag;
}
function isHighQualitySignal(consensus, instCtx, overrides = null) {
  const t = Object.assign(_qualityThresholds(), overrides || {});
  const cert = safeNumber(consensus?.certaintyScore  || consensus?.certainty || 0);
  const avg  = safeNumber(consensus?.avgConfidence   || consensus?.avg       || 0);
  const conv = safeNumber(consensus?.convictionPct   || consensus?.conviction|| 0);
  // ✅ FIX: extract direction from the consensus object and forward it so
  // the pillar count uses the same alignment rules as the display layer.
  // Without this, getInstPillarsConfirmed had no `dir` and always returned
  // 0 → every signal failed the pillars gate → "0/4 on all assets".
  const dir  = consensus?.consensusDirection || consensus?.direction || consensus?.dir || null;

  // ══ ABSOLUTE HIDDEN FLOW BLOCK ════════════════════════════════════════
  // USER REQUIREMENT: If hidden flow contradicts the signal direction it
  // must NEVER fire — regardless of certainty, avg, conviction, or pillars.
  // This is the Telegram-send path gate; captureSignal already blocks the
  // signalBucket path. Both must agree or the signal leaks to the user.
  //
  // Hidden flow is the ONLY engine that is an absolute hard block.
  // All other engines (MM, BTC dominance, volume divergence) only reduce
  // the certaintyScore via the V2 netDelta penalty — they cannot block.
  // Their penalties propagate to consensus.certaintyScore BEFORE this
  // function runs (via captureSignal → decideSignalV2 → netDelta write-back),
  // so when they contradict, the cert check below naturally fails the gate.
  if (dir) {
    const _hfOrderFlow = instCtx?.v4?.orderFlow || instCtx?.orderFlow || null;
    const _hfBias      = String(_hfOrderFlow?.hiddenBias || 'NEUTRAL').toUpperCase();
    const _hfConf      = safeNumber(_hfOrderFlow?.hiddenConf, 0);
    // ABSOLUTE BLOCK — no confidence threshold. Any hidden flow direction
    // that contradicts the main signal direction suppresses the signal
    // entirely, regardless of hidden flow confidence percentage.
    if (_hfBias !== 'NEUTRAL') {
      if ((dir === 'BUY' && _hfBias === 'SELL') || (dir === 'SELL' && _hfBias === 'BUY')) {
        console.log(`🛑 QUALITY GATE — HIDDEN FLOW BLOCK: ${dir} signal suppressed — hidden flow ${_hfBias} @ ${_hfConf}% contradicts direction (no threshold)`);
        return {
          ok:            false,
          hiddenBlocked: true,
          cert, avg, conv, pillars: getInstPillarsConfirmed(instCtx, dir),
          thresholds:    t,
          reason:        `HIDDEN FLOW BLOCK — ${_hfBias} contradicts ${dir} — blocked regardless of confidence or score`
        };
      }
    }
  }
  // ═════════════════════════════════════════════════════════════════════

  const pil  = getInstPillarsConfirmed(instCtx, dir);
  const passCert = cert >= t.certMin;
  const passAvg  = avg  >= t.avgMin;
  const passConv = conv >= t.convMin;
  const passPil  = pil  >= t.pillarMin;

  // ══ FAKE BREAKOUT GATE ════════════════════════════════════════════════
  const _candles    = instCtx?.candles || instCtx?.v4?.candles || null;
  const _entryPrice = consensus?.bestSig?.entry || instCtx?.livePrice || 0;
  let fakeBreakoutBlocked = false;
  let fakeBreakoutReason  = '';
  if (_candles && _candles.length >= 5 && dir && _entryPrice > 0) {
    const _fbResult = isFakeBreakout(_candles, dir, _entryPrice);
    if (_fbResult.isFake && _fbResult.confidence >= 60) {
      fakeBreakoutBlocked = true;
      fakeBreakoutReason  = `FAKE BREAKOUT (${_fbResult.confidence}%) — ${_fbResult.reason}`;
      console.log(`🛑 QUALITY GATE — FAKE BREAKOUT BLOCK: ${dir} signal suppressed — ${fakeBreakoutReason}`);
    }
  }
  // ═════════════════════════════════════════════════════════════════════

  // ══ APEX PRECISION GATE ═══════════════════════════════════════════════
  // Run all 11 APEX sub-engines (Power of 3, OTE, CE, Delta Divergence,
  // Volume Profile, Premium/Discount, Fractal Alignment, Liquidity Void,
  // Session ORB, Wick Absorption) and require composite score >= threshold.
  // This is the final layer — the gate that eliminates the remaining
  // marginal setups that pass cert/avg/conv/pillar but still lose.
  let apexBlocked   = false;
  let apexReason    = '';
  let apexResult    = null;
  const _apexThreshold = parseFloat(process.env.APEX_THRESHOLD || '65');
  if (_candles && _candles.length >= 20 && _entryPrice > 0 && dir) {
    const _htfC = instCtx?.htfCandles || instCtx?.v4?.htfCandles || null;
    apexResult = computeApexMasterGate(_candles, dir, _entryPrice, _htfC);
    if (apexResult.manipBlock) {
      apexBlocked = true;
      apexReason  = `APEX BLOCKED — Power of 3 MANIPULATION_ACTIVE phase: price hunting stops, NOT the real move`;
      console.log(`🚫 APEX MANIP BLOCK [${dir}]: ${apexReason}`);
    } else if (!apexResult.approved) {
      apexBlocked = true;
      apexReason  = `APEX ${apexResult.apexGrade} (${apexResult.apexScore}% < ${_apexThreshold}% threshold) — ${apexResult.reason}`;
      console.log(`⛔ APEX GATE FAIL [${dir}]: ${apexReason}`);
    } else {
      console.log(`✅ APEX ${apexResult.apexGrade} [${dir}]: Score ${apexResult.apexScore}% — ${apexResult.reason}`);
    }
  }
  // ═════════════════════════════════════════════════════════════════════

  const ok = passCert && passAvg && passConv && passPil && !fakeBreakoutBlocked && !apexBlocked;
  return {
    ok,
    cert, avg, conv, pillars: pil,
    fakeBreakoutBlocked,
    apexBlocked,
    apexResult,
    thresholds: t,
    reason: ok ? 'PASS'
      : apexBlocked        ? apexReason
      : fakeBreakoutBlocked ? fakeBreakoutReason
      : `${passCert?'':`cert ${cert}<${t.certMin} `}${passAvg?'':`avg ${avg}<${t.avgMin} `}${passConv?'':`conv ${conv}<${t.convMin} `}${passPil?'':`pillars ${pil}/${t.pillarMin}`}`.trim()
  };
}

// =========================
// SAFE LIMIT CALCULATOR (USER REQUESTED — Bybit 10x leverage safety)
// =========================
// ✅ USER RULE (HARD): Limit pullback must NEVER exceed -3% from current price,
// regardless of leverage, PLVD zone, 24h extremes, or any other engine.
// -3% is the absolute ceiling for ALL configurations.
//
//   BUY  → limit = currentPrice × (1 - pct/100)  where pct ∈ [2, 3]
//   SELL → limit = currentPrice × (1 + pct/100)  where pct ∈ [2, 3]
//
// All sub-engines (PLVD, LEPD, RMEE, V11, 24h extreme guards) feed into
// this function and are clamped by the -3% hard ceiling before returning.
// The final hard clamp is applied at the very end of computeSafeLimit AND
// again in selectBestLimitGuarded — double protection.
//
// Override via env:
//   MAX_LIMIT_PULLBACK_PCT  (default 3)    — absolute distance ceiling from price
//   SAFE_LIMIT_PCT          (default 2.5)  — default pullback percentage
//   PLVD_MAX_DIST_PCT       (default 0.03) — guard relative to 24h extreme
//   PLVD_MIN_DIST_PCT       (default 0.005)— minimum gap from 24h extreme
// ─────────────────────────────────────────────────────────────────────
function computeSafeLimit(currentPrice, dir, opts = null) {
  // ── Backward-compat arg shape ────────────────────────────────────────
  // - number      → treat as pullbackPct (legacy)
  // - object      → { pullbackPct, cert, plvd, instCtx, low24h, high24h } (new — gated)
  let pullbackPct = null, cert = null, plvd = null, instCtx = null;
  let low24h = null, high24h = null;
  if (typeof opts === 'number')      pullbackPct = opts;
  else if (opts && typeof opts === 'object') {
    pullbackPct = opts.pullbackPct ?? null;
    cert        = (typeof opts.cert === 'number') ? opts.cert : null;
    plvd        = opts.plvd || (opts.instCtx && opts.instCtx.plvd) || null;
    instCtx     = opts.instCtx || null;
    low24h      = (typeof opts.low24h  === 'number' && opts.low24h  > 0) ? opts.low24h  : null;
    high24h     = (typeof opts.high24h === 'number' && opts.high24h > 0) ? opts.high24h : null;
  }

  const px = safeNumber(currentPrice);
  if (!px || px <= 0) return null;

  // ── ✅ USER GATE 1: ONE LIMIT, ONLY WHEN CERT >= 90% ──────────────────
  // Below the formal-quality cert threshold we do NOT predict a market
  // setup limit. Caller can opt out via LIMIT_CERT_GATE=false (e.g. for
  // recovery cards that intentionally show limits at lower cert).
  const limitCertGate = (process.env.LIMIT_CERT_GATE || 'true').toLowerCase() !== 'false';
  const limitCertMin  = parseFloat(process.env.LIMIT_CERT_MIN  || '75');
  if (limitCertGate && cert !== null && cert < limitCertMin) {
    return null; // → caller should render a WAIT message instead of a limit
  }

  // ── ✅ USER GATE 2: HIGH-LIQUIDITY → WAIT FOR ZONE TO CONFIRM ─────────
  // When PLVD reports the asset is still digesting deep liquidity (sweep
  // incomplete, deep pool pending, waiting on absorption) we MUST NOT
  // predict a pullback limit — we wait until the actual liquidity zone
  // produces a confirmed precision limit. Disable via LIMIT_LIQ_GATE=false.
  const limitLiqGate = (process.env.LIMIT_LIQ_GATE || 'true').toLowerCase() !== 'false';
  if (limitLiqGate && plvd) {
    if (plvd.state === 'INCOMPLETE_SWEEP'  ||
        plvd.state === 'DEEP_POOL_PENDING' ||
        plvd.state === 'WAITING_ABSORPTION') {
      return null; // → caller renders "WAIT — liquidity zone forming"
    }
    // If PLVD already produced its confirmed precision limit, ALWAYS
    // prefer that over the pullback formula — clamp to -3% max from price.
    if (plvd.state === 'VACUUM_CONFIRMED' && Number.isFinite(plvd.precisionLimit)) {
      let _plvdL = Number(plvd.precisionLimit);
      // ✅ HARD RULE: never further than -3% from current price regardless of PLVD zone
      const _maxP = parseFloat(process.env.MAX_LIMIT_PULLBACK_PCT || '3') / 100;
      if (dir === 'BUY'  && _plvdL < px * (1 - _maxP)) {
        console.warn(`⚠️ PLVD VACUUM GUARD [BUY]: precisionLimit ${_plvdL} is more than -3% from price ${px} — clamped`);
        _plvdL = px * (1 - _maxP);
      }
      if (dir === 'SELL' && _plvdL > px * (1 + _maxP)) {
        console.warn(`⚠️ PLVD VACUUM GUARD [SELL]: precisionLimit ${_plvdL} is more than +3% from price ${px} — clamped`);
        _plvdL = px * (1 + _maxP);
      }
      const _sig = px >= 1 ? 6 : 8;
      return Number(_plvdL.toPrecision(_sig));
    }
  }

  // ── Normal path: exactly -3% max pullback (leverage-safe hard rule) ────
  // User rule: max pullback is ALWAYS -3% from current price regardless of
  // leverage. The 2%–3% range is preserved as the working band; 3% is the
  // absolute ceiling — never exceeded under any configuration.
  const pct = safeNumber(pullbackPct, parseFloat(process.env.SAFE_LIMIT_PCT || '2.5'));
  const clamped = Math.max(2, Math.min(3, pct)); // band: 2%–3%
  const factor = clamped / 100;
  let limit = dir === 'SELL' ? px * (1 + factor) : px * (1 - factor);

  // ── ✅ FIX 1: PLVD 24H EXTREME GUARD ─────────────────────────────────
  // After computing the raw pullback limit, clamp it to the safe zone
  // relative to the 24h low (BUY) or 24h high (SELL).
  //
  // BUY: limit must be between (low24h × 0.97) and (low24h × 0.995)
  //      → never more than 3% below the day's low
  // SELL: limit must be between (high24h × 1.005) and (high24h × 1.03)
  //       → never more than 3% above the day's high
  //
  // If the raw pullback already lands in the safe zone — nothing changes.
  // If it's too far out (e.g. 9.6% below low) — it's clamped back in.
  const plvdMaxDist = parseFloat(process.env.PLVD_MAX_DIST_PCT || '0.03');   // 3%
  const plvdMinDist = parseFloat(process.env.PLVD_MIN_DIST_PCT || '0.005');  // 0.5%

  if (dir === 'BUY' && low24h && low24h > 0) {
    const safeFloor = low24h * (1 - plvdMaxDist);  // 3% below 24h low — hard floor
    const safeCeil  = low24h * (1 - plvdMinDist);  // 0.5% below 24h low — soft ceiling

    if (limit < safeFloor) {
      console.warn(`⚠️ PLVD LIMIT GUARD [BUY]: raw limit ${limit.toPrecision(6)} is ${((low24h - limit) / low24h * 100).toFixed(2)}% below 24h low (${low24h}) — clamping to safe floor ${safeFloor.toPrecision(6)}`);
      limit = safeFloor;
    } else if (limit > safeCeil) {
      // Limit is above the 24h low minimum gap — still valid, but log it
      console.warn(`⚠️ PLVD LIMIT GUARD [BUY]: raw limit ${limit.toPrecision(6)} is less than ${(plvdMinDist*100)}% below 24h low — clamping to safe ceiling ${safeCeil.toPrecision(6)}`);
      limit = safeCeil;
    }

    // Final hard guarantee: BUY limit must be below current price
    if (limit >= px) {
      limit = Math.min(safeCeil, px * (1 - plvdMinDist));
      console.warn(`⚠️ PLVD LIMIT GUARD [BUY]: limit was above market price — adjusted to ${limit.toPrecision(6)}`);
    }
  }

  if (dir === 'SELL' && high24h && high24h > 0) {
    const safeFloor = high24h * (1 + plvdMinDist);  // 0.5% above 24h high — soft floor
    const safeCeil  = high24h * (1 + plvdMaxDist);  // 3% above 24h high — hard ceiling

    if (limit > safeCeil) {
      console.warn(`⚠️ PLVD LIMIT GUARD [SELL]: raw limit ${limit.toPrecision(6)} is more than ${(plvdMaxDist*100)}% above 24h high (${high24h}) — clamping to safe ceiling ${safeCeil.toPrecision(6)}`);
      limit = safeCeil;
    } else if (limit < safeFloor) {
      limit = safeFloor;
      console.warn(`⚠️ PLVD LIMIT GUARD [SELL]: raw limit adjusted to ${safeFloor.toPrecision(6)}`);
    }

    // Final hard guarantee: SELL limit must be above current price
    if (limit <= px) {
      limit = Math.max(safeFloor, px * (1 + plvdMinDist));
      console.warn(`⚠️ PLVD LIMIT GUARD [SELL]: limit was below market price — adjusted to ${limit.toPrecision(6)}`);
    }
  }

  // ✅ ABSOLUTE FINAL HARD CLAMP — max pullback is -3% from current price no matter what.
  // This overrides all guards above (PLVD 24h extreme, ATR, etc.).
  // Leverage does NOT affect this rule: -3% is the ceiling for ALL leverages.
  const _absMax = parseFloat(process.env.MAX_LIMIT_PULLBACK_PCT || '3') / 100;
  if (dir === 'BUY' && limit < px * (1 - _absMax)) {
    console.warn(`⚠️ MAX PULLBACK HARD CLAMP [BUY]: ${((px - limit) / px * 100).toFixed(2)}% pullback exceeded -3% ceiling — clamped to ${(px * (1 - _absMax)).toPrecision(6)}`);
    limit = px * (1 - _absMax);
  }
  if (dir === 'SELL' && limit > px * (1 + _absMax)) {
    console.warn(`⚠️ MAX PULLBACK HARD CLAMP [SELL]: ${((limit - px) / px * 100).toFixed(2)}% pullback exceeded +3% ceiling — clamped to ${(px * (1 + _absMax)).toPrecision(6)}`);
    limit = px * (1 + _absMax);
  }

  const sig = px >= 1 ? 6 : 8;
  return Number(limit.toPrecision(sig));
}

// =========================
// SINGLE LIMIT ARBITER — picks the BEST available limit price across
// all liquidity engines so AI Analyst, RSDE, and Recovery cards never
// disagree on the limit. Priority order (highest-confidence first):
//
//   1. PLVD VACUUM_CONFIRMED      → swept-then-confirmed liquidity vacuum
//   2. LEPD PERFECT_EXHAUSTION    → ALL pools consumed, ≥88% confidence
//   3. LEPD STRONG_EXHAUSTION     → all pools swept, no deep pools left
//   4. RMEE realEntry/preCalcEntry → predictive deep-pool sweep entry
//   5. V11 cascade optimalLimit   → chain-reaction post-cascade entry
//   6. computeSafeLimit fallback  → max -3% pullback from current price (always available)
//
// Returns: { price, source, label, confidence } or null when the cert
//          gate / liquidity gate blocks the limit entirely.
//
// The cert + PLVD wait-state gates from computeSafeLimit are honoured
// FIRST so this single function is the only thing every call site needs.
// INTERNAL — do not call directly. Use selectBestLimitGuarded which adds
// the BUY<price / SELL>price side guarantee on top of this function.
function selectBestLimit(currentPrice, dir, opts = {}) {
  const px      = safeNumber(currentPrice);
  if (!px || px <= 0) return null;
  const cert    = (typeof opts.cert === 'number') ? opts.cert : null;
  const instCtx = opts.instCtx || null;
  const plvd    = opts.plvd || instCtx?.plvd || null;
  const lepd    = opts.lepd || instCtx?.lepd || null;
  const rmee    = opts.rmee || instCtx?.rmee || null;
  const v11     = opts.v11  || instCtx?.v11  || null;
  // FIX 1: propagate 24h extremes so the fallback path honours the PLVD guard
  const low24h  = (typeof opts.low24h  === 'number' && opts.low24h  > 0) ? opts.low24h  : null;
  const high24h = (typeof opts.high24h === 'number' && opts.high24h > 0) ? opts.high24h : null;

  // ── GATE 1: cert below the formal threshold → no limit at all ───────
  const certGate = (process.env.LIMIT_CERT_GATE || 'true').toLowerCase() !== 'false';
  const certMin  = parseFloat(process.env.LIMIT_CERT_MIN || '75');
  if (certGate && cert !== null && cert < certMin) return null;

  // ── GATE 2: liquidity zone still forming → wait, don't predict ──────
  const liqGate = (process.env.LIMIT_LIQ_GATE || 'true').toLowerCase() !== 'false';
  if (liqGate && plvd && (
        plvd.state === 'INCOMPLETE_SWEEP'  ||
        plvd.state === 'DEEP_POOL_PENDING' ||
        plvd.state === 'WAITING_ABSORPTION')) {
    return null;
  }

  // ── PRIORITY 1: PLVD VACUUM_CONFIRMED ───────────────────────────────
  if (plvd && plvd.state === 'VACUUM_CONFIRMED' && Number.isFinite(plvd.precisionLimit)) {
    return {
      price:      Number(plvd.precisionLimit),
      source:     'PLVD',
      confidence: safeNumber(plvd.confidence, 95),
      label:      'PLVD vacuum confirmed — swept liquidity wick',
    };
  }

  // ── PRIORITY 2: LEPD PERFECT_EXHAUSTION (88%+) ──────────────────────
  if (lepd && lepd.state === 'PERFECT_EXHAUSTION' &&
      lepd.confidence >= 88 && Number.isFinite(lepd.precisionLimit)) {
    return {
      price:      Number(lepd.precisionLimit),
      source:     'LEPD',
      confidence: safeNumber(lepd.confidence, 88),
      label:      `LEPD perfect exhaustion — all ${lepd.poolsSwept || 'mapped'} pools consumed`,
    };
  }

  // ── PRIORITY 3: LEPD STRONG_EXHAUSTION (no deep pools left) ─────────
  if (lepd && lepd.state === 'STRONG_EXHAUSTION' &&
      Number.isFinite(lepd.precisionLimit) && !lepd.hasDeepPools) {
    return {
      price:      Number(lepd.precisionLimit),
      source:     'LEPD',
      confidence: safeNumber(lepd.confidence, 75),
      label:      `LEPD strong exhaustion — ${lepd.confirmations || 0}/7 criteria`,
    };
  }

  // ── PRIORITY 4: RMEE deep-pool predictive entry ─────────────────────
  if (rmee) {
    const rmeePx = Number.isFinite(rmee.realEntry) ? rmee.realEntry
                 : Number.isFinite(rmee.preCalcEntry) ? rmee.preCalcEntry
                 : null;
    if (rmeePx) {
      return {
        price:      Number(rmeePx),
        source:     'RMEE',
        confidence: safeNumber(rmee.confidence, 70),
        label:      `RMEE deep-pool sweep entry (${rmee.mode || 'predictive'})`,
      };
    }
  }

  // ── PRIORITY 5: V11 cascade optimal limit ───────────────────────────
  if (v11 && Number.isFinite(v11.optimalLimit)) {
    return {
      price:      Number(v11.optimalLimit),
      source:     'V11',
      confidence: safeNumber(v11.confidence, 65),
      label:      `V11 cascade chain — ${v11.poolsInChain || '?'} pools, stops at ${v11.chainStopPrice || '?'}`,
    };
  }

  // ── PRIORITY 6 (fallback): -3% max safe pullback ────────────────────
  // Disable via LIMIT_ALLOW_FALLBACK=false to FORCE liquidity-confirmed
  // entries only (skips signals when no engine produced a limit).
  const allowFallback = (process.env.LIMIT_ALLOW_FALLBACK || 'true').toLowerCase() !== 'false';
  if (!allowFallback) return null;

  // Pass low24h/high24h so computeSafeLimit can enforce the PLVD 24h-extreme guard
  const fallbackPx = computeSafeLimit(px, dir, { cert, plvd, instCtx, low24h, high24h });
  if (!fallbackPx) return null;
  return {
    price:      Number(fallbackPx),
    source:     'SAFE_PULLBACK',
    confidence: 50,
    label:      'Safe pullback fallback — max -3% from price (no liquidity engine fired)',
  };
}

// ── LIMIT SIDE-OF-PRICE GUARD ────────────────────────────────────────────────
// Wrapper around selectBestLimit that guarantees the returned limit is always
// on the CORRECT side of the current price (BUY limit < price, SELL limit > price).
// All callers should use this instead of selectBestLimit directly.
function selectBestLimitGuarded(currentPrice, dir, opts = {}) {
  const result = selectBestLimit(currentPrice, dir, opts);
  if (!result) return null;
  const px = safeNumber(currentPrice);
  if (!px || px <= 0) return null;
  const limitPx = safeNumber(result.price);
  if (!limitPx || limitPx <= 0) return null;

  const _sig2 = px >= 1 ? 6 : 8;

  // BUY limit must be strictly below current price
  if (dir === 'BUY' && limitPx >= px) {
    const adjusted = px * 0.975; // pull back to 2.5% below current price
    console.warn(`⚠️ LIMIT SIDE GUARD [BUY]: limit ${limitPx} >= price ${px} — adjusted to ${adjusted.toPrecision(6)}`);
    return { ...result, price: Number(adjusted.toPrecision(_sig2)), label: result.label + ' [side-adjusted]' };
  }
  // SELL limit must be strictly above current price
  if (dir === 'SELL' && limitPx <= px) {
    const adjusted = px * 1.025; // push up to 2.5% above current price
    console.warn(`⚠️ LIMIT SIDE GUARD [SELL]: limit ${limitPx} <= price ${px} — adjusted to ${adjusted.toPrecision(6)}`);
    return { ...result, price: Number(adjusted.toPrecision(_sig2)), label: result.label + ' [side-adjusted]' };
  }

  // ✅ DISTANCE GUARD: limit must never be more than -3% from current price.
  // This catches PLVD/LEPD/RMEE/V11 limits that are calculated relative to
  // liquidity zones far from current market price. Hard rule — no exceptions.
  const _maxDistG = parseFloat(process.env.MAX_LIMIT_PULLBACK_PCT || '3') / 100;
  if (dir === 'BUY' && limitPx < px * (1 - _maxDistG)) {
    const _clamped = px * (1 - _maxDistG);
    console.warn(`⚠️ LIMIT DISTANCE GUARD [BUY]: ${result.source} limit ${limitPx.toPrecision(_sig2)} is ${((px - limitPx) / px * 100).toFixed(2)}% below price — clamped to -3% = ${_clamped.toPrecision(_sig2)}`);
    return { ...result, price: Number(_clamped.toPrecision(_sig2)), label: result.label + ' [max -3% clamped]' };
  }
  if (dir === 'SELL' && limitPx > px * (1 + _maxDistG)) {
    const _clamped = px * (1 + _maxDistG);
    console.warn(`⚠️ LIMIT DISTANCE GUARD [SELL]: ${result.source} limit ${limitPx.toPrecision(_sig2)} is ${((limitPx - px) / px * 100).toFixed(2)}% above price — clamped to +3% = ${_clamped.toPrecision(_sig2)}`);
    return { ...result, price: Number(_clamped.toPrecision(_sig2)), label: result.label + ' [max +3% clamped]' };
  }

  return result;
}

// =========================
// DECISION ENGINE V2 — CONTRADICTION-AWARE SIGNAL RESOLVER (USER REQUESTED)
// =========================
// Implements the "decision engine, not score generator" doctrine:
//   1. Hard contradictions  → SKIP   (no trade)
//   2. Low model alignment  → WAIT   (no forced trade)
//   3. Conflicts reduce AND cap certainty at 70 (no fake 90% signals)
//   4. 90% only when alignment is strong AND no major contradictions
//
// Inputs are fully optional — when no rich context is available the
// engine returns the original signal unchanged so legacy paths still work.
//
// Why this exists:
//   The previous pipeline could emit "BUY 93%" while the hidden flow was
//   "SELL 90%" and the quantum buy probability was 0%.  Numbers were added
//   blindly so a signal could look strong while being structurally wrong.
//   This module enforces logic BEFORE confidence — contradictions either
//   cap certainty or force a SKIP/WAIT outcome.
function decideSignalV2(input) {
  const dir = String(input?.signal || input?.direction || '').toUpperCase();
  if (dir !== 'BUY' && dir !== 'SELL') {
    return { action: 'SKIP', certainty: 0, reason: 'No direction' };
  }

  const mtfScore       = safeNumber(input?.mtfScore, 0);
  const structureScore = safeNumber(input?.structureScore, 0);
  const volumeScore    = safeNumber(input?.volumeScore, 0);
  const liquidityScore = safeNumber(input?.liquidityScore, 0);
  const hiddenFlow     = String(input?.hiddenFlow || 'NEUTRAL').toUpperCase();
  const hiddenFlowConf = safeNumber(input?.hiddenFlowConf, 0);
  const quantumBuyProb = safeNumber(input?.quantumBuyProb, 0.5);
  const btcDominance   = safeNumber(input?.btcDominance, 50);
  const signals        = Array.isArray(input?.signals) ? input.signals : [];
  // ── NEW contributing engines (passed in by adaptForDecisionEngine) ───
  const smDivType      = String(input?.smDivType || 'NONE').toUpperCase();
  const smDivConf      = safeNumber(input?.smDivConf, 0);
  const mmForcedDir    = String(input?.mmForcedDir || 'NEUTRAL').toUpperCase();
  const mmConf         = safeNumber(input?.mmConf, 0);
  const leadLagDir     = String(input?.leadLagDir || 'NEUTRAL').toUpperCase();
  const leadLagConf    = safeNumber(input?.leadLagConf, 0);
  const volumeAgrees   = (input?.volumeAgrees === true)  ? true
                       : (input?.volumeAgrees === false) ? false
                       : null; // unknown — skip the factor
  const tfDissent      = safeNumber(input?.tfDissent, 0);
  const tfTotal        = safeNumber(input?.tfTotal, 0);
  // Structural context — pulled from instCtx and passed via adaptForDecisionEngine
  const structureDir   = String(input?.structureDir   || 'NEUTRAL').toUpperCase(); // BULLISH/BEARISH/NEUTRAL
  const wyckoffBias    = String(input?.wyckoffBias    || 'NEUTRAL').toUpperCase(); // BUY/SELL/NEUTRAL
  const convictionPct  = safeNumber(input?.convictionPct, 0); // % of agents that agree with direction
  // Accept a pre-computed certainty from the consensus engine when present
  // so we do not double-compute. If absent, use the weighted formula.
  const baseCertainty  = Number(input?.baseCertainty);

  // ── TUNABLE THRESHOLDS (env-configurable) ────────────────────────────
  // V2 NEW DESIGN — INTEGRATED CONFIDENCE ADJUSTER, NOT A SEPARATE GATE
  // ─────────────────────────────────────────────────────────────────────
  // The user's formal engines own the primary gate (cert 90 / avg 50 /
  // conv 40 / pillars 4). V2's job is now narrow and additive:
  //   1. CAP + heavy-penalise the certainty when the signal is
  //      genuinely contradictory (hidden flow strongly opposes, quantum
  //      probability flips) — NO MORE HARD SKIP. The signal still flows
  //      downstream (VECTOR TRADE / Telegram cards) but with a reduced
  //      certainty (typically 50–65%) so the user's quality gate can
  //      transparently reject it instead of it being silently dropped
  //      while a parallel emission path prints "cert=99%".
  //   2. BOOST the certainty when conditions confirm the direction —
  //      letting strong setups reach (or exceed) the formal threshold
  //      they would otherwise miss by a few points.
  //   3. GRADUATED soft penalty for moderate contradictions (50–95% conf)
  //      so a 99% raw signal with hidden flow opposing at 60% drops to
  //      ~75%, and at 90% drops into the 50–65% band. Linear ramp
  //      between HIDDEN_SOFT_MIN and HIDDEN_CONTRA_MIN.
  // ─────────────────────────────────────────────────────────────────────
  const HIDDEN_CONTRA_MIN  = parseFloat(process.env.DECISION_CONTRADICTION_MIN || '65'); // ≥ this → hard CAP (was 85 — lowered so 65-84% hidden-flow opposition triggers the cap, not just soft penalty)
  const HIDDEN_SOFT_MIN    = parseFloat(process.env.DECISION_SOFT_CONTRA_MIN   || '50'); // ≥ this & < HARD → graduated PENALTY
  const QUANTUM_CONTRA_MIN = parseFloat(process.env.DECISION_QUANTUM_CONTRA    || '0.10'); // SELL when buyProb>0.90; BUY when buyProb<0.10
  const BOOST_MAX          = parseFloat(process.env.DECISION_BOOST_MAX         || '20');   // hard cap on boost added
  const PENALTY_MAX        = parseFloat(process.env.DECISION_PENALTY_MAX       || '45');   // raised: multiple contradictions must be able to collectively push any signal below the 90% gate
  const ALIGN_BOOST        = parseFloat(process.env.DECISION_ALIGN_BOOST       || '6');    // strong MTF agreement → +6
  const HIDDEN_BOOST       = parseFloat(process.env.DECISION_HIDDEN_BOOST      || '6');    // hidden flow agrees → +6
  const QUANTUM_BOOST      = parseFloat(process.env.DECISION_QUANTUM_BOOST     || '4');    // quantum prob agrees → +4
  const BTC_DOM_BOOST      = parseFloat(process.env.DECISION_BTC_DOM_BOOST     || '4');    // BTC dom regime favors dir → +4
  const HIDDEN_PENALTY_MIN = parseFloat(process.env.DECISION_HIDDEN_PENALTY_MIN|| '3');    // soft hidden-flow opposition floor (was 15 — softened: contradiction is logged, signal still fires)
  const HIDDEN_PENALTY_MAX = parseFloat(process.env.DECISION_HIDDEN_PENALTY_MAX|| '10');   // soft hidden-flow opposition ceiling (was 45 — softened so signals aren't wiped before they get a chance to run 10-20%)
  const QUANTUM_PENALTY    = parseFloat(process.env.DECISION_QUANTUM_PENALTY   || '4');    // soft quantum opposition → -4 (was -15)
  const CONTRA_CAP         = parseFloat(process.env.DECISION_CONTRA_CAP        || '85');   // hard cap value — capped signals land at 85%, which is BELOW the 90% gate and will NOT fire

  // 1) HIDDEN FLOW HARD BLOCK — ABSOLUTE, NO CONFIDENCE THRESHOLD.
  // User requirement: if hidden flow direction contradicts the signal direction the signal
  // must NEVER fire — regardless of hidden flow confidence percentage, certainty score,
  // or any other engine. Even 1% hidden flow SELL kills a BUY signal completely.
  if (dir === 'BUY' && hiddenFlow === 'SELL') {
    return { action: 'SKIP', certainty: 0, hiddenBlocked: true,
             reason: `Hidden flow SELL @ ${hiddenFlowConf}% contradicts BUY — signal blocked (no threshold)`,
             baseCert: 0, boost: 0, penalty: 0, netDelta: 0, rawBoosted: 0,
             status: 'BLOCKED', contradictionCap: null };
  }
  if (dir === 'SELL' && hiddenFlow === 'BUY') {
    return { action: 'SKIP', certainty: 0, hiddenBlocked: true,
             reason: `Hidden flow BUY @ ${hiddenFlowConf}% contradicts SELL — signal blocked (no threshold)`,
             baseCert: 0, boost: 0, penalty: 0, netDelta: 0, rawBoosted: 0,
             status: 'BLOCKED', contradictionCap: null };
  }

  // 1b) QUANTUM CONTRADICTION → CAP (quantum probability is less certain than hidden flow,
  //     so we cap rather than block outright — still prevents firing through the 90% gate)
  let contradictionCap = null;
  const contradictionReasons = [];
  if (dir === 'BUY'  && quantumBuyProb <= QUANTUM_CONTRA_MIN) {
    contradictionCap = Math.min(contradictionCap ?? CONTRA_CAP, CONTRA_CAP);
    contradictionReasons.push(`quantum buyProb ${quantumBuyProb.toFixed(2)} too low for BUY → cap ${CONTRA_CAP}`);
  }
  if (dir === 'SELL' && quantumBuyProb >= (1 - QUANTUM_CONTRA_MIN)) {
    contradictionCap = Math.min(contradictionCap ?? CONTRA_CAP, CONTRA_CAP);
    contradictionReasons.push(`quantum buyProb ${quantumBuyProb.toFixed(2)} too high for SELL → cap ${CONTRA_CAP}`);
  }

  // 2) ALIGNMENT (per-timeframe vote tally — informational, no block) ──
  let bullish = 0, bearish = 0, totalWeight = 0;
  for (const s of signals) {
    const d = String(s?.direction || '').toUpperCase();
    const w = safeNumber(s?.weight, 1);
    totalWeight += w;
    if (d === 'BUY')  bullish += w;
    if (d === 'SELL') bearish += w;
  }
  const alignment = totalWeight > 0 ? Math.max(bullish, bearish) / totalWeight : 1;
  // Alignment is now ONLY used to compute boost — never to block.

  // 3) BASE CERTAINTY = the user's raw consensus score (trusted, never
  //    recomputed downward). Sub-score formula is only a fallback when
  //    consensus engine didn't pre-compute one.
  let baseCert;
  if (Number.isFinite(baseCertainty) && baseCertainty > 0) {
    baseCert = baseCertainty;
  } else {
    baseCert = (mtfScore * 0.30 + structureScore * 0.25 + liquidityScore * 0.25 + volumeScore * 0.20);
  }
  baseCert = Math.max(0, Math.min(100, baseCert));

  // ── EXTRA TUNABLES for the new contributing engines ───────────────────
  // ✅ USER REQUEST: penalties drastically softened — most signals run
  // 10-20% in their favor before any reversal, so contradictions are
  // INFORMATIONAL (so the user's liquidity detector can decide entry
  // timing), not disqualifying. Boosts kept the same so true confluence
  // still pushes signals well above the 90% gate.
  const SMD_PENALTY_MAX    = parseFloat(process.env.DECISION_SMD_PENALTY_MAX    || '10'); // smart-money divergence opposing → max -10
  const SMD_BOOST          = parseFloat(process.env.DECISION_SMD_BOOST          || '6');  // smart-money divergence agreeing → +6
  const MM_PENALTY_MAX     = parseFloat(process.env.DECISION_MM_PENALTY_MAX     || '8');  // MM forced opposite → max -8
  const MM_BOOST           = parseFloat(process.env.DECISION_MM_BOOST           || '5');  // MM forced same → +5
  const LEADLAG_PENALTY    = parseFloat(process.env.DECISION_LEADLAG_PENALTY    || '5');  // lead-lag predicts opposite → -5
  const LEADLAG_BOOST      = parseFloat(process.env.DECISION_LEADLAG_BOOST      || '4');  // lead-lag predicts same → +4
  const VOL_PENALTY        = parseFloat(process.env.DECISION_VOL_PENALTY        || '10'); // volume diverges (CVD + dominance) → -10
  const VOL_BOOST          = parseFloat(process.env.DECISION_VOL_BOOST          || '3');  // volume agrees → +3
  const TF_DISSENT_PER     = parseFloat(process.env.DECISION_TF_DISSENT_PER     || '3');  // -3 per dissenting timeframe (was -1)
  const TF_DISSENT_MAX     = parseFloat(process.env.DECISION_TF_DISSENT_MAX     || '12'); // cap on tf-dissent penalty (was 4)
  // Structural contradiction engines — these represent hard market-structure facts:
  // a BEARISH structure on a BUY signal means price is still below key levels.
  const STRUCTURE_PENALTY  = parseFloat(process.env.DECISION_STRUCTURE_PENALTY  || '18'); // market structure contradicts direction → -18
  const WYCKOFF_PENALTY    = parseFloat(process.env.DECISION_WYCKOFF_PENALTY    || '10'); // wyckoff phase/bias contradicts direction → -10
  const CONVICTION_PENALTY = parseFloat(process.env.DECISION_CONVICTION_PENALTY || '8');  // agent conviction < 50% → -8
  const BTC_DOM_PENALTY    = parseFloat(process.env.DECISION_BTC_DOM_PENALTY    || '5');  // BTC dom unfavorable for alt direction → -5

  // 4a) BOOST CALCULATION — only positive factors, capped at BOOST_MAX ──
  let boost = 0;
  const boostReasons = [];
  if (alignment >= 0.85)           { boost += ALIGN_BOOST;       boostReasons.push(`align ${(alignment*100).toFixed(0)}% +${ALIGN_BOOST}`); }
  else if (alignment >= 0.70)      { boost += ALIGN_BOOST * 0.6; boostReasons.push(`align ${(alignment*100).toFixed(0)}% +${(ALIGN_BOOST*0.6).toFixed(1)}`); }
  if (dir === 'BUY'  && hiddenFlow === 'BUY'  && hiddenFlowConf >= 50) { boost += HIDDEN_BOOST; boostReasons.push(`hidden BUY @ ${hiddenFlowConf}% +${HIDDEN_BOOST}`); }
  if (dir === 'SELL' && hiddenFlow === 'SELL' && hiddenFlowConf >= 50) { boost += HIDDEN_BOOST; boostReasons.push(`hidden SELL @ ${hiddenFlowConf}% +${HIDDEN_BOOST}`); }
  if (dir === 'BUY'  && quantumBuyProb >= 0.70) { boost += QUANTUM_BOOST; boostReasons.push(`quantum ${quantumBuyProb.toFixed(2)} +${QUANTUM_BOOST}`); }
  if (dir === 'SELL' && quantumBuyProb <= 0.30) { boost += QUANTUM_BOOST; boostReasons.push(`quantum ${quantumBuyProb.toFixed(2)} +${QUANTUM_BOOST}`); }
  // BTC dominance regime — bull alts when dom <50, BTC strong when dom >55
  if (dir === 'BUY'  && btcDominance < 50)     { boost += BTC_DOM_BOOST; boostReasons.push(`btc.dom ${btcDominance.toFixed(1)}% +${BTC_DOM_BOOST}`); }
  if (dir === 'SELL' && btcDominance > 55)     { boost += BTC_DOM_BOOST; boostReasons.push(`btc.dom ${btcDominance.toFixed(1)}% +${BTC_DOM_BOOST}`); }
  // Smart-money divergence — bullish-div + BUY confirms, bearish-div + SELL confirms
  if (dir === 'BUY'  && smDivType === 'BULLISH_DIVERGENCE' && smDivConf >= 50) { boost += SMD_BOOST; boostReasons.push(`smartMoney BULL_DIV @ ${smDivConf}% +${SMD_BOOST}`); }
  if (dir === 'SELL' && smDivType === 'BEARISH_DIVERGENCE' && smDivConf >= 50) { boost += SMD_BOOST; boostReasons.push(`smartMoney BEAR_DIV @ ${smDivConf}% +${SMD_BOOST}`); }
  // Market-maker game theory in our direction = tailwind
  if (dir === 'BUY'  && mmForcedDir === 'BUY'  && mmConf >= 50) { boost += MM_BOOST; boostReasons.push(`MM forced BUY @ ${mmConf}% +${MM_BOOST}`); }
  if (dir === 'SELL' && mmForcedDir === 'SELL' && mmConf >= 50) { boost += MM_BOOST; boostReasons.push(`MM forced SELL @ ${mmConf}% +${MM_BOOST}`); }
  // Lead-lag in our direction
  if (dir === 'BUY'  && leadLagDir === 'BUY'  && leadLagConf >= 50) { boost += LEADLAG_BOOST; boostReasons.push(`leadLag BUY @ ${leadLagConf}% +${LEADLAG_BOOST}`); }
  if (dir === 'SELL' && leadLagDir === 'SELL' && leadLagConf >= 50) { boost += LEADLAG_BOOST; boostReasons.push(`leadLag SELL @ ${leadLagConf}% +${LEADLAG_BOOST}`); }
  // Volume agrees with direction
  if (volumeAgrees === true) { boost += VOL_BOOST; boostReasons.push(`volume agrees +${VOL_BOOST}`); }
  boost = Math.min(BOOST_MAX, Math.max(0, boost));

  // 4b) ✅ USER REQUEST: SOFT CONTRADICTION PENALTY (GRADUATED) ─────────
  // When a contradiction is present but NOT extreme enough to trigger
  // the hard CAP, V2 must still REDUCE the certainty proportionally to
  // how strong the opposition is. The penalty now ramps LINEARLY between
  // HIDDEN_SOFT_MIN and HIDDEN_CONTRA_MIN so:
  //   • hidden flow opposing at 50% → -15  (just enters soft band)
  //   • hidden flow opposing at 70% → -27  (mid-band)
  //   • hidden flow opposing at 84% → -44  (about to flip to hard CAP)
  // A raw 99% signal with hidden flow opposing at 90% will fall into the
  // hard CAP path above (forced to ≤60%); at 70% it lands ~72%; at 50%
  // it lands ~84%. This matches the "reduce to 50–70% on contradiction"
  // request without silently dropping the signal.
  let penalty = 0;
  const penaltyReasons = [];
  const _gradHidden = (conf) => {
    const span = Math.max(1, HIDDEN_CONTRA_MIN - HIDDEN_SOFT_MIN);
    const ratio = Math.max(0, Math.min(1, (conf - HIDDEN_SOFT_MIN) / span));
    return HIDDEN_PENALTY_MIN + ratio * (HIDDEN_PENALTY_MAX - HIDDEN_PENALTY_MIN);
  };
  // Hidden flow soft-penalty block removed — any opposing hidden flow at ≥50% now
  // causes a hard SKIP earlier in this function, so these conditions are unreachable.
  // Kept as a comment for auditing clarity.
  // Quantum mildly opposing direction (BUY but quantum tilts SELL, etc.)
  if (dir === 'BUY'  && quantumBuyProb > QUANTUM_CONTRA_MIN && quantumBuyProb < 0.40) {
    penalty += QUANTUM_PENALTY;
    penaltyReasons.push(`quantum ${quantumBuyProb.toFixed(2)} -${QUANTUM_PENALTY}`);
  }
  if (dir === 'SELL' && quantumBuyProb < (1 - QUANTUM_CONTRA_MIN) && quantumBuyProb > 0.60) {
    penalty += QUANTUM_PENALTY;
    penaltyReasons.push(`quantum ${quantumBuyProb.toFixed(2)} -${QUANTUM_PENALTY}`);
  }

  // ── NEW: Smart-money divergence opposing the trade direction ─────────
  // BEARISH_DIVERGENCE on a BUY = institutions are distributing into
  // retail buying. BULLISH_DIVERGENCE on a SELL = institutions are
  // accumulating while retail panics. Penalty scales with divergence conf.
  if (dir === 'BUY' && smDivType === 'BEARISH_DIVERGENCE' && smDivConf >= 50) {
    const p = Math.min(SMD_PENALTY_MAX, (smDivConf / 100) * SMD_PENALTY_MAX);
    penalty += p;
    penaltyReasons.push(`smartMoney BEAR_DIV @ ${smDivConf}% -${Math.round(p)}`);
  }
  if (dir === 'SELL' && smDivType === 'BULLISH_DIVERGENCE' && smDivConf >= 50) {
    const p = Math.min(SMD_PENALTY_MAX, (smDivConf / 100) * SMD_PENALTY_MAX);
    penalty += p;
    penaltyReasons.push(`smartMoney BULL_DIV @ ${smDivConf}% -${Math.round(p)}`);
  }

  // ── NEW: Market maker forced opposite direction ──────────────────────
  if (dir === 'BUY' && mmForcedDir === 'SELL' && mmConf >= 50) {
    const p = Math.min(MM_PENALTY_MAX, (mmConf / 100) * MM_PENALTY_MAX);
    penalty += p;
    penaltyReasons.push(`MM forced SELL @ ${mmConf}% -${Math.round(p)}`);
  }
  if (dir === 'SELL' && mmForcedDir === 'BUY' && mmConf >= 50) {
    const p = Math.min(MM_PENALTY_MAX, (mmConf / 100) * MM_PENALTY_MAX);
    penalty += p;
    penaltyReasons.push(`MM forced BUY @ ${mmConf}% -${Math.round(p)}`);
  }

  // ── NEW: Lead-lag predicts the opposite direction ───────────────────
  if (dir === 'BUY' && leadLagDir === 'SELL' && leadLagConf >= 50) {
    penalty += LEADLAG_PENALTY;
    penaltyReasons.push(`leadLag SELL @ ${leadLagConf}% -${LEADLAG_PENALTY}`);
  }
  if (dir === 'SELL' && leadLagDir === 'BUY' && leadLagConf >= 50) {
    penalty += LEADLAG_PENALTY;
    penaltyReasons.push(`leadLag BUY @ ${leadLagConf}% -${LEADLAG_PENALTY}`);
  }

  // ── NEW: Volume diverges from signal direction ───────────────────────
  if (volumeAgrees === false) {
    penalty += VOL_PENALTY;
    penaltyReasons.push(`volume diverges -${VOL_PENALTY}`);
  }

  // ── NEW: Per-timeframe dissent — accumulating "no" votes from TFs ────
  if (tfDissent > 0 && tfTotal > 0) {
    // 1 dissenter = -4, 2 = -8, 3 = -12 (capped). Single dissenter is
    // tolerable; multiple dissenters mean the consensus is shakier than
    // the headline number suggests.
    const p = Math.min(TF_DISSENT_MAX, tfDissent * TF_DISSENT_PER);
    penalty += p;
    penaltyReasons.push(`${tfDissent}/${tfTotal} TFs dissent -${Math.round(p)}`);
  }

  // ── STRUCTURAL CONTRADICTION PENALTIES (new engines) ─────────────────
  // struct.direction stores 'BUY' / 'SELL' / 'NEUTRAL' — same format as
  // the signal direction. A SELL structure on a BUY signal means price is
  // below key BOS/CHoCH levels — institutions are still distributing.
  // (The card displays this as "Structure: BEARISH" via struct.structure,
  //  but the machine-readable field is struct.direction = 'SELL'.)
  if (dir === 'BUY'  && structureDir === 'SELL') {
    penalty += STRUCTURE_PENALTY;
    penaltyReasons.push(`structure SELL (bearish) on BUY -${STRUCTURE_PENALTY}`);
  }
  if (dir === 'SELL' && structureDir === 'BUY') {
    penalty += STRUCTURE_PENALTY;
    penaltyReasons.push(`structure BUY (bullish) on SELL -${STRUCTURE_PENALTY}`);
  }
  // Wyckoff bias contradicts direction (e.g. DISTRIBUTION phase on BUY)
  if (dir === 'BUY'  && wyckoffBias === 'SELL') {
    penalty += WYCKOFF_PENALTY;
    penaltyReasons.push(`wyckoff SELL bias on BUY -${WYCKOFF_PENALTY}`);
  }
  if (dir === 'SELL' && wyckoffBias === 'BUY') {
    penalty += WYCKOFF_PENALTY;
    penaltyReasons.push(`wyckoff BUY bias on SELL -${WYCKOFF_PENALTY}`);
  }
  // Low agent conviction — fewer than half the contributing agents agree
  if (convictionPct > 0 && convictionPct < 50) {
    penalty += CONVICTION_PENALTY;
    penaltyReasons.push(`conviction ${convictionPct.toFixed(0)}% < 50% -${CONVICTION_PENALTY}`);
  }
  // BTC dominance regime unfavorable: high dom = alt season not active → BUY alts penalized
  if (dir === 'BUY'  && btcDominance > 55) {
    penalty += BTC_DOM_PENALTY;
    penaltyReasons.push(`btc.dom ${btcDominance.toFixed(1)}% > 55 unfavorable for alts -${BTC_DOM_PENALTY}`);
  }
  if (dir === 'SELL' && btcDominance < 45) {
    penalty += BTC_DOM_PENALTY;
    penaltyReasons.push(`btc.dom ${btcDominance.toFixed(1)}% < 45 -${BTC_DOM_PENALTY}`);
  }

  penalty = Math.min(PENALTY_MAX, Math.max(0, penalty));

  // 5) FINAL CERTAINTY — base + boost − penalty, then HARD CAP if any ──
  // When BOTH a boost and a penalty apply (rare but possible), they net
  // out — same direction-confirmation factors (alignment, BTC dom) can
  // boost while a soft hidden-flow contradiction simultaneously penalises.
  // If a hard contradiction was detected above, we additionally clamp the
  // result down to CONTRA_CAP so the signal lands in the 50–65 band even
  // if the boosts would otherwise hold it near 99% — this is the core of
  // the user's "reduce certainty on hidden-flow contradiction" request.
  const rawBoosted = baseCert + boost - penalty;
  let certainty    = Math.max(0, Math.min(100, rawBoosted));
  if (contradictionCap !== null) {
    certainty = Math.min(certainty, contradictionCap);
  }

  // Compose human-readable reason string
  const parts = [];
  if (contradictionCap !== null) parts.push(`HARD CONTRADICTION → cap ${contradictionCap} (${contradictionReasons.join('; ')})`);
  if (boost   > 0)               parts.push(`Boost +${Math.round(boost)} (${boostReasons.join(', ')})`);
  if (penalty > 0)               parts.push(`Penalty -${Math.round(penalty)} (${penaltyReasons.join(', ')})`);
  const reason = parts.length ? parts.join(' | ') : 'No boost or penalty — base certainty preserved';

  // netDelta is the *effective* change applied to baseCert AFTER the cap.
  // This is what gets propagated back to consensus.certaintyScore by
  // captureSignal, so downstream emission paths (VECTOR TRADE / Telegram)
  // see the adjusted score, not the raw 99%.
  const effectiveDelta = Math.round(certainty - baseCert);

  return {
    action: contradictionCap !== null ? 'PENALTY' : 'BOOST', // PENALTY when cap was applied; BOOST otherwise (legacy field)
    certainty: Math.round(certainty),
    rawBoosted: Math.round(rawBoosted),    // can be >100 or <0 before clamping
    boost: Math.round(boost),
    penalty: Math.round(penalty),          // soft penalty only — hard CAP shown separately in reason
    netDelta: effectiveDelta,              // ✅ effective delta vs base, AFTER hard cap (so propagation actually lowers downstream cert)
    baseCert: Math.round(baseCert),
    alignment: Math.round(alignment * 100),
    contradictionCap: contradictionCap,    // null when no hard contradiction
    status: certainty >= 90 ? 'CONFIRMED' : certainty >= 70 ? 'STRONG' : 'STANDARD',
    reason
  };
}

// Adapter: turns the engine's (signal, consensus, instCtx, btcDom) shape
// into the decideSignalV2 input. Keeps decideSignalV2 itself pure and
// drop-in replaceable.
function adaptForDecisionEngine(signal, consensus, instCtx, btcDom) {
  if (!signal || !signal.direction) return null;
  const dir = signal.direction;

  // Per-timeframe votes for the alignment check
  const tfSignals = consensus?.tfSignals || {};
  const tfList = Object.entries(tfSignals).map(([tf, s]) => ({
    name: tf,
    direction: s?.direction,
    weight: safeNumber(s?.weight, 1)
  }));

  // ── Contributing engines pulled from the v4 institutional context ────
  // Every one of these is a documented signal source on the consensus
  // card. V2 must consider ALL of them — not just hidden flow + quantum —
  // so a card that prints "MM forced to SELL" or "BEARISH_DIVERGENCE 80%"
  // can drag the certainty down even when hidden flow agrees, and a card
  // with multiple confirmations can boost above the formal gate.
  const v4         = instCtx?.v4 || {};
  const orderFlow  = v4.orderFlow   || instCtx?.orderFlow || null;
  const hiddenFlow     = orderFlow?.hiddenBias || 'NEUTRAL';
  const hiddenFlowConf = safeNumber(orderFlow?.hiddenConf, 0);

  // Smart money divergence — bearish/bullish divergence between price and
  // institutional footprint (CVD, absorption, declining volume).
  const smDiv = v4.smDivergence || null;
  const smDivType = smDiv?.detected ? (smDiv.type || '') : 'NONE'; // BEARISH_DIVERGENCE / BULLISH_DIVERGENCE / NONE
  const smDivConf = safeNumber(smDiv?.confidence, 0);

  // Market-maker game theory — direction MM is forced to hedge into.
  const mmTheory = v4.mmTheory || null;
  const mmForcedDir = mmTheory?.mmForcedDir || 'NEUTRAL'; // BUY / SELL / NEUTRAL
  const mmConf      = safeNumber(mmTheory?.mmConf, 0);

  // Lead-lag predictor — what a leading correlated asset implies.
  const leadLag = v4.leadLag || null;
  const leadLagDir  = leadLag?.predictedDir || 'NEUTRAL';
  const leadLagConf = safeNumber(leadLag?.confidence, 0);

  // Volume divergence — true when CVD trend / dominance opposes direction.
  // Mirror the same logic the volume formatter uses on the card so what
  // the user sees ("⚠️ Volume diverges from signal direction") is what V2
  // reads.
  const volMain = (v4.volCtx?.main) || (instCtx?.volCtx?.main) || null;
  let volumeAgrees = null; // null when unknown — engine will skip this factor
  if (volMain && volMain.cvdTrend && volMain.dominance) {
    volumeAgrees = (dir === 'BUY'  && volMain.cvdTrend === 'BULLISH' && volMain.dominance !== 'BEAR') ||
                   (dir === 'SELL' && volMain.cvdTrend === 'BEARISH' && volMain.dominance !== 'BULL');
  }

  // Per-TF dissent — count of timeframes voting AGAINST the signal
  // direction (excluding NEUTRAL). Used as a soft penalty so a 1-of-7
  // dissent costs less than a 3-of-7 dissent.
  let tfDissent = 0, tfTotal = 0;
  for (const t of tfList) {
    const d = String(t.direction || '').toUpperCase();
    if (d === 'BUY' || d === 'SELL') {
      tfTotal++;
      if (d !== dir) tfDissent++;
    }
  }

  // Quantum buy probability proxy when not provided directly: derive from
  // consensus direction + avgConfidence so the engine still gets signal.
  let quantumBuyProb = 0.5;
  if (typeof signal.quantumBuyProb === 'number') {
    quantumBuyProb = signal.quantumBuyProb;
  } else if (consensus?.consensusDirection) {
    const avg = safeNumber(consensus.avgConfidence, 50) / 100;
    quantumBuyProb = consensus.consensusDirection === 'BUY'  ? 0.5 + avg * 0.5
                   : consensus.consensusDirection === 'SELL' ? 0.5 - avg * 0.5
                   : 0.5;
    quantumBuyProb = Math.max(0, Math.min(1, quantumBuyProb));
  }

  return {
    signal:         dir,
    baseCertainty:  safeNumber(consensus?.certaintyScore, signal.confidence || 0),
    mtfScore:       safeNumber(consensus?.avgConfidence, 0),
    structureScore: safeNumber(consensus?.agreementRatio, 0) * 100,
    volumeScore:    safeNumber(consensus?.convictionPct, 0),
    liquidityScore: safeNumber(consensus?.certaintyScore, 0),
    hiddenFlow, hiddenFlowConf,
    quantumBuyProb,
    btcDominance:   safeNumber(btcDom, 50),
    signals:        tfList,
    // ── NEW contributing engines (passed through to decideSignalV2) ────
    smDivType, smDivConf,
    mmForcedDir, mmConf,
    leadLagDir, leadLagConf,
    volumeAgrees,
    tfDissent, tfTotal,
    // Market-structure context — critical for contradiction detection
    structureDir:   String((instCtx?.struct || instCtx?.structure)?.direction || 'NEUTRAL').toUpperCase(),
    wyckoffBias:    String(instCtx?.wyckoff?.bias || 'NEUTRAL').toUpperCase(),
    convictionPct:  safeNumber(consensus?.convictionPct, 0),
  };
}

// =========================
// SIGNAL RESOLVER — picks ONE winner from all candidates
// =========================
function resolveFinalSignal() {
  if (signalBucket.length === 0) return null;

  // ── DIRECTIONAL CONFLICT RESOLUTION ──────────────────────────────────────
  // The bucket accumulates signals from ALL symbols across one full scan cycle.
  // Within a single cycle it is normal — and expected — for BTCUSDT to be BUY
  // while SOLUSDT is SELL.  Those are independent signals, not conflicts.
  //
  // The conflict we must prevent: the same symbol producing BOTH BUY and SELL
  // candidates in one cycle (e.g. HTF BUY + INTRA SELL for BTCUSDT).
  // Resolution: for each symbol, if both directions exist, keep only the
  // candidate with the HIGHER confidence and discard the opposing one.
  // ─────────────────────────────────────────────────────────────────────────
  const symbolMap = new Map();  // symbol → { BUY: maxConf, SELL: maxConf }
  for (const sig of signalBucket) {
    const sym = sig.symbol || 'UNKNOWN';
    if (!symbolMap.has(sym)) symbolMap.set(sym, { BUY: -1, SELL: -1 });
    const entry = symbolMap.get(sym);
    if (sig.direction === 'BUY'  && sig.confidence > entry.BUY)  entry.BUY  = sig.confidence;
    if (sig.direction === 'SELL' && sig.confidence > entry.SELL) entry.SELL = sig.confidence;
  }

  // ── HARD CONTRADICTION (per-symbol BOTH BUY + SELL strong) ─────────
  // If a symbol produced BOTH directions and BOTH are >= 60% confidence,
  // the underlying models are split — SKIP the symbol entirely instead of
  // forcing a winner. This is the "WAIT — Low alignment" behaviour at the
  // resolver layer.
  const skipSymbols = new Set();
  for (const [sym, e] of symbolMap.entries()) {
    if (e.BUY >= 60 && e.SELL >= 60) {
      console.log(`🛑 HARD CONTRADICTION [${sym}] BUY ${e.BUY}% vs SELL ${e.SELL}% — SKIP (no forced winner)`);
      skipSymbols.add(sym);
    }
  }

  // For each symbol with a conflict, mark the losing direction for removal
  const filtered = signalBucket.filter(sig => {
    const sym = sig.symbol || 'UNKNOWN';
    if (skipSymbols.has(sym)) return false;     // hard-skipped — no signal at all
    const entry = symbolMap.get(sym);
    if (!entry) return true;
    const hasBoth = entry.BUY >= 0 && entry.SELL >= 0;
    if (!hasBoth) return true;  // no conflict for this symbol
    // Keep only the winning direction for this symbol
    const winner = entry.BUY >= entry.SELL ? 'BUY' : 'SELL';
    if (sig.direction !== winner) {
      console.log(`⚔️  Directional conflict resolved [${sym}]: dropped ${sig.direction} @ ${sig.confidence}% in favour of ${winner} @ ${Math.max(entry.BUY, entry.SELL)}%`);
      return false;
    }
    return true;
  });

  if (filtered.length === 0) return null;
  // Sort descending by confidence; on exact tie, prefer the more recent signal
  // (latest timestamp = freshest market data).
  filtered.sort((a, b) => {
    if (b.confidence !== a.confidence) return b.confidence - a.confidence;
    return (b.timestamp || 0) - (a.timestamp || 0); // ✅ tie-break: newest wins
  });
  // Also update the live signalBucket reference so /status endpoint stays accurate
  signalBucket.length = 0;
  for (const s of filtered) signalBucket.push(s);
  return filtered[0];
}

// =========================
// FIX 3 — SINGLE SIGNAL OUTPUT + DUPLICATE FILTER
// =========================
let finalSignal = null;
let lastSignal  = null;   // tracks the previously emitted signal for dedup

// Safe JSON stringify — strips circular refs and very large arrays so
// emitSignal logging cannot blow up the process if the signal object
// accidentally retained a reference to candles/orderbook/etc.
function safeStringify(obj, indent = 2) {
  const seen = new WeakSet();
  try {
    return JSON.stringify(obj, (k, v) => {
      if (v && typeof v === 'object') {
        if (seen.has(v)) return '[Circular]';
        seen.add(v);
        // Skip massive arrays/buffers that have no place in a signal log
        if (Array.isArray(v) && v.length > 100) return `[Array(${v.length})]`;
      }
      return v;
    }, indent);
  } catch (_) {
    return String(obj);
  }
}

// Final certainty floor — even if a signal slipped past every other gate,
// emitSignal refuses to fire below this confidence. Configurable via env.
const EMIT_CERT_FLOOR = parseInt(process.env.EMIT_CERT_FLOOR || '0', 10); // default 0 = disabled

function emitSignal(signal) {
  if (!signal) return;
  // EMERGENCY_HALT backstop at the emit boundary
  if (process.env.EMERGENCY_HALT === '1' || _engineState.emergencyHalt === true) {
    console.log('🛑 EMERGENCY_HALT active — emitSignal refused');
    return;
  }
  // Final certainty floor — backstop independent of capture gates
  if (EMIT_CERT_FLOOR > 0 && safeNumber(signal.confidence) < EMIT_CERT_FLOOR) {
    console.log(`⏭️  emitSignal floor: ${signal.symbol||''} ${signal.direction} ${signal.confidence}% < ${EMIT_CERT_FLOOR}% — refused`);
    return;
  }

  // ── Duplicate / noise filter ─────────────────────────────────────────
  // Suppress ONLY when: same SYMBOL + same DIRECTION within 60 s.
  // Different symbols with the same direction (e.g. BTCUSDT BUY then ETHUSDT BUY)
  // are independent signals and must NOT suppress each other.
  // ✅ FIX: added symbol check so cross-symbol dedup no longer occurs.
  if (
    lastSignal &&
    lastSignal.direction === signal.direction &&
    (lastSignal.symbol || 'UNKNOWN') === (signal.symbol || 'UNKNOWN') &&
    (Date.now() - (lastSignal.timestamp || 0)) < 60_000
  ) {
    console.log(`⏭️  Duplicate ${signal.symbol || ''} ${signal.direction} suppressed (same symbol+dir within 60s)`);
    return;
  }

  finalSignal = signal;
  lastSignal  = signal;

  // Update scoped engine state for external consumers
  _engineState.signalDir = signal.direction || null;
  _engineState.riskLevel = signal.confidence >= 75 ? 'HIGH'
                         : signal.confidence >= 50 ? 'MEDIUM'
                         : 'LOW';
  // ✅ FIX: use safeStringify to prevent crashes on circular refs / huge nested arrays.
  console.log('📊 SIGNAL:', safeStringify(signal));
}

// =========================
// FIX 4 — SAFE LOOP EXECUTION (30 s interval, Render-safe)
// =========================
// Execution pipeline: clear bucket → run all engines → resolve winner → emit
async function runSignalEngine() {
  // ══ SINGLE BRAIN PIPELINE ══════════════════════════════════════════════
  // analyze → normalize → validate → resolve → emit
  // Every strategy / engine feeds captureSignal(buildSignal({...})).
  // Only ONE signal survives: the highest confidence, after dedup.
  // ═══════════════════════════════════════════════════════════════════════

  // Step 1 — CLEAR: wipe the bucket so no stale candidates survive
  signalBucket.length = 0;

  // Step 2 — ANALYZE: run full MTF + Intraday consensus auto-scanner.
  //          Internally every generateEnhancedQuantumSignal() call and
  //          every VECTOR TRADE/WATCH verdict pushes into signalBucket.
  if (typeof autoScanner === 'function') {
    await autoScanner();
  }

  // Step 3 — NORMALIZE + VALIDATE: already enforced inside captureSignal()
  //          (normalizeConfidence, NEUTRAL filter, shape via buildSignal)

  // Step 4 — RESOLVE: sort by confidence, pick the single winner
  const winner = resolveFinalSignal();

  console.log(
    winner
      ? `🧠 Single Brain → ${winner.direction} ${winner.confidence}% | ${winner.reason} | candidates: ${signalBucket.length}`
      : `🧠 Single Brain → no signal this cycle (${signalBucket.length} candidate(s))`
  );

  // Step 5 — EMIT: dedup filter inside emitSignal suppresses same-dir repeats
  if (winner) {
    emitSignal(winner);
  }
}

// ── Circuit breaker + cycle telemetry ──────────────────────────────────
// Tracks consecutive runSignalEngine failures and exposes per-cycle stats
// for /status endpoints. After CIRCUIT_BREAK_THRESHOLD consecutive failures,
// the engine pauses for CIRCUIT_BREAK_COOLDOWN_MS ms before retrying — this
// prevents tight failure loops from saturating logs / API quotas.
const CIRCUIT_BREAK_THRESHOLD   = parseInt(process.env.CIRCUIT_BREAK_THRESHOLD   || '5', 10);
const CIRCUIT_BREAK_COOLDOWN_MS = parseInt(process.env.CIRCUIT_BREAK_COOLDOWN_MS || '60000', 10);
const _cycleTelemetry = {
  totalCycles:         0,
  successCycles:       0,
  failedCycles:        0,
  consecutiveFailures: 0,
  pausedUntil:         0,
  lastError:           null,
  lastSuccessAt:       0,
  lastCycleAt:         0,
  lastCycleMs:         0,
};

async function mainLoop() {
  const now = Date.now();
  // Circuit breaker: skip the cycle if we are still in the cooldown window
  if (_cycleTelemetry.pausedUntil > now) {
    const waitMs = _cycleTelemetry.pausedUntil - now;
    console.log(`⏸  Circuit breaker active — skipping cycle (resume in ${Math.round(waitMs/1000)}s)`);
    return;
  }
  _cycleTelemetry.totalCycles++;
  _cycleTelemetry.lastCycleAt = now;
  const t0 = now;
  try {
    await runSignalEngine();
    _cycleTelemetry.successCycles++;
    _cycleTelemetry.consecutiveFailures = 0;
    _cycleTelemetry.lastSuccessAt = Date.now();
    _cycleTelemetry.lastError = null;
  } catch (err) {
    _cycleTelemetry.failedCycles++;
    _cycleTelemetry.consecutiveFailures++;
    _cycleTelemetry.lastError = err?.message || String(err);
    console.error(`Engine error (consecutive=${_cycleTelemetry.consecutiveFailures}):`, err);
    if (_cycleTelemetry.consecutiveFailures >= CIRCUIT_BREAK_THRESHOLD) {
      _cycleTelemetry.pausedUntil = Date.now() + CIRCUIT_BREAK_COOLDOWN_MS;
      console.error(`🛑 Circuit breaker tripped — pausing engine for ${Math.round(CIRCUIT_BREAK_COOLDOWN_MS/1000)}s after ${_cycleTelemetry.consecutiveFailures} consecutive failures`);
      _cycleTelemetry.consecutiveFailures = 0; // reset so we re-arm after cooldown
    }
  } finally {
    _cycleTelemetry.lastCycleMs = Date.now() - t0;
    // ── Periodic LAST_ALERT cleanup — prevents unbounded Map growth.
    // Runs every 50 cycles; drops entries older than 4 hours.
    if (_cycleTelemetry.totalCycles % 50 === 0 && typeof LAST_ALERT !== 'undefined' && LAST_ALERT instanceof Map) {
      const cutoff = Date.now() - 4 * 60 * 60 * 1000;
      let removed = 0;
      for (const [k, ts] of LAST_ALERT.entries()) {
        if (typeof ts === 'number' && ts < cutoff) { LAST_ALERT.delete(k); removed++; }
      }
      if (removed > 0) console.log(`🧹 LAST_ALERT cleanup: removed ${removed} stale entries (size=${LAST_ALERT.size})`);
    }
  }
}

// NOTE: mainLoop / runSignalEngine is driven by startEnhancedAutoScanner (WATCH_INTERVAL_MS).
// A separate 30 s setInterval here would race with that cycle, clear the shared
// signalBucket mid-scan, and produce duplicate / lost signals — so it is intentionally
// NOT registered here.  startEnhancedAutoScanner calls runSignalEngine(), which owns
// the clear → analyze → resolve → emit pipeline.

/* =========================
   MARKET PRICE HANDLER
========================= */
// fetchLivePrice is defined in the DATA FETCHERS section below.
// It is safe because generateSignal is only called at runtime, after the full script loads.

/* =========================
   RISK & CONFIDENCE ENGINE
========================= */
// computeConfidence is a function declaration at the end of the file.
// Function declarations are hoisted, so it is available throughout the file.

/* =========================
   TP / SL NORMALIZATION
========================= */
function computeTPSL(entry, direction, riskPct = 1.5) {
  // FIX: default riskPct raised from 0.5 → 1.5 (0.5% was far too tight for alts).
  // FIX: TP multiplier raised from 2× → 3.5× (was 2:1 RR → now 3.5:1 minimum).
  // A 2:1 RR means TP1 is only twice the SL — price sweeps through TP1 and reverses.
  // 3.5:1 ensures TP1 sits beyond the sweep range in the real-move zone.
  entry = safeNumber(entry);
  const risk = entry * (riskPct / 100);

  if (direction === 'BUY') {
    return {
      tp: entry + risk * 3.5,
      sl: entry - risk
    };
  } else {
    return {
      tp: entry - risk * 3.5,
      sl: entry + risk
    };
  }
}

/* =========================
   FAKE BREAKOUT DETECTOR
   ─────────────────────────────────────────────────────────────────
   Detects when price "breaks" a level (makes a new high/low) but
   the move has no institutional backing — the classic trap that
   fills your limit then reverses against you.

   A FAKE breakout has ALL of the following:
     1. The breakout candle has a long wick (wick > body × 1.5) — 
        price pushed through, got rejected, closed back inside.
     2. Volume on the breakout candle is BELOW the 20-bar average —
        real breaks need volume expansion, not contraction.
     3. The NEXT candle opens and immediately moves BACK through the
        broken level — confirming the break failed.

   Returns { isFake, reason, confidence }.
   ========================= */
function isFakeBreakout(candles, dir, price) {
  if (!candles || candles.length < 5) return { isFake: false, reason: 'Insufficient candles' };

  const last  = candles[candles.length - 1];
  const prev  = candles[candles.length - 2];
  if (!last || !prev) return { isFake: false, reason: 'No candle data' };

  const range    = (last.h - last.l) || 0.0001;
  const body     = Math.abs(last.c - last.o);
  const bodyPct  = body / range;

  // Wick analysis
  const upWick   = last.h - Math.max(last.c, last.o);
  const downWick = Math.min(last.c, last.o) - last.l;
  const wickRatio = dir === 'BUY'
    ? downWick / (body || 0.0001)   // BUY: lower wick rejection
    : upWick   / (body || 0.0001);  // SELL: upper wick rejection

  // Volume analysis
  const avgVol20 = candles.slice(-20, -1).reduce((a, c) => a + (c.v || 0), 0) / 19;
  const volCollapse = (last.v || 0) < avgVol20 * 0.90;  // breakout with falling volume

  // Price returned inside: close is back inside range of previous candle
  const returnedInside = dir === 'BUY'
    ? last.c < prev.l  // BUY breakout: price closed back below previous low
    : last.c > prev.h; // SELL breakout: price closed back above previous high

  // Momentum test: if the 3 candles BEFORE this one were also against the signal
  // direction, the "breakout" is actually a counter-trend pop
  const priorBars  = candles.slice(-4, -1);
  const priorAgainst = priorBars.filter(c =>
    dir === 'BUY' ? c.c < c.o : c.c > c.o
  ).length;
  const counterTrendPop = priorAgainst >= 2;

  // Score the fake signals
  let fakeScore = 0;
  if (wickRatio > 1.5)    fakeScore += 3;  // long rejection wick
  if (bodyPct < 0.30)     fakeScore += 2;  // tiny body = indecision
  if (volCollapse)        fakeScore += 3;  // volume not confirming
  if (returnedInside)     fakeScore += 4;  // price came right back
  if (counterTrendPop)    fakeScore += 2;  // fighting the prior trend

  const isFake      = fakeScore >= 6;  // threshold: 2+ signals = FAKE
  const confidence  = Math.min(95, fakeScore * 10);

  const reasons = [];
  if (wickRatio > 1.5)   reasons.push(`rejection wick ${(wickRatio).toFixed(1)}× body`);
  if (bodyPct < 0.30)    reasons.push(`weak body ${(bodyPct*100).toFixed(0)}%`);
  if (volCollapse)       reasons.push(`volume collapse (${Math.round((last.v||0)/avgVol20*100)}% of avg)`);
  if (returnedInside)    reasons.push('price returned inside prior range');
  if (counterTrendPop)   reasons.push(`${priorAgainst}/3 prior bars oppose direction`);

  return {
    isFake,
    confidence,
    fakeScore,
    reason: reasons.join(' | ') || 'No fake signals detected',
  };
}


/* ═══════════════════════════════════════════════════════════════════════════
   PER-SYMBOL PIPELINE TIMEOUT WRAPPER
   ──────────────────────────────────────────────────────────────────────────
   Wraps any async promise with a hard timeout. If the promise does not
   resolve within `ms` milliseconds, it rejects with a TimeoutError.
   This prevents a single slow API call from stalling the ENTIRE scan loop —
   the root cause of the "SCAN ENGINE PAUSED" Telegram alerts.

   Usage: const result = await withTimeout(buildMTFConsensus(...), 45000, 'buildMTF ALGOUSDT')
   ═══════════════════════════════════════════════════════════════════════════ */
function withTimeout(promise, ms, label = '') {
  let _timer;
  const timeoutP = new Promise((_, reject) => {
    _timer = setTimeout(() => {
      reject(new Error(`⏱ TIMEOUT (${ms}ms)${label ? ` [${label}]` : ''} — API call abandoned, scan loop continues`));
    }, ms);
  });
  return Promise.race([promise, timeoutP]).finally(() => clearTimeout(_timer));
}

/* ═══════════════════════════════════════════════════════════════════════════
   MARKET REGIME FILTER
   ──────────────────────────────────────────────────────────────────────────
   Determines whether current market conditions are worth trading.
   Returns { tradeable, regime, reason, score }.

   BLOCKS trades when:
     • ADX < REGIME_ADX_MIN     → market is in chop (no directional strength)
     • ATR contracting sharply  → volatility collapsing = range-bound trap
     • Too many inside bars     → accumulation/distribution not yet resolved
     • Overextended candle      → late entry after the move already happened
     • Abnormal ATR spike       → news/flash-crash/manipulation event

   The auto kill-switch also runs through here: consecutive losses beyond
   KILL_CONSECUTIVE_LOSSES suspends trading for the rest of the scan cycle.
   ═══════════════════════════════════════════════════════════════════════════ */
function assessMarketRegime(candles, dir) {
  if (!candles || candles.length < 30) {
    return { tradeable: true, regime: 'UNKNOWN', reason: 'Insufficient candles for regime check', score: 50 };
  }

  const last    = candles[candles.length - 1];
  const slice   = candles.slice(-50);
  const recent  = candles.slice(-14);

  // ── ATR(14) ─────────────────────────────────────────────────────────────
  const atr14  = recent.reduce((a, c) => a + (c.h - c.l), 0) / recent.length;
  const atr50  = slice.reduce((a, c) => a + (c.h - c.l), 0) / slice.length;
  const atrRatio = atr50 > 0 ? atr14 / atr50 : 1;

  // ── ABNORMAL ATR SPIKE (news / flash crash) ────────────────────────────
  const lastRange = last.h - last.l;
  const atrSpike  = atr14 > 0 && (lastRange / atr14) > KILL_ABNORMAL_ATR_MULT;

  // ── ADX PROXY (directional strength via candle movement ratio) ─────────
  // True ADX needs ±DI, but we approximate: how many of the last 14 bars
  // moved MORE than 50% of their range in ONE direction (strong trend bar)?
  const trendBars  = recent.filter(c => Math.abs(c.c - c.o) / ((c.h - c.l) || 0.0001) > 0.50).length;
  const adxProxy   = Math.round((trendBars / recent.length) * 100); // 0–100

  // ── CHOP DETECTION (inside bars) ──────────────────────────────────────
  const lastN    = candles.slice(-REGIME_CHOP_BARS - 1);
  let insideBars = 0;
  for (let i = 1; i < lastN.length; i++) {
    if (lastN[i].h <= lastN[i-1].h && lastN[i].l >= lastN[i-1].l) insideBars++;
  }
  const chopRange = insideBars >= Math.floor(REGIME_CHOP_BARS * 0.6);

  // ── OVEREXTENDED CANDLE (late entry trap) ─────────────────────────────
  // Entry candle is overextended when it has already moved > 2.5× ATR
  // from its open. Entering here = chasing the move at the worst price.
  const entryMove    = Math.abs(last.c - last.o);
  const overExtended = atr14 > 0 && (entryMove / atr14) > 2.5;

  // ── LAST CANDLE BODY CHECK ─────────────────────────────────────────────
  const bodyPct  = Math.abs(last.c - last.o) / ((last.h - last.l) || 0.0001);
  const weakBody = bodyPct < REGIME_CANDLE_BODY_MIN;

  // ── SCORE THE REGIME ──────────────────────────────────────────────────
  let score = 100;
  const blocks = [];

  if (atrSpike)       { score -= 50; blocks.push(`ATR spike ${(lastRange/atr14).toFixed(1)}×avg — news/flash crash event`); }
  if (adxProxy < REGIME_ADX_MIN) { score -= 25; blocks.push(`ADX proxy ${adxProxy} < ${REGIME_ADX_MIN} — choppy market`); }
  if (atrRatio < REGIME_ATR_MULT_MIN) { score -= 20; blocks.push(`ATR contracting (${atrRatio.toFixed(2)}×) — volatility collapsing`); }
  if (chopRange)      { score -= 20; blocks.push(`${insideBars}/${REGIME_CHOP_BARS} inside bars — range-bound`); }
  if (overExtended)   { score -= 25; blocks.push(`entry candle ${(entryMove/atr14).toFixed(1)}×ATR — overextended, late entry`); }
  if (weakBody)       { score -= 10; blocks.push(`candle body ${(bodyPct*100).toFixed(0)}% < ${REGIME_CANDLE_BODY_MIN*100}% — indecision`); }

  score = Math.max(0, score);

  const tradeable = score >= 50 && !atrSpike;
  const regime    = atrSpike       ? 'CRISIS'
                  : score >= 80    ? 'TRENDING'
                  : score >= 60    ? 'HEALTHY'
                  : score >= 40    ? 'CHOPPY'
                  : 'DEAD';

  return {
    tradeable,
    regime,
    score,
    atrRatio:    parseFloat(atrRatio.toFixed(3)),
    adxProxy,
    insideBars,
    atrSpike,
    overExtended,
    weakBody,
    reason: blocks.length ? blocks.join(' | ') : `Regime OK (score ${score}) — tradeable`,
  };
}

/* ═══════════════════════════════════════════════════════════════════════════
   MOMENTUM QUALITY GATE
   ──────────────────────────────────────────────────────────────────────────
   Checks RSI, volume surge, and price structure for momentum confirmation.
   Rejects signals where momentum is weak, exhausted, or counter-trend.
   ═══════════════════════════════════════════════════════════════════════════ */
function assessMomentumQuality(candles, dir) {
  if (!candles || candles.length < 20) {
    return { qualified: true, reason: 'Insufficient candles for momentum check', rsi: 50, volRatio: 1 };
  }

  const closes = candles.map(c => c.c);
  const n = closes.length;

  // ── RSI(14) ───────────────────────────────────────────────────────────
  let gains = 0, losses = 0;
  for (let i = n - 14; i < n; i++) {
    const d = closes[i] - closes[i - 1];
    if (d > 0) gains += d; else losses += Math.abs(d);
  }
  const avgGain = gains / 14, avgLoss = losses / 14;
  const rs  = avgLoss === 0 ? 100 : avgGain / avgLoss;
  const rsi = 100 - (100 / (1 + rs));

  // ── VOLUME SURGE ──────────────────────────────────────────────────────
  const last     = candles[candles.length - 1];
  const avgVol20 = candles.slice(-20, -1).reduce((a, c) => a + (c.v || 0), 0) / 19;
  const volRatio = avgVol20 > 0 ? (last.v || 0) / avgVol20 : 1;

  // ── MOMENTUM CHECKS ───────────────────────────────────────────────────
  const rsiOk = dir === 'BUY'
    ? rsi >= MOMENTUM_RSI_BULL_MIN
    : rsi <= MOMENTUM_RSI_BEAR_MAX;

  const volOk  = volRatio >= MOMENTUM_VOL_SURGE;

  // Trend exhaustion: last 5 bars all same direction = overstretched
  const last5 = candles.slice(-5);
  const allBull = last5.every(c => c.c > c.o);
  const allBear = last5.every(c => c.c < c.o);
  const exhausted = dir === 'BUY' ? allBull : allBear; // already moved 5 bars straight

  const issues = [];
  if (!rsiOk)    issues.push(`RSI ${rsi.toFixed(1)} ${dir==='BUY'?'<'+MOMENTUM_RSI_BULL_MIN:'>'+MOMENTUM_RSI_BEAR_MAX} — momentum not aligned`);
  if (!volOk)    issues.push(`volume ${volRatio.toFixed(2)}× avg < ${MOMENTUM_VOL_SURGE}× — no institutional participation`);
  if (exhausted) issues.push(`5 consecutive ${dir==='BUY'?'bullish':'bearish'} bars — trend exhaustion, reversal risk`);

  const qualified = rsiOk && !exhausted; // volume is advisory (logged but not hard block)

  return {
    qualified,
    rsi:       parseFloat(rsi.toFixed(1)),
    volRatio:  parseFloat(volRatio.toFixed(2)),
    exhausted,
    rsiOk,
    volOk,
    reason: issues.length ? issues.join(' | ') : `Momentum OK — RSI ${rsi.toFixed(1)}, vol ${volRatio.toFixed(2)}×`,
  };
}

/* ═══════════════════════════════════════════════════════════════════════════
   FUNDING RATE + OPEN INTEREST ALIGNMENT GATE (Futures only)
   ──────────────────────────────────────────────────────────────────────────
   Extreme funding rates mean the crowd is massively one-sided — exactly
   when the exchange sweeps stops. Blocks entries that swim with the crowd.
   ═══════════════════════════════════════════════════════════════════════════ */
function checkFundingAlignment(fundingRate, openInterestChange, dir) {
  if (fundingRate == null) return { ok: true, reason: 'No funding data' };

  const fr = parseFloat(fundingRate) || 0;
  const oiChg = parseFloat(openInterestChange) || 0;

  const issues = [];

  // Extreme positive funding + BUY = longs massively overcrowded = squeeze risk
  if (dir === 'BUY'  && fr >  0.0008) issues.push(`Funding +${(fr*100).toFixed(4)}% — longs overcrowded, squeeze risk`);
  // Extreme negative funding + SELL = shorts massively overcrowded = squeeze risk
  if (dir === 'SELL' && fr < -0.0008) issues.push(`Funding ${(fr*100).toFixed(4)}% — shorts overcrowded, squeeze risk`);

  // OI divergence: price moving but OI falling = no real conviction
  if (oiChg < -0.05 && Math.abs(fr) > 0.0003) issues.push(`OI declining ${(oiChg*100).toFixed(1)}% — real money exiting position`);

  return {
    ok:          issues.length === 0,
    fundingRate: fr,
    oiChange:    oiChg,
    reason:      issues.length ? issues.join(' | ') : `Funding OK (${(fr*100).toFixed(4)}%)`,
  };
}

/* ═══════════════════════════════════════════════════════════════════════════
   AUTO KILL-SWITCH
   ──────────────────────────────────────────────────────────────────────────
   Suspends signal emission after KILL_CONSECUTIVE_LOSSES consecutive
   rejected/losing signals. Resets after one full scan cycle with no losses.
   ═══════════════════════════════════════════════════════════════════════════ */
const _killSwitch = {
  consecutiveLosses: 0,
  suspended:         false,
  suspendedAt:       0,
  suspendReason:     '',
  RESUME_AFTER_MS:   Number(process.env.KILL_RESUME_MS || 900000), // 15 min cooldown
};

function killSwitchCheck(symbol) {
  // Auto-resume after cooldown
  if (_killSwitch.suspended && (Date.now() - _killSwitch.suspendedAt) > _killSwitch.RESUME_AFTER_MS) {
    _killSwitch.suspended         = false;
    _killSwitch.consecutiveLosses = 0;
    _killSwitch.suspendReason     = '';
    console.log('✅ KILL-SWITCH: Auto-resumed after cooldown');
  }
  if (_killSwitch.suspended) {
    const waitMin = Math.round((_killSwitch.RESUME_AFTER_MS - (Date.now() - _killSwitch.suspendedAt)) / 60000);
    console.log(`🛑 KILL-SWITCH ACTIVE — trading suspended (${waitMin}m remaining) | reason: ${_killSwitch.suspendReason}`);
    return false;
  }
  return true;
}

function killSwitchRecord(won) {
  if (!won) {
    _killSwitch.consecutiveLosses++;
    if (_killSwitch.consecutiveLosses >= KILL_CONSECUTIVE_LOSSES) {
      _killSwitch.suspended     = true;
      _killSwitch.suspendedAt   = Date.now();
      _killSwitch.suspendReason = `${_killSwitch.consecutiveLosses} consecutive losses — suspended ${Math.round(_killSwitch.RESUME_AFTER_MS/60000)}min`;
      console.error(`🛑 KILL-SWITCH TRIPPED: ${_killSwitch.suspendReason}`);
    }
  } else {
    _killSwitch.consecutiveLosses = 0;
  }
}

/* ═══════════════════════════════════════════════════════════════════════════
   MULTI-TIMEFRAME ALIGNMENT CHECK
   ──────────────────────────────────────────────────────────────────────────
   For a signal to be valid, ALL higher timeframes must agree with direction.
   A 15m BUY while 4H and 1D are SELL = counter-trend gamble = blocked.
   ═══════════════════════════════════════════════════════════════════════════ */
function checkMTFAlignment(consensus, dir) {
  if (!consensus || !consensus.tfSignals) return { ok: true, reason: 'No MTF data' };

  const tfSignals   = consensus.tfSignals;
  const htfKeys     = ['4h', '8h', '1day', '2day', '3day', '1week'];
  const conflictTFs = htfKeys.filter(tf =>
    tfSignals[tf]?.direction &&
    tfSignals[tf].direction !== dir &&
    tfSignals[tf].direction !== 'NEUTRAL'
  );

  if (conflictTFs.length > 0) {
    return {
      ok:     false,
      reason: `HTF conflict on ${conflictTFs.join(', ')} — higher timeframes oppose ${dir}`,
      conflictTFs,
    };
  }

  const agreeingHTFs = htfKeys.filter(tf =>
    tfSignals[tf]?.direction === dir
  );

  return {
    ok:          true,
    agreeingHTFs,
    reason:      `MTF aligned — ${agreeingHTFs.length} HTFs agree with ${dir}`,
  };
}

/* ═══════════════════════════════════════════════════════════════════════════
   ADAPTIVE TRAILING STOP / PARTIAL TP ENGINE
   ──────────────────────────────────────────────────────────────────────────
   Instead of a fixed 10% TP that price hits and immediately reverses from,
   this engine produces:
     • TP1 at 1.0× ATR from entry (bank 50% of position)
     • TP2 at 2.5× ATR from entry (bank 35% more)
     • Trailing stop for the final 15% (locks in via structure)
     • Hard SL at 0.8× ATR below entry (not emotion-based)
   ═══════════════════════════════════════════════════════════════════════════ */
function computeAdaptiveTPSL(candles, entry, dir, leverage = 1) {
  if (!candles || candles.length < 14 || !entry || entry <= 0) {
    return null;
  }

  const atr14  = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  if (atr14 <= 0) return null;

  // Scale ATR multipliers inversely with leverage:
  // Higher leverage = tighter stops (can't afford as wide a drawdown)
  const levScale = leverage >= 10 ? 0.6 : leverage >= 5 ? 0.8 : 1.0;

  const sl  = dir === 'BUY'
    ? entry - atr14 * 0.8 * levScale
    : entry + atr14 * 0.8 * levScale;

  const tp1 = dir === 'BUY'
    ? entry + atr14 * 1.0 * levScale
    : entry - atr14 * 1.0 * levScale;

  const tp2 = dir === 'BUY'
    ? entry + atr14 * 2.5 * levScale
    : entry - atr14 * 2.5 * levScale;

  const tp3 = dir === 'BUY'
    ? entry + atr14 * 4.5 * levScale
    : entry - atr14 * 4.5 * levScale;

  // Trailing stop: trails 0.6× ATR behind the most recent close
  const trailOffset = atr14 * 0.6 * levScale;

  const slPct   = parseFloat((Math.abs(sl  - entry) / entry * 100).toFixed(3));
  const tp1Pct  = parseFloat((Math.abs(tp1 - entry) / entry * 100).toFixed(3));
  const tp2Pct  = parseFloat((Math.abs(tp2 - entry) / entry * 100).toFixed(3));
  const rrRatio = parseFloat((Math.abs(tp1 - entry) / Math.abs(sl - entry)).toFixed(2));

  return {
    sl,    tp1,    tp2,    tp3,
    slPct, tp1Pct, tp2Pct,
    rrRatio,
    trailOffset,
    atr14:       parseFloat(atr14.toFixed(6)),
    scaleOutPlan: `Close 50% at TP1 (${tp1Pct}%), 35% at TP2 (${tp2Pct}%), trail 15% with ${parseFloat((trailOffset/entry*100).toFixed(3))}% trailing stop`,
    breakEvenNote: `Move SL → entry after TP1 fills. Runner is now risk-free.`,
  };
}

