/* ─────────────────────────────────────────────────────────────────────────
   IE-1 — BOLLINGER BAND SQUEEZE + BREAKOUT DETECTOR
   Source: Altcoin Alchemist — "Advanced indicators including Bollinger Bands
           to spot optimal entry points"
   ─────────────────────────────────────────────────────────────────────────
   Bollinger Bands (BB) measure volatility. When the bands CONTRACT
   (squeeze), it signals that a BIG MOVE is coming — the market is coiling.
   When price BREAKS OUT of the contracted bands with volume, the direction
   of the breakout is the direction of the next major move.

   The Squeeze is defined as: bandwidth at a 20-bar low.
   The Breakout: close outside the upper/lower band with above-avg volume.
   The Momentum: the distance of the breakout from the midline (more = stronger).
   ───────────────────────────────────────────────────────────────────────── */
function computeBollingerBreakout(candles, dir) {
  if (!candles || candles.length < 25) {
    return { squeezing: false, breakout: false, bbScore: 0, reason: 'Insufficient data' };
  }

  const period  = 20;
  const mult    = 2.0;
  const slice   = candles.slice(-period);
  const close   = slice.map(c => c.c);

  // SMA and Standard Deviation
  const sma   = close.reduce((a, b) => a + b, 0) / period;
  const variance = close.reduce((a, b) => a + Math.pow(b - sma, 2), 0) / period;
  const stdDev = Math.sqrt(variance);

  const upperBB  = sma + mult * stdDev;
  const lowerBB  = sma - mult * stdDev;
  const bandwidth= (upperBB - lowerBB) / sma; // normalize

  // Historical bandwidth for squeeze detection (20-bar lookback on bandwidth)
  const histBandwidths = [];
  for (let i = 25; i <= candles.length; i++) {
    const s   = candles.slice(i - period, i).map(c => c.c);
    const m   = s.reduce((a, b) => a + b, 0) / period;
    const v   = s.reduce((a, b) => a + Math.pow(b - m, 2), 0) / period;
    const sd  = Math.sqrt(v);
    histBandwidths.push((m + 2*sd - (m - 2*sd)) / m);
  }
  const minBW    = Math.min(...histBandwidths.slice(-20));
  const squeezing= bandwidth <= minBW * 1.1; // within 10% of 20-bar minimum

  // Breakout detection: last close outside bands
  const lastC   = candles[candles.length - 1].c;
  const breakUp = lastC > upperBB;
  const breakDn = lastC < lowerBB;
  const breakout= (dir === 'BUY' ? breakUp : breakDn);

  // Volume confirmation
  const avgVol20 = candles.slice(-20).reduce((a, c) => a + (c.v || 0), 0) / 20;
  const lastVol  = candles[candles.length - 1].v || 0;
  const volConfirm = lastVol > avgVol20 * 1.3;

  // Momentum: how far outside the band
  const breakDist = breakUp ? (lastC - upperBB) / stdDev : breakDn ? (lowerBB - lastC) / stdDev : 0;

  const bbScore = Math.min(100, Math.round(
    (squeezing          ? 35 : 0) +
    (breakout           ? 30 : 0) +
    (volConfirm         ? 20 : 0) +
    Math.min(15, breakDist * 15)
  ));

  return {
    squeezing,
    breakout,
    breakUp,
    breakDn,
    upperBB:   parseFloat(upperBB.toFixed(6)),
    lowerBB:   parseFloat(lowerBB.toFixed(6)),
    middleBB:  parseFloat(sma.toFixed(6)),
    bandwidth: parseFloat((bandwidth * 100).toFixed(2)),
    volConfirm,
    bbScore,
    reason: squeezing && breakout
      ? `BB SQUEEZE BREAKOUT ${dir}: bandwidth ${(bandwidth*100).toFixed(2)}% at 20-bar low | ${volConfirm?'Vol confirmed':'Low vol'} | momentum ${breakDist.toFixed(2)}σ`
      : squeezing
        ? `BB SQUEEZING: bandwidth ${(bandwidth*100).toFixed(2)}% — coiling, await breakout`
        : `BB normal: bandwidth ${(bandwidth*100).toFixed(2)}%`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-2 — HIDDEN RSI / MACD DIVERGENCE ENGINE
   Source: Altcoin Alchemist — "Hidden bullish divergences on RSI/MACD"
   ─────────────────────────────────────────────────────────────────────────
   TWO types of divergence:

   REGULAR divergence (trend reversal):
   - Regular BULLISH: price lower low + RSI higher low → upward reversal
   - Regular BEARISH: price higher high + RSI lower high → downward reversal

   HIDDEN divergence (trend continuation — the "money" divergence):
   - Hidden BULLISH: price higher low + RSI lower low → uptrend continues
   - Hidden BEARISH: price lower high + RSI higher high → downtrend continues

   Hidden divergence is more powerful because it confirms continuation
   AFTER a pullback — this is exactly when institutions add to positions.
   ───────────────────────────────────────────────────────────────────────── */
function computeHiddenDivergence(candles, dir) {
  if (!candles || candles.length < 30) {
    return { regularDiv: false, hiddenDiv: false, divScore: 0, reason: 'Insufficient data' };
  }

  const closes = candles.map(c => c.c);
  const n = closes.length;

  // RSI(14) for each candle
  function rsiAt(end) {
    if (end < 14) return 50;
    let gains = 0, losses = 0;
    for (let i = end - 13; i <= end; i++) {
      const d = closes[i] - closes[i - 1];
      if (d > 0) gains += d; else losses -= d;
    }
    const ag = gains / 14, al = losses / 14;
    return al === 0 ? 100 : 100 - 100 / (1 + ag / al);
  }

  // MACD(12,26,9)
  function ema(arr, p, end) {
    const k = 2 / (p + 1);
    let e = arr[Math.max(0, end - p)];
    for (let i = Math.max(1, end - p + 1); i <= end; i++) e = arr[i] * k + e * (1 - k);
    return e;
  }
  function macdAt(end) {
    if (end < 26) return 0;
    return ema(closes, 12, end) - ema(closes, 26, end);
  }

  // Find pivots (swing highs/lows) in last 30 bars
  const pivotHighs = [], pivotLows = [];
  for (let i = 2; i < n - 2; i++) {
    if (candles[i].h > candles[i-1].h && candles[i].h > candles[i-2].h &&
        candles[i].h > candles[i+1].h && candles[i].h > candles[i+2].h) {
      pivotHighs.push({ idx: i, price: candles[i].h, rsi: rsiAt(i), macd: macdAt(i) });
    }
    if (candles[i].l < candles[i-1].l && candles[i].l < candles[i-2].l &&
        candles[i].l < candles[i+1].l && candles[i].l < candles[i+2].l) {
      pivotLows.push({ idx: i, price: candles[i].l, rsi: rsiAt(i), macd: macdAt(i) });
    }
  }

  let regularDiv = false, hiddenDiv = false, divType = 'NONE';

  // Check last 2 pivot lows for BULLISH divergence (regular + hidden)
  if (pivotLows.length >= 2) {
    const a = pivotLows[pivotLows.length - 2];
    const b = pivotLows[pivotLows.length - 1];
    // Regular bullish: price LL + RSI HL
    if (b.price < a.price && b.rsi > a.rsi && dir === 'BUY') {
      regularDiv = true; divType = 'REGULAR_BULLISH';
    }
    // Hidden bullish: price HL + RSI LL (continuation)
    if (b.price > a.price && b.rsi < a.rsi && dir === 'BUY') {
      hiddenDiv = true; divType = 'HIDDEN_BULLISH';
    }
  }

  // Check last 2 pivot highs for BEARISH divergence
  if (pivotHighs.length >= 2) {
    const a = pivotHighs[pivotHighs.length - 2];
    const b = pivotHighs[pivotHighs.length - 1];
    // Regular bearish: price HH + RSI LH
    if (b.price > a.price && b.rsi < a.rsi && dir === 'SELL') {
      regularDiv = true; divType = 'REGULAR_BEARISH';
    }
    // Hidden bearish: price LH + RSI HH (continuation)
    if (b.price < a.price && b.rsi > a.rsi && dir === 'SELL') {
      hiddenDiv = true; divType = 'HIDDEN_BEARISH';
    }
  }

  const currentRSI = rsiAt(n - 1);
  const currentMACD = macdAt(n - 1);

  const divScore = Math.min(100, Math.round(
    (hiddenDiv   ? 55 : 0) +
    (regularDiv  ? 40 : 0) +
    (currentRSI > 50 && dir === 'BUY'  ? 5 : 0) +
    (currentRSI < 50 && dir === 'SELL' ? 5 : 0)
  ));

  return {
    regularDiv,
    hiddenDiv,
    divType,
    currentRSI: parseFloat(currentRSI.toFixed(1)),
    currentMACD: parseFloat(currentMACD.toFixed(6)),
    pivotLowCount:  pivotLows.length,
    pivotHighCount: pivotHighs.length,
    divScore,
    reason: (hiddenDiv || regularDiv)
      ? `${divType}: confirms ${hiddenDiv ? 'CONTINUATION' : 'REVERSAL'} | RSI: ${currentRSI.toFixed(1)}`
      : `No divergence | RSI: ${currentRSI.toFixed(1)} MACD: ${currentMACD.toFixed(4)}`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-3 — CUP AND HANDLE FORMATION DETECTOR
   Source: Altcoin Alchemist — "Cup and Handle formations with increasing volume"
   ─────────────────────────────────────────────────────────────────────────
   The Cup and Handle is one of the most reliable bullish continuation
   patterns in technical analysis. It consists of:
   1. A rounded bottom (the Cup) — a U-shape over 10–50 bars
   2. A small pullback (the Handle) — 10–30% of the cup height, brief
   3. A breakout above the cup rim on volume expansion

   When the handle consolidates and price breaks the cup rim with volume:
   the target is the cup depth added to the breakout point.
   This pattern has among the highest success rates of any chart pattern.
   ───────────────────────────────────────────────────────────────────────── */
function detectCupAndHandle(candles, dir) {
  if (!candles || candles.length < 40 || dir !== 'BUY') {
    return { detected: false, chScore: 0, reason: dir !== 'BUY' ? 'Cup & Handle is bullish only' : 'Insufficient data' };
  }

  const n      = candles.length;
  const atr14  = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;

  // Cup: look for U-shaped pattern in last 40 bars
  const cupSlice = candles.slice(-40, -8); // 32 bars for the cup
  const cupHigh  = Math.max(...cupSlice.map(c => c.h));
  const cupLow   = Math.min(...cupSlice.map(c => c.l));
  const cupDepth = cupHigh - cupLow;

  // Cup shape test: left rim, bottom, right rim should form a U
  const cupLeft  = cupSlice.slice(0, 8).map(c => c.h);
  const cupMid   = cupSlice.slice(12, 20).map(c => c.l);
  const cupRight = cupSlice.slice(24).map(c => c.h);

  const leftAvgH = cupLeft.reduce((a, b) => a + b, 0) / cupLeft.length;
  const midAvgL  = cupMid.reduce((a, b) => a + b, 0) / cupMid.length;
  const rightAvgH= cupRight.reduce((a, b) => a + b, 0) / cupRight.length;

  // U-shape: left and right rims are high, middle is low
  const isUShaped = leftAvgH > midAvgL + cupDepth * 0.3 &&
                    rightAvgH > midAvgL + cupDepth * 0.3 &&
                    Math.abs(leftAvgH - rightAvgH) < cupDepth * 0.25; // rims roughly equal

  // Handle: last 8 bars should be a small pullback from right rim
  const handleSlice = candles.slice(-8);
  const handleHigh  = Math.max(...handleSlice.map(c => c.h));
  const handleLow   = Math.min(...handleSlice.map(c => c.l));
  const handleDrop  = handleHigh - handleLow;
  const handleOk    = handleDrop < cupDepth * 0.35 && handleDrop > atr14 * 0.5;

  // Breakout: current price above cup rim
  const currentPrice = candles[n-1].c;
  const breakingOut  = currentPrice > cupHigh * 0.99; // within 1% of rim

  // Volume: should be expanding in handle breakout
  const cupAvgVol    = cupSlice.reduce((a, c) => a + (c.v || 0), 0) / cupSlice.length;
  const handleAvgVol = handleSlice.reduce((a, c) => a + (c.v || 0), 0) / handleSlice.length;
  const volExpanding = handleAvgVol > cupAvgVol * 0.8; // handle vol should be moderate

  const detected = isUShaped && handleOk && cupDepth > atr14 * 2;
  const priceTarget = breakingOut ? currentPrice + cupDepth : null;

  const chScore = Math.min(100, Math.round(
    (isUShaped     ? 40 : 0) +
    (handleOk      ? 25 : 0) +
    (volExpanding  ? 20 : 0) +
    (breakingOut   ? 15 : 0)
  ));

  return {
    detected,
    chScore,
    cupHigh:     parseFloat(cupHigh.toFixed(6)),
    cupLow:      parseFloat(cupLow.toFixed(6)),
    cupDepth:    parseFloat((cupDepth / atr14).toFixed(1)),
    handleDrop:  parseFloat((handleDrop / atr14).toFixed(1)),
    breakingOut,
    priceTarget: priceTarget ? parseFloat(priceTarget.toFixed(6)) : null,
    reason: detected
      ? `Cup & Handle: cup depth ${(cupDepth/atr14).toFixed(1)}×ATR | handle ${(handleDrop/atr14).toFixed(1)}×ATR | ${breakingOut?`BREAKING OUT → target ${priceTarget?.toFixed(6)}`:'Handle forming'}`
      : `No Cup & Handle: U-shape=${isUShaped} handle=${handleOk}`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-4 — MULTI-DAY CONSOLIDATION BREAKOUT SCANNER
   Source: Altcoin Alchemist — "Breakouts from multi-day/week consolidation"
   ─────────────────────────────────────────────────────────────────────────
   Price consolidation (tight range over many bars) builds potential energy.
   The longer the consolidation, the more powerful the breakout.

   Detection logic:
   1. Identify a range: max-high minus min-low < N × ATR for M bars
   2. Measure how many consecutive bars have been inside this range
   3. Detect when price breaks out with volume expansion
   4. Score by consolidation duration × breakout strength × volume confirmation

   Longer consolidations produce more explosive moves because:
   - Impatient traders exit (reducing supply/demand imbalance)
   - Institutions accumulate positions quietly inside the range
   - When they decide to move price, all the weak hands have exited
   ───────────────────────────────────────────────────────────────────────── */
function detectConsolidationBreakout(candles, dir) {
  if (!candles || candles.length < 20) {
    return { breakingOut: false, consolidationScore: 0, reason: 'Insufficient data' };
  }

  const atr14    = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  const current  = candles[candles.length - 1];
  const avgVol20 = candles.slice(-20).reduce((a, c) => a + (c.v || 0), 0) / 20;

  // Scan from most recent backward to find how many bars have been in a tight range
  let consolidationBars = 0;
  let rangeHigh = -Infinity, rangeLow = Infinity;

  for (let i = candles.length - 2; i >= Math.max(0, candles.length - 40); i--) {
    const c = candles[i];
    const testHigh = Math.max(rangeHigh, c.h);
    const testLow  = Math.min(rangeLow, c.l);
    const testRange = testHigh - testLow;

    // If this candle's inclusion keeps the range tight (< 2.5× ATR), include it
    if (testRange <= atr14 * 2.5) {
      rangeHigh = testHigh;
      rangeLow  = testLow;
      consolidationBars++;
    } else break;
  }

  // Quality: at least 8 bars of consolidation
  const isConsolidating = consolidationBars >= 8;

  // Breakout: current close is outside the consolidation range
  const breakUp = current.c > rangeHigh && dir === 'BUY';
  const breakDn = current.c < rangeLow  && dir === 'SELL';
  const breakingOut = breakUp || breakDn;

  // Breakout strength: how far beyond the range
  const breakDist = breakUp
    ? (current.c - rangeHigh) / atr14
    : breakDn
      ? (rangeLow - current.c) / atr14
      : 0;

  // Volume expansion on breakout
  const breakVol = (current.v || 0) > avgVol20 * 1.4;

  // Duration bonus: longer consolidation = more powerful breakout
  const durationBonus = Math.min(30, consolidationBars);

  const consolidationScore = Math.min(100, Math.round(
    (isConsolidating ? 25 : 0) +
    (breakingOut     ? 30 : 0) +
    (breakVol        ? 20 : 0) +
    Math.min(15, breakDist * 10) +
    durationBonus / 2
  ));

  return {
    breakingOut,
    consolidationBars,
    rangeHigh:   parseFloat(rangeHigh.toFixed(6)),
    rangeLow:    parseFloat(rangeLow.toFixed(6)),
    rangeATR:    parseFloat(((rangeHigh - rangeLow) / atr14).toFixed(2)),
    breakDist:   parseFloat(breakDist.toFixed(2)),
    volumeConfirmed: breakVol,
    consolidationScore,
    reason: breakingOut
      ? `CONSOLIDATION BREAKOUT ${dir}: ${consolidationBars} bars compressed into ${((rangeHigh-rangeLow)/atr14).toFixed(1)}×ATR | breakout ${breakDist.toFixed(1)}×ATR ${breakVol?'✅ vol confirmed':'⚠️ low vol'}`
      : isConsolidating
        ? `Consolidating: ${consolidationBars} bars in ${((rangeHigh-rangeLow)/atr14).toFixed(1)}×ATR range — await breakout`
        : `No significant consolidation detected`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-5 — SUPPORT BOUNCE + SELLING PRESSURE DECAY DETECTOR
   Source: Altcoin Alchemist — "Support bounces with decreasing selling pressure"
   ─────────────────────────────────────────────────────────────────────────
   A support bounce is only reliable when the SELLING PRESSURE DECAYS
   as price approaches the support level. If sellers are weakening on
   each test, buyers will overwhelm them on the next touch.

   Signals of selling pressure decay:
   1. Progressively smaller red candles near support (less selling conviction)
   2. Volume decreasing on each successive test (sellers exhausting)
   3. Wicks increasingly long on the downside (buyers stepping in earlier)
   4. RSI making higher lows while price makes equal lows (classic divergence)
   ───────────────────────────────────────────────────────────────────────── */
function detectSupportBounceDecay(candles, dir) {
  if (!candles || candles.length < 20) {
    return { bouncing: false, decayScore: 0, reason: 'Insufficient data' };
  }

  const atr14 = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  const last10 = candles.slice(-10);

  // Only meaningful for BUY (support bounce) and SELL (resistance rejection)
  const pivotLevel = dir === 'BUY'
    ? Math.min(...last10.map(c => c.l))
    : Math.max(...last10.map(c => c.h));

  // Count candles touching the level
  const touches = last10.filter(c =>
    dir === 'BUY'
      ? c.l <= pivotLevel + atr14 * 0.3
      : c.h >= pivotLevel - atr14 * 0.3
  );

  if (touches.length < 2) {
    return { bouncing: false, decayScore: 0, reason: 'Less than 2 level touches — no decay detectable' };
  }

  // Decay signals
  // 1. Volume decay: each touch has lower volume than the previous
  const touchVols = touches.map(c => c.v || 0);
  const volDecaying = touchVols.length >= 2 &&
    touchVols[touchVols.length - 1] < touchVols[0] * 0.8;

  // 2. Candle body size decay: smaller opposing candles
  const bearBodies = touches
    .filter(c => dir === 'BUY' ? c.c < c.o : c.c > c.o)
    .map(c => Math.abs(c.c - c.o));
  const bodyDecaying = bearBodies.length >= 2 &&
    bearBodies[bearBodies.length - 1] < bearBodies[0] * 0.75;

  // 3. Lower wick growth: buyers stepping in earlier
  const lowerWicks = touches.map(c => Math.min(c.c, c.o) - c.l);
  const wickGrowing = lowerWicks.length >= 2 &&
    lowerWicks[lowerWicks.length - 1] > lowerWicks[0] * 1.2;

  // 4. Current candle direction aligns with bounce
  const lastC = candles[candles.length - 1];
  const bouncing = dir === 'BUY' ? lastC.c > lastC.o : lastC.c < lastC.o;

  const decayCount = [volDecaying, bodyDecaying, wickGrowing, bouncing].filter(Boolean).length;

  const decayScore = Math.min(100, Math.round(
    (touches.length * 10) +
    (volDecaying   ? 25 : 0) +
    (bodyDecaying  ? 25 : 0) +
    (wickGrowing   ? 25 : 0) +
    (bouncing      ? 15 : 0)
  ));

  return {
    bouncing,
    touches:     touches.length,
    pivotLevel:  parseFloat(pivotLevel.toFixed(6)),
    volDecaying,
    bodyDecaying,
    wickGrowing,
    decayCount,
    decayScore,
    reason: decayCount >= 2
      ? `SUPPORT DECAY: ${touches.length} touches at ${pivotLevel.toFixed(6)} | ${decayCount}/4 decay signals | ${volDecaying?'vol↓ ':''} ${bodyDecaying?'bodies↓ ':''} ${wickGrowing?'wicks↑ ':''}${bouncing?'↗ bouncing':''}`
      : `Minimal decay: ${decayCount}/4 signals at level ${pivotLevel.toFixed(6)}`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-6 — UNUSUAL VOLUME SPIKE DETECTOR
   Source: Altcoin Alchemist — "Instant notifications when our AI detects
           unusual volume spikes in altcoins"
   ─────────────────────────────────────────────────────────────────────────
   Volume is the FUEL of a price move. Without unusual volume, a price
   move has no institutional backing and will reverse.

   An unusual volume spike has THREE tiers:
   NOTABLE  (1.5–2.0× avg): Elevated attention — watch for confirmation
   UNUSUAL  (2.0–3.5× avg): Clear institutional participation — high probability
   EXTREME  (3.5×+ avg):    Major event or capitulation — directional explosive

   Combined with price direction:
   EXTREME vol + bullish close = institutional accumulation
   EXTREME vol + bearish close = capitulation (potential reversal, not continuation)
   ───────────────────────────────────────────────────────────────────────── */
function detectUnusualVolume(candles, dir) {
  if (!candles || candles.length < 20) {
    return { spike: false, spikeLevel: 'NORMAL', volScore: 0, reason: 'Insufficient data' };
  }

  const current  = candles[candles.length - 1];
  const avgVol20 = candles.slice(-20, -1).reduce((a, c) => a + (c.v || 0), 0) / 19;
  const avgVol50 = candles.length >= 50
    ? candles.slice(-50, -1).reduce((a, c) => a + (c.v || 0), 0) / 49
    : avgVol20;
  const baseline = Math.min(avgVol20, avgVol50); // use lower baseline = more sensitive

  const currentVol = current.v || 0;
  const volRatio   = baseline > 0 ? currentVol / baseline : 1;

  const spikeLevel = volRatio >= 3.5 ? 'EXTREME'
                   : volRatio >= 2.0 ? 'UNUSUAL'
                   : volRatio >= 1.5 ? 'NOTABLE'
                   : 'NORMAL';

  const spike = spikeLevel !== 'NORMAL';

  // Directional quality: is the spike in our signal direction?
  const bodyPct = (current.h - current.l) > 0
    ? Math.abs(current.c - current.o) / (current.h - current.l)
    : 0;
  const dirAligned = dir === 'BUY'
    ? current.c > current.o   // bullish close on spike
    : current.c < current.o;  // bearish close on spike

  // Capitulation flag: extreme vol + opposing close = sellers exhausting (bullish)
  const isCap = spikeLevel === 'EXTREME' && !dirAligned;

  const volScore = Math.min(100, Math.round(
    (spike       ? 30 : 0) +
    (dirAligned  ? 25 : 0) +
    (isCap       ? 20 : 0) + // capitulation is also bullish signal for BUY
    Math.min(25, (volRatio - 1) * 8)
  ));

  return {
    spike,
    spikeLevel,
    volRatio:    parseFloat(volRatio.toFixed(2)),
    currentVol,
    avgVol20:    parseFloat(avgVol20.toFixed(0)),
    dirAligned,
    isCap,
    bodyPct:     parseFloat((bodyPct * 100).toFixed(1)),
    volScore,
    reason: spike
      ? `${spikeLevel} VOLUME: ${volRatio.toFixed(2)}× avg (${currentVol.toLocaleString()}) | ${dirAligned?`${dir}-aligned`:'Opposite direction'}${isCap?' | CAPITULATION — potential reversal':''}`
      : `Normal volume: ${volRatio.toFixed(2)}× avg`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-7 — ADAPTIVE STOP-LOSS + DYNAMIC TAKE-PROFIT ENGINE
   Source: YAN Elite + RoboTrader Supreme + Altcoin Alchemist
   "Automated stop-loss and take-profit with dynamic adjustment"
   "Advanced derivatives strategies and real-time hedging"
   "Automated stop-loss, take-profit, and position sizing"
   ─────────────────────────────────────────────────────────────────────────
   Four SL types — selects the TIGHTEST that still gives room to breathe:

   1. ATR-BASED: SL = entry ± (ATR × multiplier) — adapts to volatility
   2. STRUCTURE-BASED: SL just below nearest significant swing point
   3. PERCENTAGE-BASED: fixed maximum % risk (leverage-adjusted)
   4. BREAKEVEN TRIGGER: after TP1 fills, SL moves to entry + small profit

   TP levels use the liquidity magnet concept (from Ghost Engine IE-G3):
   TP1 = nearest liquidity pool in signal direction
   TP2 = second pool or 2× the SL distance
   TP3 = third pool or 4× the SL distance (runner)
   ───────────────────────────────────────────────────────────────────────── */
function computeAdaptiveSLTP(candles, dir, entry, leverage = 1) {
  if (!candles || candles.length < 14 || !entry || entry <= 0) {
    return null;
  }

  const atr14   = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  const atr28   = candles.length >= 28
    ? candles.slice(-28).reduce((a, c) => a + (c.h - c.l), 0) / 28
    : atr14;

  // Volatility regime: is current ATR expanded or contracted?
  const atrRatio    = atr14 / atr28;
  const isHighVol   = atrRatio > 1.3;
  const isLowVol    = atrRatio < 0.7;

  // SL multiplier: tighter in high volatility (don't chase), wider in low (give room)
  const levAdjust   = leverage >= 10 ? 0.5 : leverage >= 5 ? 0.7 : 1.0;
  const volAdjust   = isHighVol ? 0.8 : isLowVol ? 1.2 : 1.0;
  const slMultATR   = 1.2 * levAdjust * volAdjust;

  // 1. ATR-based SL
  const slATR = dir === 'BUY' ? entry - atr14 * slMultATR : entry + atr14 * slMultATR;

  // 2. Structure-based SL (below nearest swing low for BUY)
  const swings = [];
  for (let i = 3; i < candles.length - 3; i++) {
    if (dir === 'BUY') {
      if (candles[i].l < candles[i-1].l && candles[i].l < candles[i-2].l &&
          candles[i].l < candles[i+1].l && candles[i].l < candles[i+2].l &&
          candles[i].l < entry) {
        swings.push(candles[i].l - atr14 * 0.1); // just below swing low
      }
    } else {
      if (candles[i].h > candles[i-1].h && candles[i].h > candles[i-2].h &&
          candles[i].h > candles[i+1].h && candles[i].h > candles[i+2].h &&
          candles[i].h > entry) {
        swings.push(candles[i].h + atr14 * 0.1);
      }
    }
  }
  const slStructure = swings.length > 0
    ? (dir === 'BUY' ? Math.max(...swings) : Math.min(...swings))
    : slATR;

  // Use the SL that gives the best (tightest valid) risk per trade
  const sl = dir === 'BUY'
    ? Math.max(slATR, slStructure) // highest of the two (closer to entry)
    : Math.min(slATR, slStructure); // lowest of the two

  const riskDist = Math.abs(entry - sl);

  // TP levels: 1.5×, 3×, 5× risk distance (ensuring minimum RR)
  const tp1 = dir === 'BUY' ? entry + riskDist * 1.8 : entry - riskDist * 1.8;
  const tp2 = dir === 'BUY' ? entry + riskDist * 3.2 : entry - riskDist * 3.2;
  const tp3 = dir === 'BUY' ? entry + riskDist * 5.5 : entry - riskDist * 5.5;

  // Breakeven trigger: move SL to entry + 0.3 × risk when TP1 fills
  const breakeven = dir === 'BUY' ? entry + riskDist * 0.3 : entry - riskDist * 0.3;

  const slPct   = parseFloat((riskDist / entry * 100).toFixed(3));
  const tp1Pct  = parseFloat((Math.abs(tp1 - entry) / entry * 100).toFixed(3));
  const tp2Pct  = parseFloat((Math.abs(tp2 - entry) / entry * 100).toFixed(3));
  const rr1     = parseFloat((tp1Pct / slPct).toFixed(2));
  const rr2     = parseFloat((tp2Pct / slPct).toFixed(2));

  return {
    sl:        parseFloat(sl.toFixed(6)),
    tp1:       parseFloat(tp1.toFixed(6)),
    tp2:       parseFloat(tp2.toFixed(6)),
    tp3:       parseFloat(tp3.toFixed(6)),
    breakeven: parseFloat(breakeven.toFixed(6)),
    slPct,
    tp1Pct,
    tp2Pct,
    rr1,
    rr2,
    atrMultiplied: parseFloat((riskDist / atr14).toFixed(2)),
    isHighVol,
    isLowVol,
    scaleOutPlan: `Close 40% at TP1 (+${tp1Pct}%), 40% at TP2 (+${tp2Pct}%), trail 20% with ${(riskDist*0.5/entry*100).toFixed(2)}% trailing stop`,
    breakevenNote: `After TP1 fills → move SL to ${breakeven.toFixed(6)} (locked-in profit)`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-8 — PROFIT COMPOUNDING POSITION SIZER
   Source: RoboTrader Supreme — "Automatically compounds your earnings by
           reinvesting profits into new high-probability trades"
   Source: Fifth Intelligence — Profit simulator
   ─────────────────────────────────────────────────────────────────────────
   Kelly Criterion + Risk-Adjusted Compounding.

   The Kelly formula: f = (p × b - q) / b
   Where: p = win probability, q = 1-p, b = avg win / avg loss (RR ratio)
   Full Kelly is too aggressive — we use Quarter Kelly for safety.

   Then compound: each winning trade reinvests a portion of profit into the
   next trade, growing position size geometrically. The compound growth
   accelerates as account grows but never risks more than max% per trade.
   ───────────────────────────────────────────────────────────────────────── */
function computeCompoundPositionSize(accountSize, winRate, rrRatio, maxRiskPct = 2.0) {
  if (!accountSize || accountSize <= 0) return { positionSize: 0, riskAmount: 0 };

  const p = Math.min(0.95, Math.max(0.05, winRate / 100));
  const q = 1 - p;
  const b = Math.max(0.5, rrRatio);

  // Full Kelly fraction
  const kelly = (p * b - q) / b;

  // Quarter Kelly (conservative, reduces drawdown significantly)
  const qKelly = Math.max(0, kelly * 0.25);

  // Cap at maxRiskPct
  const riskFraction = Math.min(maxRiskPct / 100, qKelly);

  // Risk amount in currency
  const riskAmount     = accountSize * riskFraction;
  const positionSize   = riskAmount;

  // Compounding projection (1, 5, 10, 20 trades)
  const compound = (n) => accountSize * Math.pow(1 + riskFraction * (p * b - q), n);

  return {
    riskFraction: parseFloat((riskFraction * 100).toFixed(3)),
    riskAmount:   parseFloat(riskAmount.toFixed(2)),
    positionSize: parseFloat(positionSize.toFixed(2)),
    kellyFull:    parseFloat((kelly * 100).toFixed(2)),
    kellyQuarter: parseFloat((qKelly * 100).toFixed(2)),
    projections: {
      trade5:  parseFloat(compound(5).toFixed(2)),
      trade10: parseFloat(compound(10).toFixed(2)),
      trade20: parseFloat(compound(20).toFixed(2)),
    },
    recommendation: `Risk ${(riskFraction*100).toFixed(2)}% per trade (¼ Kelly) | Win: ${(p*100).toFixed(0)}% @ ${b.toFixed(1)}:1 RR → expected edge: +${((p*b-q)*100).toFixed(1)}% per trade`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-9 — MULTI-STRATEGY CONFLUENCE SELECTOR
   Source: RoboTrader Supreme — Strategy Selector component
   Source: Altcoin Alchemist — Algorithmic Pattern Recognition
   ─────────────────────────────────────────────────────────────────────────
   Selects the PRIMARY trading strategy based on current market conditions.
   Different strategies work best in different regimes:

   TRENDING MARKET:    Momentum Continuation + OTE entry
   RANGING MARKET:     Support/Resistance Fade + BB Squeeze
   VOLATILE MARKET:    Breakout + Volume Confirmation
   LOW VOLATILITY:     Consolidation Breakout (energy coiling)
   REVERSAL ZONE:      Divergence + Cup & Handle

   The selector outputs: strategy name, confidence, specific rules to apply,
   and which other engines to weight more heavily for this setup.
   ───────────────────────────────────────────────────────────────────────── */
function selectOptimalStrategy(candles, dir, bbResult, divResult, chResult, consResult, bounceResult) {
  if (!candles || candles.length < 20) {
    return { strategy: 'UNKNOWN', strategyScore: 0, rules: [] };
  }

  const atr14  = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  const atr28  = candles.length >= 28 ? candles.slice(-28).reduce((a, c) => a + (c.h - c.l), 0) / 28 : atr14;
  const atrR   = atr14 / atr28;

  // Regime classification
  const isHighVol   = atrR > 1.3;
  const isLowVol    = atrR < 0.8;
  const isTrending  = (function() {
    const closes = candles.slice(-20).map(c => c.c);
    const sma20  = closes.reduce((a, b) => a + b, 0) / 20;
    const above  = closes.filter(c => dir === 'BUY' ? c > sma20 : c < sma20).length;
    return above >= 14; // 70%+ candles on correct side of SMA
  })();

  const isRanging = !isTrending && !isHighVol;

  // Strategy selection with scoring
  const strategies = [];

  if (bbResult?.squeezing && bbResult?.breakout) {
    strategies.push({ name: 'BB_SQUEEZE_BREAKOUT',    score: bbResult.bbScore,         rules: ['Entry: breakout candle close', 'SL: opposite band', 'Scale out: TP1=1.5×ATR, TP2=3×ATR'] });
  }
  if (divResult?.hiddenDiv) {
    strategies.push({ name: 'HIDDEN_DIVERGENCE',      score: divResult.divScore,       rules: ['Entry: after confirmation candle', 'SL: below divergence pivot', 'Scale out: TP1=2×risk, TP2=4×risk'] });
  }
  if (chResult?.detected && dir === 'BUY') {
    strategies.push({ name: 'CUP_AND_HANDLE',         score: chResult.chScore,         rules: ['Entry: breakout above cup rim', 'SL: handle low', `Target: ${chResult.priceTarget}`] });
  }
  if (consResult?.breakingOut) {
    strategies.push({ name: 'CONSOLIDATION_BREAKOUT', score: consResult.consolidationScore, rules: [`Entry: close above ${consResult.rangeHigh}`, 'SL: midpoint of range', 'Target: range height added to breakout'] });
  }
  if (bounceResult?.bouncing && bounceResult.decayCount >= 2) {
    strategies.push({ name: 'SUPPORT_DECAY_BOUNCE',   score: bounceResult.decayScore,  rules: [`Entry: limit at ${bounceResult.pivotLevel}`, 'SL: below support by 0.5×ATR', 'Scale: close 50% at 2×risk'] });
  }

  // Default to best available
  if (strategies.length === 0) {
    const defScore = isTrending ? 55 : isRanging ? 45 : 40;
    strategies.push({
      name:  isTrending ? 'MOMENTUM_CONTINUATION' : isRanging ? 'RANGE_FADE' : 'DIRECTIONAL_BIAS',
      score: defScore,
      rules: ['Entry: OTE zone pullback', 'SL: ATR-based', 'Scale: standard 3-tier TP']
    });
  }

  // Sort by score, pick best
  strategies.sort((a, b) => b.score - a.score);
  const best = strategies[0];

  return {
    strategy:      best.name,
    strategyScore: best.score,
    rules:         best.rules,
    allStrategies: strategies,
    regime:        isTrending ? 'TRENDING' : isHighVol ? 'HIGH_VOLATILITY' : isRanging ? 'RANGING' : 'LOW_VOLATILITY',
    reason:        `${best.name} (${best.score}%) in ${isTrending?'TRENDING':isHighVol?'VOLATILE':isRanging?'RANGING':'QUIET'} market`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-10 — DEEP-LEARNING RISK SHIELD (DRAWDOWN PROTECTOR)
   Source: Fifth Intelligence — "Deep-Learning Risk Shield"
   Source: RoboTrader Supreme — "ZeroLoss Algorithm (hedging)"
   ─────────────────────────────────────────────────────────────────────────
   The Risk Shield monitors 5 risk dimensions simultaneously:

   1. VOLATILITY RISK: ATR spike → reduce position size or skip
   2. CORRELATION RISK: if BTC is falling hard, alts follow → avoid longs
   3. DRAWDOWN RISK: if account is in drawdown → reduce risk per trade
   4. OVEREXPOSURE RISK: too many positions in same direction → skip
   5. NEWS RISK: abnormal spread/volume → news event likely → skip

   When 3+ dimensions are in warning state → SHIELD ACTIVE → no new entries.
   This is the "circuit breaker" that prevents catastrophic drawdowns.
   ───────────────────────────────────────────────────────────────────────── */
function computeRiskShield(candles, dir, btcDom = null, consecutiveLosses = 0, openPositions = 0) {
  if (!candles || candles.length < 14) {
    return { shieldActive: false, riskLevel: 'UNKNOWN', riskScore: 50, reason: 'Insufficient data' };
  }

  const atr14  = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  const atr5   = candles.slice(-5).reduce((a, c) => a + (c.h - c.l), 0) / 5;
  const last   = candles[candles.length - 1];
  const avgVol = candles.slice(-20).reduce((a, c) => a + (c.v || 0), 0) / 20;

  const warnings = [];
  let riskScore = 0; // 0 = low risk, 100 = extreme risk

  // 1. Volatility Risk
  const volSpike = atr5 / atr14;
  if (volSpike > 2.5)      { riskScore += 30; warnings.push(`ATR spike ${volSpike.toFixed(1)}× — news/flash crash`); }
  else if (volSpike > 1.8) { riskScore += 15; warnings.push(`Elevated ATR ${volSpike.toFixed(1)}×`); }

  // 2. Spread/Volume anomaly (news risk)
  const lastRange = last.h - last.l;
  const rangeSpike = atr14 > 0 ? lastRange / atr14 : 1;
  if (rangeSpike > 3.0)    { riskScore += 25; warnings.push(`Abnormal candle ${rangeSpike.toFixed(1)}×ATR — possible news`); }

  // 3. BTC Dominance risk for alt longs
  if (btcDom !== null && dir === 'BUY' && btcDom > 60) {
    riskScore += 15; warnings.push(`BTC dominance ${btcDom}% — alts underperforming`);
  }

  // 4. Consecutive loss risk
  if (consecutiveLosses >= 3)      { riskScore += 25; warnings.push(`${consecutiveLosses} consecutive losses — skip`); }
  else if (consecutiveLosses >= 2) { riskScore += 10; warnings.push(`${consecutiveLosses} losses — reduce size`); }

  // 5. Overexposure risk
  if (openPositions >= 5)          { riskScore += 20; warnings.push(`${openPositions} open positions — overexposed`); }
  else if (openPositions >= 3)     { riskScore += 8;  warnings.push(`${openPositions} positions open`); }

  riskScore = Math.min(100, riskScore);

  const riskLevel   = riskScore >= 60 ? 'EXTREME'
                    : riskScore >= 40 ? 'HIGH'
                    : riskScore >= 20 ? 'MODERATE'
                    : 'LOW';

  const shieldActive = riskScore >= 50; // Shield activates at 50+

  // Position size multiplier (reduce size when risk is elevated)
  const sizeMultiplier = riskScore >= 60 ? 0
                       : riskScore >= 40 ? 0.5
                       : riskScore >= 20 ? 0.75
                       : 1.0;

  return {
    shieldActive,
    riskLevel,
    riskScore,
    sizeMultiplier,
    warnings,
    reason: warnings.length > 0
      ? `RISK SHIELD ${riskLevel} (${riskScore}%): ${warnings.join(' | ')} | Size multiplier: ${sizeMultiplier}×`
      : `Risk Shield: LOW (${riskScore}%) — full size entry permitted`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-11 — ALTCOIN MOMENTUM SCANNER (EXPLOSIVE MOVE DETECTOR)
   Source: Altcoin Alchemist — "AI scans the market 24/7 for specific
           technical patterns that historically precede explosive moves"
   ─────────────────────────────────────────────────────────────────────────
   Small/mid-cap altcoins have different characteristics to BTC/ETH:
   - Higher volatility: 2–5× the typical BTC move
   - Lower liquidity: institutions can move them with less capital
   - "Rotation" effect: BTC pumps first, then ETH, then large alts, then small alts
   - Pump and dump risk: volume spikes on low-cap = potential manipulation

   The Explosive Move Detector scores the setup quality for altcoins by:
   1. Relative strength vs BTC (outperforming = rotation in progress)
   2. Volume classification (unusual = institutional vs extreme = potential dump)
   3. Pattern quality (breakout + BB squeeze + no wick rejection = quality)
   4. Manipulation filter: if extreme vol + tiny body = likely manipulation
   ───────────────────────────────────────────────────────────────────────── */
function detectAltcoinExplosiveSetup(candles, dir, btcCandles = null) {
  if (!candles || candles.length < 20) {
    return { explosive: false, altScore: 0, reason: 'Insufficient data' };
  }

  const atr14  = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
  const last   = candles[candles.length - 1];
  const avgVol = candles.slice(-20, -1).reduce((a, c) => a + (c.v || 0), 0) / 19;
  const volR   = avgVol > 0 ? (last.v || 0) / avgVol : 1;

  // Momentum: price change rate over last 5 candles
  const momentum5 = (candles[candles.length-1].c - candles[candles.length-6].c) /
                     candles[candles.length-6].c * 100;

  // Relative strength vs BTC (if available)
  let relativeStrength = 0;
  if (btcCandles && btcCandles.length >= 5) {
    const btcMom = (btcCandles[btcCandles.length-1].c - btcCandles[btcCandles.length-6].c) /
                   btcCandles[btcCandles.length-6].c * 100;
    relativeStrength = momentum5 - btcMom; // positive = outperforming BTC
  }

  // Manipulation filter: extreme vol + tiny candle body = whale trap
  const bodyPct   = (last.h - last.l) > 0 ? Math.abs(last.c - last.o) / (last.h - last.l) : 0;
  const manipulation = volR > 4.0 && bodyPct < 0.2; // huge vol, tiny body = manipulation

  // Quality signals
  const momentumOk  = dir === 'BUY' ? momentum5 > 0 : momentum5 < 0;
  const volOk       = volR >= 1.5 && volR <= 5.0; // unusual but not extreme
  const rsOk        = btcCandles ? relativeStrength > 0 : true; // outperforming BTC

  // Explosive pattern: breakout candle with strong body and volume
  const strongCandle = bodyPct >= 0.55 && (dir === 'BUY' ? last.c > last.o : last.c < last.o);

  const explosive = !manipulation && momentumOk && volOk && strongCandle && !manipulation;

  const altScore = Math.min(100, Math.round(
    (explosive        ? 30 : 0) +
    (!manipulation    ? 20 : -30) +
    (strongCandle     ? 20 : 0) +
    (volOk            ? 15 : 0) +
    (rsOk             ? 15 : 0)
  ));

  return {
    explosive,
    manipulation,
    altScore: Math.max(0, altScore),
    momentum5:       parseFloat(momentum5.toFixed(2)),
    relativeStrength: parseFloat(relativeStrength.toFixed(2)),
    volRatio:        parseFloat(volR.toFixed(2)),
    bodyPct:         parseFloat((bodyPct * 100).toFixed(1)),
    reason: manipulation
      ? `⚠️ MANIPULATION RISK: ${volR.toFixed(1)}× vol + ${(bodyPct*100).toFixed(0)}% body = whale trap / pump-dump`
      : explosive
        ? `EXPLOSIVE SETUP: ${momentum5.toFixed(1)}% momentum | vol ${volR.toFixed(1)}× | body ${(bodyPct*100).toFixed(0)}%${relativeStrength>0?` | RS +${relativeStrength.toFixed(1)}% vs BTC`:''}`
        : `No explosive setup: momentum=${momentum5.toFixed(1)}% vol=${volR.toFixed(1)}× body=${(bodyPct*100).toFixed(0)}%`,
  };
}

/* ─────────────────────────────────────────────────────────────────────────
   IE-12 — INTELLIGENCE MASTER COMPOSITE SCORE
   Combines all 11 Intelligence Engines into a single score that is
   added to the APEX and Ghost scores in the final signal quality gate.
   ───────────────────────────────────────────────────────────────────────── */
function computeIntelligenceMasterScore(candles, dir, currentPrice, opts = {}) {
  if (!candles || candles.length < 20 || !currentPrice || !dir) {
    return { ieScore: 0, ieGrade: 'INSUFFICIENT', ieApproved: false, reason: 'Insufficient data' };
  }

  // Run all IE engines
  const bb     = computeBollingerBreakout(candles, dir);
  const div    = computeHiddenDivergence(candles, dir);
  const ch     = detectCupAndHandle(candles, dir);
  const cons   = detectConsolidationBreakout(candles, dir);
  const bounce = detectSupportBounceDecay(candles, dir);
  const vol    = detectUnusualVolume(candles, dir);
  const sltp   = computeAdaptiveSLTP(candles, dir, currentPrice, opts.leverage || 1);
  const shield = computeRiskShield(candles, dir, opts.btcDom, opts.consecutiveLosses || 0, opts.openPositions || 0);
  const alt    = detectAltcoinExplosiveSetup(candles, dir, opts.btcCandles || null);
  const strat  = selectOptimalStrategy(candles, dir, bb, div, ch, cons, bounce);

  // Weighted composite
  const ieScore = Math.min(100, Math.round(
    bb.bbScore     * 0.12 +
    div.divScore   * 0.18 + // hidden divergence has highest weight
    ch.chScore     * 0.10 +
    cons.consolidationScore * 0.12 +
    bounce.decayScore * 0.10 +
    vol.volScore   * 0.10 +
    (100 - shield.riskScore) * 0.15 + // inverse: lower risk = higher score
    alt.altScore   * 0.08 +
    strat.strategyScore * 0.05
  ));

  // Block if manipulation detected
  if (alt.manipulation) {
    return {
      ieScore: 0, ieGrade: 'BLOCKED', ieApproved: false,
      reason: `⚠️ INTELLIGENCE SHIELD: ${alt.reason}`,
      bb, div, ch, cons, bounce, vol, sltp, shield, alt, strat,
    };
  }

  // Block if risk shield active
  if (shield.shieldActive) {
    return {
      ieScore: Math.round(ieScore * 0.3), ieGrade: 'RISK_BLOCKED', ieApproved: false,
      reason: `🛡️ RISK SHIELD: ${shield.reason}`,
      bb, div, ch, cons, bounce, vol, sltp, shield, alt, strat,
    };
  }

  const IE_THRESHOLD = parseFloat(process.env.IE_THRESHOLD || '45');
  const ieGrade = ieScore >= 75 ? 'ELITE'
                : ieScore >= 60 ? 'STRONG'
                : ieScore >= IE_THRESHOLD ? 'QUALIFIED'
                : 'WEAK';

  const ieApproved = ieScore >= IE_THRESHOLD && !shield.shieldActive && !alt.manipulation;

  const topSignals = [
    bb.breakout && bb.squeezing && `BB Squeeze Breakout (${bb.bbScore}%)`,
    div.hiddenDiv                && `Hidden ${div.divType} (${div.divScore}%)`,
    ch.detected                  && `Cup & Handle (${ch.chScore}%)`,
    cons.breakingOut             && `Consolidation Break (${cons.consolidationScore}%)`,
    bounce.decayCount >= 2       && `Support Decay (${bounce.decayScore}%)`,
    vol.spike                    && `${vol.spikeLevel} Volume (${vol.volRatio}×)`,
    alt.explosive                && `Altcoin Explosive (${alt.altScore}%)`,
  ].filter(Boolean);

  return {
    ieScore,
    ieGrade,
    ieApproved,
    topSignals,
    strategy: strat.strategy,
    adaptiveSLTP: sltp,
    riskShield: shield,
    bb, div, ch, cons, bounce, vol, sltp, shield, alt, strat,
    reason: `IE ${ieGrade} (${ieScore}%) | Strategy: ${strat.strategy} | ${topSignals.slice(0,3).join(' + ') || 'Sub-threshold signal'}`,
  };
}

/* ████████████████████████████████████████████████████████████████████████████
   ██                                                                        ██
   ██   K E R A S   N E U R A L   B R A I N   —   S E L F - L E A R N I N G ██
   ██   M A R K E T   I N T E L L I G E N C E   E N G I N E               ██
   ██                                                                        ██
   ██  A production-grade deep learning brain built on TensorFlow.js         ██
   ██  (@tensorflow/tfjs-node) that runs natively inside your Node.js        ██
   ██  engine. It does what no indicator can: it LEARNS.                     ██
   ██                                                                        ██
   ██  ARCHITECTURE:                                                         ██
   ██  ┌─────────────────────────────────────────────────────────────┐      ██
   ██  │  Input Layer    60 candles × 52 features = 3,120 inputs    │      ██
   ██  │  LSTM Layer 1   256 units, return_sequences=true            │      ██
   ██  │  Dropout        0.25                                        │      ██
   ██  │  LSTM Layer 2   128 units, return_sequences=true            │      ██
   ██  │  Dropout        0.20                                        │      ██
   ██  │  LSTM Layer 3   64 units, return_sequences=false            │      ██
   ██  │  Dense          128 units, ReLU + BatchNorm                 │      ██
   ██  │  Dense          64 units, ReLU                              │      ██
   ██  │  Output Layer   3 units (BUY/SELL/NEUTRAL) + Softmax        │      ██
   ██  └─────────────────────────────────────────────────────────────┘      ██
   ██                                                                        ██
   ██  SELF-LEARNING LOOP:                                                   ██
   ██  1. Every signal fired → features stored as training candidate         ██
   ██  2. 4 hours later → outcome checked (price vs SL/TP)                  ██
   ██  3. Labelled (WIN=1, LOSS=0) → added to experience replay buffer       ██
   ██  4. Daily 3:00 AM UTC → full retrain on last 30 days of outcomes       ██
   ██  5. New model evaluated → only replaces current if better              ██
   ██  6. Model saved to disk → survives Render restarts                     ██
   ██                                                                        ██
   ██  52 FEATURES PER CANDLE (the market's DNA):                           ██
   ██  Price:     OHLCV, returns, log-returns, range, body, wicks            ██
   ██  Momentum:  RSI(14), RSI(7), MACD, MACD signal, MACD hist             ██
   ██  Trend:     EMA(9), EMA(21), EMA(50), SMA(20), Bollinger Bands         ██
   ██  Volume:    Vol ratio, CVD, VWAP deviation, OBV slope                  ██
   ██  Structure: Swing H/L distance, BOS flag, CHoCH flag                   ██
   ██  Session:   UTC hour sin/cos (cyclical encoding), kill zone flag        ██
   ██  Market:    BTC correlation, funding rate, OI change                   ██
   ██  Context:   APEX score, Ghost score, regime score                      ██
   ██                                                                        ██
   ████████████████████████████████████████████████████████████████████████████ */

/* ─────────────────────────────────────────────────────────────────────────
   TENSORFLOW.JS LOADER — graceful degradation if not installed
   ─────────────────────────────────────────────────────────────────────────
   Uses @tensorflow/tfjs-node (C++ backend — 10–50× faster than pure JS).
   Falls back to @tensorflow/tfjs (pure JS) if native not available.
   Falls back to null if neither installed (brain disabled but engine runs).

   TO INSTALL on Render: add to package.json dependencies:
     "@tensorflow/tfjs-node": "^4.17.0"
   ───────────────────────────────────────────────────────────────────────── */
let tf = null;
(function _loadTF() {
  try {
    tf = require('@tensorflow/tfjs-node');
    console.log('🧠 TensorFlow.js (native C++ backend) loaded');
  } catch (_) {
    try {
      tf = require('@tensorflow/tfjs');
      console.log('🧠 TensorFlow.js (pure JS fallback) loaded');
    } catch (__) {
      console.warn('⚠️ TensorFlow.js not installed — Keras Brain disabled');
      console.warn('   To enable: add "@tensorflow/tfjs-node": "^4.17.0" to package.json');
      tf = null;
    }
  }
})();

/* ─────────────────────────────────────────────────────────────────────────
   KERAS BRAIN CLASS
   ─────────────────────────────────────────────────────────────────────────
   The entire self-learning system in one class. One instance created at
   startup: `const kerasBrain = new KerasBrain()`.
   Called from the scanner after every signal with `kerasBrain.predict()`.
   The brain's prediction is added to the signal card and APEX composite.
   ───────────────────────────────────────────────────────────────────────── */
class KerasBrain {
  constructor() {
    this.model          = null;      // active TF model
    this.bestModel      = null;      // best validated model (never replaced by worse)
    this.isReady        = false;     // true once model loaded/built
    this.isTraining     = false;     // lock: prevents concurrent retrains
    this.version        = 0;        // increments on every successful retrain
    this.lastTrainedAt  = 0;        // timestamp of last retrain
    this.lastAccuracy   = 0;        // validation accuracy of current model
    this.bestAccuracy   = 0;        // best accuracy ever achieved

    // Feature engineering config
    this.SEQ_LEN        = 60;       // 60 candles of history per prediction
    this.N_FEATURES     = 52;       // features per candle
    this.N_CLASSES      = 3;        // BUY / SELL / NEUTRAL
    this.CLASS_LABELS   = ['BUY', 'NEUTRAL', 'SELL'];

    // Experience replay buffer (stores labelled training examples)
    this.replayBuffer   = [];
    this.MAX_REPLAY     = 5000;     // max examples before oldest are dropped
    this.MIN_TRAIN_EXAMPLES = 100; // minimum examples needed before first train

    // Outcome checker: pending signals awaiting outcome labelling
    this.pendingOutcomes = new Map(); // signalId → { entry, sl, tp1, dir, features, ts }

    // Model file paths (Render persists /tmp only within a deployment)
    this.MODEL_DIR      = path.join(process.env.MODEL_SAVE_DIR || '/tmp', 'keras_brain');
    this.REPLAY_FILE    = path.join(this.MODEL_DIR, 'replay_buffer.json');
    this.METRICS_FILE   = path.join(this.MODEL_DIR, 'brain_metrics.json');

    // Daily retrain schedule: 3:00 AM UTC
    this.RETRAIN_HOUR_UTC = parseInt(process.env.BRAIN_RETRAIN_HOUR || '3', 10);

    // Performance metrics tracking
    this.metrics = {
      totalPredictions:  0,
      correctPredictions: 0,
      totalRetrains:     0,
      lastRetrain:       null,
      accuracyHistory:   [],  // [{ ts, accuracy, version }]
    };

    console.log('🧠 KerasBrain initialising...');
  }

  /* ── FEATURE ENGINEERING ──────────────────────────────────────────────
     Converts raw candle data + context into the 52-feature tensor the
     LSTM ingests. Every feature is normalised to [-1, 1] or [0, 1].
     The LSTM sees the market as numbers, not charts.
  ──────────────────────────────────────────────────────────────────────── */
  extractFeatures(candles, ctxObj = {}) {
    if (!candles || candles.length < this.SEQ_LEN + 14) return null;

    const closes  = candles.map(c => c.c);
    const highs   = candles.map(c => c.h);
    const lows    = candles.map(c => c.l);
    const opens   = candles.map(c => c.o);
    const vols    = candles.map(c => c.v || 0);
    const n       = candles.length;

    // ── Indicator computations ──────────────────────────────────────────
    function ema(arr, p, i) {
      const k = 2 / (p + 1);
      let e = arr[Math.max(0, i - p)];
      for (let j = Math.max(1, i - p + 1); j <= i; j++) e = arr[j] * k + e * (1 - k);
      return e;
    }

    function rsi(arr, p, i) {
      if (i < p) return 50;
      let g = 0, l = 0;
      for (let j = i - p + 1; j <= i; j++) {
        const d = arr[j] - arr[j - 1];
        if (d > 0) g += d; else l -= d;
      }
      const ag = g / p, al = l / p;
      return al === 0 ? 100 : 100 - 100 / (1 + ag / al);
    }

    function sma(arr, p, i) {
      const s = arr.slice(Math.max(0, i - p + 1), i + 1);
      return s.reduce((a, b) => a + b, 0) / s.length;
    }

    function stdDev(arr, p, i) {
      const m = sma(arr, p, i);
      const s = arr.slice(Math.max(0, i - p + 1), i + 1);
      return Math.sqrt(s.reduce((a, b) => a + Math.pow(b - m, 2), 0) / s.length);
    }

    // CVD (cumulative delta proxy)
    let cvd = 0;
    const cvdArr = candles.map(c => {
      const range = c.h - c.l || 0.0001;
      const delta = ((c.c - c.l) / range - 0.5) * 2 * (c.v || 0);
      cvd += delta;
      return cvd;
    });

    // OBV
    let obv = 0;
    const obvArr = candles.map((c, i) => {
      if (i === 0) return 0;
      obv += (c.c > candles[i-1].c ? 1 : c.c < candles[i-1].c ? -1 : 0) * (c.v || 0);
      return obv;
    });

    // ATR(14) at each position for normalisation
    const atrArr = candles.map((_, i) => {
      if (i < 14) return candles[i].h - candles[i].l;
      return candles.slice(i - 13, i + 1).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    });

    // VWAP (rolling 20-bar)
    const vwapArr = candles.map((_, i) => {
      const s = candles.slice(Math.max(0, i - 19), i + 1);
      const tv = s.reduce((a, c) => a + ((c.h + c.l + c.c) / 3) * (c.v || 0), 0);
      const tv2 = s.reduce((a, c) => a + (c.v || 0), 0);
      return tv2 > 0 ? tv / tv2 : candles[i].c;
    });

    // Swing high/low distance
    function swingLow(i, lb = 10) {
      const s = candles.slice(Math.max(0, i - lb), i);
      return s.length > 0 ? Math.min(...s.map(c => c.l)) : candles[i].l;
    }
    function swingHigh(i, lb = 10) {
      const s = candles.slice(Math.max(0, i - lb), i);
      return s.length > 0 ? Math.max(...s.map(c => c.h)) : candles[i].h;
    }

    // UTC hour cyclical encoding from context or approximated
    const now      = new Date();
    const utcHour  = ctxObj.utcHour ?? now.getUTCHours();
    const hourSin  = Math.sin(2 * Math.PI * utcHour / 24);
    const hourCos  = Math.cos(2 * Math.PI * utcHour / 24);
    const killZone = [7, 8, 12, 13, 14, 19, 20].includes(utcHour) ? 1 : 0;

    // Context features (from APEX/Ghost/IE scores if available)
    const apexScore  = (ctxObj.apexScore  ?? 50) / 100;
    const ghostScore = (ctxObj.ghostScore ?? 50) / 100;
    const ieScore    = (ctxObj.ieScore    ?? 50) / 100;
    const regime     = (ctxObj.regimeScore ?? 50) / 100;
    const btcDom     = (ctxObj.btcDom     ?? 50) / 100;
    const fundingR   = Math.tanh((ctxObj.fundingRate ?? 0) * 1000); // normalise
    const oiChange   = Math.tanh((ctxObj.oiChange    ?? 0) * 10);

    // Build the sequence: last SEQ_LEN candles
    const seq = [];
    const startIdx = n - this.SEQ_LEN;

    for (let i = startIdx; i < n; i++) {
      const c    = candles[i];
      const atr  = atrArr[i] || 0.0001;
      const price = c.c || 0.0001;

      // Normalise price features relative to ATR (scale-invariant)
      const feat = [
        /* 0  */ (c.c - c.o) / atr,                                    // body (ATR-normalised)
        /* 1  */ (c.h - c.c) / atr,                                    // upper wick
        /* 2  */ (c.c - c.l) / atr,                                    // lower wick
        /* 3  */ (c.h - c.l) / atr,                                    // range
        /* 4  */ i > 0 ? (c.c - candles[i-1].c) / (candles[i-1].c || 1) : 0, // 1-bar return
        /* 5  */ i > 1 ? (c.c - candles[i-2].c) / (candles[i-2].c || 1) : 0, // 2-bar return
        /* 6  */ i > 4 ? (c.c - candles[i-5].c) / (candles[i-5].c || 1) : 0, // 5-bar return
        /* 7  */ i > 0 ? Math.log(c.c / (candles[i-1].c || 1)) : 0,   // log return
        /* 8  */ (rsi(closes, 14, i) - 50) / 50,                       // RSI(14) normalised
        /* 9  */ (rsi(closes, 7, i)  - 50) / 50,                       // RSI(7) normalised
        /* 10 */ (() => { const m=ema(closes,12,i)-ema(closes,26,i); return Math.tanh(m/(atr||1)); })(), // MACD
        /* 11 */ (() => { const m=ema(closes,12,i)-ema(closes,26,i); const s=ema([m],9,0); return Math.tanh((m-s)/(atr||1)); })(), // MACD hist
        /* 12 */ (ema(closes, 9,  i) - price) / (atr * 5),             // EMA9 deviation
        /* 13 */ (ema(closes, 21, i) - price) / (atr * 5),             // EMA21 deviation
        /* 14 */ (ema(closes, 50, i) - price) / (atr * 10),            // EMA50 deviation
        /* 15 */ (sma(closes, 20, i) - price) / (atr * 5),             // SMA20 deviation
        /* 16 */ (() => { const sd=stdDev(closes,20,i); const m=sma(closes,20,i); return sd>0?(price-(m+2*sd))/(2*sd):0; })(), // BB upper deviation
        /* 17 */ (() => { const sd=stdDev(closes,20,i); const m=sma(closes,20,i); return sd>0?(price-(m-2*sd))/(2*sd):0; })(), // BB lower deviation
        /* 18 */ (() => { const sd=stdDev(closes,20,i); const m=sma(closes,20,i); return m>0?(4*sd)/m:0; })(), // BB bandwidth
        /* 19 */ vols[i] > 0 && i >= 20 ? Math.tanh((vols[i] / (vols.slice(i-20,i).reduce((a,b)=>a+b,0)/20)) - 1) : 0, // vol ratio
        /* 20 */ (() => { const v20=vols.slice(Math.max(0,i-20),i); const avg=v20.length>0?v20.reduce((a,b)=>a+b,0)/v20.length:1; return Math.tanh((vols[i]||0)/avg - 1); })(), // vol z-score
        /* 21 */ cvdArr[i] > 0 ? Math.tanh(cvdArr[i] / (Math.abs(cvdArr[Math.max(0,i-20)]) || 1)) : 0, // CVD normalised
        /* 22 */ i > 0 ? Math.tanh((cvdArr[i] - cvdArr[i-1]) / (price * (vols[i]||1) || 1)) : 0, // CVD delta
        /* 23 */ obvArr[i] ? Math.tanh(obvArr[i] / (Math.abs(obvArr[Math.max(0,i-20)]) || 1)) : 0, // OBV normalised
        /* 24 */ (price - vwapArr[i]) / (atr * 3),                     // VWAP deviation
        /* 25 */ (swingHigh(i) - price) / (atr * 5),                   // distance to swing high
        /* 26 */ (price - swingLow(i))  / (atr * 5),                   // distance to swing low
        /* 27 */ (() => { // BOS flag: price broke swing high
          const sh = swingHigh(i, 10);
          return c.c > sh && candles[Math.max(0,i-1)].c <= sh ? 1 : 0;
        })(),
        /* 28 */ (() => { // CHoCH flag: opposite swing broken
          const sl = swingLow(i, 10);
          return c.c < sl && candles[Math.max(0,i-1)].c >= sl ? 1 : 0;
        })(),
        /* 29 */ atr / (price || 1),                                    // normalised ATR (volatility)
        /* 30 */ i >= 14 ? Math.tanh((atr - (atrArr.slice(Math.max(0,i-14),i).reduce((a,b)=>a+b,0)/14)) / atr) : 0, // ATR change
        /* 31 */ hourSin,                                                // time cyclical (sin)
        /* 32 */ hourCos,                                                // time cyclical (cos)
        /* 33 */ killZone,                                               // kill zone flag
        /* 34 */ (() => { // Candle pattern: doji
          const body = Math.abs(c.c - c.o);
          const range2 = c.h - c.l || 0.0001;
          return body / range2 < 0.1 ? 1 : 0;
        })(),
        /* 35 */ (() => { // Candle pattern: engulf
          if (i === 0) return 0;
          const prev = candles[i-1];
          return (c.c > c.o && c.c > prev.o && c.o < prev.c) ? 1
               : (c.c < c.o && c.c < prev.o && c.o > prev.c) ? -1 : 0;
        })(),
        /* 36 */ (() => { // Higher high chain (3 bars)
          if (i < 3) return 0;
          return (highs[i]>highs[i-1] && highs[i-1]>highs[i-2]) ? 1
               : (highs[i]<highs[i-1] && highs[i-1]<highs[i-2]) ? -1 : 0;
        })(),
        /* 37 */ (() => { // Lower low chain (3 bars)
          if (i < 3) return 0;
          return (lows[i]<lows[i-1] && lows[i-1]<lows[i-2]) ? 1
               : (lows[i]>lows[i-1] && lows[i-1]>lows[i-2]) ? -1 : 0;
        })(),
        /* 38 */ (() => { // Compression: range narrowing
          const r5 = candles.slice(Math.max(0,i-5),i).map(c2=>c2.h-c2.l);
          const r20 = candles.slice(Math.max(0,i-20),i-5).map(c2=>c2.h-c2.l);
          const avg5 = r5.length > 0 ? r5.reduce((a,b)=>a+b,0)/r5.length : atr;
          const avg20 = r20.length > 0 ? r20.reduce((a,b)=>a+b,0)/r20.length : atr;
          return avg20 > 0 ? Math.tanh(1 - avg5/avg20) : 0;
        })(),
        /* 39 */ (() => { // Momentum: 10-bar rate of change
          const p10 = closes[Math.max(0,i-10)];
          return p10 > 0 ? Math.tanh((c.c - p10) / p10 * 10) : 0;
        })(),
        /* 40 */ (() => { // Volume-price correlation (5-bar)
          if (i < 5) return 0;
          const pChg = closes.slice(i-5,i+1).map((p,j) => j>0?p-closes[i-5+j-1]:0).slice(1);
          const vChg = vols.slice(i-5,i+1).map((v,j)=>j>0?v-vols[i-5+j-1]:0).slice(1);
          let num=0,d1=0,d2=0;
          for(let j=0;j<pChg.length;j++){num+=pChg[j]*vChg[j];d1+=pChg[j]**2;d2+=vChg[j]**2;}
          return d1>0&&d2>0?num/Math.sqrt(d1*d2):0;
        })(),
        /* 41 */ Math.tanh((price - ema(closes, 200, i)) / (atr * 20)),  // distance from EMA200
        /* 42 */ apexScore,                                               // APEX precision score
        /* 43 */ ghostScore,                                              // Ghost engine score
        /* 44 */ ieScore,                                                 // IE-12 composite
        /* 45 */ regime,                                                  // regime filter score
        /* 46 */ btcDom,                                                  // BTC dominance
        /* 47 */ fundingR,                                                // funding rate
        /* 48 */ oiChange,                                                // OI change
        /* 49 */ (() => { // Fear/Greed proxy: price vs 30d SMA
          const sma30 = sma(closes, 30, i);
          return sma30 > 0 ? Math.tanh((price - sma30) / sma30 * 5) : 0;
        })(),
        /* 50 */ (() => { // Liquidity imbalance: up vs down vol (5 bars)
          const s5 = candles.slice(Math.max(0,i-5),i+1);
          const upV = s5.filter(cc=>cc.c>cc.o).reduce((a,cc)=>a+(cc.v||0),0);
          const dnV = s5.filter(cc=>cc.c<cc.o).reduce((a,cc)=>a+(cc.v||0),0);
          const tot = upV + dnV;
          return tot > 0 ? (upV - dnV) / tot : 0;
        })(),
        /* 51 */ (() => { // Market efficiency ratio (MER): directional vs total movement
          if (i < 10) return 0;
          const netMove = Math.abs(closes[i] - closes[i-10]);
          const totalPath = candles.slice(i-10,i+1).reduce((a,c2,j) =>
            j>0?a+Math.abs(c2.c-candles[i-10+j-1].c):a, 0);
          return totalPath > 0 ? netMove / totalPath : 0;
        })(),
      ];

      // Clip all features to [-3, 3] to prevent gradient explosion
      seq.push(feat.map(f => Math.max(-3, Math.min(3, isNaN(f) ? 0 : f))));
    }

    return seq; // shape: [SEQ_LEN, N_FEATURES]
  }

  /* ── MODEL ARCHITECTURE ──────────────────────────────────────────────
     3-layer stacked LSTM with dropout and batch normalisation.
     Designed for sequence-to-class prediction on financial time series.
     Trained with categorical cross-entropy (3 classes: BUY/NEUTRAL/SELL).
  ──────────────────────────────────────────────────────────────────────── */
  buildModel() {
    if (!tf) return null;
    const model = tf.sequential();

    // Layer 1: LSTM 256 — captures long-range dependencies
    model.add(tf.layers.lstm({
      units:          256,
      returnSequences: true,
      inputShape:     [this.SEQ_LEN, this.N_FEATURES],
      recurrentDropout: 0.10,
      kernelRegularizer: tf.regularizers.l2({ l2: 0.0001 }),
    }));
    model.add(tf.layers.dropout({ rate: 0.25 }));

    // Layer 2: LSTM 128 — mid-level pattern extraction
    model.add(tf.layers.lstm({
      units:          128,
      returnSequences: true,
      recurrentDropout: 0.10,
    }));
    model.add(tf.layers.dropout({ rate: 0.20 }));

    // Layer 3: LSTM 64 — high-level signal compression
    model.add(tf.layers.lstm({
      units:          64,
      returnSequences: false,
      recurrentDropout: 0.10,
    }));
    model.add(tf.layers.dropout({ rate: 0.15 }));

    // Dense head
    model.add(tf.layers.dense({
      units: 128, activation: 'relu',
      kernelRegularizer: tf.regularizers.l2({ l2: 0.0001 }),
    }));
    model.add(tf.layers.batchNormalization());
    model.add(tf.layers.dropout({ rate: 0.15 }));

    model.add(tf.layers.dense({
      units: 64, activation: 'relu',
    }));
    model.add(tf.layers.dropout({ rate: 0.10 }));

    // Output: 3 classes (BUY=0, NEUTRAL=1, SELL=2) with softmax
    model.add(tf.layers.dense({
      units:      this.N_CLASSES,
      activation: 'softmax',
    }));

    model.compile({
      optimizer: tf.train.adam(0.0005),
      loss:      'categoricalCrossentropy',
      metrics:   ['accuracy'],
    });

    console.log(`🧠 KerasBrain model built: ${model.countParams().toLocaleString()} parameters`);
    return model;
  }

  /* ── INITIALISE ───────────────────────────────────────────────────────
     Called on startup. Tries to load saved model from disk.
     If not found, builds a new untrained model.
     Loads replay buffer from disk if available.
  ──────────────────────────────────────────────────────────────────────── */
  async init() {
    if (!tf) { console.warn('🧠 KerasBrain: TensorFlow not available — predictions disabled'); return; }
    try {
      // Ensure model directory exists
      if (!fs.existsSync(this.MODEL_DIR)) fs.mkdirSync(this.MODEL_DIR, { recursive: true });

      // Try loading saved model
      const modelJsonPath = path.join(this.MODEL_DIR, 'model', 'model.json');
      if (fs.existsSync(modelJsonPath)) {
        try {
          this.model = await tf.loadLayersModel(`file://${path.join(this.MODEL_DIR, 'model', 'model.json')}`);
          this.model.compile({ optimizer: tf.train.adam(0.0005), loss: 'categoricalCrossentropy', metrics: ['accuracy'] });
          console.log('🧠 KerasBrain: loaded saved model from disk ✅');
        } catch (_loadErr) {
          console.warn('🧠 KerasBrain: saved model corrupted — building fresh');
          this.model = this.buildModel();
        }
      } else {
        this.model = this.buildModel();
        console.log('🧠 KerasBrain: new model built (no saved model found)');
      }

      // Load replay buffer
      if (fs.existsSync(this.REPLAY_FILE)) {
        try {
          this.replayBuffer = JSON.parse(fs.readFileSync(this.REPLAY_FILE, 'utf8'));
          console.log(`🧠 KerasBrain: loaded ${this.replayBuffer.length} replay examples from disk`);
        } catch (_) { this.replayBuffer = []; }
      }

      // Load metrics
      if (fs.existsSync(this.METRICS_FILE)) {
        try { this.metrics = { ...this.metrics, ...JSON.parse(fs.readFileSync(this.METRICS_FILE, 'utf8')) }; }
        catch (_) {}
      }

      this.version    = this.metrics.totalRetrains || 0;
      this.lastAccuracy = this.metrics.accuracyHistory?.slice(-1)[0]?.accuracy || 0;
      this.isReady    = true;

      console.log(`🧠 KerasBrain ready: v${this.version} | accuracy: ${(this.lastAccuracy*100).toFixed(1)}% | ${this.replayBuffer.length} examples`);

      // Schedule daily retrain
      this._scheduleDailyRetrain();

      // Schedule outcome checker (every 15 min)
      setInterval(() => this._checkPendingOutcomes(), 15 * 60 * 1000);

    } catch (err) {
      console.error('🧠 KerasBrain init error:', err.message);
    }
  }

  /* ── PREDICTION ────────────────────────────────────────────────────────
     Main entry point called by the scanner for every signal candidate.
     Returns { direction, confidence, BUY, NEUTRAL, SELL, version }.
     Fast: typically < 50ms on CPU.
  ──────────────────────────────────────────────────────────────────────── */
  async predict(candles, ctxObj = {}) {
    if (!tf || !this.model || !this.isReady) {
      return { direction: 'NEUTRAL', confidence: 0, BUY: 0.33, NEUTRAL: 0.34, SELL: 0.33, version: 0, available: false };
    }

    try {
      const features = this.extractFeatures(candles, ctxObj);
      if (!features) return { direction: 'NEUTRAL', confidence: 0, available: false };

      // Run inference inside tf.tidy to prevent memory leaks
      const probs = tf.tidy(() => {
        const input = tf.tensor3d([features], [1, this.SEQ_LEN, this.N_FEATURES]);
        const output = this.model.predict(input);
        return Array.from(output.dataSync());
      });

      const [pBuy, pNeutral, pSell] = probs;
      const maxProb  = Math.max(pBuy, pNeutral, pSell);
      const dirIdx   = probs.indexOf(maxProb);
      const direction = this.CLASS_LABELS[dirIdx];
      const confidence = parseFloat((maxProb * 100).toFixed(1));

      this.metrics.totalPredictions++;

      return {
        direction,
        confidence,
        BUY:     parseFloat((pBuy     * 100).toFixed(1)),
        NEUTRAL: parseFloat((pNeutral * 100).toFixed(1)),
        SELL:    parseFloat((pSell    * 100).toFixed(1)),
        version: this.version,
        available: true,
        lastAccuracy: parseFloat((this.lastAccuracy * 100).toFixed(1)),
      };
    } catch (err) {
      console.warn('🧠 KerasBrain predict error:', err.message);
      return { direction: 'NEUTRAL', confidence: 0, available: false };
    }
  }

  /* ── RECORD SIGNAL FOR OUTCOME TRACKING ──────────────────────────────
     Called immediately after a signal fires. Stores the feature vector
     and signal parameters so the outcome can be labelled 4 hours later.
  ──────────────────────────────────────────────────────────────────────── */
  recordSignal(signalId, candles, dir, entry, sl, tp1, ctxObj = {}) {
    if (!this.isReady) return;
    try {
      const features = this.extractFeatures(candles, ctxObj);
      if (!features) return;
      this.pendingOutcomes.set(signalId, {
        features,
        dir,
        entry:    parseFloat(entry) || 0,
        sl:       parseFloat(sl)    || 0,
        tp1:      parseFloat(tp1)   || 0,
        ts:       Date.now(),
        symbol:   ctxObj.symbol || '',
      });
    } catch (_) {}
  }

  /* ── OUTCOME CHECKER ──────────────────────────────────────────────────
     Runs every 15 minutes. Checks pending signals: fetches current price
     and determines if SL or TP1 was hit. Labels the example and adds
     it to the replay buffer for the next retrain.
  ──────────────────────────────────────────────────────────────────────── */
  async _checkPendingOutcomes() {
    const now = Date.now();
    const CHECK_AFTER_MS = 4 * 60 * 60 * 1000; // 4 hours

    for (const [signalId, pending] of this.pendingOutcomes.entries()) {
      if (now - pending.ts < CHECK_AFTER_MS) continue; // too early

      try {
        // Fetch current price
        const currentPrice = await raceDeadline(fetchLivePrice(pending.symbol), 8000, `outcomeCheck:${pending.symbol}`);
        if (!currentPrice || currentPrice <= 0) { this.pendingOutcomes.delete(signalId); continue; }

        // Determine outcome
        let outcome = 'NEUTRAL';
        if (pending.dir === 'BUY') {
          if (currentPrice >= pending.tp1 && pending.tp1 > 0)       outcome = 'WIN';
          else if (currentPrice <= pending.sl && pending.sl > 0)    outcome = 'LOSS';
          else if (currentPrice > pending.entry * 1.005)            outcome = 'WIN';   // +0.5% in direction
          else if (currentPrice < pending.entry * 0.995)            outcome = 'LOSS';  // -0.5% against
        } else if (pending.dir === 'SELL') {
          if (currentPrice <= pending.tp1 && pending.tp1 > 0)       outcome = 'WIN';
          else if (currentPrice >= pending.sl && pending.sl > 0)    outcome = 'LOSS';
          else if (currentPrice < pending.entry * 0.995)            outcome = 'WIN';
          else if (currentPrice > pending.entry * 1.005)            outcome = 'LOSS';
        }

        if (outcome !== 'NEUTRAL') {
          // Add to replay buffer as a labelled training example
          // Labels: BUY WIN → [1,0,0], BUY LOSS → [0,1,0],
          //         SELL WIN → [0,0,1], SELL LOSS → [0,1,0]
          const label = pending.dir === 'BUY' && outcome === 'WIN'  ? [1, 0, 0]
                      : pending.dir === 'SELL' && outcome === 'WIN' ? [0, 0, 1]
                      : [0, 1, 0]; // loss → neutral label (don't reinforce direction)

          this.replayBuffer.push({ features: pending.features, label, outcome, dir: pending.dir, ts: pending.ts });

          // Cap replay buffer
          if (this.replayBuffer.length > this.MAX_REPLAY) {
            this.replayBuffer.splice(0, this.replayBuffer.length - this.MAX_REPLAY);
          }

          // Update metrics
          if (outcome === 'WIN') this.metrics.correctPredictions++;

          // Persist replay buffer
          this._saveReplayBuffer();

          console.log(`🧠 KerasBrain outcome: ${pending.symbol} ${pending.dir} → ${outcome} | buffer: ${this.replayBuffer.length} examples`);
        }

        this.pendingOutcomes.delete(signalId);
      } catch (_) {
        // If price fetch fails, leave pending for next check
      }
    }
  }

  /* ── TRAINING ──────────────────────────────────────────────────────────
     Retrains the model on the full replay buffer.
     Uses 80/20 train/validation split.
     Only replaces the active model if validation accuracy improves.
     Reports results to Telegram.
  ──────────────────────────────────────────────────────────────────────── */
  async retrain() {
    if (!tf || !this.model) { console.warn('🧠 KerasBrain: cannot retrain — TF not available'); return; }
    if (this.isTraining) { console.warn('🧠 KerasBrain: retrain already in progress — skipping'); return; }
    if (this.replayBuffer.length < this.MIN_TRAIN_EXAMPLES) {
      console.log(`🧠 KerasBrain: only ${this.replayBuffer.length}/${this.MIN_TRAIN_EXAMPLES} examples — skipping retrain`);
      return;
    }

    this.isTraining = true;
    const startTime = Date.now();
    console.log(`🧠 KerasBrain: starting retrain on ${this.replayBuffer.length} examples...`);

    try {
      // Shuffle replay buffer
      const shuffled = [...this.replayBuffer].sort(() => Math.random() - 0.5);

      // Build tensors
      const xs = tf.tensor3d(shuffled.map(e => e.features), [shuffled.length, this.SEQ_LEN, this.N_FEATURES]);
      const ys = tf.tensor2d(shuffled.map(e => e.label),    [shuffled.length, this.N_CLASSES]);

      // Build fresh model for retraining (don't train the live model)
      const trainModel = this.buildModel();

      // Copy weights from current model as starting point (transfer learning)
      try {
        const currentWeights = this.model.getWeights();
        trainModel.setWeights(currentWeights);
      } catch (_) { /* fresh start if weight copy fails */ }

      // Train with callbacks
      const history = await trainModel.fit(xs, ys, {
        epochs:           25,
        batchSize:        32,
        validationSplit:  0.20,
        shuffle:          true,
        callbacks: {
          onEpochEnd: (epoch, logs) => {
            if (epoch % 5 === 0) {
              console.log(`🧠 Epoch ${epoch}/25 — loss: ${logs.loss?.toFixed(4)} acc: ${(logs.acc||logs.accuracy||0)?.toFixed(4)} val_acc: ${(logs.val_acc||logs.val_accuracy||0)?.toFixed(4)}`);
            }
          },
        },
      });

      // Get final validation accuracy
      const finalValAcc = history.history.val_acc?.slice(-1)[0] ||
                          history.history.val_accuracy?.slice(-1)[0] || 0;

      xs.dispose();
      ys.dispose();

      // Only replace model if this version is better
      if (finalValAcc >= this.lastAccuracy - 0.02) { // accept if within 2% of best
        // Dispose old model weights
        if (this.model && finalValAcc > this.lastAccuracy) {
          this.model.dispose();
          this.model = trainModel;
          this.lastAccuracy = finalValAcc;
          if (finalValAcc > this.bestAccuracy) this.bestAccuracy = finalValAcc;
          console.log(`🧠 KerasBrain: model IMPROVED → v${this.version + 1} | val_acc: ${(finalValAcc*100).toFixed(1)}%`);
        } else {
          // Same or slightly worse but within tolerance — use new model for freshness
          this.model.dispose();
          this.model = trainModel;
          this.lastAccuracy = finalValAcc;
        }
      } else {
        trainModel.dispose();
        console.log(`🧠 KerasBrain: new model worse (${(finalValAcc*100).toFixed(1)}% < ${(this.lastAccuracy*100).toFixed(1)}%) — keeping current`);
      }

      this.version++;
      this.lastTrainedAt = Date.now();
      this.metrics.totalRetrains++;
      this.metrics.lastRetrain = new Date().toISOString();
      this.metrics.accuracyHistory.push({ ts: Date.now(), accuracy: finalValAcc, version: this.version });
      if (this.metrics.accuracyHistory.length > 100) this.metrics.accuracyHistory.splice(0, 50);

      // Save model to disk
      await this._saveModel();
      this._saveMetrics();

      const elapsed = Math.round((Date.now() - startTime) / 1000);
      console.log(`🧠 KerasBrain retrain complete: v${this.version} | acc: ${(finalValAcc*100).toFixed(1)}% | ${elapsed}s`);

      // Notify Telegram
      if (TELEGRAM_CHAT_ID) {
        const winCount  = this.replayBuffer.filter(e => e.outcome === 'WIN').length;
        const lossCount = this.replayBuffer.filter(e => e.outcome === 'LOSS').length;
        const trainWR   = winCount + lossCount > 0 ? Math.round(winCount / (winCount + lossCount) * 100) : 0;
        await raceDeadline(tg('sendMessage', {
          chat_id: TELEGRAM_CHAT_ID,
          text: [
            `🧠 <b>Keras Brain Retrained — v${this.version}</b>`,
            ``,
            `📊 Training data: <b>${this.replayBuffer.length}</b> examples`,
            `✅ Wins: ${winCount} | ❌ Losses: ${lossCount} | Win rate: <b>${trainWR}%</b>`,
            `🎯 Validation accuracy: <b>${(finalValAcc*100).toFixed(1)}%</b>`,
            `🏆 Best accuracy ever: <b>${(this.bestAccuracy*100).toFixed(1)}%</b>`,
            `⏱ Training time: ${elapsed}s`,
            ``,
            `<i>Brain will apply new patterns to all future signals</i>`,
          ].join('\n'),
          parse_mode: 'HTML', disable_web_page_preview: true,
        }), 8000, 'brainRetrainNotif').catch(() => {});
      }

    } catch (err) {
      console.error('🧠 KerasBrain retrain error:', err.message);
    } finally {
      this.isTraining = false;
    }
  }

  /* ── DAILY RETRAIN SCHEDULER ──────────────────────────────────────────
     Checks every minute whether it is the scheduled retrain hour (3 AM
     UTC by default). Fires retrain once per day. Also fires an event-
     driven retrain if the replay buffer grows rapidly (>200 new examples
     since last retrain — indicates a regime change is being captured).
  ──────────────────────────────────────────────────────────────────────── */
  _scheduleDailyRetrain() {
    let _lastRetrainDay  = -1;
    let _bufferAtRetrain = this.replayBuffer.length;

    setInterval(async () => {
      const now   = new Date();
      const hour  = now.getUTCHours();
      const day   = now.getUTCDate();

      // Daily scheduled retrain
      if (hour === this.RETRAIN_HOUR_UTC && day !== _lastRetrainDay && !this.isTraining) {
        _lastRetrainDay  = day;
        _bufferAtRetrain = this.replayBuffer.length;
        console.log(`🧠 KerasBrain: daily retrain scheduled at ${this.RETRAIN_HOUR_UTC}:00 UTC`);
        await this.retrain();
        return;
      }

      // Event-driven retrain: buffer grew significantly (regime change)
      const newExamples = this.replayBuffer.length - _bufferAtRetrain;
      if (newExamples >= 200 && !this.isTraining && this.replayBuffer.length >= this.MIN_TRAIN_EXAMPLES) {
        _bufferAtRetrain = this.replayBuffer.length;
        console.log(`🧠 KerasBrain: event-driven retrain triggered (${newExamples} new examples)`);
        await this.retrain();
      }
    }, 60 * 1000); // check every minute
  }

  /* ── EVENT DETECTION ──────────────────────────────────────────────────
     Detects market-wide events that affect all signals:
     - Liquidity cascade (BTC drops >3% in 1 candle)
     - Funding rate extreme (mass squeeze incoming)
     - Volatility collapse (range < 20% of ATR — dead market)
     - Volume collapse (< 30% of average — no institutional participation)
     Returns event flags that the scanner uses to suppress signals.
  ──────────────────────────────────────────────────────────────────────── */
  detectMarketEvent(candles, fundingRate = 0, btcCandles = null) {
    if (!candles || candles.length < 14) return { event: 'NONE', severity: 0, suppress: false };

    const last    = candles[candles.length - 1];
    const atr14   = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    const avgVol  = candles.slice(-20, -1).reduce((a, c) => a + (c.v || 0), 0) / 19;
    const lastVol = last.v || 0;

    const events = [];
    let maxSeverity = 0;

    // Flash crash / liquidation cascade
    const btcLast = btcCandles?.[btcCandles.length - 1];
    const btcPrev = btcCandles?.[btcCandles.length - 2];
    if (btcLast && btcPrev && btcPrev.c > 0) {
      const btcDrop = (btcLast.c - btcPrev.c) / btcPrev.c * 100;
      if (Math.abs(btcDrop) > 3) {
        events.push(`BTC ${btcDrop.toFixed(1)}% candle — cascade risk`);
        maxSeverity = Math.max(maxSeverity, 80);
      }
    }

    // Abnormal range (news event)
    const rangeRatio = atr14 > 0 ? (last.h - last.l) / atr14 : 1;
    if (rangeRatio > 4.0) {
      events.push(`Range ${rangeRatio.toFixed(1)}×ATR — news/manipulation`);
      maxSeverity = Math.max(maxSeverity, 75);
    }

    // Volume collapse (dead market — signals unreliable)
    const volRatio = avgVol > 0 ? lastVol / avgVol : 1;
    if (volRatio < 0.20) {
      events.push(`Volume ${(volRatio*100).toFixed(0)}% of avg — market dead`);
      maxSeverity = Math.max(maxSeverity, 60);
    }

    // Extreme funding (mass squeeze)
    if (Math.abs(fundingRate) > 0.002) {
      events.push(`Extreme funding ${(fundingRate*100).toFixed(3)}% — squeeze risk`);
      maxSeverity = Math.max(maxSeverity, 65);
    }

    const event    = events.length > 0 ? events[0] : 'NONE';
    const suppress = maxSeverity >= 65; // suppress all signals if severity >= 65

    return { event, events, severity: maxSeverity, suppress, rangeRatio, volRatio };
  }

  /* ── PERSISTENCE HELPERS ──────────────────────────────────────────────*/
  async _saveModel() {
    if (!tf || !this.model) return;
    try {
      const savePath = path.join(this.MODEL_DIR, 'model');
      await this.model.save(`file://${savePath}`);
      console.log(`🧠 KerasBrain: model saved to ${savePath}`);
    } catch (err) { console.warn('🧠 KerasBrain: save error —', err.message); }
  }

  _saveReplayBuffer() {
    try { fs.writeFileSync(this.REPLAY_FILE, JSON.stringify(this.replayBuffer)); }
    catch (_) {}
  }

  _saveMetrics() {
    try { fs.writeFileSync(this.METRICS_FILE, JSON.stringify(this.metrics)); }
    catch (_) {}
  }

  /* ── STATUS REPORT ──────────────────────────────────────────────────── */
  getStatus() {
    const wins   = this.replayBuffer.filter(e => e.outcome === 'WIN').length;
    const losses = this.replayBuffer.filter(e => e.outcome === 'LOSS').length;
    return {
      ready:          this.isReady,
      version:        this.version,
      accuracy:       parseFloat((this.lastAccuracy * 100).toFixed(1)),
      bestAccuracy:   parseFloat((this.bestAccuracy  * 100).toFixed(1)),
      replaySize:     this.replayBuffer.length,
      pendingOutcomes:this.pendingOutcomes.size,
      wins,
      losses,
      trainWinRate:   wins + losses > 0 ? Math.round(wins / (wins + losses) * 100) : 0,
      lastTrained:    this.metrics.lastRetrain || 'Never',
      totalRetrains:  this.metrics.totalRetrains,
      totalPredictions: this.metrics.totalPredictions,
      available:      !!tf,
    };
  }
}

/* ── Global brain instance — initialised in startup sequence ────────────── */
const kerasBrain = new KerasBrain();

/* =========================
   STRATEGY AGGREGATOR
========================= */
function evaluateStrategies(results) {
  return results.filter(r => r.signal).map(r => r.weight);
}

/* =========================
   MAIN EXECUTION ENGINE
========================= */
async function generateSignal(symbol, direction, strategyResults) {
  const price = await fetchLivePrice(symbol);
  if (!price) return null;

  const confidence = computeConfidence(evaluateStrategies(strategyResults));
  const { tp, sl } = computeTPSL(price, direction);

  const sig = {
    symbol,
    direction,
    entry: price,
    tp: safeNumber(tp),
    sl: safeNumber(sl),
    confidence
  };

  // ── Single Brain: push into resolver bucket ──────────────────────────
  if (direction && direction !== 'NEUTRAL') {
    captureSignal(buildSignal({
      symbol,                            // ✅ FIX: symbol tagged for per-symbol conflict resolution
      direction,
      confidence: normalizeConfidence(confidence),
      entry:      price,
      stopLoss:   safeNumber(sl),
      takeProfit: safeNumber(tp),
      timeframe:  'computed',
      reason:     `generateSignal — ${symbol}`
    }));
  }

  return sig;
}

