/* ================= NATIVE MATH UTILITIES ================= */
// Native error function (erf) approximation — replaces mathjs dependency
// Abramowitz & Stegun formula 7.1.26 — accurate to ~1.5e-7
function erf(x) {
  const t = 1.0 / (1.0 + 0.3275911 * Math.abs(x));
  const y = 1.0 - (((((1.061405429 * t - 1.453152027) * t) + 1.421413741) * t - 0.284496736) * t + 0.254829592) * t * Math.exp(-x * x);
  return x < 0 ? -y : y;
}

/* ================= QUANTUM ENVIRONMENT ================= */
// .trim() is critical — env vars from deployment platforms often carry trailing
// \n or \r characters which cause "Request path contains unescaped characters"
// in Node.js https.request when the token is embedded in the URL path.
const TELEGRAM_TOKEN = (process.env.TELEGRAM_TOKEN || "").trim().replace(/[^\x20-\x7E]/g, '');
const TELEGRAM_CHAT_ID = (process.env.TELEGRAM_CHAT_ID || "").trim().replace(/[^\x20-\x7E]/g, '');

/* ═══════════════════════════════════════════════════════════════════════
   ADMIN ACCESS CONTROL — SINGLE OWNER MODE
   ─────────────────────────────────────────────────────────────────────
   Only the admin user can receive signals or send commands.
   TELEGRAM_CHAT_ID is used as the primary admin identifier.
   Additionally set ADMIN_USER_ID as env variable (your Telegram user ID).
   Get your Telegram user ID by messaging @userinfobot on Telegram.

   How to set:
   TELEGRAM_CHAT_ID = your chat ID (already set — this is your admin chat)
   ADMIN_USER_ID    = your Telegram user ID number (optional extra check)

   Any message from any other user is silently ignored — no response,
   no error, completely invisible. Only you receive signals.
   ═══════════════════════════════════════════════════════════════════════ */
const ADMIN_USER_ID  = (process.env.ADMIN_USER_ID || '').trim();
// Parse TELEGRAM_CHAT_ID as numeric for comparison
const ADMIN_CHAT_ID_NUM = parseInt(TELEGRAM_CHAT_ID, 10);

/**
 * isAdminMessage(message)
 * Returns true ONLY if the message comes from the admin user.
 * Three-layer check:
 * 1. chat.id matches TELEGRAM_CHAT_ID (primary — always set)
 * 2. from.id matches ADMIN_USER_ID if set (secondary — optional)
 * 3. chat.type is 'private' (bot should only work in private chat with admin)
 */
function isAdminMessage(message) {
  if (!message) return false;
  const chatId  = message.chat?.id;
  const userId  = message.from?.id;
  const chatType = message.chat?.type;

  // Primary check: chat ID must match admin chat
  if (TELEGRAM_CHAT_ID && chatId !== undefined) {
    const chatIdNum = typeof chatId === 'string' ? parseInt(chatId, 10) : chatId;
    if (ADMIN_CHAT_ID_NUM && chatIdNum !== ADMIN_CHAT_ID_NUM) {
      console.log(`🚫 Unauthorized access blocked — chat ${chatId} (admin: ${TELEGRAM_CHAT_ID})`);
      return false;
    }
  }

  // Secondary check: user ID if ADMIN_USER_ID is configured
  if (ADMIN_USER_ID && userId !== undefined) {
    const adminIdNum = parseInt(ADMIN_USER_ID, 10);
    const userIdNum  = typeof userId === 'string' ? parseInt(userId, 10) : userId;
    if (adminIdNum && userIdNum !== adminIdNum) {
      console.log(`🚫 Unauthorized user blocked — user ${userId} (admin: ${ADMIN_USER_ID})`);
      return false;
    }
  }

  return true;
}

/* Long-polling mode — no webhook URL needed */
// Polling interval between getUpdates calls (ms)
const POLLING_TIMEOUT_SEC = 30;
// Default tuned for a small LIVE account ($10). Override with the
// ACCOUNT_BALANCE env var (e.g. "100000") for paper-trading mode.
const ACCOUNT_BALANCE = parseFloat(process.env.ACCOUNT_BALANCE || "10");
// ✅ FIX: ACCOUNT_RISK_PERCENT, MARKET_TYPE and FUTURES_LEVERAGE are reassigned
// by the /risk, /market and /leverage Telegram commands further down the file.
// They were declared with `const`, which throws TypeError ("Assignment to
// constant variable") in strict mode the first time a user runs any of those
// commands. Switched to `let` so the existing reassignment logic actually works.
// 2.0% per-trade risk: on a $10 account this risks $0.20 per signal, leaving
// room for ~50 consecutive losses before ruin (vs ~125 at 0.8%, but 0.8% on
// $10 = $0.08 which is too small to size any meaningful FX position).
let   ACCOUNT_RISK_PERCENT = parseFloat(process.env.ACCOUNT_RISK_PERCENT || "2.0");
let   QUANTUM_RISK_REWARD  = parseFloat(process.env.QUANTUM_RR || "3.2");
let   MARKET_TYPE          = process.env.MARKET_TYPE || "futures";
let   FUTURES_LEVERAGE     = parseFloat(process.env.FUTURES_LEVERAGE || "5.0");
// Spot-FX leverage is independent of crypto FUTURES_LEVERAGE.
// 30x = EU/UK regulated retail, 100x = offshore standard, 500x = high-risk.
let   FX_LEVERAGE          = parseFloat(process.env.FX_LEVERAGE || "30.0");

// =========================
// FIX: BOT CONFIG PERSISTENCE
// =========================
// MARKET_TYPE, FUTURES_LEVERAGE and ALERT_THRESHOLD are runtime mutable
// (changed via /market, /leverage, /threshold Telegram commands). Without
// persistence they silently reset to env-var/hardcoded defaults on every
// process restart — causing the "stuck in spot mode" / "no futures signals"
// bug reported after platform restarts.
//
// Strategy:
//   • On startup: read bot_config.json and override the env-var defaults.
//   • On any setting change: call saveBotConfig() to write bot_config.json.
//   • Config file wins over env var (it represents the operator's last intent).
//   • If the file doesn't exist or is unreadable, fall through to env vars silently.
const _BOT_CONFIG_PATH = './bot_config.json';
function saveBotConfig() {
  try {
    const cfg = { MARKET_TYPE, FUTURES_LEVERAGE, ALERT_THRESHOLD: typeof ALERT_THRESHOLD !== 'undefined' ? ALERT_THRESHOLD : 90 };
    fs.writeFileSync(_BOT_CONFIG_PATH, JSON.stringify(cfg, null, 2), 'utf8');
    console.log(`💾 Bot config saved: MARKET_TYPE=${cfg.MARKET_TYPE} FUTURES_LEVERAGE=${cfg.FUTURES_LEVERAGE}x ALERT_THRESHOLD=${cfg.ALERT_THRESHOLD}%`);
  } catch (e) {
    console.warn('⚠️ Could not save bot_config.json:', e.message);
  }
}
// Load persisted config immediately (overrides env-var defaults set above)
try {
  if (fs.existsSync(_BOT_CONFIG_PATH)) {
    const _cfg = JSON.parse(fs.readFileSync(_BOT_CONFIG_PATH, 'utf8'));
    // ✅ FIX: Never restore spot from saved config — env default is futures.
    // A stale bot_config.json with MARKET_TYPE=spot (e.g. from an accidental
    // /market spot) locks the bot in spot mode on every restart. Now we only
    // restore futures, or spot if the env var MARKET_TYPE explicitly opts in.
    if (_cfg.MARKET_TYPE === 'futures') {
      MARKET_TYPE = 'futures';
    } else if (_cfg.MARKET_TYPE === 'spot' && process.env.MARKET_TYPE === 'spot') {
      MARKET_TYPE = 'spot'; // only if env explicitly requests spot
    } else if (_cfg.MARKET_TYPE === 'spot') {
      console.log('⚠️  Saved config had MARKET_TYPE=spot — resetting to futures. Send /market spot to re-enable spot mode.');
      MARKET_TYPE = 'futures';
    }
    if (_cfg.FUTURES_LEVERAGE && !isNaN(_cfg.FUTURES_LEVERAGE) && _cfg.FUTURES_LEVERAGE >= 1) {
      FUTURES_LEVERAGE = Math.min(10, parseFloat(_cfg.FUTURES_LEVERAGE)); // max 10x cap
    }
    // ALERT_THRESHOLD is declared later; stash it and apply after declaration
    if (_cfg.ALERT_THRESHOLD && !isNaN(_cfg.ALERT_THRESHOLD)) {
      process.env._SAVED_ALERT_THRESHOLD = String(_cfg.ALERT_THRESHOLD);
    }
    console.log(`📂 Bot config restored: MARKET_TYPE=${MARKET_TYPE} FUTURES_LEVERAGE=${FUTURES_LEVERAGE}x`);
  }
} catch (_cfgErr) {
  console.warn('⚠️ Could not load bot_config.json (using env defaults):', _cfgErr.message);
}

// =========================
// FIX 2: LEVERAGE-BASED STOP LOSS ENGINE
// =========================
// Stop loss percentage is now tied to both the CURRENT leverage AND the
// current market phase (confirmed real move vs active sweep vs neutral entry).
//
// Rules at a glance:
//   • Entry at 10x      → stop 7.5%  (tight — real move expected)
//   • Sweep detected    → REDUCE to 5x, widen stop to 15.5%
//   • Long green candle → INCREASE to 10x, tighten stop to 7.5%
//   • Never stay at 10x during an active sweep (liquidation risk)
//
// Overridable via env vars:
//   LEVERAGE_STOP_10X_CONFIRMED (default 0.075)
//   LEVERAGE_STOP_5X_SWEEP      (default 0.155)
//   LEVERAGE_STOP_10X_DEFAULT   (default 0.10)
// =========================

const MARKET_PHASE = {
  ENTRY:        'ENTRY',      // Limit placed, waiting for fill
  SWEEP_ACTIVE: 'SWEEP',      // Price moving against position
  REAL_MOVE:    'CONFIRMED',  // Long green candle confirmed
  TAKING_PROFIT:'TP'          // Taking partial profits
};

const STOP_LOSS_CONFIG = {
  CONFIRMED: {   // Long green candle present — real move confirmed
    10: parseFloat(process.env.LEVERAGE_STOP_10X_CONFIRMED || '0.075'),  // 7.5%
    5:  0.15,    // 15%
    2:  0.30,    // 30%
  },
  SWEEP: {       // Sweep in progress — uncertainty, reduce leverage first
    10: 0.15,    // 15% — emergency only (should reduce to 5x immediately)
    5:  parseFloat(process.env.LEVERAGE_STOP_5X_SWEEP || '0.155'),       // 15.5%
    2:  0.35,    // 35%
  },
  DEFAULT: {     // Entry / neutral — no strong confirmation yet
    10: parseFloat(process.env.LEVERAGE_STOP_10X_DEFAULT || '0.10'),     // 10%
    5:  0.18,    // 18%
    2:  0.40,    // 40%
  }
};

/**
 * calculateStopLoss — returns leverage-aware stop loss price and metadata.
 *
 * @param {number} entryPrice      - Filled limit price
 * @param {'BUY'|'SELL'} direction
 * @param {number} currentLeverage - Active leverage (2 | 5 | 10)
 * @param {string} marketPhase     - One of MARKET_PHASE values
 * @returns {{ stopPrice, stopPercent, leverage, marketPhase, riskAmount, warning }}
 */
function calculateStopLoss(entryPrice, direction, currentLeverage, marketPhase) {
  entryPrice = safeNumber(entryPrice);
  if (!entryPrice || entryPrice <= 0) {
    console.error(`calculateStopLoss: invalid entryPrice ${entryPrice}`);
    return null;
  }
  if (direction !== 'BUY' && direction !== 'SELL') {
    console.error(`calculateStopLoss: invalid direction ${direction}`);
    return null;
  }

  // Normalize leverage to a supported tier
  const supportedLevs = [2, 5, 10];
  if (!supportedLevs.includes(currentLeverage)) {
    console.warn(`⚠️ calculateStopLoss: unusual leverage ${currentLeverage}x — defaulting to 10x rules`);
    currentLeverage = 10;
  }

  // Select stop percentage based on phase and leverage
  let stopPercent;
  const phase = marketPhase === MARKET_PHASE.REAL_MOVE    ? 'CONFIRMED'
              : marketPhase === MARKET_PHASE.SWEEP_ACTIVE ? 'SWEEP'
              : 'DEFAULT';

  if (phase === 'SWEEP' && currentLeverage === 10) {
    console.warn(`⚠️ SWEEP ACTIVE at 10x! Reduce to 5x immediately. Applying emergency 15% stop.`);
    stopPercent = 0.15;
  } else {
    stopPercent = STOP_LOSS_CONFIG[phase][currentLeverage];
  }

  let stopPrice = direction === 'BUY'
    ? entryPrice * (1 - stopPercent)
    : entryPrice * (1 + stopPercent);

  // Sanity guard — stop must be on the correct side of entry
  if (direction === 'BUY'  && stopPrice >= entryPrice) {
    console.error(`❌ calculateStopLoss: BUY stop above entry — applying emergency 8% stop`);
    stopPrice = entryPrice * 0.92;
    stopPercent = 0.08;
  }
  if (direction === 'SELL' && stopPrice <= entryPrice) {
    console.error(`❌ calculateStopLoss: SELL stop below entry — applying emergency 8% stop`);
    stopPrice = entryPrice * 1.08;
    stopPercent = 0.08;
  }

  const accountRisk = (stopPercent * currentLeverage * 100).toFixed(1) + '% account at risk';

  return {
    stopPrice,
    stopPercent:  (stopPercent * 100).toFixed(1) + '%',
    leverage:     currentLeverage,
    marketPhase,
    riskAmount:   accountRisk,
    warning: (currentLeverage === 10 && phase === 'SWEEP')
      ? '⚠️ HIGH RISK: 10x during active sweep — reduce to 5x immediately'
      : null
  };
}

/**
 * suggestLeverageAdjustment — recommends a leverage change based on market state.
 *
 * @param {number}  currentLeverage
 * @param {number}  priceMovement      - Fractional move from entry (e.g. -0.02 = -2%)
 * @param {boolean} isLongGreenCandle  - Confirmed real-move candle
 * @param {boolean} isSweeping         - Active sweep (price moving against position)
 * @returns {{ currentLeverage, suggestedLeverage, suggestions, shouldAdjust, nextAction }}
 */
function suggestLeverageAdjustment(currentLeverage, priceMovement, isLongGreenCandle, isSweeping) {
  const suggestions = [];
  let newLeverage = currentLeverage;

  if (isSweeping && currentLeverage === 10) {
    suggestions.push({
      action:  'REDUCE',
      from:     10,
      to:       5,
      reason:  'Sweep detected — reduce to 5x to survive drawdown without liquidation',
      urgency: 'HIGH'
    });
    newLeverage = 5;
  } else if (isLongGreenCandle && currentLeverage < 10) {
    suggestions.push({
      action:  'INCREASE',
      from:     currentLeverage,
      to:       10,
      reason:  'Long green candle confirmed real move — increase to 10x for full profit capture',
      urgency: 'MEDIUM'
    });
    newLeverage = 10;
  } else if (!isSweeping && priceMovement > 0.02) {
    suggestions.push({
      action:  'MAINTAIN',
      from:     currentLeverage,
      to:       currentLeverage,
      reason:  `Price +${(priceMovement * 100).toFixed(1)}% in your favour — hold ${currentLeverage}x`,
      urgency: 'LOW'
    });
  } else if (!isSweeping && !isLongGreenCandle && currentLeverage === 10) {
    suggestions.push({
      action:  'CONSIDER_REDUCE',
      from:     10,
      to:       5,
      reason:  'No confirmation yet — consider 5x until long green candle appears',
      urgency: 'LOW'
    });
  }

  return {
    currentLeverage,
    suggestedLeverage: newLeverage,
    suggestions,
    shouldAdjust: newLeverage !== currentLeverage,
    nextAction:   newLeverage > currentLeverage ? 'INCREASE'
                : newLeverage < currentLeverage ? 'REDUCE'
                : 'HOLD'
  };
}
