// Pip size depends on the quote currency: JPY pairs use 0.01, all others 0.0001.
function pipSize(symbol) {
  if (!symbol || typeof symbol !== 'string') return 0.0001;
  // Strip any "=X" suffix just in case a Yahoo-form symbol slips through
  const s = symbol.replace('=X', '').toUpperCase();
  // JPY as quote currency → pip = 0.01 (e.g. USD/JPY, EUR/JPY, GBP/JPY)
  if (s.endsWith('JPY') || s.endsWith('/JPY')) return 0.01;
  return 0.0001;
}

// Heuristic forex detector that works even when the symbol isn't passed
// down: a true forex ATR/price ratio is essentially always < 0.003 on a
// major TF, while crypto is essentially always > 0.005. The slash check
// is the primary path; the ratio check is a safety net.
function looksLikeForex(symbol, atrValue, entry) {
  if (typeof symbol === 'string' && symbol.indexOf('/') !== -1) return true;
  if (entry > 0 && atrValue > 0 && (atrValue / entry) < 0.003) return true;
  return false;
}

