/* ═══════════════════════════════════════════════════════════════════════════
   DYNAMIC BITGET FULL-UNIVERSE SYMBOL SYSTEM
   ─────────────────────────────────────────────────────────────────────────
   Instead of a hardcoded list of 70 symbols, the engine now:

   1. Fetches ALL USDT-M perpetual futures symbols from Bitget on startup
      (typically 300–500+ contracts) and again every 6 hours to catch new
      listings automatically.

   2. RANKS every symbol by a composite OPPORTUNITY SCORE:
      • 24h volume (higher = better liquidity, tighter fills)
      • 24h price change % (absolute value — moving coins have signals)
      • Open interest (institutional participation)
      • Funding rate magnitude (extreme = mean-reversion opportunity)
      • Volatility (ATR proxy from 24h high-low range)

   3. FILTERS out coins that fail minimum quality bars:
      • Min 24h volume: $1M USDT (ensures fills won't slip)
      • Max spread proxy: price > $0.000001 (filters dust tokens)
      • Available on USDT-M futures (confirmed by API response)

   4. PRIORITIZES by scanning the top-ranked symbols first every cycle,
      ensuring the best setups are never missed because they were further
      down a static list.

   5. ROTATES through the full ranked universe over successive scan cycles
      using the existing batch rotation system — every symbol gets scanned
      regularly, but the hottest coins get extra attention.

   Result: your engine sees every opportunity on every Bitget-listed coin,
   prioritizes the ones most likely to have a signal right now, and still
   maintains the same high-quality gate stack. More coins = more chances
   to find the rare perfect setup.
   ═══════════════════════════════════════════════════════════════════════════ */

// ── Symbol universe state ──────────────────────────────────────────────────
let _dynamicSymbolsLoaded   = false;
let _dynamicSymbolsLoadedAt = 0;
let _rankedSymbols          = [];         // all symbols sorted by opportunity score
const SYMBOL_REFRESH_MS     = 6 * 60 * 60 * 1000; // re-fetch every 6h (new listings)
const MIN_VOLUME_USDT       = parseFloat(process.env.MIN_SYMBOL_VOLUME  || '1000000');  // $1M min
const MAX_SYMBOLS_IN_WATCH  = parseInt  (process.env.MAX_SYMBOLS_WATCH  || '500', 10); // cap

/**
 * fetchAllBitgetFuturesSymbols — pulls the complete list of USDT-M perpetual
 * contracts from Bitget, ranks them by opportunity score, and returns a
 * sorted array of { symbol, score, vol24h, change24h, oi, funding } objects.
 *
 * Uses the public /api/v2/mix/market/tickers endpoint (no API key needed).
 * Falls back to DEFAULT_SCAN_SYMBOLS if the API call fails.
 */
async function fetchAllBitgetFuturesSymbols() {
  console.log('🌐 Fetching ALL Bitget USDT-M futures symbols...');
  try {
    // Public endpoint — no auth required
    const url = 'https://api.bitget.com/api/v2/mix/market/tickers?productType=USDT-FUTURES';
    const resp = await raceDeadline(
      axiosGetSafe(url, 15000, { headers: { 'Content-Type': 'application/json' } }),
      18000,
      'fetchAllBitgetSymbols'
    );

    if (!resp?.data?.data || !Array.isArray(resp.data.data)) {
      console.warn('⚠️ Bitget symbol fetch returned unexpected format — using default list');
      return null;
    }

    const tickers = resp.data.data;
    console.log(`📊 Bitget returned ${tickers.length} USDT-M futures contracts`);

    const ranked = [];

    for (const t of tickers) {
      // Only USDT-M perpetuals ending in USDT
      const sym = t.symbol || t.instId || '';
      if (!sym.endsWith('USDT') && !sym.endsWith('USDT_UMCBL')) continue;

      // Normalise symbol to XXXUSDT format (Bitget sometimes includes suffix)
      const cleanSym = sym.replace('_UMCBL', '').replace('_SPBL', '');

      const vol24h    = parseFloat(t.usdtVolume  || t.baseVolume  || t.vol24h  || 0);
      const price     = parseFloat(t.lastPr      || t.last        || t.close   || 0);
      const change24h = Math.abs(parseFloat(t.change24h || t.priceChangePercent || 0));
      const high24h   = parseFloat(t.high24h  || t.highPr  || price * 1.01);
      const low24h    = parseFloat(t.low24h   || t.lowPr   || price * 0.99);
      const oi        = parseFloat(t.holdingAmount || t.openInterest || 0);
      const funding   = Math.abs(parseFloat(t.fundingRate || 0));

      // Quality filter — skip dust/ultra-low-liquidity tokens
      if (vol24h < MIN_VOLUME_USDT) continue;
      if (price <= 0)               continue;

      // Opportunity Score — weighted composite (0–100)
      // Normalised against rough market-wide maximums
      const volScore      = Math.min(40, (vol24h       / 500_000_000) * 40); // up to $500M = full score
      const momentumScore = Math.min(30, (change24h    / 15)          * 30); // 15% move = full score
      const voltyScore    = Math.min(15, price > 0 ? ((high24h - low24h) / price * 100 / 10) * 15 : 0);
      const fundingScore  = Math.min(10, (funding      / 0.001)        * 10); // 0.1% funding = full
      const oiScore       = Math.min(5,  (oi           / 100_000_000)  * 5);

      const opportunityScore = parseFloat((volScore + momentumScore + voltyScore + fundingScore + oiScore).toFixed(2));

      ranked.push({
        symbol:        cleanSym,
        score:         opportunityScore,
        vol24h:        parseFloat(vol24h.toFixed(0)),
        price,
        change24h:     parseFloat(change24h.toFixed(2)),
        high24h,
        low24h,
        oi:            parseFloat(oi.toFixed(0)),
        funding:       parseFloat(funding.toFixed(6)),
      });
    }

    // Sort by opportunity score descending — best coins first
    ranked.sort((a, b) => b.score - a.score);

    // Cap total (avoid scanning 500+ symbols in one pass)
    const final = ranked.slice(0, MAX_SYMBOLS_IN_WATCH);
    console.log(`✅ Ranked universe: ${final.length} symbols | Top 5: ${final.slice(0,5).map(s => `${s.symbol}(${s.score.toFixed(1)})`).join(', ')}`);

    return final;
  } catch (err) {
    console.error('❌ fetchAllBitgetFuturesSymbols error:', err.message);
    return null;
  }
}

/**
 * loadDynamicSymbolUniverse — fetches all Bitget symbols, ranks them, and
 * populates the WATCH map with the full universe.
 * Called on startup and every SYMBOL_REFRESH_MS hours.
 */
async function loadDynamicSymbolUniverse(forceRefresh = false) {
  const now = Date.now();
  if (!forceRefresh && _dynamicSymbolsLoaded && (now - _dynamicSymbolsLoadedAt) < SYMBOL_REFRESH_MS) {
    return; // still fresh — don't re-fetch
  }

  const ranked = await fetchAllBitgetFuturesSymbols();

  if (!ranked || ranked.length === 0) {
    // Fallback: keep existing WATCH entries if fetch failed
    console.warn('⚠️ Dynamic symbol fetch failed — keeping existing watch list');
    if (!_dynamicSymbolsLoaded) {
      // First startup and fetch failed — load defaults
      for (const sym of DEFAULT_SCAN_SYMBOLS) {
        if (!WATCH.has(sym)) {
          WATCH.set(sym, {
            quantum_id:   `Q${sym.replace('USDT','')}`,
            entanglement: 0.65, coherence: 0.65,
            type:         MARKET_TYPE, leverage: FUTURES_LEVERAGE,
            tf: '1h', added: Date.now(), score: 50
          });
        }
      }
    }
    return;
  }

  // Store ranked list for getScanBatch to use
  _rankedSymbols = ranked;

  // Count new vs updated symbols
  let added = 0, updated = 0;

  for (const { symbol, score, vol24h, change24h, funding } of ranked) {
    // Skip forex — they are managed separately
    if (isForex && isForex(symbol)) continue;

    const existing = WATCH.get(symbol);
    if (existing) {
      // Update live metrics on existing entry
      WATCH.set(symbol, { ...existing, score, vol24h, change24h, funding, lastRefresh: now });
      updated++;
    } else {
      // New listing — add to watch
      WATCH.set(symbol, {
        quantum_id:   `Q${symbol.replace('USDT','')}`,
        entanglement: Math.min(0.95, 0.55 + score / 100),
        coherence:    Math.min(0.90, 0.50 + score / 120),
        type:         MARKET_TYPE,
        leverage:     FUTURES_LEVERAGE,
        tf:           '1h',
        added:        now,
        score,
        vol24h,
        change24h,
        funding,
        lastRefresh:  now,
      });
      added++;
    }
  }

  // Remove symbols that are no longer on Bitget (delisted)
  const activeSet = new Set(ranked.map(r => r.symbol));
  let removed = 0;
  for (const [sym, data] of WATCH.entries()) {
    // Don't remove forex symbols
    if (data.type === 'forex') continue;
    // Don't remove manually added symbols (user /watch command)
    if (data._manuallyAdded) continue;
    // Remove if no longer in Bitget's active futures list
    if (!activeSet.has(sym)) {
      WATCH.delete(sym);
      removed++;
    }
  }

  _dynamicSymbolsLoaded   = true;
  _dynamicSymbolsLoadedAt = now;

  console.log([
    `🔄 Symbol universe refreshed:`,
    `${added} new | ${updated} updated | ${removed} delisted`,
    `Total watching: ${WATCH.size} symbols`,
    `(${ranked.length} crypto + ${Array.from(WATCH.values()).filter(v=>v.type==='forex').length} forex)`,
  ].join(' '));

  // Notify Telegram on first load
  if (added > 0 && TELEGRAM_CHAT_ID) {
    const top5 = ranked.slice(0, 5).map(s => `${s.symbol} (score: ${s.score.toFixed(1)})`).join('\n  ');
    await raceDeadline(
      tg('sendMessage', {
        chat_id: TELEGRAM_CHAT_ID,
        text: [
          `🌐 <b>Symbol Universe Loaded</b>`,
          ``,
          `📊 Watching <b>${WATCH.size} symbols</b> (${ranked.length} crypto + forex)`,
          `✅ New: ${added} | Updated: ${updated} | Removed: ${removed}`,
          ``,
          `🏆 Top 5 by opportunity score:`,
          `  ${top5}`,
          ``,
          `<i>Re-scans every 6h for new Bitget listings</i>`,
        ].join('\n'),
        parse_mode: 'HTML',
        disable_web_page_preview: true,
      }),
      8000,
      'symbolLoadNotification'
    ).catch(() => {});
  }
}

// ── Ranked getScanBatch — always scans highest-opportunity symbols first ───
// Override getScanBatch to use the ranked list when available.
// High-score symbols (hottest coins) get scanned first every cycle.
// Lower-score symbols are still scanned via rotation — nothing is missed.

const SCAN_BATCH_SIZE = Math.max(1, Number(process.env.SCAN_BATCH_SIZE || '35'));
let _scanRotationCursor = 0;

function getScanBatch() {
  // Build ranked order: top symbols first, then rotation through rest
  let ordered;
  if (_rankedSymbols.length > 0) {
    // Split into HOT (top 20% by score) and NORMAL
    const allKeys   = Array.from(WATCH.keys());
    const hotThresh = _rankedSymbols.length > 0
      ? _rankedSymbols[Math.floor(_rankedSymbols.length * 0.2)]?.score || 0
      : 0;
    // Always include top-scored symbols in every batch
    const hot    = allKeys.filter(s => (WATCH.get(s)?.score || 0) >= hotThresh).slice(0, 10);
    const normal = allKeys.filter(s => !hot.includes(s));
    // Fill rest of batch from rotating normal pool
    const needed = Math.max(0, SCAN_BATCH_SIZE - hot.length);
    const rotated = [];
    for (let i = 0; i < needed; i++) {
      if (normal.length === 0) break;
      rotated.push(normal[(_scanRotationCursor + i) % normal.length]);
    }
    _scanRotationCursor = (_scanRotationCursor + needed) % Math.max(1, normal.length);
    ordered = [...hot, ...rotated];
  } else {
    // Fallback: standard rotation
    const all = Array.from(WATCH.keys());
    if (all.length === 0) return [];
    if (all.length <= SCAN_BATCH_SIZE) return all;
    ordered = [];
    for (let i = 0; i < SCAN_BATCH_SIZE; i++) {
      ordered.push(all[(_scanRotationCursor + i) % all.length]);
    }
    _scanRotationCursor = (_scanRotationCursor + SCAN_BATCH_SIZE) % all.length;
  }
  return [...new Set(ordered)]; // deduplicate
}

