    const lepdCertBoost = lepd?.certBoost || 0;
    // macro2Y directional cert boost — active when macro has a strong direction
    const macroCertBoost = (m2yData?.certBoost || 0) * (m2yDir === dir ? 1 : m2yDir === 'NEUTRAL' ? 0 : -1);
    // RMEE cert boost — real move confirmation
    const rmeeCertBoost  = rmee?.certBoost || 0;
    // CLGE gravity cert boost — liquidity gravity conviction
    const clgeCertBoost  = clge?.certBoost || 0;
    // APEX liquidity cert boost — total liquidity fuel
