    // v6 entry gate + session + freshness boost
    const v6Boost     = (instCtx?.v6) ? getV6CertaintyBoost(instCtx.v6, dir) : 0;
    // ANCS — Apex Neural Convergence Suite (5 world-first engines)
    const ancsCertBoost = (instCtx?.ancs?.totalCertBoost || 0);
    const effectiveCert = Math.min(98, Math.max(0, cert + certBoost + corrBoost + v4CertBoost + v5CertBoost + crossAssetBoost + v7CertBoost + v8CertBoost + v6Boost + lepdCertBoost + macroCertBoost + rmeeCertBoost + clgeCertBoost + apexCertBoost + ancsCertBoost));
    const totalBoost = certBoost+corrBoost+v4CertBoost+v5CertBoost+crossAssetBoost+v7CertBoost+v8CertBoost+v6Boost+lepdCertBoost+macroCertBoost+rmeeCertBoost+clgeCertBoost+apexCertBoost+ancsCertBoost;
    const certDisplay = totalBoost!==0
      ? `${cert}%${certBoost>0?` +${certBoost}%preInst`:''}${corrBoost!==0?` ${corrBoost>0?'+':''}${corrBoost}%corr`:''}${v4CertBoost!==0?` ${v4CertBoost>0?'+':''}${v4CertBoost}%v4`:''}${v5CertBoost!==0?` ${v5CertBoost>0?'+':''}${v5CertBoost}%v5`:''}${crossAssetBoost!==0?` ${crossAssetBoost>0?'+':''}${crossAssetBoost}%cross`:''}${v7CertBoost!==0?` ${v7CertBoost>0?'+':''}${v7CertBoost}%sweep`:''}${v8CertBoost!==0?` ${v8CertBoost>0?'+':''}${v8CertBoost}%contagion`:''}${v6Boost!==0?` ${v6Boost>0?'+':''}${v6Boost}%v6`:''}${lepdCertBoost!==0?` ${lepdCertBoost>0?'+':''}${lepdCertBoost}%lepd`:''}${macroCertBoost!==0?` ${macroCertBoost>0?'+':''}${macroCertBoost}%macro`:''}${rmeeCertBoost!==0?` ${rmeeCertBoost>0?'+':''}${rmeeCertBoost}%rmee`:''}${clgeCertBoost!==0?` ${clgeCertBoost>0?'+':''}${clgeCertBoost}%gravity`:''}${apexCertBoost!==0?` ${apexCertBoost>0?'+':''}${apexCertBoost}%apex`:''}${ancsCertBoost!==0?` ${ancsCertBoost>0?'+':''}${ancsCertBoost}%ancs`:''}=${effectiveCert}%`
      : `${cert}%`;

    let aiVerdict,entryMethod,keyCondition,riskNote,extraNote='';

    // ── LEPD ABSOLUTE GATE — checked FIRST before any other verdict ─────────
    // LEPD state directly determines what action is possible.
