const bitgetAPI = new BitgetAPI();

/* ================= IMPROVED NETWORK FUNCTIONS ================= */
// Endpoints that permanently fail (401/404) are blacklisted for 30 min
// to avoid wasting API calls and log spam on every scan cycle
const _qFetchBlacklist = new Map();
const QFETCH_BLACKLIST_TTL = 30 * 60 * 1000; // 30 minutes

// ── DELISTED-SYMBOL BLACKLIST (Bitget code 40309) ─────────────────────────
// When Bitget reports a (symbol, timeframe) pair as "removed", we cache it
// here to skip future requests for 6 hours. Without this, the engine wastes
// thousands of API calls per day on dead pairs (BONKUSDT 5m, EOSUSDT 8h, etc).
const _BITGET_DELISTED      = new Map();
const BITGET_DELISTED_TTL   = 6 * 60 * 60 * 1000; // 6 hours

// ── DEAD-SOURCE FLAGS (geo-restricted exchanges) ──────────────────────────
// Binance returns HTTP 451 ("unavailable for legal reasons") from many cloud
// regions — once we see it, we permanently disable Binance for the session
// rather than wasting 5–8 seconds per fetch on a guaranteed timeout.
let _BINANCE_DEAD = false;
let _BYBIT_DEAD   = false;
// ✅ NEW: 5 additional public-API exchange fallbacks. Each gets its own
// session-kill flag so a geo-block / 403 / 451 disables ONLY that
// exchange and never the rest of the cascade.
let _OKX_DEAD      = false;
let _KUCOIN_DEAD   = false;
let _MEXC_DEAD     = false;
let _GATEIO_DEAD   = false;
let _COINBASE_DEAD = false;

// ─────────────────────────────────────────────────────────────────────────
// Shared helpers for the new exchanges. They convert a Bitget-style symbol
// (e.g. "XRPUSDT") to whatever each exchange uses, and expose the candle
// timeframe map. Centralizing this means every fetch routine looks the
// same and adding a 6th exchange later is a 5-line change.
// ─────────────────────────────────────────────────────────────────────────
const _EXCHANGE_TF = {
  okx:      { '5min':'5m','15min':'15m','30min':'30m','1h':'1H','4h':'4H','8h':'8H','12h':'12H','1day':'1D','1week':'1W' },
  kucoin:   { '5min':'5min','15min':'15min','30min':'30min','1h':'1hour','4h':'4hour','8h':'8hour','12h':'12hour','1day':'1day','1week':'1week' },
  mexc:     { '5min':'5m','15min':'15m','30min':'30m','1h':'60m','4h':'4h','8h':'8h','1day':'1d','1week':'1W' },
  gateio:   { '5min':'5m','15min':'15m','30min':'30m','1h':'1h','4h':'4h','8h':'8h','1day':'1d','1week':'7d' },
  coinbase: { '5min':300,'15min':900,'1h':3600,'4h':21600,'1day':86400 } // seconds, no 30min/8h/1week
};

// "BONKUSDT" → quote-base translation for each venue.
function _splitSym(symbol) {
  // Heuristic: USDT is by far the most common quote on these venues.
  if (symbol.endsWith('USDT')) return { base: symbol.slice(0, -4), quote: 'USDT' };
  if (symbol.endsWith('USDC')) return { base: symbol.slice(0, -4), quote: 'USDC' };
  if (symbol.endsWith('USD'))  return { base: symbol.slice(0, -3), quote: 'USD' };
  if (symbol.endsWith('BTC'))  return { base: symbol.slice(0, -3), quote: 'BTC' };
  return { base: symbol, quote: '' };
}
function _toOkxSym(symbol)      { const {base,quote}=_splitSym(symbol); return quote ? `${base}-${quote}` : symbol; }
function _toKucoinSym(symbol)   { const {base,quote}=_splitSym(symbol); return quote ? `${base}-${quote}` : symbol; }
function _toGateioSym(symbol)   { const {base,quote}=_splitSym(symbol); return quote ? `${base}_${quote}` : symbol; }
function _toCoinbaseSym(symbol) { const {base,quote}=_splitSym(symbol); return (quote==='USDT'||quote==='USDC')?`${base}-${quote}`:`${base}-USD`; }

// ─────────────────────────────────────────────────────────────────────────
// Generic candle helper: tries one exchange, returns Bitget-shape rows
// ([[ts,o,h,l,c,v], ...]) on success, null on miss. The caller (fetchCandles)
// reverses these into oldest-first the same way it does for Bybit/Binance.
// ─────────────────────────────────────────────────────────────────────────
async function _tryOkxCandles(symbol, tf, limit) {
  if (_OKX_DEAD) return null;
  const ytf = _EXCHANGE_TF.okx[tf]; if (!ytf) return null;
  try {
    const inst = _toOkxSym(symbol);
    const r = await axiosGetSafe(`https://www.okx.com/api/v5/market/candles?instId=${inst}&bar=${ytf}&limit=${Math.min(limit,300)}`, 8000);
    if (r.data?.code === '0' && Array.isArray(r.data.data) && r.data.data.length > 0) {
      // OKX shape: [ts, o, h, l, c, vol, volCcy, volCcyQuote, confirm] — newest-first
      return r.data.data.slice().reverse().map(k => [Number(k[0]), k[1], k[2], k[3], k[4], k[5]]);
    }
  } catch (e) {
    if (e.response && [403,451,429].includes(e.response.status)) {
      _OKX_DEAD = true; console.warn(`🚫 OKX dead (HTTP ${e.response.status}) — disabled for session`);
    }
  }
  return null;
}
async function _tryKucoinCandles(symbol, tf, limit) {
  if (_KUCOIN_DEAD) return null;
  const ytf = _EXCHANGE_TF.kucoin[tf]; if (!ytf) return null;
  try {
    const sym = _toKucoinSym(symbol);
    const r = await axiosGetSafe(`https://api.kucoin.com/api/v1/market/candles?symbol=${sym}&type=${ytf}`, 8000);
    if (r.data?.code === '200000' && Array.isArray(r.data.data) && r.data.data.length > 0) {
      // KuCoin shape: [ts(s), open, close, high, low, volume, turnover] — newest-first
      // Note KuCoin uses [o, c, h, l] order — we remap to [o, h, l, c]
      return r.data.data.slice(0, limit).reverse().map(k => [Number(k[0])*1000, k[1], k[3], k[4], k[2], k[5]]);
    }
  } catch (e) {
    if (e.response && [403,451,429].includes(e.response.status)) {
      _KUCOIN_DEAD = true; console.warn(`🚫 KuCoin dead (HTTP ${e.response.status}) — disabled for session`);
    }
  }
  return null;
}
async function _tryMexcCandles(symbol, tf, limit) {
  if (_MEXC_DEAD) return null;
  const ytf = _EXCHANGE_TF.mexc[tf]; if (!ytf) return null;
  try {
    const r = await axiosGetSafe(`https://api.mexc.com/api/v3/klines?symbol=${symbol}&interval=${ytf}&limit=${Math.min(limit,1000)}`, 8000);
    if (Array.isArray(r.data) && r.data.length > 0) {
      // MEXC shape: same as Binance — [ts, o, h, l, c, v, ...] — oldest-first already
      return r.data.map(k => [Number(k[0]), k[1], k[2], k[3], k[4], k[5]]);
    }
  } catch (e) {
    if (e.response && [403,451,429].includes(e.response.status)) {
      _MEXC_DEAD = true; console.warn(`🚫 MEXC dead (HTTP ${e.response.status}) — disabled for session`);
    }
  }
  return null;
}
async function _tryGateioCandles(symbol, tf, limit) {
  if (_GATEIO_DEAD) return null;
  const ytf = _EXCHANGE_TF.gateio[tf]; if (!ytf) return null;
  try {
    const sym = _toGateioSym(symbol);
    const r = await axiosGetSafe(`https://api.gateio.ws/api/v4/spot/candlesticks?currency_pair=${sym}&interval=${ytf}&limit=${Math.min(limit,1000)}`, 8000);
    if (Array.isArray(r.data) && r.data.length > 0) {
      // Gate.io shape: [ts(s), volume, close, high, low, open, ...] — oldest-first
      return r.data.map(k => [Number(k[0])*1000, k[5], k[3], k[4], k[2], k[1]]);
    }
  } catch (e) {
    if (e.response && [403,451,429].includes(e.response.status)) {
      _GATEIO_DEAD = true; console.warn(`🚫 Gate.io dead (HTTP ${e.response.status}) — disabled for session`);
    }
  }
  return null;
}
async function _tryCoinbaseCandles(symbol, tf, limit) {
  if (_COINBASE_DEAD) return null;
  const granularity = _EXCHANGE_TF.coinbase[tf]; if (!granularity) return null;
  try {
    const sym = _toCoinbaseSym(symbol); // base-USD (USDT often unsupported on Coinbase Exchange)
    const r = await axiosGetSafe(`https://api.exchange.coinbase.com/products/${sym}/candles?granularity=${granularity}`, 8000);
    if (Array.isArray(r.data) && r.data.length > 0) {
      // Coinbase shape: [ts(s), low, high, open, close, volume] — newest-first
      return r.data.slice(0, limit).reverse().map(k => [Number(k[0])*1000, k[3], k[2], k[1], k[4], k[5]]);
    }
  } catch (e) {
    if (e.response && [403,451,429].includes(e.response.status)) {
      _COINBASE_DEAD = true; console.warn(`🚫 Coinbase dead (HTTP ${e.response.status}) — disabled for session`);
    }
  }
  return null;
}

