    const mem    = process.memoryUsage();
    const memUsed = Math.round(mem.heapUsed / 1024 / 1024);
    const memTotal = Math.round(mem.heapTotal / 1024 / 1024);
    const scanRunning = !!global._tradingSystem?.autoScannerInterval;
    const watching   = WATCH?.size ?? 0;
    const histLen    = typeof pipelineDatabase !== 'undefined' ? (pipelineDatabase.history?.length ?? 0) : 0;
