    const slDistance = round(Math.abs(signal.entry - signal.stop_loss) / signal.entry * 100, 2);
    const _slDist = Math.abs(signal.entry - signal.stop_loss);
    const tpDirArrow = signal.direction === 'BUY' ? '🎯▲' : '🎯▼';

    // ── SCALE-OUT + BREAKEVEN RUNNER PLAN ─────────────────────────────────
    // Empirically, strong-gate signals hit TP1 ~90%+ of the time even when
    // they ultimately reverse (MFE bias). Splitting the position lets us
    // bank a near-certain TP1 profit, then ride the remainder risk-free.
    //
    // Plan (only emitted when signal_tier === 'STRONG'):
    //   • Close 60% at TP1 → locks in profit
    //   • Move SL → entry on TP1 fill (runner is now risk-free)
    //   • Close 25% at TP2 → 35% of position remains
    //   • Close final 15% at TP3
    // Weak/moderate signals get the standard "all-or-nothing" TP layout
    // because TP1 hit-rate isn't high enough to make scale-out worthwhile.
    const SCALE_OUT_PCTS = [60, 25, 15];
    const useScaleOut    = signal.signal_tier === 'STRONG';

    const tps = signal.take_profits.map((tp, i) => {
      const dist  = round(Math.abs(tp - signal.entry) / signal.entry * 100, 2);
      const rrRaw = _slDist > 0
        ? round(Math.abs(tp - signal.entry) / _slDist, 1)
        : (signal.risk_params?.reward_risk_ratio
            ? round(signal.risk_params.reward_risk_ratio * (i === 0 ? 1 : i === 1 ? 1.618 : 2.618), 2)
            : signal.reward_ratios?.[i] || '—');
      const bars = '▸'.repeat(Math.min(Math.round(dist / 0.5), 10));
      const tpSign = signal.direction === 'BUY' ? '+' : '-'; // BUY TPs above, SELL TPs below entry
      // Scale-out tag: "Close 60%" on TP1, "Close 25%" on TP2, etc. — STRONG only.
      const closePct  = SCALE_OUT_PCTS[i] ?? null;
      const closeUnits = (useScaleOut && closePct && signal.position_size)
        ? round(signal.position_size * closePct / 100, 4)
        : null;
      const scaleTag = (useScaleOut && closePct)
        ? `  💼 Close <b>${closePct}%</b>${closeUnits ? ` (${closeUnits} units)` : ''}`
        : '';
      return `${tpDirArrow} <b>TP${i+1}</b>: <code>${tp}</code>  ${tpSign}${dist}%  R:R 1:${rrRaw}  ${bars}${scaleTag}`;
    }).join('\n');

    // Runner instruction block — appended below the TP list when STRONG.
