    startEnhancedQuantumScanner() {
    let _scanRunning = false;
    let _scanStartedAt = 0;
    const _scanMaxMs = SCAN_INTERVAL_MS * 3;
    this.scanInterval = setInterval(async () => {
      if (_scanRunning) {
        const stuckMs = Date.now() - _scanStartedAt;
        if (stuckMs > _scanMaxMs) {
          console.warn('⚠️ WATCHDOG: quantum scan stuck ' + Math.round(stuckMs/1000) + 's — force-resetting flag');
          _scanRunning = false;
        } else {
          console.log('⏭️ Scan skipped — previous cycle still running (' + Math.round(stuckMs/1000) + 's elapsed)');
          return;
        }
      }
      _scanRunning = true;
      _scanStartedAt = Date.now();
      try {
        await this.enhancedQuantumScanCycle();
      } catch (e) {
        console.error('Scanner cycle error:', e.message);
      } finally {
        _scanRunning = false;
      }
    }, SCAN_INTERVAL_MS);
    console.log("🔍 Enhanced quantum scanner active:", SCAN_INTERVAL_MS / 1000, "second intervals");
  }

  startEnhancedAutoScanner() {
    let _autoRunning = false;
    let _autoStartedAt = 0;
    let _lastCompletedAt = Date.now();
    const _autoMaxMs    = 20 * 60 * 1000;  // FIX: was 10min — raised to 20min to match longer per-symbol timeouts (18min). With 45s per-symbol
                                            // timeout, 70 symbols × 1.2s delay = ~85s best case, worst
                                            // case 70 × (1.2s + 45s) = ~3249s. A stuck scan with ALL
                                            // symbols timing out takes ≤55 min but normally <5 min.
                                            // 10 min hard cap: if the cycle hasn't finished in 10 min,
                                            // the watchdog resets the flag and lets the next cycle start.
    const _alertMaxMs   = 25 * 60 * 1000;  // FIX: raised to 25min watchdog alert threshold (24min). Alert at 12 min —
                                            // early enough to know something is wrong, not so early it fires
                                            // during a normal slow scan.

    const runScan = async () => {
      if (_autoRunning) {
        const stuckMs = Date.now() - _autoStartedAt;
        if (stuckMs > _autoMaxMs) {
          // ✅ WATCHDOG FIX: The previous scan cycle hung on a TCP-level API
          // call that never resolved. axios timeout only fires after the request
          // is sent — a stalled TCP connection after handshake is invisible to
          // it. Without this reset, _autoRunning stays true permanently and ALL
          // future scan ticks are silently skipped (the 7-hour silence bug).
          console.warn('⚠️ WATCHDOG: auto-scan stuck ' + Math.round(stuckMs/1000) + 's — force-resetting and restarting cycle');
          _autoRunning = false;
          // fall through to start a fresh cycle
        } else {
          console.log('⏭️ Auto-scan skipped — previous cycle still running (' + Math.round(stuckMs/1000) + 's elapsed)');
          return;
        }
      }
      _autoRunning = true;
      _autoStartedAt = Date.now();
      try {
        // ── Single Brain pipeline ──────────────────────────────────────────
        // runSignalEngine: clear bucket → autoScanner (captureSignal) →
        //                  resolveFinalSignal → emitSignal (dedup + log).
        // Calling runSignalEngine() instead of autoScanner() directly ensures
        // the bucket is cleared before each cycle, one winner is resolved, and
        // the duplicate filter in emitSignal() fires correctly every time.
        await runSignalEngine();
        _lastCompletedAt = Date.now();
      } catch (e) {
        console.error('Auto-scanner error:', e.message);
      } finally {
        _autoRunning = false;
      }
    };

    // ── WATCHDOG: self-healing auto-restart + Telegram alert ─────────────
    // Fires every WATCH_INTERVAL_MS * 2. If no scan completed in _alertMaxMs:
    //   1. Resets the _autoRunning lock  2. Fires fresh scan  3. Sends ONE alert
    // This eliminates the repeating 24/36/48 min PAUSED alerts permanently.
    let _lastWatchdogRestart = 0;
    setInterval(async () => {
      const silenceMs = Date.now() - _lastCompletedAt;
      if (silenceMs > _alertMaxMs) {
        if (Date.now() - _lastWatchdogRestart < _alertMaxMs) return; // throttle
        _lastWatchdogRestart = Date.now();
        const silenceMin = Math.round(silenceMs / 60000);
        console.warn(`⚠️ WATCHDOG: no scan in ${silenceMin}min — resetting lock + auto-restarting`);
        _autoRunning   = false;
        _autoStartedAt = 0;
        _lastCompletedAt = Date.now() - (_alertMaxMs - 90000);
        try {
          if (TELEGRAM_CHAT_ID) {
            await tg('sendMessage', {
              chat_id: TELEGRAM_CHAT_ID,
              text: `✅ <b>SCAN ENGINE AUTO-RESTARTED</b>\n\nDetected stuck API call after <b>${silenceMin} min</b>.\nWatchdog cleared the lock and restarted automatically.\n\n<i>No manual restart needed. Signals will resume shortly.</i>`,
              parse_mode: 'HTML', disable_web_page_preview: true
            });
          }
        } catch (_we) { console.error('Watchdog Telegram error:', _we.message); }
        runScan().catch(e => console.error('Watchdog restart error:', e.message));
      }
    }, WATCH_INTERVAL_MS * 2);

    // Run immediately on startup — don't wait for first interval
    setTimeout(() => runScan(), 5000);

    // Then repeat every WATCH_INTERVAL_MS
    this.autoScannerInterval = setInterval(runScan, WATCH_INTERVAL_MS);
    console.log("🚨 Enhanced auto-scanner active: first scan in 5s, then every", WATCH_INTERVAL_MS / 1000, "seconds");
  }
  
