// Minimum price move on leader to trigger contagion signal (%)
const CONTAGION_MOVE_THRESHOLD = 1.2;
// Cache for leader candle fetches — reused across all follower symbols in same cycle
const LEADER_CACHE     = new Map();
const LEADER_CACHE_TTL = 3 * 60 * 1000;

async function getLeaderMoves() {
  const cacheKey = 'leader_moves';
  const hit = LEADER_CACHE.get(cacheKey);
  if (hit && Date.now() - hit.ts < LEADER_CACHE_TTL) return hit.data;

  const LEADERS = ['BTCUSDT', 'ETHUSDT', 'BNBUSDT', 'SOLUSDT', 'DOGEUSDT'];
  const moves = {};

  await Promise.allSettled(LEADERS.map(async leader => {
    try {
      const c1h = await fetchCandlesCached(leader, '1h', 12).catch(() => null);
      const c4h = await fetchCandlesCached(leader, '4h', 8).catch(() => null);
      if (!c1h || c1h.length < 4) return;

      const last   = c1h[c1h.length - 1];
      const prev3h = c1h[Math.max(0, c1h.length - 4)];
      const prev6h = c1h[Math.max(0, c1h.length - 7)];

      const move1h = prev3h.c > 0 ? ((last.c - prev3h.c) / prev3h.c) * 100 : 0;
      const move3h = prev6h.c > 0 ? ((last.c - prev6h.c) / prev6h.c) * 100 : 0;

      // 4h context
      let move4h = 0;
      if (c4h && c4h.length >= 3) {
        const l4 = c4h[c4h.length - 1], p4 = c4h[c4h.length - 3];
        move4h = p4.c > 0 ? ((l4.c - p4.c) / p4.c) * 100 : 0;
      }

      // Momentum quality: is the move accelerating?
      const body1  = Math.abs(last.c - last.o);
      const range1 = (last.h - last.l) || 1;
      const bodyRatio = body1 / range1; // >0.6 = strong directional candle

      moves[leader.replace('USDT', '')] = {
        symbol:    leader,
        price:     last.c,
        dir:       last.c > last.o ? 'BUY' : 'SELL',
        move1h:    Math.round(move1h * 100) / 100,
        move3h:    Math.round(move3h * 100) / 100,
        move4h:    Math.round(move4h * 100) / 100,
        bodyRatio: Math.round(bodyRatio * 100) / 100,
        strong:    Math.abs(move1h) >= CONTAGION_MOVE_THRESHOLD && bodyRatio > 0.55,
        vol:       last.v || 0,
      };
    } catch (_) {}
  }));

  LEADER_CACHE.set(cacheKey, { data: moves, ts: Date.now() });
  return moves;
}

const CONTAGION_CACHE     = new Map();
const CONTAGION_CACHE_TTL = 3 * 60 * 1000;

async function getCrossAssetContagion(symbol, dir) {
  const key = `cag_${symbol}_${dir}`;
  const hit = CONTAGION_CACHE.get(key);
  if (hit && Date.now() - hit.ts < CONTAGION_CACHE_TTL) return hit.data;

  try {
    const followerMap = VOLATILITY_CONTAGION_MAP[symbol];
    if (!followerMap) {
      const data = { hasContagion: false, signal: 'NONE', label: 'No contagion map for this asset', leaders: [] };
      CONTAGION_CACHE.set(key, { data, ts: Date.now() }); return data;
    }

    const leaderMoves = await getLeaderMoves();
    const signals = [];
    let totalContagionBoost = 0;

    for (const [leaderTicker, params] of Object.entries(followerMap)) {
      const leaderData = leaderMoves[leaderTicker];
      if (!leaderData) continue;

      const { lagH, amp, corr } = params;
      const leaderMove = Math.abs(leaderData.move1h) >= Math.abs(leaderData.move3h)
        ? leaderData.move1h : leaderData.move3h;
      const leaderDir  = leaderData.dir;

      // Is the leader making a significant move?
      if (Math.abs(leaderMove) < CONTAGION_MOVE_THRESHOLD) continue;

      // Does leader direction agree with our signal direction?
      const agrees = leaderDir === dir;

      // Predicted follow-on move for this symbol
      const predictedMove = Math.round(leaderMove * amp * 10) / 10;

      // Confidence from historical correlation + current move strength
      const conf = Math.min(88, Math.round(corr * 75 + Math.min(Math.abs(leaderMove) / 3, 1) * 13));

      // How likely has the symbol ALREADY followed? (check its own recent move)
      const symCandles = await fetchCandlesCached(symbol, '1h', 6).catch(() => null);
      let alreadyFollowed = false, followPct = 0;
      if (symCandles && symCandles.length >= 3) {
        const sLast = symCandles[symCandles.length - 1];
        const sPrev = symCandles[Math.max(0, symCandles.length - 4)];
        followPct = sPrev.c > 0 ? ((sLast.c - sPrev.c) / sPrev.c) * 100 : 0;
        // Already followed if symbol moved > 50% of what contagion predicts
        alreadyFollowed = Math.abs(followPct) > Math.abs(predictedMove) * 0.5
          && (followPct > 0) === agrees;
      }

      signals.push({
        leader:         leaderTicker + 'USDT',
        leaderDir,
        leaderMove:     Math.round(leaderMove * 100) / 100,
        lagHours:       lagH,
        ampRatio:       amp,
        predictedMove,
        agrees,
        alreadyFollowed,
        followPct:      Math.round(followPct * 100) / 100,
        confidence:     conf,
        remainingMove:  alreadyFollowed
          ? Math.round((predictedMove - followPct) * 100) / 100
          : predictedMove,
        label: `${leaderTicker} ${leaderDir} ${leaderMove > 0 ? '+' : ''}${leaderData.move1h}% → ${symbol} predicted ${predictedMove > 0 ? '+' : ''}${predictedMove}% within ~${lagH}h`,
      });

      // Boost: leader agrees + not yet followed = highest-probability early entry
      if (agrees && !alreadyFollowed) totalContagionBoost += Math.round(corr * 12);
      // Penalty: strong leader in OPPOSITE direction
      if (!agrees && Math.abs(leaderMove) >= 2.0) totalContagionBoost -= Math.round(corr * 8);
    }

    // Overall contagion verdict
    const agreeingLeaders = signals.filter(s => s.agrees);
    const conflictLeaders = signals.filter(s => !s.agrees);
    const earlyEntry      = agreeingLeaders.filter(s => !s.alreadyFollowed);

    let signal = 'NONE', label = '';
    if (earlyEntry.length >= 2) {
      signal = 'STRONG_EARLY_ENTRY';
      label  = `${earlyEntry.length} leaders moving ${dir} — ${symbol} hasn't followed yet (EARLY ENTRY)`;
    } else if (earlyEntry.length === 1) {
      signal = 'EARLY_ENTRY';
      label  = `${earlyEntry[0].leader} leading ${dir} — ${symbol} follow-through pending`;
    } else if (agreeingLeaders.length > 0 && conflictLeaders.length === 0) {
      signal = 'CONFIRMED';
      label  = `Leaders confirm ${dir} — ${symbol} already following`;
    } else if (conflictLeaders.length >= 2) {
      signal = 'CONFLICT';
      label  = `Leaders split — ${conflictLeaders.length} opposing ${dir}, caution`;
    } else if (conflictLeaders.length === 1 && agreeingLeaders.length === 0) {
      signal = 'OPPOSING';
      label  = `${conflictLeaders[0].leader} strongly opposing ${dir}`;
    } else {
      signal = 'NEUTRAL';
      label  = 'Leaders not making significant moves';
    }

    const certBoost = clamp(totalContagionBoost, -20, 20);

    const data = {
      hasContagion: signals.length > 0,
      signal,
      label,
      certBoost,
      leaders:       signals,
      agreeCount:    agreeingLeaders.length,
      conflictCount: conflictLeaders.length,
      earlyEntryCount: earlyEntry.length,
      bestPrediction: signals.length > 0
        ? signals.sort((a, b) => b.confidence - a.confidence)[0]
        : null,
    };

    CONTAGION_CACHE.set(key, { data, ts: Date.now() });
    return data;
  } catch (e) {
    console.warn('getCrossAssetContagion error:', e.message);
    return { hasContagion: false, signal: 'NONE', label: 'Contagion error', leaders: [], certBoost: 0 };
  }
}

function formatContagionContext(cag, dir) {
  if (!cag || !cag.hasContagion) return '';
  const L = ['\n━━━ 🔗 CROSS-ASSET CONTAGION ━━━'];

  const sigIcon = {
    STRONG_EARLY_ENTRY: '🚀 STRONG EARLY ENTRY',
    EARLY_ENTRY:        '⚡ EARLY ENTRY WINDOW',
    CONFIRMED:          '✅ CONFIRMED',
    CONFLICT:           '⚠️ CONFLICT',
    OPPOSING:           '🔴 OPPOSING',
    NEUTRAL:            '⚪ NEUTRAL',
  }[cag.signal] || cag.signal;

  L.push(`Signal: <b>${sigIcon}</b>`);
  L.push(`${cag.label}`);
  if (cag.certBoost !== 0) L.push(`Cert boost: ${cag.certBoost > 0 ? '+' : ''}${cag.certBoost}% from contagion`);

  (Array.isArray(cag.leaders) ? cag.leaders : []).slice(0, 3).forEach(s => {
    const icon  = s.agrees ? (s.alreadyFollowed ? '✅' : '⚡') : '⚠️';
    const state = s.alreadyFollowed ? 'already followed' : `${s.remainingMove > 0 ? '+' : ''}${s.remainingMove}% remaining`;
    L.push(`${icon} ${s.leader}: ${s.leaderDir} ${s.leaderMove > 0 ? '+' : ''}${s.leaderMove}% → predicted ${s.predictedMove > 0 ? '+' : ''}${s.predictedMove}% within ~${s.lagHours}h (${state})`);
  });

  if (cag.bestPrediction && !cag.bestPrediction.alreadyFollowed && cag.bestPrediction.agrees) {
    L.push(`\n📌 <b>Best setup:</b> ${cag.bestPrediction.label}`);
  }
  return L.join('\n');
}


/* ═══════════════════════════════════════════════════════════════════════════
   ██████████████████████████████████████████████████████████████████████████
   ADAPTIVE INTELLIGENCE SUITE — 5 UPGRADES
   ██████████████████████████████████████████████████████████████████████████

   UPGRADE 1: Adaptive Bayesian Agent Weight Engine
   UPGRADE 2: Per-Verdict Confidence Calibration
   UPGRADE 3: Market Regime Aware Agent Weights (Trending vs Ranging)
   UPGRADE 4: Real-Time Order Book Imbalance Agent
   UPGRADE 5: Certainty-Squared Precision Position Sizing

   All upgrades are:
   - Wired into existing pipeline (no idle code)
   - Backward compatible (graceful defaults if data absent)
   - Persisted to disk across restarts
   - Connected to existing SIGNAL_JOURNAL, quantumConsensus, and position sizing
   ═══════════════════════════════════════════════════════════════════════════ */


/* ═══════════════════════════════════════════════════════════════════════════
   UPGRADE 1 + 3: ADAPTIVE BAYESIAN AGENT WEIGHT ENGINE
   ─────────────────────────────────────────────────────────────────────────
   After every /won or /lost command:
   1. Pull signal's agent_breakdown from SIGNAL_JOURNAL
   2. For each agent that voted: reward correct votes, penalise wrong votes
   3. Update weight: new = old × (1 + lr × factor), clamped [MIN_W, MAX_W]
   4. Persist to NEURAL_WEIGHTS_FILE so weights survive restarts

   UPGRADE 3 embedded: Two weight tables maintained simultaneously —
   TRENDING_WEIGHTS and RANGING_WEIGHTS — activated by macro2Y regime.
   ═══════════════════════════════════════════════════════════════════════════ */

const ADAPTIVE_WEIGHTS_FILE = './adaptive_agent_weights.json';
const AGENT_WEIGHT_MIN = 0.10;   // agent never silenced completely
const AGENT_WEIGHT_MAX = 5.00;   // single agent never dominates everything
const BAYESIAN_LR      = 0.06;   // learning rate per trade — fast enough to adapt, slow enough to be stable
const MIN_TRADES_TO_ADAPT = 5;   // need at least 5 resolved trades before adapting

// ── Baseline weights — copied from quantumConsensus hardcoded table ───────
const BASELINE_WEIGHTS = {
  PriceAction:        2.5,
  Structure:          2.2,
  OrderFlow:          1.8,
  Volume:             1.5,
  Momentum:           1.3,
  Quantum:            1.0,
  Volatility:         0.3,
  OrderBlock:         2.8,
  CVD:                2.4,
  Wyckoff:            2.0,
  FundingRate:        1.6,
  HiddenDiv:          1.4,
  Deception:          3.2,
  Reflexivity:        2.2,
  EntropyGradient:    1.8,
  CriticalState:      1.6,
  Adversarial:        1.5,
  CIF:                1.3,
  RQA:                2.6,
  Thermodynamic:      2.4,
  LempelZiv:          2.0,
  Kuramoto:           2.2,
  StochasticResonance:1.8,
  TickBias:           1.1,
  SMCI:               2.6,
  OrderBookImbalance: 2.0,  // new agent (Upgrade 4) — starts at neutral weight
};

// Live weight state: two tables for trending and ranging regimes
let ADAPTIVE_WEIGHTS = {
  trending: { ...BASELINE_WEIGHTS },
  ranging:  { ...BASELINE_WEIGHTS },
  tradeCount: 0,
  lastUpdated: null,
};

// Load persisted weights on startup
try {
  if (fs.existsSync(ADAPTIVE_WEIGHTS_FILE)) {
    const loaded = JSON.parse(fs.readFileSync(ADAPTIVE_WEIGHTS_FILE, 'utf8'));
    // Merge loaded weights with baseline (handles new agents added since last save)
    if (loaded.trending) {
      ADAPTIVE_WEIGHTS.trending = { ...BASELINE_WEIGHTS, ...loaded.trending };
      ADAPTIVE_WEIGHTS.ranging  = { ...BASELINE_WEIGHTS, ...loaded.ranging };
      ADAPTIVE_WEIGHTS.tradeCount = loaded.tradeCount || 0;
      ADAPTIVE_WEIGHTS.lastUpdated = loaded.lastUpdated || null;
      console.log(`🧠 Adaptive weights loaded — ${ADAPTIVE_WEIGHTS.tradeCount} trades trained`);
    }
  } else {
    console.log('🧠 Adaptive weights: no save file — using baselines');
  }
} catch(e) {
  console.warn('Adaptive weights load error:', e.message, '— using baselines');
}

/**
 * getAdaptiveWeights(regime)
 * Returns the correct weight table based on current market regime.
 * Falls back to baselines if insufficient training data.
 */
function getAdaptiveWeights(regime) {
  if (ADAPTIVE_WEIGHTS.tradeCount < MIN_TRADES_TO_ADAPT) {
    return BASELINE_WEIGHTS; // not enough data yet — use hand-tuned baselines
  }
  const isTrending = regime && ['BULLISH','BEARISH','STRONG_BULL','STRONG_BEAR','BULL','BEAR'].includes(regime);
  return isTrending ? ADAPTIVE_WEIGHTS.trending : ADAPTIVE_WEIGHTS.ranging;
}

/**
 * bayesianWeightUpdate(agentLabel, wasCorrect, regime)
 * Applies one Bayesian update step to a single agent's weight.
 */
function bayesianWeightUpdate(agentLabel, wasCorrect, regime) {
  const isTrending = regime && ['BULLISH','BEARISH','STRONG_BULL','STRONG_BEAR','BULL','BEAR'].includes(regime);
  const table = isTrending ? ADAPTIVE_WEIGHTS.trending : ADAPTIVE_WEIGHTS.ranging;
  const current = table[agentLabel] ?? BASELINE_WEIGHTS[agentLabel] ?? 1.0;

  // Reward: multiply by (1 + lr). Penalise: multiply by (1 - lr)
  // Abstain (NEUTRAL vote): mild reward — correct humility is valuable
  const factor = wasCorrect === true ? BAYESIAN_LR
               : wasCorrect === false ? -BAYESIAN_LR
               : BAYESIAN_LR * 0.1; // abstain
  const updated = current * (1 + factor);
  table[agentLabel] = Math.max(AGENT_WEIGHT_MIN, Math.min(AGENT_WEIGHT_MAX, updated));
}

/**
 * updateAgentWeightsFromOutcome(journalEntry, won)
 * Called after /won or /lost — pulls agent_breakdown and applies Bayesian updates.
 * This is the core self-learning loop.
 */
function updateAgentWeightsFromOutcome(journalEntry, won) {
  try {
    if (!journalEntry) return;

    const breakdown = journalEntry.agent_breakdown;
    if (!breakdown || typeof breakdown !== 'object') return;

    const correctDir = journalEntry.dir; // 'BUY' or 'SELL'
    const regime     = journalEntry.macro_regime || null;

    let updated = 0;
    for (const [label, agentData] of Object.entries(breakdown)) {
      if (!agentData) continue;
      const agentDir = agentData.dir || agentData.direction;
      if (!agentDir || agentDir === 'NEUTRAL') {
        // Agent abstained — mild reward
        bayesianWeightUpdate(label, null, regime);
      } else {
        const agentWasRight = (agentDir === correctDir) === won;
        bayesianWeightUpdate(label, agentWasRight, regime);
      }
      updated++;
    }

    ADAPTIVE_WEIGHTS.tradeCount++;
    ADAPTIVE_WEIGHTS.lastUpdated = Date.now();

    // Normalise weights within each regime table to prevent drift
    // (ensures total weight budget stays ≈ constant)
    for (const table of [ADAPTIVE_WEIGHTS.trending, ADAPTIVE_WEIGHTS.ranging]) {
      const vals = Object.values(table).filter(Number.isFinite);
      const avg  = vals.reduce((a, b) => a + b, 0) / vals.length;
      const baselineAvg = Object.values(BASELINE_WEIGHTS).reduce((a, b) => a + b, 0) / Object.values(BASELINE_WEIGHTS).length;
      if (avg > 0) {
        const scale = baselineAvg / avg;
        for (const k of Object.keys(table)) {
          table[k] = Math.max(AGENT_WEIGHT_MIN, Math.min(AGENT_WEIGHT_MAX, table[k] * scale));
        }
      }
    }

    // Persist updated weights
    try {
      fs.writeFileSync(ADAPTIVE_WEIGHTS_FILE, JSON.stringify(ADAPTIVE_WEIGHTS, null, 2));
    } catch(_) {}

    console.log(`🧠 Bayesian update: ${updated} agents updated (trade #${ADAPTIVE_WEIGHTS.tradeCount}) [${won?'WIN':'LOSS'}]`);
    return { updated, tradeCount: ADAPTIVE_WEIGHTS.tradeCount };
  } catch(e) {
    console.error('updateAgentWeightsFromOutcome error:', e.message);
  }
}

/**
 * getTopAgents(regime, n)
 * Returns the top N agents by current adaptive weight — used in Telegram /weights command.
 */
function getTopAgents(regime, n = 5) {
  const table = getAdaptiveWeights(regime);
  return Object.entries(table)
    .sort((a, b) => b[1] - a[1])
    .slice(0, n)
    .map(([name, w]) => ({
      name,
      weight: Math.round(w * 100) / 100,
      baseline: BASELINE_WEIGHTS[name] || 1.0,
      delta: Math.round((w - (BASELINE_WEIGHTS[name] || 1.0)) * 100) / 100,
    }));
}


/* ═══════════════════════════════════════════════════════════════════════════
   UPGRADE 2: PER-VERDICT CONFIDENCE CALIBRATION
   ─────────────────────────────────────────────────────────────────────────
   Computes historical win rate per verdict type from SIGNAL_JOURNAL.
   Multiplies into effectiveCert as a calibration factor.
   A verdict with 80% historical accuracy boosts confidence.
   A verdict with 40% historical accuracy reduces it.
   ═══════════════════════════════════════════════════════════════════════════ */

/**
 * getVerdictCalibration(verdict, minSamples)
 * Returns { accuracy, sampleSize, calibrationBoost } for a given verdict type.
 * calibrationBoost: +/-% to add to effectiveCert. Capped at ±15.
 */
function getVerdictCalibration(verdict, minSamples = 8) {
  try {
    if (!verdict) return { accuracy: null, sampleSize: 0, calibrationBoost: 0 };

    // Find all resolved journal entries with this verdict
    const verdictEntries = SIGNAL_JOURNAL.filter(e =>
      e.verdict && e.verdict.includes(verdict.replace(/[⛔🎯🚀💥⚡👁⏳📰🔄🔴🚫⚠️]/g, '').trim()) &&
      e.outcome !== null
    );

    if (verdictEntries.length < minSamples) {
      return { accuracy: null, sampleSize: verdictEntries.length, calibrationBoost: 0 };
    }

    const wins = verdictEntries.filter(e => e.outcome === 'WIN').length;
    const accuracy = wins / verdictEntries.length; // 0.0 – 1.0

    // Calibration boost: centered at 60% expected accuracy
    // 80% accuracy → +12 boost, 40% accuracy → -12 penalty
    const calibrationBoost = Math.round((accuracy - 0.60) * 40);
    const clamped = Math.max(-15, Math.min(15, calibrationBoost));

    return {
      accuracy: Math.round(accuracy * 100),
      sampleSize: verdictEntries.length,
      calibrationBoost: clamped,
    };
  } catch(e) {
    return { accuracy: null, sampleSize: 0, calibrationBoost: 0 };
  }
}

/**
 * getVerdictAccuracyReport()
 * Returns a full table of all verdict types with their historical accuracy.
 * Used in /performance Telegram command.
 */
function getVerdictAccuracyReport() {
  const verdictTypes = [
    'VECTOR TRADE','POST-SWEEP LIMIT','POST-LIQ LIMIT','CASCADE LIMIT',
    'PRE-INSTITUTIONAL LIMIT','TRADE NOW','SET LIMIT','VECTOR WATCH',
  ];
  return verdictTypes.map(v => {
    const cal = getVerdictCalibration(v, 3);
    return { verdict: v, ...cal };
  }).filter(r => r.sampleSize > 0);
}


/* ═══════════════════════════════════════════════════════════════════════════
   UPGRADE 4: REAL-TIME ORDER BOOK IMBALANCE AGENT
   ─────────────────────────────────────────────────────────────────────────
   Reads live order book depth from QUANTUM_CACHE (populated by WebSocket).
   Computes bid/ask imbalance within 0.5% of current price.
   When 75%+ of visible book depth is on one side → near-guaranteed direction.
   Feeds directly into quantumConsensus as the 'OrderBookImbalance' agent.
   ═══════════════════════════════════════════════════════════════════════════ */

/**
 * getOrderBookImbalanceAgent(symbol)
 * Returns a standard agent-shaped object for quantumConsensus.
 * Uses WebSocket order book data if available; gracefully returns NEUTRAL if not.
 */
function getOrderBookImbalanceAgent(symbol) {
  try {
    const obData = QUANTUM_CACHE.get(`orderbook_${symbol}`);
    if (!obData || !obData.data) {
      return { direction: 'NEUTRAL', confidence: 0, label: 'OrderBookImbalance', source: 'no_data' };
    }

    const metrics = obData.data;
    const imbalance = metrics.imbalance; // -1 (all asks) to +1 (all bids)
    const ageSec    = obData.ts ? (Date.now() - obData.ts) / 1000 : 999;

    // Stale data (>90 seconds) = unreliable
    if (ageSec > 90) {
      return { direction: 'NEUTRAL', confidence: 0, label: 'OrderBookImbalance', source: 'stale' };
    }

    // Imbalance thresholds
    // > 0.40 = strong bid wall → BUY
    // < -0.40 = strong ask wall → SELL
    // 0.25-0.40 = moderate imbalance
    let direction  = 'NEUTRAL';
    let confidence = 0;

    if (imbalance > 0.60) {
      direction  = 'BUY';
      confidence = Math.min(0.90, 0.65 + (imbalance - 0.60) * 0.8); // 0.65 – 0.90
    } else if (imbalance > 0.40) {
      direction  = 'BUY';
      confidence = 0.50 + (imbalance - 0.40) * 0.75; // 0.50 – 0.65
    } else if (imbalance < -0.60) {
      direction  = 'SELL';
      confidence = Math.min(0.90, 0.65 + (Math.abs(imbalance) - 0.60) * 0.8);
    } else if (imbalance < -0.40) {
      direction  = 'SELL';
      confidence = 0.50 + (Math.abs(imbalance) - 0.40) * 0.75;
    } else if (Math.abs(imbalance) > 0.25) {
      // Weak lean — low confidence vote
      direction  = imbalance > 0 ? 'BUY' : 'SELL';
      confidence = 0.25 + Math.abs(imbalance) * 0.5;
    }

    return {
      direction,
      confidence: Math.round(confidence * 100) / 100,
      label:      'OrderBookImbalance',
      imbalance:  Math.round(imbalance * 1000) / 1000,
      bidVol:     metrics.bid_volume,
      askVol:     metrics.ask_volume,
      spreadPct:  metrics.spread_percent,
      ageSec:     Math.round(ageSec),
      source:     'live_ws',
    };
  } catch(e) {
    return { direction: 'NEUTRAL', confidence: 0, label: 'OrderBookImbalance', source: 'error' };
  }
}


/* ═══════════════════════════════════════════════════════════════════════════
   UPGRADE 5: CERTAINTY-SQUARED PRECISION POSITION SIZING
   ─────────────────────────────────────────────────────────────────────────
   Combines three factors into final position size multiplier:
     1. effectiveCert² — best signals get exponentially larger positions
     2. verdictAccuracy — historically accurate verdicts get more capital
     3. adaptiveWeightConfidence — how much the adaptive weight system
        agrees with the current signal direction

   Formula: multiplier = (cert/100)² × verdictFactor × weightFactor
   Capped at 1.5× (150% of base size for exceptional setups)
   Floored at 0.10× (always keep 10% minimum to stay in the game)
   ═══════════════════════════════════════════════════════════════════════════ */

/**
 * computePrecisionPositionSize(baseSize, effectiveCert, verdict, agentBreakdown, regime)
 * Returns { finalSize, multiplier, breakdown, label }
 */
function computePrecisionPositionSize(baseSize, effectiveCert, verdict, agentBreakdown, regime) {
  try {
    if (!baseSize || isNaN(baseSize) || baseSize <= 0) {
      return { finalSize: baseSize, multiplier: 1.0, breakdown: 'No base size', label: '1.0×' };
    }

    const cert = Math.max(0, Math.min(100, effectiveCert || 0));

    // Factor 1: Certainty squared (0.0 – 1.0)
    // 95% cert → 0.90 factor, 80% cert → 0.64, 60% cert → 0.36
    const certFactor = Math.pow(cert / 100, 2);

    // Factor 2: Verdict calibration (0.7 – 1.3)
    const verdictCal = verdict ? getVerdictCalibration(verdict, 8) : null;
    let verdictFactor = 1.0;
    if (verdictCal && verdictCal.accuracy !== null) {
      // 80% accuracy → 1.2×, 60% accuracy → 1.0×, 40% accuracy → 0.8×
      verdictFactor = 0.7 + (verdictCal.accuracy / 100) * 0.6;
      verdictFactor = Math.max(0.7, Math.min(1.3, verdictFactor));
    }

    // Factor 3: Adaptive weight agreement (0.85 – 1.15)
    let weightAgreeFactor = 1.0;
    if (agentBreakdown && typeof agentBreakdown === 'object') {
      const weights = getAdaptiveWeights(regime);
      let agreeScore = 0, totalW = 0;
      for (const [label, data] of Object.entries(agentBreakdown)) {
        const w = weights[label] || 1.0;
        if (data && data.confidence > 0) {
          agreeScore += w * data.confidence;
          totalW += w;
        }
      }
      const avgWeightedConf = totalW > 0 ? agreeScore / totalW : 0;
      // 0.7 weighted confidence → 1.1 factor, 0.3 → 0.90
      weightAgreeFactor = 0.85 + avgWeightedConf * 0.4;
      weightAgreeFactor = Math.max(0.85, Math.min(1.15, weightAgreeFactor));
    }

    // Combined multiplier
    let multiplier = certFactor * verdictFactor * weightAgreeFactor;

    // Hard caps: floor 10%, ceiling 150%
    multiplier = Math.max(0.10, Math.min(1.50, multiplier));

    const finalSize  = Math.round(baseSize * multiplier * 100) / 100;
    const pct        = Math.round(multiplier * 100);
    const label      = `${pct}% (cert²=${Math.round(certFactor*100)}% × verdict=${Math.round(verdictFactor*100)}% × weights=${Math.round(weightAgreeFactor*100)}%)`;
    const breakdown  = `Cert ${cert}%² → ${Math.round(certFactor*100)}% | Verdict accuracy ${verdictCal?.accuracy ?? 'N/A'}% → ${Math.round(verdictFactor*100)}% | Weight agreement → ${Math.round(weightAgreeFactor*100)}%`;

    return { finalSize, multiplier, pct, breakdown, label };
  } catch(e) {
    console.warn('computePrecisionPositionSize error:', e.message);
    return { finalSize: baseSize, multiplier: 1.0, breakdown: 'Error fallback', label: '1.0×' };
  }
}

// ── Export precision sizing for use in /status and signal display ──────────
const PRECISION_SIZING_STATS = {
  lastMultiplier: 1.0,
  lastVerdict: null,
  lastCert: 0,
  count: 0,
};


/* ═══════════════════════════════════════════════════════════════════════════
   INTEGRATION WRAPPERS
   Connect all 5 upgrades to the existing pipeline
   ═══════════════════════════════════════════════════════════════════════════ */

// ── Wrap logSignalOutcome to trigger Bayesian weight update ────────────────
const _origLogSignalOutcome = logSignalOutcome;
logSignalOutcome = function(symbol, dir, entryPrice, won) {
  // 1. Run original outcome logging
  _origLogSignalOutcome(symbol, dir, entryPrice, won);

  // 2. Find the matching journal entry that was just updated
  try {
    const journalEntry = SIGNAL_JOURNAL
      .slice()
      .reverse()
      .find(e =>
        (symbol ? e.symbol === symbol : true) &&
        (dir    ? e.dir    === dir    : true) &&
        e.outcome === (won ? 'WIN' : 'LOSS') &&
        Date.now() - e.ts < 30 * 24 * 60 * 60 * 1000
      );

    if (journalEntry) {
      updateAgentWeightsFromOutcome(journalEntry, won);
    }
  } catch(e) {
    console.warn('Bayesian update trigger error:', e.message);
  }
};

// ── Add macro_regime to logSignalFired entries for regime-aware learning ───
const _origLogSignalFired = logSignalFired;
logSignalFired = function(symbol, consensus, instCtx, scored) {
  const entry = _origLogSignalFired(symbol, consensus, instCtx, scored);
  if (entry) {
    // Store agent_breakdown and macro_regime for Bayesian learning
    entry.agent_breakdown  = consensus?.bestSig?.raw?.agent_breakdown || null;
    entry.macro_regime     = consensus?.bestSig?.macro2Y?.regime || null;
  }
  return entry;
};

// ── Wrap quantumConsensus to use adaptive weights ──────────────────────────
// Stores the current regime on the instance so quantumConsensus can access it
// (regime is passed down from generateEnhancedQuantumSignal's macroRegime var)

const _origQuantumConsensus = EnhancedQuantumSignalGenerator.prototype.quantumConsensus;
EnhancedQuantumSignalGenerator.prototype.quantumConsensus = function(agents, regime) {
  // If adaptive weights have enough training data, substitute them
  const weights = getAdaptiveWeights(regime || this._currentRegime);

  // Override the hardcoded agentWeights inside the original method
  // by temporarily patching the instance
  this._adaptiveWeights = weights;
  const result = _origQuantumConsensus.call(this, agents);
  return result;
};

// Patch the original quantumConsensus to check for adaptive weights
const _patchedQC = function(agents) {
  const agentWeights = this._adaptiveWeights || {
    PriceAction:2.5,Structure:2.2,OrderFlow:1.8,Volume:1.5,Momentum:1.3,
    Quantum:1.0,Volatility:0.3,OrderBlock:2.8,CVD:2.4,Wyckoff:2.0,
    FundingRate:1.6,HiddenDiv:1.4,Deception:3.2,Reflexivity:2.2,
    EntropyGradient:1.8,CriticalState:1.6,Adversarial:1.5,CIF:1.3,
    RQA:2.6,Thermodynamic:2.4,LempelZiv:2.0,Kuramoto:2.2,
    StochasticResonance:1.8,TickBias:1.1,SMCI:2.6,OrderBookImbalance:2.0,
  };

  let buyScore = 0, sellScore = 0, totalWeight = 0;
  let votingAgentCount = 0;
  const breakdown = {};

  for (const agent of agents) {
    if (!agent || !agent.label) continue;
    const w = agentWeights[agent.label] || 1.0;
    const voted = agent.direction !== 'NEUTRAL' && (agent.confidence || 0) > 0;
    if (voted) {
      const effectiveWeight = w * agent.confidence;
      totalWeight += w;
      votingAgentCount++;
      if (agent.direction === 'BUY')  buyScore  += effectiveWeight;
      else if (agent.direction === 'SELL') sellScore += effectiveWeight;
    }
    breakdown[agent.label] = { dir: agent.direction, conf: agent.confidence || 0, w };
  }

  if (totalWeight === 0 || votingAgentCount === 0) {
    return { direction: 'NEUTRAL', confidence: 0, breakdown, delta: 0 };
  }

  const buyNorm  = buyScore  / totalWeight;
  const sellNorm = sellScore / totalWeight;
  const delta    = Math.abs(buyNorm - sellNorm);

  let direction = 'NEUTRAL', confidence = 0, signal_tier = 'NEUTRAL';

  if (buyNorm > sellNorm) {
    direction  = 'BUY';
    confidence = clamp(buyNorm, 0, 1);
  } else if (sellNorm > buyNorm) {
    direction  = 'SELL';
    confidence = clamp(sellNorm, 0, 1);
  } else {
    direction  = 'NEUTRAL';
    confidence = Math.max(buyNorm, sellNorm);
  }

  signal_tier = delta > 0.55 ? 'STRONG'
              : delta > 0.35 ? 'MODERATE'
              : delta > 0.15 ? 'EARLY_WARNING'
              : 'SPECULATIVE';

  return { direction, confidence, delta, signal_tier, breakdown, votingAgentCount, totalWeight };
};

EnhancedQuantumSignalGenerator.prototype.quantumConsensus = _patchedQC;

// ── Patch generateEnhancedQuantumSignal to:
