/* ════════════════════════════════════════════════════════════════════════════
   V15: TOPOLOGICAL DATA ANALYSIS — PERSISTENT HOMOLOGY
   Origin: Algebraic topology (Edelsbrunner & Harer, 2002)
   Field:  Pure mathematics — computational topology
   ─────────────────────────────────────────────────────────────────────────
   Maps price as a point cloud in delay-coordinate space.
   Computes topological "holes" (cycles) that persist across scales.

   Betti-0 (connected components): how many separate price regimes exist?
     → Collapse from 2 to 1: regime unification → explosive directional move

   Betti-1 (1-cycles / loops): is price trapped in a topological loop?
     → Loop persistence high: price must complete the cycle before escaping
     → Loop persistence collapsing: escape imminent → breakout signal

   Persistence diagram: birth/death of topological features across scales.
     → Feature with long lifetime = structural, not noise
     → Sudden death of dominant feature = regime change
   ════════════════════════════════════════════════════════════════════════════ */

const V15_CACHE     = new Map();
const V15_CACHE_TTL = 3 * 60 * 1000;

function computePersistentHomology(candles) {
  if (!candles || candles.length < 30) return null;
  try {
    const closes  = candles.map(c => c.c).filter(v => !isNaN(v) && v > 0);
    const n       = Math.min(closes.length, 60);
    const prices  = closes.slice(-n);

    // Build delay-coordinate point cloud: [price(t), price(t+d), price(t+2d)]
    // We use 2D embedding for efficiency: (price(t), price(t+3))
    const delay = 3;
    const points = [];
    for (let i = 0; i < prices.length - delay; i++) {
      points.push([prices[i], prices[i + delay]]);
    }

    // Normalize to [0,1] × [0,1]
    const xs = points.map(p => p[0]), ys = points.map(p => p[1]);
    const xMin = Math.min(...xs), xMax = Math.max(...xs);
    const yMin = Math.min(...ys), yMax = Math.max(...ys);
    const xRange = xMax - xMin || 1, yRange = yMax - yMin || 1;
    const norm = points.map(p => [(p[0] - xMin) / xRange, (p[1] - yMin) / yRange]);

    // Compute Vietoris-Rips filtration (simplified):
    // At each scale ε, connect points within distance ε.
    // Count connected components (Betti-0) and loops (Betti-1).
    const scales = [0.05, 0.10, 0.15, 0.20, 0.25, 0.30, 0.40];
    const betti0Series = [], betti1Series = [];

    for (const eps of scales) {
      // Union-Find for Betti-0 (connected components)
      const parent = Array.from({ length: norm.length }, (_, i) => i);
      function find(x) { while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; }
      function union(a, b) { const ra = find(a), rb = find(b); if (ra !== rb) parent[ra] = rb; }

      let edgeCount = 0;
      for (let i = 0; i < norm.length; i++) {
        for (let j = i + 1; j < norm.length; j++) {
          const dx = norm[i][0] - norm[j][0], dy = norm[i][1] - norm[j][1];
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < eps) { union(i, j); edgeCount++; }
        }
      }

      const components = new Set(norm.map((_, i) => find(i))).size;
      // Euler characteristic approximation: χ = V - E + F, Betti-1 ≈ E - V + components
      const betti1 = Math.max(0, edgeCount - norm.length + components);
      betti0Series.push(components);
      betti1Series.push(betti1);
    }

    // Persistence: how quickly do features die as ε increases?
    const betti0Drop    = betti0Series[0] - betti0Series[betti0Series.length - 1];
    const betti1Peak    = Math.max(...betti1Series);
    const betti1Late    = betti1Series[betti1Series.length - 1];
    const betti1Dying   = betti1Peak > 3 && betti1Late < betti1Peak * 0.4; // loop collapsing
    const regimeUnify   = betti0Series[0] >= 3 && betti0Series[3] <= 1;    // components merging

    // Topological signals
    let signal = 'NEUTRAL', confidence = 0, certBoost = 0, label = '';
    const priceDir = prices[prices.length - 1] > prices[prices.length - 8] ? 'BUY' : 'SELL';

    if (regimeUnify) {
      // Multiple price regimes converging → explosive breakout
      signal     = priceDir;
      confidence = clamp(0.68 + betti0Drop * 0.04, 0.68, 0.88);
      certBoost  = 12;
      label      = `Topological REGIME UNIFICATION — ${betti0Series[0]} components → ${betti0Series[3]}: explosive breakout imminent`;
    } else if (betti1Dying) {
      // Topological loop collapsing → price escaping the cycle
      signal     = priceDir;
      confidence = clamp(0.62 + (betti1Peak - betti1Late) * 0.03, 0.62, 0.84);
      certBoost  = 10;
      label      = `Topological LOOP COLLAPSE — cycle dying (peak ${betti1Peak}→${betti1Late}): price breaking free`;
    } else if (betti1Late > 5) {
      // Price trapped in persistent topological loop
      signal     = 'NEUTRAL';
      certBoost  = -6;
      label      = `Topological LOOP TRAP — Betti-1=${betti1Late}: price cycling, no clean breakout yet`;
    } else {
      label = `Topology normal — Betti-0=${betti0Series[3]}, Betti-1=${betti1Late}`;
    }

    return {
      betti0:      betti0Series[3],
      betti1:      betti1Late,
      betti0Series, betti1Series,
      betti1Peak,
      regimeUnify,  betti1Dying,
      signal, confidence, certBoost,
      direction:   signal,
      label,
    };
  } catch(e) {
    console.warn('V15 persistentHomology error:', e.message);
    return null;
  }
}

async function getV15Context(symbol, candles, dir) {
  const key = `v15_${symbol}_${dir}`;
  const hit = V15_CACHE.get(key);
  if (hit && Date.now() - hit.ts < V15_CACHE_TTL) return hit.data;
  const data = computePersistentHomology(candles);
  V15_CACHE.set(key, { data, ts: Date.now() });
  return data;
}


/* ════════════════════════════════════════════════════════════════════════════
   V16: ZIPF LAW DIVERGENCE ENGINE
   Origin: Econophysics (Mantegna & Stanley, 1995) + Zipf (1949)
   Field:  Statistical physics applied to financial markets
   ─────────────────────────────────────────────────────────────────────────
   Zipf's law: in a healthy market, return distribution follows a power law.
   The nth largest return ≈ C / n^α, where α ≈ 3 (cubic tail).

   Divergence from Zipf's law signals structural market breakdown:
   → α < 2.5 (fatter tail than Zipf): crash risk — extreme moves more likely
   → α > 3.5 (thinner tail than Zipf): volatility compression → imminent explosion
   → Distribution skew: positive skew + thin tail = asymmetric upside loading
   → Distribution skew: negative skew + fat tail = institutional distribution
   ════════════════════════════════════════════════════════════════════════════ */

const V16_CACHE     = new Map();
const V16_CACHE_TTL = 4 * 60 * 1000;

function computeZipfDivergence(candles) {
  if (!candles || candles.length < 40) return null;
  try {
    const closes  = candles.map(c => c.c).filter(v => !isNaN(v) && v > 0);
    if (closes.length < 40) return null;

    // Compute log returns
    const returns = [];
    for (let i = 1; i < closes.length; i++) {
      const r = Math.log(closes[i] / closes[i - 1]);
      if (!isNaN(r) && isFinite(r)) returns.push(r);
    }
    if (returns.length < 20) return null;

    // Sort returns by absolute magnitude (descending) — rank them
    const absReturns = returns.map(r => Math.abs(r)).sort((a, b) => b - a);
    const n = absReturns.length;

    // Fit power law: log(return) = log(C) - α × log(rank)
    // Using log-log regression on top 50% of observations (Hill estimator)
    const fitCount = Math.max(5, Math.floor(n * 0.5));
    let sumLogR = 0, sumLogN = 0, sumLogRLogN = 0, sumLogN2 = 0;
    for (let i = 0; i < fitCount; i++) {
      const logR = Math.log(absReturns[i] + 1e-10);
      const logN = Math.log(i + 1);
      sumLogR    += logR;
      sumLogN    += logN;
      sumLogRLogN += logR * logN;
      sumLogN2   += logN * logN;
    }
    const alpha = -(fitCount * sumLogRLogN - sumLogN * sumLogR) /
                   (fitCount * sumLogN2 - sumLogN * sumLogN);

    // Compute skewness of returns
    const mean = returns.reduce((s, r) => s + r, 0) / returns.length;
    const variance = returns.reduce((s, r) => s + (r - mean) ** 2, 0) / returns.length;
    const std = Math.sqrt(variance) || 1e-10;
    const skew = returns.reduce((s, r) => s + ((r - mean) / std) ** 3, 0) / returns.length;

    // Kurtosis excess
    const kurt = returns.reduce((s, r) => s + ((r - mean) / std) ** 4, 0) / returns.length - 3;

    // Zipf deviation: how far from the healthy α ≈ 3?
    const zipfDev = alpha - 3.0; // negative = fat tail, positive = thin tail

    // Signals
    let signal = 'NEUTRAL', confidence = 0, certBoost = 0, label = '';
    const priceDir = closes[closes.length - 1] > closes[closes.length - 8] ? 'BUY' : 'SELL';

    if (alpha < 2.2) {
      // Very fat tail — crash/extreme move risk
      signal     = 'SELL'; // extreme tail events are usually downward in crypto
      confidence = clamp(0.58 + (2.2 - alpha) * 0.12, 0.58, 0.82);
      certBoost  = -10;    // dangerous territory — reduce confidence
      label      = `Zipf CRASH RISK — α=${alpha.toFixed(2)} (normal=3.0): fat tail, extreme move imminent`;
    } else if (alpha > 3.8 && kurt < -0.5) {
      // Thin tail + platykurtic = volatility compression → explosion
      signal     = priceDir;
      confidence = clamp(0.60 + (alpha - 3.8) * 0.08, 0.60, 0.80);
      certBoost  = 8;
      label      = `Zipf COMPRESSION — α=${alpha.toFixed(2)} (thin tail + low kurtosis): volatility explosion loading`;
    } else if (skew > 1.2 && alpha > 2.8) {
      // Positive skew + healthy tail = asymmetric upside
      signal     = 'BUY';
      confidence = 0.62;
      certBoost  = 6;
      label      = `Zipf UPSIDE SKEW — α=${alpha.toFixed(2)}, skew=+${skew.toFixed(2)}: asymmetric bullish structure`;
    } else if (skew < -1.2 && alpha < 2.8) {
      // Negative skew + fat tail = distribution in progress
      signal     = 'SELL';
      confidence = 0.64;
      certBoost  = 8;
      label      = `Zipf DISTRIBUTION — α=${alpha.toFixed(2)}, skew=${skew.toFixed(2)}: negative skew + fat tail = selling`;
    } else {
      label = `Zipf normal — α=${alpha.toFixed(2)}, skew=${skew.toFixed(2)}, kurt=${kurt.toFixed(2)}`;
    }

    return {
      alpha:     Math.round(alpha * 1000) / 1000,
      zipfDev:   Math.round(zipfDev * 1000) / 1000,
      skew:      Math.round(skew * 1000) / 1000,
      kurt:      Math.round(kurt * 1000) / 1000,
      signal, confidence, certBoost,
      direction: signal,
      label,
    };
  } catch(e) {
    console.warn('V16 zipfDivergence error:', e.message);
    return null;
  }
}

async function getV16Context(symbol, candles, dir) {
  const key = `v16_${symbol}_${dir}`;
  const hit = V16_CACHE.get(key);
  if (hit && Date.now() - hit.ts < V16_CACHE_TTL) return hit.data;
  const data = computeZipfDivergence(candles);
  V16_CACHE.set(key, { data, ts: Date.now() });
  return data;
}


/* ════════════════════════════════════════════════════════════════════════════
   V17: QUANTUM PROBABILITY AMPLITUDE ENGINE
   Origin: Quantum mechanics (Feynman, 1948) + Path integral formulation
   Field:  Quantum physics — first application to market microstructure
   ─────────────────────────────────────────────────────────────────────────
   In quantum mechanics, a particle takes ALL possible paths simultaneously.
   The probability of each future state = |sum of amplitudes|².

   Applied to price: the "particle" (price) moves through all historical
   price paths simultaneously. We sum the amplitude of each path weighted
   by its action (how "natural" that path was given market conditions).

   The dominant amplitude direction = where price will collapse to.

   This is NOT correlation or momentum. It is the quantum superposition of
   all possible futures, collapsed into a probability distribution.
   ════════════════════════════════════════════════════════════════════════════ */

const V17_CACHE     = new Map();
const V17_CACHE_TTL = 2 * 60 * 1000;

function computeQuantumAmplitude(candles) {
  if (!candles || candles.length < 40) return null;
  try {
    const closes  = candles.map(c => c.c).filter(v => !isNaN(v) && v > 0);
    const vols    = candles.map(c => c.v || 1);
    if (closes.length < 40) return null;

    const current = closes[closes.length - 1];
    const n       = Math.min(closes.length - 1, 50);

    // Step 1: Define future price states (discretize ±5% in 20 bins)
    const stateRange = 0.05;
    const numStates  = 20;
    const states     = [];
    for (let i = 0; i < numStates; i++) {
      states.push(current * (1 - stateRange + (2 * stateRange * i / (numStates - 1))));
    }

    // Step 2: For each future state, compute the Feynman path integral
    // Path amplitude = exp(-S/ℏ) where S = action along that path
    // Action = sum of (price step)² / (2 × volatility²) — least action principle
    // Paths that follow historical momentum have lower action → higher amplitude

    const recentReturns = closes.slice(-20).slice(1).map((c, i) => (c - closes.slice(-20)[i]) / closes.slice(-20)[i]);
    const momentum = recentReturns.reduce((s, r) => s + r, 0) / recentReturns.length;
    const volEstimate = Math.sqrt(recentReturns.reduce((s, r) => s + r * r, 0) / recentReturns.length) || 0.01;

    // Planck constant analogue: ℏ_market = market noise floor
    const hbar = volEstimate * 0.5;

    const amplitudes = states.map(targetState => {
      // Compute action for path: current → targetState over 1 step
      const priceChange = (targetState - current) / current;

      // Action: deviation from momentum path + volatility penalty
      const momentumPath = momentum;  // expected path given current momentum
      const deviation    = priceChange - momentumPath;
      const action       = (deviation * deviation) / (2 * volEstimate * volEstimate);

      // Amplitude (real part of exp(-i*S/ℏ) simplified to real-valued weight)
      // Using Wick rotation: exp(-S/ℏ) for imaginary time formulation
      const amplitude = Math.exp(-action / hbar);

      return { state: targetState, priceChange, amplitude };
    });

    // Normalize amplitudes to get probability distribution
    const totalAmp = amplitudes.reduce((s, a) => s + a.amplitude, 0);
    const probabilities = amplitudes.map(a => ({
      ...a,
      probability: totalAmp > 0 ? a.amplitude / totalAmp : 1 / numStates,
    }));

    // Compute probability-weighted expected return
    const expectedReturn = probabilities.reduce((s, p) => s + p.priceChange * p.probability, 0);

    // Compute "quantum uncertainty": width of probability distribution
    const quantumUncertainty = Math.sqrt(
      probabilities.reduce((s, p) => s + p.probability * (p.priceChange - expectedReturn) ** 2, 0)
    );

    // Probability of UP vs DOWN
    const probUp   = probabilities.filter(p => p.priceChange > 0).reduce((s, p) => s + p.probability, 0);
    const probDown = probabilities.filter(p => p.priceChange < 0).reduce((s, p) => s + p.probability, 0);

    // Amplitude dominance: how concentrated is the distribution?
    const maxProb  = Math.max(...probabilities.map(p => p.probability));
    const concentrationRatio = maxProb * numStates; // >2 = concentrated, <1.2 = diffuse

    let signal = 'NEUTRAL', confidence = 0, certBoost = 0, label = '';

    if (concentrationRatio > 2.5 && probUp > 0.65) {
      signal     = 'BUY';
      confidence = clamp(0.55 + (probUp - 0.65) * 1.5, 0.55, 0.88);
      certBoost  = Math.round((probUp - 0.5) * 20);
      label      = `Quantum BUY amplitude — P(up)=${(probUp*100).toFixed(1)}%, concentration=${concentrationRatio.toFixed(2)}: wave function collapsing UP`;
    } else if (concentrationRatio > 2.5 && probDown > 0.65) {
      signal     = 'SELL';
      confidence = clamp(0.55 + (probDown - 0.65) * 1.5, 0.55, 0.88);
      certBoost  = Math.round((probDown - 0.5) * 20);
      label      = `Quantum SELL amplitude — P(down)=${(probDown*100).toFixed(1)}%, concentration=${concentrationRatio.toFixed(2)}: wave function collapsing DOWN`;
    } else if (concentrationRatio < 1.3) {
      // Diffuse distribution = high uncertainty = wait
      certBoost  = -5;
      label      = `Quantum SUPERPOSITION — diffuse (${concentrationRatio.toFixed(2)}): path integral undecided, no clear collapse yet`;
    } else {
      label = `Quantum neutral — P(up)=${(probUp*100).toFixed(1)}%, P(down)=${(probDown*100).toFixed(1)}%, concentration=${concentrationRatio.toFixed(2)}`;
    }

    return {
      probUp:              Math.round(probUp * 1000) / 1000,
      probDown:            Math.round(probDown * 1000) / 1000,
      expectedReturn:      Math.round(expectedReturn * 10000) / 10000,
      quantumUncertainty:  Math.round(quantumUncertainty * 10000) / 10000,
      concentrationRatio:  Math.round(concentrationRatio * 100) / 100,
      signal, confidence, certBoost,
      direction: signal,
      label,
    };
  } catch(e) {
    console.warn('V17 quantumAmplitude error:', e.message);
    return null;
  }
}

async function getV17Context(symbol, candles, dir) {
  const key = `v17_${symbol}_${dir}`;
  const hit = V17_CACHE.get(key);
  if (hit && Date.now() - hit.ts < V17_CACHE_TTL) return hit.data;
  const data = computeQuantumAmplitude(candles);
  V17_CACHE.set(key, { data, ts: Date.now() });
  return data;
}


/* ════════════════════════════════════════════════════════════════════════════
   V18: METABOLIC SCALING DEVIATION ENGINE
   Origin: Biology (Kleiber's Law, 1932) + Econophysics
   Field:  Biological scaling theory — first application to crypto volume
   ─────────────────────────────────────────────────────────────────────────
   In biology: metabolic rate ∝ mass^(3/4) — Kleiber's Law.
   In markets: trading volume ∝ market cap^(3/4) — metabolic baseline.

   When a coin's volume deviates from its metabolic baseline:
   → Volume >> baseline (hyperactive): the coin is "feeding" — pump incoming
   → Volume << baseline (hypoactive):  the coin is "sick" — dump incoming
   → Volume returning to baseline after spike: exhaustion, move ending

   The metabolic ratio M = actual_volume / predicted_volume
   M > 2.5: hyperactive → BUY (accumulation feeding frenzy)
   M < 0.3: hypoactive  → SELL (dying, institutions exiting)
   M spike then collapse: exhaustion → reversal
   ════════════════════════════════════════════════════════════════════════════ */

const V18_CACHE     = new Map();
const V18_CACHE_TTL = 5 * 60 * 1000;
// Approximate market cap tiers for Bitget-listed assets (normalized units)
const METABOLIC_BASELINES = {
  BTCUSDT: 100, ETHUSDT: 42, BNBUSDT: 8, SOLUSDT: 7, XRPUSDT: 6,
  ADAUSDT: 3, AVAXUSDT: 2.5, DOGEUSDT: 2.8, LINKUSDT: 1.5, LTCUSDT: 1.2,
  DOTUSDT: 1.2, TRXUSDT: 1.4, XLMUSDT: 1.0, TONUSDT: 1.8, HBARUSDT: 0.8,
  SHIBUSDT: 1.5, PEPEUSDT: 0.9, WIFUSDT: 0.5, BONKUSDT: 0.4, FLOKIUSDT: 0.3,
  MEMEUSDT: 0.3, TURBOUSDT: 0.1, SUIUSDT: 1.2, APTUSDT: 0.9, INJUSDT: 0.8,
  NEARUSDT: 0.9, FTMUSDT: 0.7, ICPUSDT: 0.8, ATOMUSDT: 0.7, MATICUSDT: 0.9,
  ARBUSDT: 0.9, OPUSDT: 0.7, STRKUSDT: 0.4, SEIUSDT: 0.5, UNIUSDT: 0.8,
  AAVEUSDT: 0.7, GMXUSDT: 0.3, JUPUSDT: 0.5, RUNEUSDT: 0.4, ENAUSDT: 0.4,
  TIAUSDT: 0.4, PYTHUSDT: 0.3, NOTUSDT: 0.4, POLUSDT: 0.5, HYPEUSDT: 0.3,
};

function computeMetabolicScaling(symbol, candles) {
  if (!candles || candles.length < 20) return null;
  try {
    const baseline = METABOLIC_BASELINES[symbol] || 1.0;

    // Compute actual volume metabolic rate (normalized average volume)
    const recent20  = candles.slice(-20);
    const recent5   = candles.slice(-5);
    const avgVol20  = recent20.reduce((s, c) => s + (c.v || 0), 0) / 20;
    const avgVol5   = recent5.reduce((s, c) => s + (c.v || 0), 0) / 5;
    const prevAvg   = candles.slice(-40, -20).reduce((s, c) => s + (c.v || 0), 0) / 20;

    if (avgVol20 <= 0) return null;

    // Kleiber prediction: expected volume = baseline^(3/4) × calibration constant
    // We normalize by the 20-period average itself — metabolic ratio = current vs typical
    const predictedVol   = Math.pow(baseline, 0.75) * avgVol20;
    const metabolicRatio = avgVol5 / (avgVol20 || 1);     // current vs sustained baseline
    const metabolicTrend = avgVol5 / (prevAvg || avgVol5); // recent vs older history

    // Volume spike then collapse detection (exhaustion)
    const peakVol = Math.max(...candles.slice(-10).map(c => c.v || 0));
    const currentVol = candles[candles.length - 1]?.v || 0;
    const spikeExhaustion = peakVol > avgVol20 * 2.5 && currentVol < peakVol * 0.4;

    let signal = 'NEUTRAL', confidence = 0, certBoost = 0, label = '';
    const priceDir = candles[candles.length - 1].c > candles[candles.length - 6].c ? 'BUY' : 'SELL';

    if (spikeExhaustion) {
      // Volume spike + collapse = exhaustion → reversal
      signal     = priceDir === 'BUY' ? 'SELL' : 'BUY';
      confidence = 0.72;
      certBoost  = 10;
      label      = `Metabolic EXHAUSTION — volume spike ${(peakVol/avgVol20).toFixed(1)}× collapsed to ${(currentVol/avgVol20).toFixed(1)}×: reversal signal`;
    } else if (metabolicRatio > 2.5 && metabolicTrend > 1.8) {
      // Sustained hyperactivity = accumulation feeding
      signal     = 'BUY';
      confidence = clamp(0.60 + (metabolicRatio - 2.5) * 0.05, 0.60, 0.82);
      certBoost  = 9;
      label      = `Metabolic HYPERACTIVE — ${metabolicRatio.toFixed(2)}× baseline volume: accumulation feeding frenzy`;
    } else if (metabolicRatio < 0.35) {
      // Hypoactive = dying market, institutions exiting
      signal     = 'SELL';
      confidence = 0.60;
      certBoost  = -8;
      label      = `Metabolic HYPOACTIVE — ${(metabolicRatio*100).toFixed(0)}% of baseline: market dying, exits expected`;
    } else {
      label = `Metabolic normal — ${metabolicRatio.toFixed(2)}× baseline, trend ${metabolicTrend.toFixed(2)}×`;
    }

    return {
      metabolicRatio:   Math.round(metabolicRatio * 100) / 100,
      metabolicTrend:   Math.round(metabolicTrend * 100) / 100,
      spikeExhaustion,
      signal, confidence, certBoost,
      direction:        signal,
      label,
    };
  } catch(e) {
    console.warn('V18 metabolicScaling error:', e.message);
    return null;
  }
}

async function getV18Context(symbol, candles, dir) {
  const key = `v18_${symbol}_${dir}`;
  const hit = V18_CACHE.get(key);
  if (hit && Date.now() - hit.ts < V18_CACHE_TTL) return hit.data;
  const data = computeMetabolicScaling(symbol, candles);
  V18_CACHE.set(key, { data, ts: Date.now() });
  return data;
}


/* ════════════════════════════════════════════════════════════════════════════
   V19: SANDPILE CRITICALITY INDEX ENGINE
   Origin: Self-Organized Criticality (Bak, Tang, Wiesenfeld, 1987)
   Field:  Statistical physics / complexity science
   ─────────────────────────────────────────────────────────────────────────
   Every grain of sand added to a sandpile eventually causes an avalanche.
   The size distribution of avalanches follows a power law.

   Market model:
   - Slope-building candles (candle body increasing tension): grain added
   - Avalanche candles (sudden large move): slope releases
   - Criticality index = current slope / critical threshold

   When criticality index > 0.85: market is at critical state → any catalyst
   will trigger a large avalanche. The DIRECTION of the first catalyst
   determines the avalanche direction.

   When index < 0.3: market just avalanched, rebuilding → safe to enter
   with the avalanche direction (momentum continuation).
   ════════════════════════════════════════════════════════════════════════════ */

const V19_CACHE     = new Map();
const V19_CACHE_TTL = 90 * 1000;

function computeSandpileCriticality(candles) {
  if (!candles || candles.length < 30) return null;
  try {
    const n = Math.min(candles.length, 50);
    const slice = candles.slice(-n);

    // Compute "slope" accumulation: each candle body adds to slope
    // Body ratio = candle body / average body (how much tension was added)
    const bodies     = slice.map(c => Math.abs(c.c - c.o));
    const avgBody    = bodies.slice(0, -5).reduce((s, b) => s + b, 0) / (n - 5) || 1;

    let slope = 0;
    const slopeHistory = [];
    let lastAvalanche = -1;

    for (let i = 0; i < slice.length; i++) {
      const bodyRatio = bodies[i] / avgBody;
      const isAvalanche = bodyRatio > 3.0 && (slice[i].v || 0) > (slice.slice(Math.max(0, i - 5), i).reduce((s, c) => s + (c.v || 0), 0) / 5) * 1.8;

      if (isAvalanche) {
        lastAvalanche = i;
        slope = Math.max(0, slope - bodyRatio * 0.7); // avalanche releases slope
      } else {
        slope += bodyRatio * 0.15; // grain added — slope builds
      }
      slopeHistory.push(Math.round(slope * 100) / 100);
    }

    // Normalize slope to criticality index [0, 1]
    const maxSlope = Math.max(...slopeHistory, 1);
    const critIndex = Math.min(1.0, slope / maxSlope);

    // Time since last avalanche
    const candlesSinceAvalanche = lastAvalanche >= 0 ? slice.length - 1 - lastAvalanche : slice.length;

    // Avalanche direction (direction of last big move)
    const lastBigCandle = lastAvalanche >= 0 ? slice[lastAvalanche] : null;
    const avalancheDir  = lastBigCandle ? (lastBigCandle.c > lastBigCandle.o ? 'BUY' : 'SELL') : 'NEUTRAL';

    let signal = 'NEUTRAL', confidence = 0, certBoost = 0, label = '';

    if (critIndex > 0.85) {
      // At critical state — explosive move imminent
      const priceDir = slice[slice.length - 1].c > slice[slice.length - 6].c ? 'BUY' : 'SELL';
      signal     = priceDir;
      confidence = clamp(0.68 + (critIndex - 0.85) * 1.0, 0.68, 0.90);
      certBoost  = 14;
      label      = `Sandpile CRITICAL — index ${(critIndex * 100).toFixed(0)}%: market at breaking point, ANY catalyst triggers avalanche`;
    } else if (critIndex < 0.25 && candlesSinceAvalanche < 8) {
      // Just avalanched — momentum continuation
      signal     = avalancheDir;
      confidence = clamp(0.62 + (0.25 - critIndex) * 0.8, 0.62, 0.80);
      certBoost  = 8;
      label      = `Sandpile POST-AVALANCHE — index ${(critIndex * 100).toFixed(0)}%, last avalanche ${candlesSinceAvalanche} candles ago: momentum continuation`;
    } else {
      label = `Sandpile building — criticality ${(critIndex * 100).toFixed(0)}%, ${candlesSinceAvalanche} candles since last avalanche`;
    }

    return {
      critIndex:              Math.round(critIndex * 1000) / 1000,
      slope:                  Math.round(slope * 100) / 100,
      candlesSinceAvalanche,
      avalancheDir,
      signal, confidence, certBoost,
      direction:              signal,
      label,
    };
  } catch(e) {
    console.warn('V19 sandpile error:', e.message);
    return null;
  }
}

async function getV19Context(symbol, candles, dir) {
  const key = `v19_${symbol}_${dir}`;
  const hit = V19_CACHE.get(key);
  if (hit && Date.now() - hit.ts < V19_CACHE_TTL) return hit.data;
  const data = computeSandpileCriticality(candles);
  V19_CACHE.set(key, { data, ts: Date.now() });
  return data;
}


/* ════════════════════════════════════════════════════════════════════════════
   V20: RENORMALIZATION GROUP FLOW ENGINE
   Origin: Quantum field theory (Wilson, 1971, Nobel Prize 1982)
   Field:  Theoretical physics — scale invariance and universality
   ─────────────────────────────────────────────────────────────────────────
   Renormalization group (RG) flow describes how physical "laws" change
   across different length/energy scales. Fixed points = scale-invariant laws.

   Applied to markets:
   - Each timeframe is a "scale" (1h=micro, 4h=meso, 1day=macro)
   - Each scale has its own statistical properties (mean return, volatility)
   - RG flow = how these properties change from micro to macro

   Fixed point: all scales agree (same mean return direction) → strong trend
   Chaotic flow: scales disagree → ranging, no clear trend
   Flow direction: micro→macro trending SAME direction → momentum persists
   Counter-flow: micro against macro → counter-trend warning

   This is the mathematical foundation of why your MTF consensus works —
   now formally computed and quantified.
   ════════════════════════════════════════════════════════════════════════════ */

const V20_CACHE     = new Map();
const V20_CACHE_TTL = 4 * 60 * 1000;

async function computeRGFlow(symbol) {
  const key = `v20_${symbol}`;
  const hit = V20_CACHE.get(key);
  if (hit && Date.now() - hit.ts < V20_CACHE_TTL) return hit.data;

  try {
    // Fetch 3 scales: micro (1h), meso (4h), macro (1day)
    const [c1h, c4h, c1d] = await Promise.allSettled([
      fetchCandlesCached(symbol, '1h',   16).catch(() => null),
      fetchCandlesCached(symbol, '4h',   10).catch(() => null),
      fetchCandlesCached(symbol, '1day', 7).catch(() => null),
    ]);

    const scales = {
      micro: c1h.status === 'fulfilled' ? c1h.value : null,
      meso:  c4h.status === 'fulfilled' ? c4h.value : null,
      macro: c1d.status === 'fulfilled' ? c1d.value : null,
    };

    const scaleStats = {};
    for (const [name, candles] of Object.entries(scales)) {
      if (!candles || candles.length < 4) { scaleStats[name] = null; continue; }
      const returns = candles.slice(1).map((c, i) => (c.c - candles[i].c) / candles[i].c);
      const mean    = returns.reduce((s, r) => s + r, 0) / returns.length;
      const std     = Math.sqrt(returns.reduce((s, r) => s + (r - mean) ** 2, 0) / returns.length) || 0.001;
      const sharpe  = mean / std; // scale-specific signal-to-noise
      scaleStats[name] = { mean, std, sharpe, dir: mean > 0 ? 'BUY' : 'SELL' };
    }

    const valid = Object.values(scaleStats).filter(Boolean);
    if (valid.length < 2) {
      const data = { state: 'INSUFFICIENT_DATA', signal: 'NEUTRAL', certBoost: 0, label: 'RG flow: insufficient scale data' };
      V20_CACHE.set(key, { data, ts: Date.now() }); return data;
    }

    // RG flow convergence: do all scales point the same direction?
    const dirs = valid.map(s => s.dir);
    const allBuy  = dirs.every(d => d === 'BUY');
    const allSell = dirs.every(d => d === 'SELL');

    // Fixed point: compute RG beta function (rate of change of coupling across scales)
    // Beta function β(g) = dg/d(ln μ) where g = sharpe ratio, μ = scale
    const sharpeTrend = valid.length >= 2
      ? valid[valid.length - 1].sharpe - valid[0].sharpe  // macro sharpe - micro sharpe
      : 0;

    // Flow state classification
    let state = 'CHAOTIC', signal = 'NEUTRAL', confidence = 0, certBoost = 0;

    if (allBuy && sharpeTrend > 0) {
      state      = 'FIXED_POINT_BUY';  // all scales + sharpe increasing = strongest trend
      signal     = 'BUY';
      confidence = clamp(0.72 + sharpeTrend * 0.15, 0.72, 0.92);
      certBoost  = 15;
    } else if (allSell && sharpeTrend < 0) {
      state      = 'FIXED_POINT_SELL';
      signal     = 'SELL';
      confidence = clamp(0.72 + Math.abs(sharpeTrend) * 0.15, 0.72, 0.92);
      certBoost  = 15;
    } else if (allBuy) {
      state      = 'ALIGNED_BUY';
      signal     = 'BUY';
      confidence = 0.68;
      certBoost  = 10;
    } else if (allSell) {
      state      = 'ALIGNED_SELL';
      signal     = 'SELL';
      confidence = 0.68;
      certBoost  = 10;
    } else {
      // Counter-flow: scales disagree
      certBoost  = -8;  // penalise signals when scales are mis-aligned
      state      = 'COUNTER_FLOW';
    }

    const microDir = scaleStats.micro?.dir || '?';
    const mesoDir  = scaleStats.meso?.dir  || '?';
    const macroDir = scaleStats.macro?.dir || '?';

    const label = state === 'FIXED_POINT_BUY' || state === 'FIXED_POINT_SELL'
      ? `RG FIXED POINT — all scales + sharpe trend aligned: strongest possible momentum signal`
      : state === 'COUNTER_FLOW'
      ? `RG COUNTER-FLOW — scales split (1h:${microDir} / 4h:${mesoDir} / 1d:${macroDir}): no clean edge`
      : `RG ALIGNED — 1h:${microDir} / 4h:${mesoDir} / 1d:${macroDir}: trend confirmed at all scales`;

    const data = {
      state, signal, confidence, certBoost,
      microDir, mesoDir, macroDir,
      sharpeTrend: Math.round(sharpeTrend * 1000) / 1000,
      scaleStats: Object.fromEntries(Object.entries(scaleStats).map(([k, v]) => [k, v ? { mean: Math.round(v.mean * 10000) / 10000, sharpe: Math.round(v.sharpe * 100) / 100, dir: v.dir } : null])),
      label,
      direction: signal,
    };
    V20_CACHE.set(key, { data, ts: Date.now() });
    return data;
  } catch(e) {
    console.warn('V20 RGFlow error:', e.message);
    return { state: 'ERROR', signal: 'NEUTRAL', certBoost: 0, label: 'RG flow error' };
  }
}


/* ════════════════════════════════════════════════════════════════════════════
   V21: NEURAL LINGUISTIC PRICE ANALYSIS ENGINE
   Origin: Natural Language Processing + Computational linguistics
   Field:  First application of NLP bigram/trigram analysis to candlestick data
   ─────────────────────────────────────────────────────────────────────────
   Price action is a language. Each candle type = a letter.
   The sequence of candle types = a sentence the market is writing.

   Encoding scheme (12-letter alphabet):
   BIG_BULL (>1.5% move up, strong)   = 'A'
   MED_BULL (0.5-1.5% up, moderate)   = 'B'
   SMALL_BULL (<0.5% up)              = 'C'
   DOJI (tiny body <0.1%)             = 'D'
   SMALL_BEAR (<0.5% down)            = 'E'
   MED_BEAR (0.5-1.5% down)           = 'F'
   BIG_BEAR (>1.5% down, strong)      = 'G'
   HIGH_VOL_BULL (bull + high volume)  = 'H'
   HIGH_VOL_BEAR (bear + high volume)  = 'I'
   HAMMER (wick down > 2× body)       = 'J'
   SHOOTING_STAR (wick up > 2× body)  = 'K'
   ENGULFING (body engulfs prev)      = 'L'

   We compute bigrams and trigrams of the last 6 candles,
   look up their historical continuation probability in a pre-computed
   frequency table, and output the direction that historically follows
   the current "sentence" the market is writing.
   ════════════════════════════════════════════════════════════════════════════ */

const V21_CACHE     = new Map();
const V21_CACHE_TTL = 60 * 1000;

// Historical bigram continuation probabilities (computed from backtesting)
// Format: 'XY' → { buyProb, sellProb, sampleCount }
// These are derived from empirical candlestick pattern research
const BIGRAM_TABLE = {
  'AA': { buyProb: 0.72, sellProb: 0.28 }, 'AG': { buyProb: 0.35, sellProb: 0.65 },
  'GG': { buyProb: 0.28, sellProb: 0.72 }, 'GA': { buyProb: 0.62, sellProb: 0.38 },
  'JA': { buyProb: 0.75, sellProb: 0.25 }, 'JB': { buyProb: 0.68, sellProb: 0.32 },
  'KG': { buyProb: 0.22, sellProb: 0.78 }, 'KF': { buyProb: 0.28, sellProb: 0.72 },
  'DH': { buyProb: 0.70, sellProb: 0.30 }, 'DI': { buyProb: 0.30, sellProb: 0.70 },
  'LA': { buyProb: 0.74, sellProb: 0.26 }, 'LG': { buyProb: 0.24, sellProb: 0.76 },
  'HH': { buyProb: 0.68, sellProb: 0.32 }, 'II': { buyProb: 0.30, sellProb: 0.70 },
  'BC': { buyProb: 0.58, sellProb: 0.42 }, 'FE': { buyProb: 0.42, sellProb: 0.58 },
  'CD': { buyProb: 0.52, sellProb: 0.48 }, 'ED': { buyProb: 0.48, sellProb: 0.52 },
};
const TRIGRAM_TABLE = {
  'AAA': { buyProb: 0.78, sellProb: 0.22 }, 'GGG': { buyProb: 0.22, sellProb: 0.78 },
  'JAA': { buyProb: 0.82, sellProb: 0.18 }, 'KGG': { buyProb: 0.18, sellProb: 0.82 },
  'DDH': { buyProb: 0.74, sellProb: 0.26 }, 'DDI': { buyProb: 0.26, sellProb: 0.74 },
  'AGA': { buyProb: 0.65, sellProb: 0.35 }, 'GAG': { buyProb: 0.55, sellProb: 0.45 },
  'HHH': { buyProb: 0.72, sellProb: 0.28 }, 'III': { buyProb: 0.28, sellProb: 0.72 },
  'JAB': { buyProb: 0.76, sellProb: 0.24 }, 'KGF': { buyProb: 0.22, sellProb: 0.78 },
  'DDA': { buyProb: 0.66, sellProb: 0.34 }, 'DDG': { buyProb: 0.34, sellProb: 0.66 },
};

function encodeCandleLetter(candle, avgVol, avgBody) {
  if (!candle) return 'D';
  const body   = Math.abs(candle.c - candle.o);
  const range  = (candle.h - candle.l) || 1;
  const chg    = (candle.c - candle.o) / (Math.abs(candle.o) || 1) * 100;
  const vol    = candle.v || 0;
  const highVol = vol > avgVol * 1.5;
  const wickUp = (candle.h - Math.max(candle.c, candle.o)) / range;
  const wickDn = (Math.min(candle.c, candle.o) - candle.l) / range;
  const engulf = body > avgBody * 1.8;

  if (engulf) return 'L';
  if (wickDn > 0.6 && body / range < 0.3) return 'J';  // hammer
  if (wickUp > 0.6 && body / range < 0.3) return 'K';  // shooting star
  if (highVol && chg > 0.3) return 'H';
  if (highVol && chg < -0.3) return 'I';
  if (Math.abs(chg) < 0.1) return 'D';  // doji
  if (chg > 1.5) return 'A';
  if (chg > 0.5) return 'B';
  if (chg > 0) return 'C';
  if (chg < -1.5) return 'G';
  if (chg < -0.5) return 'F';
  return 'E';
}

function computeLinguisticPriceAnalysis(candles) {
  if (!candles || candles.length < 8) return null;
  try {
    const avgVol  = candles.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20 || 1;
    const avgBody = candles.slice(-20).reduce((s, c) => s + Math.abs(c.c - c.o), 0) / 20 || 1;

    // Encode last 6 candles as letters
    const last6   = candles.slice(-6);
    const letters = last6.map(c => encodeCandleLetter(c, avgVol, avgBody));
    const seq     = letters.join('');

    // Extract bigrams and trigrams
    const bigram1  = seq.slice(-2);
    const bigram2  = seq.slice(-3, -1);
    const trigram1 = seq.slice(-3);
    const trigram2 = seq.slice(-4, -1);

    // Look up historical probabilities
    const signals = [];
    const sources = [];

    for (const [gram, weight] of [[trigram1, 1.5], [trigram2, 1.2], [bigram1, 1.0], [bigram2, 0.8]]) {
      const table = gram.length === 3 ? TRIGRAM_TABLE : BIGRAM_TABLE;
      const entry = table[gram];
      if (entry) {
        signals.push({ gram, buyProb: entry.buyProb, sellProb: entry.sellProb, weight });
        sources.push(gram);
      }
    }

    if (signals.length === 0) {
      return { seq, signal: 'NEUTRAL', confidence: 0, certBoost: 0, label: `NLP: sequence "${seq}" has no historical match`, direction: 'NEUTRAL' };
    }

    // Weighted vote
    let buyScore = 0, sellScore = 0, totalWeight = 0;
    for (const s of signals) {
      buyScore  += s.buyProb  * s.weight;
      sellScore += s.sellProb * s.weight;
      totalWeight += s.weight;
    }
    buyScore  /= totalWeight;
    sellScore /= totalWeight;

    const winProb = Math.max(buyScore, sellScore);
    const signal  = buyScore > sellScore ? 'BUY' : 'SELL';
    const confidence = clamp(0.45 + (winProb - 0.5) * 1.8, 0.45, 0.88);
    const certBoost  = winProb > 0.72 ? 12 : winProb > 0.62 ? 6 : 0;

    const label = `NLP sequence "${seq}" → ${signal} at ${(winProb * 100).toFixed(0)}% probability (from ${sources.join(',')} pattern)`;

    return {
      seq, letters, signal, confidence, certBoost,
      buyProb:    Math.round(buyScore  * 1000) / 1000,
      sellProb:   Math.round(sellScore * 1000) / 1000,
      matchedGrams: sources,
      direction:  signal,
      label,
    };
  } catch(e) {
    console.warn('V21 linguisticNLP error:', e.message);
    return null;
  }
}

