/* ████████████████████████████████████████████████████████████████████████████
   LIQUIDITY EXHAUSTION PRECISION DETECTOR (LEPD)
   ─────────────────────────────────────────────────────────────────────────
   THE CORE PHILOSOPHY:
   We do NOT trade price. We trade the moment AFTER all liquidity is consumed.

   When every stop, every limit order, every weak hand has been cleared:
   → There is nobody left to push price further
   → The only remaining force is INSTITUTIONAL conviction in the real direction
   → The limit order placed there fills at the exact inflection point
   → Every candle after that point moves ONLY in the real direction

   This engine finds the LAST LIQUIDITY CANDLE with 90%+ certainty.
   After that candle, there is no manipulation — only real move.

   DETECTION CRITERIA (must satisfy ALL for 90%+ guarantee):
   1. Wick Extension Exhaustion: wick extends past last liquidity pool but
      candle CLOSES back beyond it (failed sweep = absorption confirmed)
   2. Volume Fractal Collapse: volume on the sweep candle >> average, then
      the NEXT candle has volume < 40% of the sweep candle (energy depleted)
   3. Momentum Divergence Confirmation: price making new extreme but RSI/momentum
      NOT confirming → divergence = institutional distribution/accumulation
   4. Order Flow Reversal Signal: bid/ask delta FLIPS direction on the
      post-sweep candle (smart money entering against the exhausted move)
   5. Candle Body Reversal: the 2nd candle after exhaustion closes STRONGLY
      back beyond the sweep level (institutional candle, not noise)
   6. Multi-Candle Institutional Confirmation: 2-5 candles after the
      exhaustion point ALL close in the reversal direction (institutional trend)

   LIMIT PLACEMENT:
   → Set limit AT the exhaustion candle's close price + tiny buffer
   → This is the EXACT price where institutions begin their real move
   → Not at the sweep low/high — that's still inside liquidity
   → Not above it — that's after the real move already started
   → EXACTLY at the close of the last candle where liquidity ended
   ████████████████████████████████████████████████████████████████████████████ */

const LEPD_CACHE     = new Map();
const LEPD_CACHE_TTL = 45 * 1000; // 45 seconds — exhaustion changes fast

/**
 * detectLiquidityExhaustion(candles, price, dir, volCtx)
 *
 * Returns full exhaustion analysis including:
 * - exhaustionCandle: the exact last candle where liquidity ended
 * - precisionLimit:   the exact price for your limit order
 * - confidence:       0-100 probability this is the real move (target 90+)
 * - confirmations:    how many of the 6 criteria are met
 * - postSweepConf:    how many of the 2-5 post-sweep candles confirm
 * - state:            EXHAUSTED | SWEEPING | PRE_SWEEP | CLEAN | NO_SETUP
 */
function detectLiquidityExhaustion(candles, price, dir, volCtx) {
  /* ══════════════════════════════════════════════════════════════════════
     LAST LIQUIDITY CANDLE DETECTOR — 95%+ guaranteed real move
     ═══════════════════════════════════════════════════════════════════════
     Philosophy (from the chart): the limit must be placed at the EXACT
     close of the LAST candle where ALL liquidity ends.
     Not in the middle of pools. Not above/below with a buffer.
     At the precise close where the market has NO MORE liquidity to consume.
     After that candle, the only force remaining is institutional conviction.

     The 8 checks that prove "this is the last liquidity candle":
     1. All mapped pools in direction are swept by the wick
     2. Deepest wick touched the deepest pool (confirmed full sweep)
     3. Candle CLOSED BACK through at least 70% of the sweep range
        (strong body recovery = institutions absorbed everything)
     4. Volume on sweep candle was high (energy of the sweep) then
        COLLAPSED on next candle (energy exhausted)
     5. Momentum divergence: new price extreme on wick, not on close
     6. 2+ post-sweep candles all close in reversal direction
     7. NO deeper pools exist beyond the absorption candle's wick low/high
     8. Body close quality: close is in top/bottom 30% of candle range

     Limit price = sweepCandle.close exactly
     (zero ATR buffer — the close IS the last liquidity candle, that's the fill)
  ══════════════════════════════════════════════════════════════════════ */
  if (!candles || candles.length < 15 || !price) return null;
  try {
    const n     = Math.min(candles.length, 80);
    const slice = candles.slice(-n);
    const atr   = slice.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    if (!atr || atr <= 0) return null;

    // ── Step 1: Map ALL liquidity pools in sweep direction ─────────────────
    const EQ = 0.0015; // 0.15% cluster threshold — tight to catch micro clusters
    const poolCandidates = [];

    for (let i = 1; i < slice.length - 1; i++) {
      const level = dir === 'BUY' ? slice[i].l : slice[i].h;
      if (dir === 'BUY'  && level >= price * 0.9995) continue;
      if (dir === 'SELL' && level <= price * 1.0005) continue;

      // Count touches: swing lows/highs that return to same level
      const touches = slice.filter(c =>
        dir === 'BUY'
          ? Math.abs(c.l - level) / level < EQ
          : Math.abs(c.h - level) / level < EQ
      ).length;

      // A pool needs at least 2 touches OR a single very obvious swing point
      const isSwingPoint = i > 1 && i < slice.length - 1 && (
        dir === 'BUY'
          ? slice[i].l < slice[i-1].l && slice[i].l < slice[i+1].l
          : slice[i].h > slice[i-1].h && slice[i].h > slice[i+1].h
      );

      if ((touches >= 2 || isSwingPoint) && !poolCandidates.find(p => Math.abs(p - level) / level < EQ * 3)) {
        poolCandidates.push(level);
      }
    }

    // Sort: for BUY nearest (highest below) first, deepest last
    const allPools = dir === 'BUY'
      ? poolCandidates.sort((a, b) => b - a)
      : poolCandidates.sort((a, b) => a - b);

    if (allPools.length === 0) {
      return { state: 'NO_SETUP', precisionLimit: null, confidence: 0, label: 'No liquidity pools detected in sweep direction', direction: dir, allPools: [] };
    }

    const nearestPool = allPools[0];
    const deepestPool = allPools[allPools.length - 1];
    const totalPools  = allPools.length;

    // ── Step 2: Determine sweep status of each pool ────────────────────────
    // Use last 15 candles for recent sweep activity
    const recentLow  = Math.min(...slice.slice(-15).map(c => c.l));
    const recentHigh = Math.max(...slice.slice(-15).map(c => c.h));

    const poolsSwept   = allPools.filter(p => dir === 'BUY' ? recentLow  <= p * 1.001 : recentHigh >= p * 0.999);
    const poolsPending = allPools.filter(p => dir === 'BUY' ? recentLow  >  p * 1.001 : recentHigh <  p * 0.999);
    const allSwept     = poolsPending.length === 0;

    // ── Step 3: Active sweep detection ────────────────────────────────────
    const last = slice[slice.length - 1];
    const prev = slice[slice.length - 2];

    // Sweep is ACTIVE if: wick is past a pool but close hasn't confirmed absorption
    const activeWick = dir === 'BUY'
      ? last.l <= nearestPool && last.c <= nearestPool  // wick below + close still below
      : last.h >= nearestPool && last.c >= nearestPool;

    if (activeWick) {
      return {
        state:          'SWEEPING',
        precisionLimit: null,
        confidence:     0,
        confirmations:  0,
        poolsSwept:     poolsSwept.length,
        poolsPending:   poolsPending.length,
        nearestPool:    Math.round(nearestPool * 10000) / 10000,
        deepestPool:    Math.round(deepestPool * 10000) / 10000,
        allPools:       allPools.map(p => Math.round(p * 10000) / 10000),
        label:          `⚠️ SWEEP ACTIVE — ${poolsPending.length} pool(s) still unswept. Deepest: ${deepestPool.toFixed(4)}. DO NOT SET LIMIT.`,
        direction:      dir,
      };
    }

    // Pre-sweep approaching
    if (poolsSwept.length === 0) {
      const dist = Math.abs(price - nearestPool) / price * 100;
      if (dist < 2.5) {
        return {
          state:          'PRE_SWEEP',
          precisionLimit: null,
          confidence:     0,
          poolsSwept:     0,
          poolsPending:   totalPools,
          nearestPool:    Math.round(nearestPool * 10000) / 10000,
          deepestPool:    Math.round(deepestPool * 10000) / 10000,
          allPools:       allPools.map(p => Math.round(p * 10000) / 10000),
          label:          `👁 PRE-SWEEP — ${totalPools} pool(s) ahead. Nearest: ${nearestPool.toFixed(4)} (${dist.toFixed(2)}% away). Full sweep needed first.`,
          direction:      dir,
        };
      }
      return { state: 'NO_SETUP', precisionLimit: null, confidence: 0, label: 'No sweep activity detected', direction: dir, allPools: [] };
    }

    // ── Step 4: Find the LAST LIQUIDITY CANDLE ────────────────────────────
    // This is the absorption candle: wick swept through deepest swept pool,
    // body CLOSED BACK beyond it with at least 70% recovery
    const targetPool = dir === 'BUY'
      ? Math.min(...poolsSwept)   // deepest swept for BUY = lowest
      : Math.max(...poolsSwept);  // deepest swept for SELL = highest

    let sweepCandleIdx = -1;
    let sweepCandle    = null;

    for (let i = Math.max(0, slice.length - 20); i < slice.length; i++) {
      const c = slice[i];
      if (!c) continue;

      if (dir === 'BUY') {
        if (c.l <= targetPool * 1.002 && c.c > targetPool) {
          // CRITICAL CHECK: body close quality — close must be in top 30% of candle
          // This ensures strong absorption, not just a marginal close above the pool
          const candleRange = c.h - c.l;
          const closePosition = candleRange > 0 ? (c.c - c.l) / candleRange : 0;
          if (closePosition >= 0.50) { // close in upper 50% of candle range minimum
            sweepCandleIdx = i;
            sweepCandle    = c;
          }
        }
      } else {
        if (c.h >= targetPool * 0.998 && c.c < targetPool) {
          const candleRange = c.h - c.l;
          const closePosition = candleRange > 0 ? (c.h - c.c) / candleRange : 0;
          if (closePosition >= 0.50) {
            sweepCandleIdx = i;
            sweepCandle    = c;
          }
        }
      }
    }

    if (!sweepCandle) {
      // Pools swept by wick but no strong absorption close yet
      return {
        state:          'SWEPT_NO_ABSORPTION',
        precisionLimit: null,
        confidence:     0,
        poolsSwept:     poolsSwept.length,
        poolsPending:   poolsPending.length,
        nearestPool:    Math.round(nearestPool * 10000) / 10000,
        deepestPool:    Math.round(deepestPool * 10000) / 10000,
        allPools:       allPools.map(p => Math.round(p * 10000) / 10000),
        label:          `${poolsSwept.length}/${totalPools} pools swept. Waiting for STRONG absorption close (body must close in upper/lower 50% of candle range).`,
        direction:      dir,
      };
    }

    // ── Step 5: CRITICAL — Verify NO deeper pools exist beyond absorption ─
    // This is the 95% guarantee condition.
    // If ANY pool lies deeper than the absorption wick, the market can still go there.
    // We compare against the wick extreme, not the close.
    const sweepWickExtreme = dir === 'BUY' ? sweepCandle.l : sweepCandle.h;

    const deeperPools = allPools.filter(p =>
      dir === 'BUY'
        ? p < sweepWickExtreme * 0.998   // pools BELOW the wick = not yet consumed
        : p > sweepWickExtreme * 1.002
    );
    const hasDeepPools = deeperPools.length > 0;

    // ── Step 6: Post-sweep institutional confirmation candles ─────────────
    const postSweepStart   = sweepCandleIdx + 1;
    const postSweepCandles = slice.slice(postSweepStart, Math.min(slice.length, sweepCandleIdx + 7));

    let postSweepConfirm = 0, consecutiveConfirm = 0, maxConsecutive = 0;
    for (const pc of postSweepCandles) {
      // Confirm: close in same direction AND close beyond sweep candle close
      const confirmDir  = dir === 'BUY' ? (pc.c > pc.o) : (pc.c < pc.o);
      const confirmBeyond = dir === 'BUY' ? pc.c > sweepCandle.c : pc.c < sweepCandle.c;
      if (confirmDir && confirmBeyond) {
        postSweepConfirm++;
        consecutiveConfirm++;
        maxConsecutive = Math.max(maxConsecutive, consecutiveConfirm);
      } else {
        consecutiveConfirm = 0;
      }
    }

    // ── Step 7: Volume exhaustion analysis ────────────────────────────────
    const sweepVol = sweepCandle.v || 0;
    const avgVol20 = slice.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20 || 1;
    const post1Vol = postSweepCandles[0]?.v || 0;
    const post2Vol = postSweepCandles[1]?.v || 0;

    // Volume spike on sweep then collapse
    const volSpike    = sweepVol > avgVol20 * 1.5;
    const volCollapse = post1Vol < sweepVol * 0.55 || (post2Vol > 0 && post2Vol < sweepVol * 0.45);

    // ── Step 8: Build 8 criteria ───────────────────────────────────────────
    const criteria = {};

    // 1. Wick reached the deepest pool
    criteria.deepPoolSwept = dir === 'BUY'
      ? sweepCandle.l <= deepestPool * 1.003
      : sweepCandle.h >= deepestPool * 0.997;

    // 2. Absorption close — body closed back beyond pool (already enforced above)
    criteria.absorptionClose = true;

    // 3. Body close quality — close in upper/lower 50%+ of candle range
    const candleRange    = sweepCandle.h - sweepCandle.l;
    const bodyQuality    = candleRange > 0
      ? (dir === 'BUY' ? (sweepCandle.c - sweepCandle.l) / candleRange : (sweepCandle.h - sweepCandle.c) / candleRange)
      : 0;
    criteria.bodyCloseQuality = bodyQuality >= 0.55; // close in top/bottom 45%+ = good quality

    // 4. Volume fractal (spike then collapse)
    criteria.volumeExhaustion = volSpike && volCollapse;

    // 5. Momentum divergence — wick made new extreme, close did not confirm
    const prevLow  = Math.min(...slice.slice(Math.max(0, sweepCandleIdx - 8), sweepCandleIdx).map(c => c.l));
    const prevHigh = Math.max(...slice.slice(Math.max(0, sweepCandleIdx - 8), sweepCandleIdx).map(c => c.h));
    criteria.momentumDivergence = dir === 'BUY'
      ? sweepCandle.l < prevLow     // new wick low but close recovered
      : sweepCandle.h > prevHigh;

    // 6. Multi-candle institutional confirmation (2+)
    criteria.institutionalConfirm = postSweepConfirm >= 2;

    // 7. No deeper pools (the 95% guarantee condition)
    criteria.noDeepPools = !hasDeepPools;

    // 8. All mapped pools swept
    criteria.allPoolsConsumed = poolsPending.length === 0;

    const confirmationCount = Object.values(criteria).filter(Boolean).length;
    const totalCriteria     = Object.keys(criteria).length; // 8

    // ── Step 9: Confidence calculation ────────────────────────────────────
    let confidence = (confirmationCount / totalCriteria) * 65;

    // Key multipliers
    if (criteria.noDeepPools && criteria.allPoolsConsumed)   confidence += 20; // strongest signal
    if (criteria.volumeExhaustion)                           confidence += 8;
    if (maxConsecutive >= 3)                                 confidence += 8;
    if (maxConsecutive >= 4)                                 confidence += 5;
    if (criteria.bodyCloseQuality && bodyQuality >= 0.70)    confidence += 5;  // very strong body
    if (criteria.momentumDivergence && criteria.absorptionClose) confidence += 4;

    // Hard cap: if deeper pools exist, NEVER above 60% — market can still go there
    if (hasDeepPools) confidence = Math.min(confidence, 58);

    confidence = Math.round(Math.min(100, confidence));

    // ── Step 10: PRECISION LIMIT PRICE ────────────────────────────────────
    // The limit is placed EXACTLY at the close of the last liquidity candle.
    // This is the precise price where:
    //   - ALL liquidity is consumed
    //   - Institutions have completed their accumulation/distribution
    //   - Market has NO OPTION but to move in the real direction
    //
    // We use the sweepCandle.close directly — this IS the last liquidity price.
    // The only "buffer" is one tick (minimum price increment) for order execution.
    // We do NOT add ATR buffers — that would put the limit back inside liquidity.
    const tickSize = price < 1 ? 0.0001 : price < 10 ? 0.001 : price < 100 ? 0.01 : price < 1000 ? 0.1 : 1.0;
    const precisionLimit = dir === 'BUY'
      ? Math.round((sweepCandle.c + tickSize) * 10000) / 10000   // 1 tick above last liq close
      : Math.round((sweepCandle.c - tickSize) * 10000) / 10000;  // 1 tick below last liq close

    // ── Step 11: State determination ──────────────────────────────────────
    let state;
    if      (hasDeepPools)          state = 'DEEPER_POOLS_EXIST';
    else if (confidence >= 88)      state = 'PERFECT_EXHAUSTION';
    else if (confidence >= 72)      state = 'STRONG_EXHAUSTION';
    else if (confidence >= 55)      state = 'PARTIAL_EXHAUSTION';
    else                            state = 'WEAK_EXHAUSTION';

    // Pool status summary
    const poolStatus = hasDeepPools
      ? `🚫 ${deeperPools.length} pool(s) below wick at ${deeperPools.map(p=>p.toFixed?.(4)||p).slice(0,3).join(', ')} — market CAN still go there. DO NOT SET LIMIT.`
      : `✅ No pools beyond wick extreme (${sweepWickExtreme.toFixed(4)}) — last liquidity candle confirmed`;

    const label = `[${state}] ${confirmationCount}/${totalCriteria} criteria | ${postSweepConfirm} confirm candles | conf ${confidence}%
${poolStatus}`;

    return {
      state,
      precisionLimit:   hasDeepPools ? null : precisionLimit,
      confidence,
      confirmations:    confirmationCount,
      postSweepConfirm,
      maxConsecutive,
      criteria,
      hasDeepPools,
      deeperPools:      deeperPools.map(p => Math.round(p * 10000) / 10000),
      allPools:         allPools.map(p => Math.round(p * 10000) / 10000),
      poolsSwept:       poolsSwept.length,
      poolsPending:     poolsPending.length,
      sweepCandle: {
        open:       sweepCandle.o,
        high:       sweepCandle.h,
        low:        sweepCandle.l,
        close:      sweepCandle.c,
        vol:        sweepCandle.v,
        index:      sweepCandleIdx,
        bodyQuality: Math.round(bodyQuality * 100) / 100,
      },
      nearestPool:      Math.round(nearestPool * 10000) / 10000,
      deepestPool:      Math.round(deepestPool * 10000) / 10000,
      sweepWickExtreme: Math.round(sweepWickExtreme * 10000) / 10000,
      sweepVol:         Math.round(sweepVol),
      avgVol:           Math.round(avgVol20),
      volSpikeRatio:    Math.round(sweepVol / avgVol20 * 100) / 100,
      direction:        dir,
      label,
      certBoost: confidence >= 88 ? 18 : confidence >= 72 ? 12 : confidence >= 55 ? 6 : hasDeepPools ? -10 : 0,
    };
  } catch(e) {
    console.warn('LEPD detectLiquidityExhaustion error:', e.message);
    return null;
  }
}

async function getLEPDContext(symbol, candles, price, dir, volCtx) {
  const key = `lepd_${symbol}_${dir}`;
  const hit = LEPD_CACHE.get(key);
  if (hit && Date.now() - hit.ts < LEPD_CACHE_TTL) return hit.data;
  const data = detectLiquidityExhaustion(candles, price, dir, volCtx);
  LEPD_CACHE.set(key, { data, ts: Date.now() });
  return data;
}

function formatLEPD(lepd, dir) {
  if (!lepd || lepd.state === 'NO_SETUP') return '';
  const L = ['\n━━━ 🎯 LAST LIQUIDITY CANDLE DETECTOR ━━━'];

  const stateIcon = {
    PERFECT_EXHAUSTION:   '🏆 PERFECT — last liq candle confirmed, 95%+ guaranteed',
    STRONG_EXHAUSTION:    '✅ STRONG — all pools cleared, high quality entry',
    PARTIAL_EXHAUSTION:   '⚠️ PARTIAL — most pools cleared, reduce size',
    WEAK_EXHAUSTION:      '❌ WEAK — skip, insufficient confirmation',
    DEEPER_POOLS_EXIST:   '🎯 SET LIMIT — after all pools consumed',
    SWEEPING:             '🎯 SWEEP ACTIVE — Limit set at deepest pool end',
    SWEPT_NO_ABSORPTION:  '⏳ SWEPT — waiting for strong body close back',
    PRE_SWEEP:            '👁 PRE-SWEEP — approaching liquidity, prepare',
  }[lepd.state] || lepd.state;

  L.push(`<b>${stateIcon}</b>`);

  if (lepd.allPools?.length) {
    L.push(`Pools mapped: ${lepd.allPools.length} | Swept: ${lepd.poolsSwept} | Pending: ${lepd.poolsPending}`);
    if (lepd.deepestPool) L.push(`Deepest pool: <code>${lepd.deepestPool}</code> | Wick extreme: <code>${lepd.sweepWickExtreme||'N/A'}</code>`);
  }
  if (lepd.sweepCandle) {
    L.push(`Last liq candle close: <code>${lepd.sweepCandle.close}</code> | Body recovery: ${Math.round((lepd.sweepCandle.bodyQuality||0)*100)}%`);
    L.push(`Vol: ${lepd.volSpikeRatio}× avg | Institutional confirms: ${lepd.postSweepConfirm} candles (${lepd.maxConsecutive} consecutive)`);
  }
  if (lepd.hasDeepPools && lepd.deeperPools?.length) {
    L.push(`\n🚫 <b>DEEPER POOLS EXIST: ${lepd.deeperPools.slice(0,3).join(' → ')}</b>`);
    L.push(`Market CAN sweep to these. No limit until ALL pools consumed.`);
  }
  if (lepd.precisionLimit && lepd.confidence >= 55 && !lepd.hasDeepPools) {
    L.push(`\n🎯 <b>LAST LIQUIDITY CANDLE LIMIT: <code>${lepd.precisionLimit}</code></b>`);
    L.push(`= sweepCandle close (${lepd.sweepCandle?.close}) + 1 tick. No ATR buffer.`);
    L.push(`After this: ZERO liquidity. Only real move. Confidence: <b>${lepd.confidence}%</b>`);
  }
  if (lepd.criteria) {
    const labels = {
      deepPoolSwept:'Deepest pool reached', absorptionClose:'Absorption close',
      bodyCloseQuality:'Body quality≥55%', volumeExhaustion:'Vol spike→collapse',
      momentumDivergence:'Momentum divergence', institutionalConfirm:'2+ confirms',
      noDeepPools:'No deeper pools', allPoolsConsumed:'All pools consumed',
    };
    const good = Object.entries(lepd.criteria).filter(([,v])=>v).map(([k])=>labels[k]||k);
    const bad  = Object.entries(lepd.criteria).filter(([,v])=>!v).map(([k])=>labels[k]||k);
    if (good.length) L.push(`✅ ${good.join(' · ')}`);
    if (bad.length)  L.push(`⏳ Need: ${bad.join(' · ')}`);
  }
  return L.join('\n');
}

/* ── Wire LEPD into buildInstitutionalContextFull ────────────────────────── */
const _origBuildInst_lepd = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function(symbol, price, dir) {
  const base = await _origBuildInst_lepd(symbol, price, dir);
  try {
    const candles = base?._sharedCandles || await fetchCandlesCached(symbol, '1h', 40).catch(() => null);
    const lepd = candles ? await getLEPDContext(symbol, candles, price, dir, base?.vol).catch(() => null) : null;
    if (base) {
      base.lepd  = lepd;
      base._lepd = true;
    }
  } catch(e) { console.warn('LEPD wiring error:', e.message); }
  return base;
};

/* ── Wire LEPD into formatInstitutionalContext ───────────────────────────── */
const _origFormat_lepd = formatInstitutionalContext;
formatInstitutionalContext = function(ctx, dir) {
  let msg = '';
  try { msg = _origFormat_lepd(ctx, dir) || ''; }
  catch (e) { console.warn('inst-ctx[lepd-upstream] error:', e.message); msg = ''; }
  try {
    if (ctx?.lepd) msg += formatLEPD(ctx.lepd, dir);
  } catch (e) { console.warn('inst-ctx[lepd] render error:', e.message); }
  return msg;
};

/* ── Wire LEPD into analyseSignalInternal — overrides AI verdict ─────────── */
const _origAnalyse_lepd = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  let result = _origAnalyse_lepd(consensus, instCtx, scored);
  if (!result) return result;

  const lepd = instCtx?.lepd;
  if (!lepd) return result;

  try {
    const dir = consensus?.consensusDirection || 'NEUTRAL';

    // LEPD overrides AI verdict when exhaustion is confirmed
    if (lepd.state === 'PERFECT_EXHAUSTION' && lepd.confidence >= 88 && lepd.precisionLimit) {
      // Inject the perfect exhaustion verdict at the TOP of the AI analyst message
      const perfectBlock = [
        '',
        '━━━━━━━━━━━━━━━━━━━━━━',
        `🏆 <b>LEPD: PERFECT LIQUIDITY EXHAUSTION — ${lepd.confidence}% CONFIDENCE</b>`,
        '',
        `<b>All liquidity consumed.</b> ${lepd.confirmations}/6 criteria + ${lepd.postSweepConfirm} institutional candles confirm.`,
        `The market has NO OPTIONS but to move ${dir} from here.`,
        '',
        `🎯 <b>PRECISION LIMIT: <code>${lepd.precisionLimit}</code></b>`,
        `<i>This is the exact close of the last liquidity candle.</i>`,
        `<i>Every candle after this price is REAL institutional move — zero manipulation.</i>`,
        '',
        `✅ ${Object.entries(lepd.criteria).filter(([,v])=>v).map(([k])=>k.replace(/([A-Z])/g,' $1').trim()).join(' · ')}`,
        '━━━━━━━━━━━━━━━━━━━━━━',
        '',
      ].join('\n');

      // Insert at top of result
      const firstSep = result.indexOf('━━━━━━━━━━━━━━━━━━━━━━');
      if (firstSep >= 0) {
        result = result.slice(0, firstSep) + perfectBlock + result.slice(firstSep);
      } else {
        result = perfectBlock + result;
      }
    } else if (lepd.state === 'SWEEPING') {
      // Sweep in progress — show deepest limit
      // ✅ FIX: this patch wrapper of analyseSignalInternal only receives
      // (consensus, instCtx, scored) — there is no `price` parameter in
      // scope here, so the previous `price < 1 ? ...` ladder threw a
      // ReferenceError and the whole SWEEPING branch never executed.
      // Derive a reference price from the LEPD object instead (any nearby
      // level works because we only need it to pick a sensible tick size).
      const lepd_priceRef = lepd.deepestPool
                         || lepd.sweepWickExtreme
                         || (lepd.sweepCandle && lepd.sweepCandle.close)
                         || 0;
      const lepd_tickSz = lepd_priceRef < 1    ? 0.00001
                        : lepd_priceRef < 10   ? 0.0001
                        : lepd_priceRef < 100  ? 0.001
                        : lepd_priceRef < 1000 ? 0.01
                        :                        0.1;
      const lepd_deepLimit = lepd.deepestPool
        ? (dir === 'BUY' ? Math.round((lepd.deepestPool + lepd_tickSz) * 100000) / 100000
                         : Math.round((lepd.deepestPool - lepd_tickSz) * 100000) / 100000)
        : null;
      const lepd_sweepNote = lepd_deepLimit
        ? `\n🎯 <b>LEPD: SET LIMIT AFTER ALL LIQUIDITY</b> — <code>${lepd_deepLimit}</code>\nSweep active through ${lepd.allPools?.length||'?'} pools → your limit is at the end.\n`
        : `\n🔄 <b>LEPD: SWEEP ACTIVE</b> — Calculating deepest pool...\n`;
      result = result.replace('━━━━━━━━━━━━━━━━━━━━━━', '━━━━━━━━━━━━━━━━━━━━━━' + lepd_sweepNote);
    } else if (lepd.state === 'STRONG_EXHAUSTION' && lepd.precisionLimit) {
      const strongBlock = `\n✅ <b>LEPD STRONG EXHAUSTION</b> — Precision limit: <code>${lepd.precisionLimit}</code> | ${lepd.confidence}% confidence | ${lepd.confirmations}/6 criteria\n`;
      result += strongBlock;
    }
  } catch(e) { console.warn('LEPD analyseSignalInternal patch error:', e.message); }
  return result;
};

/* ── Wire LEPD certBoost into V9-V22 certBoost chain ─────────────────────── */
// LEPD confidence directly feeds into signal certainty
const _origGetPostSweep_lepd = getPostSweepLimit;
getPostSweepLimit = async function(symbol, candles, price, dir, volCtx) {
  // Run both the original and LEPD in parallel, return the more precise one
  const [orig, lepd] = await Promise.allSettled([
    _origGetPostSweep_lepd(symbol, candles, price, dir, volCtx),
    getLEPDContext(symbol, candles, price, dir, volCtx),
  ]);

  const origData = orig.status === 'fulfilled' ? orig.value : null;
  const lepdData = lepd.status === 'fulfilled' ? lepd.value : null;

  // Prefer LEPD if it has higher confidence
  if (lepdData?.confidence >= 72 && (!origData || lepdData.confidence > (origData.confidence || 0))) {
    return {
      ...lepdData,
      limitEntry:   lepdData.precisionLimit,
      state:        lepdData.state,
      _source:      'LEPD',
    };
  }
  return origData;
};

/* ════════════════════════════════════════════════════════════════════════════
   PLVD — PERFECT LIQUIDITY VACUUM DETECTOR
   ════════════════════════════════════════════════════════════════════════════
   Goal: only fire when EVERY pool of liquidity in the trade direction has been
   consumed across multiple timeframes AND post-sweep absorption is confirmed
   AND no deeper liquidity exists on a higher TF AND no event/funding risk.

   Two modes:
     • strict   — ALL gates must pass on 5m/15m/1h/4h/1D/1W
     • balanced — drops the 1W deep-pool check; otherwise identical
     • off      — engine disabled, no decoration, no gating

   Two gate behaviours:
     • hard — when state !== VACUUM_CONFIRMED, signal is BLOCKED (returns null)
     • soft — signal still fires, PLVD verdict is just informational

   All controls are runtime-mutable via Telegram /plvd commands. Defaults below.
   ──────────────────────────────────────────────────────────────────────────── */

const PLVD_CONFIG = {
  mode: (process.env.PLVD_MODE || 'balanced').toLowerCase(),  // 'strict' | 'balanced' | 'off'
  gate: (process.env.PLVD_GATE || 'soft').toLowerCase(),      // 'hard' | 'soft'
};

const PLVD_CACHE = new Map();
const PLVD_CACHE_TTL = 90 * 1000;

/* ── Pool finders — work directly on candle arrays ─────────────────────────── */

function plvdFindEqualLevels(candles, side /* 'high'|'low' */, tolPct = 0.0008, minTouches = 2) {
  // Cluster highs/lows that come within tolPct of each other (default 0.08%)
  if (!candles || candles.length < 5) return [];
  const out = [];
  const used = new Set();
  for (let i = 0; i < candles.length; i++) {
    if (used.has(i)) continue;
    const ref = side === 'high' ? candles[i].h : candles[i].l;
    if (!ref) continue;
    const tol = ref * tolPct;
    let touches = 1;
    let extreme = ref;
    let lastIdx = i;
    for (let j = i + 1; j < candles.length; j++) {
      const v = side === 'high' ? candles[j].h : candles[j].l;
      if (!v) continue;
      if (Math.abs(v - ref) <= tol) {
        touches++;
        used.add(j);
        if (side === 'high' && v > extreme) extreme = v;
        if (side === 'low'  && v < extreme) extreme = v;
        lastIdx = j;
      }
    }
    if (touches >= minTouches) {
      out.push({ price: extreme, touches, lastIdx, kind: side === 'high' ? 'EQH' : 'EQL' });
    }
  }
  return out;
}

function plvdFindSwingPivots(candles, lookback = 5) {
  // Classic N-bar pivot: highest/lowest of (lookback) bars on each side
  if (!candles || candles.length < lookback * 2 + 1) return { highs: [], lows: [] };
  const highs = [];
  const lows  = [];
  for (let i = lookback; i < candles.length - lookback; i++) {
    const c = candles[i];
    let isHigh = true, isLow = true;
    for (let k = 1; k <= lookback; k++) {
      if (candles[i - k].h >= c.h || candles[i + k].h >= c.h) isHigh = false;
      if (candles[i - k].l <= c.l || candles[i + k].l <= c.l) isLow  = false;
      if (!isHigh && !isLow) break;
    }
    if (isHigh) highs.push({ price: c.h, idx: i, kind: 'PIVOT_H' });
    if (isLow)  lows .push({ price: c.l, idx: i, kind: 'PIVOT_L' });
  }
  return { highs, lows };
}

function plvdFindFVGs(candles) {
  // 3-candle FVG: bullish = candle[i+2].low > candle[i].high → unfilled gap on the way up
  //               bearish = candle[i+2].high < candle[i].low → unfilled gap on the way down
  const bull = [], bear = [];
  if (!candles || candles.length < 3) return { bull, bear };
  for (let i = 0; i < candles.length - 2; i++) {
    const a = candles[i], c = candles[i + 2];
    if (!a || !c) continue;
    if (c.l > a.h) bull.push({ top: c.l, bottom: a.h, idx: i, kind: 'FVG_BULL' });
    if (c.h < a.l) bear.push({ top: a.l, bottom: c.h, idx: i, kind: 'FVG_BEAR' });
  }
  return { bull, bear };
}

function plvdFindOrderBlocks(candles, impulseMult = 1.5) {
  // Last opposite-direction candle right before an impulsive move (>= impulseMult × ATR)
  if (!candles || candles.length < 20) return { bull: [], bear: [] };
  const ranges = candles.map(c => Math.abs(c.h - c.l));
  const atr = ranges.slice(-20).reduce((a, b) => a + b, 0) / 20;
  const bull = [], bear = [];
  for (let i = 1; i < candles.length - 1; i++) {
    const prev = candles[i - 1], cur = candles[i], next = candles[i + 1];
    const nextBody = Math.abs(next.c - next.o);
    if (nextBody < atr * impulseMult) continue;
    if (next.c > next.o && prev.c < prev.o) {
      // bullish impulse preceded by bearish candle → bullish OB
      bull.push({ top: prev.h, bottom: prev.l, idx: i - 1, kind: 'OB_BULL' });
    }
    if (next.c < next.o && prev.c > prev.o) {
      bear.push({ top: prev.h, bottom: prev.l, idx: i - 1, kind: 'OB_BEAR' });
    }
  }
  return { bull, bear };
}

function plvdSessionExtremes(candles) {
  // Approximation: split the last 72 hourly candles into 3 sessions × 8h each.
  // Caller should pass 1h candles. Returns last 3 sessions of highs/lows.
  if (!candles || candles.length < 24) return [];
  const recent = candles.slice(-72);
  const sessions = [];
  for (let s = 0; s < 9 && s * 8 < recent.length; s++) {
    const slice = recent.slice(s * 8, (s + 1) * 8);
    if (!slice.length) continue;
    const high = Math.max(...slice.map(c => c.h));
    const low  = Math.min(...slice.map(c => c.l));
    sessions.push({ high, low, sessionIdx: s, kind: 'SESSION' });
  }
  return sessions;
}

/* ── Multi-TF pool aggregation ─────────────────────────────────────────────── */

function plvdBuildPoolMap(candlesByTF, price, dir) {
  // Returns { above: [pool,...], below: [pool,...] } across all TFs.
  // Each pool has { price, source, tf, kind }.
  const above = [], below = [];
  const push = (arr, p, source, tf, kind) => {
    if (typeof p !== 'number' || !isFinite(p) || p <= 0) return;
    arr.push({ price: p, source, tf, kind });
  };

  for (const [tf, candles] of Object.entries(candlesByTF || {})) {
    if (!candles || candles.length < 5) continue;

    // EQH / EQL — strongest liquidity signature
    for (const e of plvdFindEqualLevels(candles, 'high')) push(e.price > price ? above : below, e.price, 'EQH',  tf, 'EQH');
    for (const e of plvdFindEqualLevels(candles, 'low'))  push(e.price > price ? above : below, e.price, 'EQL',  tf, 'EQL');

    // Swing pivots
    // ✅ FIX: TF keys are '5min'/'15min'/'1h'/... not '5m'. The previous
    // `tf === '5m'` comparison NEVER matched, so 5-minute pools were always
    // computed with the slower 5-bar lookback and many never qualified —
    // a major reason PLVD missed signals on fast-moving assets.
    const { highs, lows } = plvdFindSwingPivots(candles, (tf === '5min' || tf === '5m') ? 3 : 5);
    for (const h of highs) push(h.price > price ? above : below, h.price, 'PIVOT', tf, 'PIVOT_H');
    for (const l of lows)  push(l.price > price ? above : below, l.price, 'PIVOT', tf, 'PIVOT_L');

    // FVG
    const { bull, bear } = plvdFindFVGs(candles);
    for (const f of bull) {
      const mid = (f.top + f.bottom) / 2;
      push(mid > price ? above : below, mid, 'FVG', tf, 'FVG_BULL');
    }
    for (const f of bear) {
      const mid = (f.top + f.bottom) / 2;
      push(mid > price ? above : below, mid, 'FVG', tf, 'FVG_BEAR');
    }

    // Session extremes (only meaningful on 1h)
    if (tf === '1h') {
      for (const s of plvdSessionExtremes(candles)) {
        push(s.high > price ? above : below, s.high, 'SESSION', tf, 'SESSION_H');
        push(s.low  > price ? above : below, s.low,  'SESSION', tf, 'SESSION_L');
      }
    }
  }

  // De-dup: collapse pools within 0.05% of each other into one (keeping the strongest)
  const dedup = (arr) => {
    arr.sort((a, b) => a.price - b.price);
    const out = [];
    for (const p of arr) {
      const last = out[out.length - 1];
      if (last && Math.abs(p.price - last.price) / p.price < 0.0005) {
        // merge — bump strength by adding source labels
        last.sources = (last.sources || [last.source]).concat(p.source);
        last.tfs     = (last.tfs     || [last.tf])    .concat(p.tf);
      } else {
        out.push({ ...p, sources: [p.source], tfs: [p.tf] });
      }
    }
    return out;
  };

  return { above: dedup(above), below: dedup(below) };
}

/* ── Pool sweep tagging ────────────────────────────────────────────────────── */

function plvdTagSweptPools(pools, candles, side /* 'above'|'below' */, lookback = 50) {
  // For each pool, check if any of the last `lookback` candles wicked through it.
  if (!pools.length || !candles || !candles.length) return pools;
  const recent = candles.slice(-lookback);
  for (const p of pools) {
    let swept = false;
    let sweepWick = null;
    for (const c of recent) {
      if (side === 'above' && c.h >= p.price) { swept = true; sweepWick = Math.max(sweepWick || 0, c.h); }
      if (side === 'below' && c.l <= p.price) { swept = true; sweepWick = sweepWick === null ? c.l : Math.min(sweepWick, c.l); }
    }
    p.status    = swept ? 'SWEPT' : 'PENDING';
    p.sweepWick = sweepWick;
  }
  return pools;
}

/* ── Absorption checks (post-sweep confirmation) ───────────────────────────── */

function plvdCheckAbsorption(candles, dir, lookback = 8) {
  // After the sweep, we need:
  //  • Vol exhaustion: sweep candle vol > 2× sma20, next candle vol < 0.6× sma20
  //  • Body recovery ≥ 75% on the absorption candle
  //  • CVD-proxy reversal: signed-volume flips opposite to sweep within 2 bars
  //  • ≥ 2 consecutive opposite-direction candles with body > 60% of range
  if (!candles || candles.length < 25) return { passed: false, reason: 'insufficient_candles', score: 0 };
  const slice = candles.slice(-lookback - 20);
  const last20 = slice.slice(0, 20);
  const recent = slice.slice(-lookback);
  if (!recent.length) return { passed: false, reason: 'no_recent', score: 0 };

  const avgVol = last20.reduce((a, c) => a + (c.v || 0), 0) / 20;
  if (!avgVol) return { passed: false, reason: 'no_volume_data', score: 0 };

  // Find the sweep candle (largest volume in recent window with wick in trade-against direction)
  let sweepIdx = -1, sweepVol = 0;
  for (let i = 0; i < recent.length - 2; i++) {
    const c = recent[i];
    const wick = dir === 'BUY' ? (Math.min(c.o, c.c) - c.l) : (c.h - Math.max(c.o, c.c));
    const range = c.h - c.l;
    const wickRatio = range > 0 ? wick / range : 0;
    if ((c.v || 0) > avgVol * 1.8 && wickRatio > 0.4 && (c.v || 0) > sweepVol) {
      sweepIdx = i; sweepVol = c.v || 0;
    }
  }
  if (sweepIdx < 0) return { passed: false, reason: 'no_sweep_candle', score: 0 };
  const sweep = recent[sweepIdx];

  // Vol exhaustion
  const volSpike     = (sweep.v || 0) / avgVol;
  const next         = recent[sweepIdx + 1];
  const nextVolDrop  = next ? ((next.v || 0) / avgVol) : 1;
  const exhaustion   = volSpike >= 2.0 && nextVolDrop <= 0.6;

  // Body recovery on the sweep candle itself
  const range = sweep.h - sweep.l;
  const closePos = range > 0 ? (sweep.c - sweep.l) / range : 0.5;
  const bodyRecovery = dir === 'BUY' ? closePos : (1 - closePos);
  const bodyOK = bodyRecovery >= 0.75;

  // CVD-proxy reversal — sum of signed volume after sweep should oppose sweep direction
  const post = recent.slice(sweepIdx + 1, sweepIdx + 3);
  const signedVol = post.reduce((a, c) => a + ((c.c >= c.o ? 1 : -1) * (c.v || 0)), 0);
  const cvdFlip = dir === 'BUY' ? signedVol > 0 : signedVol < 0;

  // Institutional defense — 2+ consecutive opposite candles with body > 60%
  let consec = 0;
  for (const c of post) {
    const bRange = c.h - c.l;
    const body   = Math.abs(c.c - c.o);
    const bodyR  = bRange > 0 ? body / bRange : 0;
    const goodDir = dir === 'BUY' ? c.c > c.o : c.c < c.o;
    if (goodDir && bodyR >= 0.6) consec++;
    else break;
  }
  const defenceOK = consec >= 2;

  // Composite score
  const checks = { exhaustion, bodyOK, cvdFlip, defenceOK };
  const passes = Object.values(checks).filter(Boolean).length;
  const score  = Math.round((passes / 4) * 100);
  const passed = passes === 4;

  return {
    passed, score, checks,
    sweepIdx, volSpike: +volSpike.toFixed(2),
    nextVolDrop: +nextVolDrop.toFixed(2),
    bodyRecovery: +bodyRecovery.toFixed(2),
    cvdSignedVol: Math.round(signedVol),
    consecOppositeCandles: consec,
    sweepCandle: sweep,
  };
}

/* ── Main detector ─────────────────────────────────────────────────────────── */

async function detectPerfectVacuum(symbol, price, dir, mode = 'balanced') {
  // ✅ FIX: Build a guaranteed-complete shape that satisfies formatPLVD()
  // even on early exits. Without this, an INSUFFICIENT_DATA result was
  // missing `mode`, `pools_consumed`, `pools_total`, `timeframes_aligned`,
  // `pools_remaining` and `absorption` — and formatPLVD then crashed at
  // `plvd.mode.toUpperCase()`. That uncaught throw inside the
  // formatInstitutionalContext wrapper killed the entire signal card for
  // every asset whose 1h candles were short — the single biggest reason
  // PLVD appeared to "not operate on all signals".
  const _emptyShape = (state, confidence, reason, extra = {}) => ({
    state, confidence, reason,
    mode: mode || PLVD_CONFIG.mode || 'balanced',
    precisionLimit: null, invalidation: null,
    pools_consumed: 0, pools_total: 0, pools_remaining: [],
    deep_pending: null,
    timeframes_aligned: [],
    absorption: { passed: false, score: 0, checks: {}, consecOppositeCandles: 0 },
    opposite_pools_count: 0,
    ...extra,
  });

  // ✅ FIX: PLVD pool selection is direction-dependent. When `dir` is null,
  // 'NEUTRAL' or anything other than BUY/SELL, the previous code silently
  // routed to `pools.above` (the SELL branch), producing nonsense scoring
  // for every NEUTRAL/missing-direction signal. Now we return an explicit
  // INSUFFICIENT_DATA shape so the card still renders but PLVD does not
  // emit a misleading verdict.
  if (dir !== 'BUY' && dir !== 'SELL') {
    return _emptyShape('INSUFFICIENT_DATA', 0, `no_direction (got ${dir})`);
  }
  if (!Number.isFinite(price) || price <= 0) {
    return _emptyShape('INSUFFICIENT_DATA', 0, `invalid_price (${price})`);
  }

  // Pull candles across all needed TFs in parallel
  const tfs = mode === 'strict'
    ? ['5min', '15min', '1h', '4h', '1day', '1week']
    : ['5min', '15min', '1h', '4h', '1day'];   // balanced drops 1W

  const fetched = await Promise.all(
    tfs.map(tf => fetchCandlesCached(symbol, tf, 200).catch(() => []))
  );
  const candlesByTF = {};
  tfs.forEach((tf, i) => { candlesByTF[tf] = fetched[i] || []; });

  // Need at minimum the 1h to do anything meaningful
  const hourly = candlesByTF['1h'] || [];
  if (hourly.length < 30) {
    return _emptyShape('INSUFFICIENT_DATA', 0, 'no_hourly_candles', { timeframes_aligned: tfs });
  }

  // Build the multi-TF pool map
  const pools = plvdBuildPoolMap(candlesByTF, price, dir);

  // Tag every pool as SWEPT/PENDING using each TF's own candles
  for (const tf of tfs) {
    const cs = candlesByTF[tf] || [];
    plvdTagSweptPools(pools.above, cs, 'above', 60);
    plvdTagSweptPools(pools.below, cs, 'below', 60);
  }

  // Pools in the trade direction = pools we need consumed before going.
  //  - For LONG (BUY): we want all BELOW pools swept (they'd be the magnet pulling us down)
  //  - For SHORT (SELL): we want all ABOVE pools swept
  const sidePools = dir === 'BUY' ? pools.below : pools.above;
  const oppPools  = dir === 'BUY' ? pools.above : pools.below;

  // Filter to pools within 5% of price (anything farther is not the immediate magnet)
  const inRange = sidePools.filter(p => Math.abs(p.price - price) / price <= 0.05);
  const remaining = inRange.filter(p => p.status !== 'SWEPT');

  // Check higher-TF deep pool — the killer. If 1W (strict) or 1D (balanced) has
  // a pending pool further than the deepest swept wick, we cannot fire.
  const deepCheckTF = mode === 'strict' ? '1week' : '1day';
  const deepCs = candlesByTF[deepCheckTF] || [];
  let deepPendingPool = null;
  if (deepCs.length >= 10) {
    const deepPools = sidePools.filter(p => p.tfs.includes(deepCheckTF));
    const deepestSweep = inRange
      .filter(p => p.status === 'SWEPT' && p.sweepWick != null)
      .reduce((acc, p) => {
        if (acc == null) return p.sweepWick;
        return dir === 'BUY' ? Math.min(acc, p.sweepWick) : Math.max(acc, p.sweepWick);
      }, null);
    for (const dp of deepPools) {
      if (dp.status === 'SWEPT') continue;
      if (deepestSweep == null) { deepPendingPool = dp; break; }
      if (dir === 'BUY' && dp.price < deepestSweep) { deepPendingPool = dp; break; }
      if (dir === 'SELL' && dp.price > deepestSweep) { deepPendingPool = dp; break; }
    }
  }

  // Absorption confirmation on the 1h
  const absorption = plvdCheckAbsorption(hourly, dir, 8);

  // Compose state
  let state, confidence, reason;
  if (remaining.length > 0) {
    state = 'INCOMPLETE_SWEEP';
    confidence = Math.max(0, 60 - remaining.length * 10);
    reason = `${remaining.length} pool(s) still pending`;
  } else if (deepPendingPool) {
    state = 'DEEP_POOL_PENDING';
    confidence = 30;
    reason = `${deepCheckTF} pool @ ${deepPendingPool.price} not swept`;
  } else if (!absorption.passed) {
    state = 'WAITING_ABSORPTION';
    confidence = absorption.score || 40;
    // ✅ FIX: When `absorption.checks` is undefined (e.g. no-sweep early exit
    // returns `{passed:false, reason, score:0}` with no `checks`), the join
    // below yielded `undefined` text. Now we fall back to the absorption
    // reason string so the verdict is still informative.
    const _missing = Object.entries(absorption.checks || {})
      .filter(([,v]) => !v).map(([k]) => k).join(', ');
    reason = `absorption ${absorption.score}/100 — ${_missing || absorption.reason || 'pending'}`;
  } else {
    state = 'VACUUM_CONFIRMED';
    confidence = Math.min(99, 80 + absorption.consecOppositeCandles * 5 + (absorption.volSpike >= 3 ? 5 : 0));
    reason = 'all pools consumed + absorption confirmed';
  }

  // Precision limit = sweep wick extreme + 1 tick (in trade favour)
  let precisionLimit = null, invalidation = null;
  if (state === 'VACUUM_CONFIRMED' && absorption.sweepCandle) {
    const sw = absorption.sweepCandle;
    const tick = price < 1   ? 0.00001
               : price < 10  ? 0.0001
               : price < 100 ? 0.001
               : price < 1000? 0.01
               :               0.1;
    if (dir === 'BUY') {
      precisionLimit = Math.round((sw.l + tick) * 1e6) / 1e6;
      invalidation  = Math.round((sw.l - tick) * 1e6) / 1e6;
    } else {
      precisionLimit = Math.round((sw.h - tick) * 1e6) / 1e6;
      invalidation  = Math.round((sw.h + tick) * 1e6) / 1e6;
    }
  }

  return {
    state, confidence, reason, mode,
    precisionLimit, invalidation,
    pools_consumed: inRange.filter(p => p.status === 'SWEPT').length,
    pools_total:    inRange.length,
    pools_remaining: remaining.map(p => ({ price: p.price, sources: p.sources, tfs: p.tfs })),
    deep_pending:   deepPendingPool ? { price: deepPendingPool.price, tf: deepCheckTF } : null,
    timeframes_aligned: tfs,
    absorption,
    opposite_pools_count: oppPools.length,
  };
}

/* ── Cached entry point ────────────────────────────────────────────────────── */

async function getPLVDContext(symbol, price, dir) {
  if (PLVD_CONFIG.mode === 'off') return null;
  // ✅ FIX: Cache key now includes the gate so /plvd hard|soft toggles
  // don't keep returning a stale verdict whose gate label disagrees with
  // the live PLVD_CONFIG.gate. Also includes a coarse price bucket so a
  // significant move (>0.5%) recomputes pool sweep status instead of
  // showing stale SWEPT/PENDING tags within the 90s TTL.
  const _bucket = Number.isFinite(price) && price > 0
    ? Math.round(price * 200) / 200    // ~0.5% price quantisation
    : 0;
  const key = `plvd_${symbol}_${dir}_${PLVD_CONFIG.mode}_${PLVD_CONFIG.gate}_${_bucket}`;
  const hit = PLVD_CACHE.get(key);
  if (hit && Date.now() - hit.ts < PLVD_CACHE_TTL) return hit.data;
  try {
    const data = await detectPerfectVacuum(symbol, price, dir, PLVD_CONFIG.mode);
    PLVD_CACHE.set(key, { data, ts: Date.now() });
    // ✅ FIX: Bound cache size — without this the engine leaks memory across
    // long Render uptimes (one entry per symbol × dir × bucket × tick).
    if (PLVD_CACHE.size > 2000) {
      const firstKey = PLVD_CACHE.keys().next().value;
      PLVD_CACHE.delete(firstKey);
    }
    return data;
  } catch (e) {
    console.warn('PLVD detect error:', e.message);
    // ✅ FIX: Return a defensive empty shape rather than null, so the
    // formatter still renders a verdict line ("⚠️ INSUFFICIENT_DATA")
    // instead of silently dropping PLVD from the signal card.
    return {
      state: 'INSUFFICIENT_DATA',
      confidence: 0,
      reason: `detect_error: ${e.message}`,
      mode: PLVD_CONFIG.mode || 'balanced',
      precisionLimit: null, invalidation: null,
      pools_consumed: 0, pools_total: 0, pools_remaining: [],
      deep_pending: null,
      timeframes_aligned: [],
      absorption: { passed: false, score: 0, checks: {}, consecOppositeCandles: 0 },
      opposite_pools_count: 0,
    };
  }
}

/* ── Format for Telegram signal card ───────────────────────────────────────── */

function formatPLVD(plvd, dir) {
  // ✅ FIX: Fully defensive — every field that previously assumed presence
  // (mode, confidence, pools_*, absorption.*) is now safely coalesced. This
  // is the function that, when it threw, used to wipe out the entire
  // signal card via the un-try/caught formatInstitutionalContext wrapper.
  if (!plvd) return '';
  try {
    const L = [];
    L.push('');
    L.push('━━━━━━━━━━━━━━━━━━━━━━');
    const icon = {
      VACUUM_CONFIRMED:    '🏆',
      INCOMPLETE_SWEEP:    '⏳',
      DEEP_POOL_PENDING:   '🚫',
      WAITING_ABSORPTION:  '⏳',
      INSUFFICIENT_DATA:   '⚠️',
    }[plvd.state] || '•';
    const _mode = (plvd.mode || PLVD_CONFIG.mode || 'balanced').toString().toUpperCase();
    const _gate = (PLVD_CONFIG.gate || 'soft').toString().toUpperCase();
    const _state = plvd.state || 'UNKNOWN';
    const _conf  = Number.isFinite(plvd.confidence) ? plvd.confidence : 0;
    L.push(`<b>${icon} PLVD [${_mode}/${_gate}]: ${_state} — ${_conf}%</b>`);
    L.push(`<i>${plvd.reason || 'no_reason'}</i>`);
    const _consumed = Number.isFinite(plvd.pools_consumed) ? plvd.pools_consumed : 0;
    const _total    = Number.isFinite(plvd.pools_total)    ? plvd.pools_total    : 0;
    const _tfs      = Array.isArray(plvd.timeframes_aligned) ? plvd.timeframes_aligned : [];
    L.push(`Pools: ${_consumed}/${_total} swept · TFs: ${_tfs.join('/') || '—'}`);
    if (plvd.deep_pending && plvd.deep_pending.tf) {
      L.push(`🚫 <b>${plvd.deep_pending.tf} deep pool pending @ <code>${plvd.deep_pending.price}</code></b>`);
    }
    if (Array.isArray(plvd.pools_remaining) && plvd.pools_remaining.length) {
      const top = plvd.pools_remaining.slice(0, 3)
        .map(p => `<code>${p.price}</code> (${(p.sources || []).join('+') || '?'})`).join(' · ');
      L.push(`Pending: ${top}${plvd.pools_remaining.length > 3 ? ` +${plvd.pools_remaining.length - 3}` : ''}`);
    }
    if (plvd.absorption) {
      const a = plvd.absorption;
      const checks = a.checks || {};
      const goodList = Object.entries(checks).filter(([,v]) => v).map(([k]) => k);
      const badList  = Object.entries(checks).filter(([,v]) => !v).map(([k]) => k);
      const _score = Number.isFinite(a.score) ? a.score : 0;
      const _vol   = Number.isFinite(a.volSpike) ? a.volSpike : 0;
      const _body  = Number.isFinite(a.bodyRecovery) ? a.bodyRecovery : 0;
      const _conf2 = Number.isFinite(a.consecOppositeCandles) ? a.consecOppositeCandles : 0;
      L.push(`Absorption: ${_score}/100 · vol×${_vol} · body ${(_body*100).toFixed(0)}% · ${_conf2} confirms`);
      if (goodList.length) L.push(`✅ ${goodList.join(' · ')}`);
      if (badList.length)  L.push(`⏳ Need: ${badList.join(' · ')}`);
    }
    if (plvd.state === 'VACUUM_CONFIRMED' && plvd.precisionLimit != null) {
      L.push(`\n🎯 <b>PRECISION LIMIT: <code>${plvd.precisionLimit}</code></b>`);
      L.push(`Invalidation: <code>${plvd.invalidation}</code> (1 tick beyond sweep)`);
      L.push(`No deeper liquidity in range. Move starts here, not before.`);
    }
    return L.join('\n');
  } catch (e) {
    console.warn('formatPLVD error:', e.message);
    // Last-resort fallback so the SIGNAL CARD never breaks because of PLVD.
    return `\n━━━━━━━━━━━━━━━━━━━━━━\n⚠️ PLVD format error: ${e.message}`;
  }
}

/* ── Wire PLVD into buildInstitutionalContextFull ─────────────────────────── */
const _origBuildInst_plvd = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function(symbol, price, dir) {
  // ✅ FIX: Even if the underlying chain returns null/undefined (e.g.
  // because a downstream wrapper threw), synthesise a minimal base object
  // so PLVD context can still attach. Previously, when `base` was null,
  // PLVD silently went missing for that asset.
  let base = null;
  try { base = await _origBuildInst_plvd(symbol, price, dir); }
  catch (e) { console.warn('inst-ctx upstream error:', e.message); }
  if (!base) base = {};
  try {
    const plvd = await getPLVDContext(symbol, price, dir);
    base.plvd  = plvd;
    base._plvd = true;
  } catch (e) {
    console.warn('PLVD wiring error:', e.message);
    base.plvd  = null;
    base._plvd = false;
  }
  return base;
};

/* ── Wire PLVD into formatInstitutionalContext ────────────────────────────── */
const _origFormat_plvd = formatInstitutionalContext;
formatInstitutionalContext = function(ctx, dir) {
  // ✅ FIX: Wrap the entire chain in try/catch and ensure PLVD always
  // appends — even when the upstream formatter throws. Without this, a
  // single bug anywhere in the long wrapper chain (LEPD/SEPS/V9-V14/etc.)
  // would prevent the PLVD section from ever being rendered for that asset.
  let msg = '';
  try { msg = _origFormat_plvd(ctx, dir) || ''; }
  catch (e) {
    console.warn('formatInstitutionalContext upstream error:', e.message);
    msg = '';
  }
  try {
    if (ctx?.plvd) msg += formatPLVD(ctx.plvd, dir);
  } catch (e) {
    console.warn('formatPLVD outer error:', e.message);
  }
  return msg;
};

/* ── Wire PLVD into analyseSignalInternal — hard gate enforcement ─────────── */
const _origAnalyse_plvd = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  // ✅ FIX: Run the upstream chain inside try/catch so a downstream wrapper
  // throwing doesn't blank out the AI analyst block — instead we still
  // surface PLVD verdict (and reason for the upstream failure) to the user.
  let result = null;
  try { result = _origAnalyse_plvd(consensus, instCtx, scored); }
  catch (e) { console.warn('analyse upstream error:', e.message); }

  const plvd = instCtx?.plvd;
  const dir  = consensus?.consensusDirection || 'NEUTRAL';

  // PLVD disabled or unavailable → preserve upstream behaviour exactly.
  if (!plvd || PLVD_CONFIG.mode === 'off') return result;

  // ✅ FIX: HARD GATE used to return null for ANY non-VACUUM_CONFIRMED state
  // — including INSUFFICIENT_DATA caused by transient candle-fetch failures.
  // That meant a single API blip muted the AI analyst entirely. Now the
  // hard gate only blocks DEFINITIVE rejections (INCOMPLETE_SWEEP /
  // DEEP_POOL_PENDING / WAITING_ABSORPTION) and lets INSUFFICIENT_DATA
  // / UNKNOWN states fall through to soft behaviour with a clear notice.
  const _definitiveReject =
    plvd.state === 'INCOMPLETE_SWEEP'   ||
    plvd.state === 'DEEP_POOL_PENDING'  ||
    plvd.state === 'WAITING_ABSORPTION';

  if (PLVD_CONFIG.gate === 'hard' && _definitiveReject) {
    console.log(`🚫 PLVD HARD GATE blocked signal: ${plvd.state} — ${plvd.reason}`);
    return null;
  }

  // If upstream produced no analyst body, build a minimal one so PLVD
  // verdict still reaches the user instead of the whole signal silently
  // disappearing.
  if (!result) {
    result = `🤖 <b>AI Analyst</b> — upstream chain unavailable, PLVD verdict only.\n`;
  }

  // SOFT mode (or hard + confirmed): inject the precision-limit verdict at the top
  if (plvd.state === 'VACUUM_CONFIRMED' && plvd.precisionLimit != null) {
    const _mode = (plvd.mode || PLVD_CONFIG.mode || 'balanced').toString().toUpperCase();
    const _tfs  = Array.isArray(plvd.timeframes_aligned) && plvd.timeframes_aligned.length
      ? plvd.timeframes_aligned.join('/') : '—';
    const block = [
      '',
      '━━━━━━━━━━━━━━━━━━━━━━',
      `🏆 <b>PLVD: PERFECT LIQUIDITY VACUUM — ${plvd.confidence}% CONFIDENCE</b>`,
      `Mode: ${_mode} · Direction: ${dir}`,
      `🎯 LIMIT @ <code>${plvd.precisionLimit}</code> · INVAL @ <code>${plvd.invalidation}</code>`,
      `All pools (${plvd.pools_consumed || 0}/${plvd.pools_total || 0}) consumed across ${_tfs}.`,
      `No deeper liquidity. ${plvd.absorption?.consecOppositeCandles || 0} institutional confirms.`,
      '━━━━━━━━━━━━━━━━━━━━━━',
      '',
    ].join('\n');
    return block + result;
  }

  // ✅ FIX (USER REPORT — "PLVD never appears in AI analyst"):
  //
  // Previously this branch only fired for INSUFFICIENT_DATA or non-rejected
  // states. The three most COMMON real-world states
  // (INCOMPLETE_SWEEP / DEEP_POOL_PENDING / WAITING_ABSORPTION) hit the
  // bare `return result;` below, so PLVD silently dropped out of the AI
  // analyst card — exactly the symptom the user reported.
  //
  // Fix: ALWAYS emit a rich PLVD status block in the AI analyst output for
  // every defined state so PLVD is unconditionally visible. We pick a
  // state-appropriate icon and include pools/timeframes/absorption summary
  // so the trader can see at a glance how close the setup is to firing.
  try {
    const _mode = (plvd.mode || PLVD_CONFIG.mode || 'balanced').toString().toUpperCase();
    const _gate = (PLVD_CONFIG.gate || 'soft').toString().toUpperCase();
    const _state = plvd.state || 'UNKNOWN';
    const _conf  = Number.isFinite(plvd.confidence) ? plvd.confidence : 0;
    const _consumed = Number.isFinite(plvd.pools_consumed) ? plvd.pools_consumed : 0;
    const _total    = Number.isFinite(plvd.pools_total)    ? plvd.pools_total    : 0;
    const _tfs      = Array.isArray(plvd.timeframes_aligned) && plvd.timeframes_aligned.length
      ? plvd.timeframes_aligned.join('/') : '—';
    const stateIcon = ({
      VACUUM_CONFIRMED:    '🏆',
      INCOMPLETE_SWEEP:    '⏳',
      DEEP_POOL_PENDING:   '🚫',
      WAITING_ABSORPTION:  '⏳',
      INSUFFICIENT_DATA:   '⚠️',
    })[_state] || '•';

    const lines = [
      '',
      '━━━━━━━━━━━━━━━━━━━━━━',
      `${stateIcon} <b>PLVD [${_mode}/${_gate}]: ${_state} — ${_conf}%</b>`,
      `<i>${plvd.reason || 'no_reason'}</i>`,
      `Pools: ${_consumed}/${_total} swept · TFs: ${_tfs} · Direction: ${dir}`,
    ];
    if (plvd.deep_pending && plvd.deep_pending.tf) {
      lines.push(`🚫 ${plvd.deep_pending.tf} deep pool pending @ <code>${plvd.deep_pending.price}</code>`);
    }
    if (Array.isArray(plvd.pools_remaining) && plvd.pools_remaining.length) {
      const top = plvd.pools_remaining.slice(0, 3)
        .map(p => `<code>${p.price}</code> (${(p.sources || []).join('+') || '?'})`).join(' · ');
      lines.push(`Pending: ${top}${plvd.pools_remaining.length > 3 ? ` +${plvd.pools_remaining.length - 3}` : ''}`);
    }
    if (plvd.absorption) {
      const a = plvd.absorption;
      const _score = Number.isFinite(a.score) ? a.score : 0;
      const _vol   = Number.isFinite(a.volSpike) ? a.volSpike : 0;
      const _conf2 = Number.isFinite(a.consecOppositeCandles) ? a.consecOppositeCandles : 0;
      lines.push(`Absorption: ${_score}/100 · vol×${_vol} · ${_conf2} confirms`);
    }
    if (_state === 'VACUUM_CONFIRMED' && plvd.precisionLimit != null) {
      lines.push(`🎯 PRECISION LIMIT: <code>${plvd.precisionLimit}</code>`);
      if (plvd.invalidation != null) lines.push(`Invalidation: <code>${plvd.invalidation}</code>`);
    }
    lines.push('━━━━━━━━━━━━━━━━━━━━━━');
    lines.push('');
    return lines.join('\n') + result;
  } catch (e) {
    console.warn('PLVD AI-analyst banner error:', e.message);
    return result;
  }
};

