/* ████████████████████████████████████████████████████████████████████████████
   REAL SWEEP DEPTH ENGINE (RSDE) — v1.0
   ─────────────────────────────────────────────────────────────────────────
   THE PROBLEM (from your screenshots):
   ALGO entered at 0.11210 → market swept to 0.10726 → -44.60% loss at 10x
   XLM entered at 0.17360 → market swept to 0.16855 → -29.80% loss
   XTZ entered at 0.3745 → market swept to 0.3644 → -27.57% loss

   In every case: direction was CORRECT. Entry was WRONG (too early).
   The market swept through 3-5 more pools AFTER the first absorption.
   The LEPD fired on the first absorption and said "enter here."
   But the REAL entry was far below (after ALL pools were consumed).

   THE FIX — Three engines working together:

   ENGINE 1: FULL POOL MAP (multi-timeframe)
   Scans 1h + 4h + Daily candles simultaneously to build a complete
   liquidity map — not just what's visible on the current TF.
   Finds pools at ALL levels the market might sweep before reversing.

   ENGINE 2: SWEEP DEPTH PREDICTOR
   Using: volatility regime, momentum, funding rate, and historical
   sweep patterns — predicts HOW FAR the sweep will go.
   Output: "expectedSweepBottom/Top" = where the sweep will FULLY exhaust.
   This is shown in the signal card BEFORE the sweep starts.

   ENGINE 3: REAL MOVE ENTRY ENGINE
   Waits for evidence that price has reached the predicted sweep bottom.
   Only fires when: (a) all pools swept AND (b) absorption at deepest level
   AND (c) 2+ institutional candles confirm AND (d) no more pools below.
   Places limit at EXACT close of the deepest absorption candle + 1 tick.

   RESULT: You set the limit FAR below/above current price.
   The market sweeps all the way down, fills your limit at the bottom,
   then makes the real move. You get the full move, not the loss.
   ████████████████████████████████████████████████████████████████████████████ */

const RSDE_CACHE     = new Map();
const RSDE_CACHE_TTL = 60 * 1000; // 60s — sweep conditions change fast

/* ════════════════════════════════════════════════════════════════════════════
   ENGINE 1: MULTI-TIMEFRAME FULL POOL MAP
   Builds the COMPLETE liquidity picture from 1h + 4h + Daily
   ════════════════════════════════════════════════════════════════════════════ */

async function buildFullLiquidityMap(symbol, price, dir) {
  const key = `flm_${symbol}_${dir}`;
  const hit = RSDE_CACHE.get(key);
  if (hit && Date.now() - hit.ts < RSDE_CACHE_TTL) return hit.data;

  try {
    const [c1h, c4h, c1d] = await Promise.allSettled([
      fetchCandlesCached(symbol, '1h',   96),
      fetchCandlesCached(symbol, '4h',   60),
      fetchCandlesCached(symbol, '1day', 30),
    ]);

    const candles1h = c1h.status === 'fulfilled' ? c1h.value : [];
    const candles4h = c4h.status === 'fulfilled' ? c4h.value : [];
    const candles1d = c1d.status === 'fulfilled' ? c1d.value : [];

    // Pool detection for each timeframe with weight
    const allPoolsRaw = new Map(); // level → {count, weight, sources}

    function detectPoolsOnTF(candles, weight, tfName) {
      if (!candles || candles.length < 5) return;
      const EQ = 0.0018; // 0.18% cluster threshold

      for (let i = 1; i < candles.length - 1; i++) {
        const level = dir === 'BUY' ? candles[i].l : candles[i].h;
        if (dir === 'BUY'  && level >= price * 0.9998) continue;
        if (dir === 'SELL' && level <= price * 1.0002) continue;

        // Swing point check
        const isSwing = dir === 'BUY'
          ? candles[i].l < (candles[i-1]?.l || Infinity) && candles[i].l < (candles[i+1]?.l || Infinity)
          : candles[i].h > (candles[i-1]?.h || 0)        && candles[i].h > (candles[i+1]?.h || 0);

        // Touch count
        const touches = candles.filter(c =>
          dir === 'BUY'
            ? Math.abs(c.l - level) / level < EQ
            : Math.abs(c.h - level) / level < EQ
        ).length;

        if (!isSwing && touches < 2) continue;

        // Find or create pool entry
        let found = false;
        for (const [k, v] of allPoolsRaw.entries()) {
          if (Math.abs(k - level) / level < EQ * 2.5) {
            v.count   += touches;
            v.weight  += weight;
            v.sources += `,${tfName}`;
            found = true;
            break;
          }
        }
        if (!found) {
          allPoolsRaw.set(level, { count: touches, weight, sources: tfName, level });
        }
      }
    }

    detectPoolsOnTF(candles1h, 1.0, '1h');
    detectPoolsOnTF(candles4h, 2.5, '4h'); // 4h pools are stronger
    detectPoolsOnTF(candles1d, 4.0, '1d'); // Daily pools are strongest

    // Convert to sorted array, weighted by importance
    const pools = Array.from(allPoolsRaw.entries())
      .map(([level, data]) => ({
        level:     Math.round(level * 100000) / 100000,
        weight:    data.weight,
        count:     data.count,
        sources:   data.sources,
        strength:  Math.min(100, Math.round(data.weight * data.count * 10)),
      }))
      .filter(p => dir === 'BUY' ? p.level < price : p.level > price);

    // Sort: nearest first → deepest last
    pools.sort((a, b) => dir === 'BUY' ? b.level - a.level : a.level - b.level);

    // Remove clusters within 0.3% of each other (keep strongest)
    const deduped = [];
    for (const p of pools) {
      const existing = deduped.find(d => Math.abs(d.level - p.level) / p.level < 0.003);
      if (!existing) deduped.push(p);
      else if (p.weight > existing.weight) Object.assign(existing, p);
    }

    const data = {
      pools:        deduped,
      nearestPool:  deduped[0]?.level || null,
      deepestPool:  deduped[deduped.length - 1]?.level || null,
      totalPools:   deduped.length,
      strongPools:  deduped.filter(p => p.weight >= 3.5), // 4h+ confirmed pools
    };

    RSDE_CACHE.set(key, { data, ts: Date.now() });
    return data;
  } catch(e) {
    console.warn('buildFullLiquidityMap error:', e.message);
    return { pools: [], nearestPool: null, deepestPool: null, totalPools: 0, strongPools: [] };
  }
}


/* ════════════════════════════════════════════════════════════════════════════
   ENGINE 2: SWEEP DEPTH PREDICTOR
   Predicts HOW FAR the sweep will go before the real move begins.
   This is the pre-calculated entry — shown BEFORE the sweep starts.
   ════════════════════════════════════════════════════════════════════════════ */

function predictSweepDepth(candles, price, dir, fundingData, liqMap) {
  try {
    if (!candles || candles.length < 20 || !price) return null;

    const atr    = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    const avgVol = candles.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20;

    // Factor 1: Volatility regime — higher ATR-Z = deeper sweeps
    const recentATR  = atr;
    const historicATR = candles.slice(-50, -20).reduce((a, c) => a + (c.h - c.l), 0) / 30;
    const atrZ        = historicATR > 0 ? recentATR / historicATR : 1.0;

    // Factor 2: Momentum of the current move
    const recentMove  = Math.abs(candles[candles.length - 1].c - candles[candles.length - 8].c) / price;
    const momentumPct = recentMove * 100;

    // Factor 3: Funding rate — extreme funding = more violent sweep
    const frPct = (fundingData?.fundingRate || 0) * 100;
    const frIntensity = Math.abs(frPct) / 0.1; // normalize to 0-1 range roughly

    // Factor 4: Pool density — how many pools in the path?
    const pools = liqMap?.pools || [];
    const poolCount = pools.length;
    const strongPoolCount = (liqMap?.strongPools || []).length;

    // ── Pre-calc entry = deepest mapped pool + 1 tick ─────────────────────
    // We use the ACTUAL deepest pool level, not a formula-based prediction.
    // This ensures the limit is always placed at the true end of all liquidity.
    const tickSize = price < 1 ? 0.00001 : price < 10 ? 0.0001 : price < 100 ? 0.001 : price < 1000 ? 0.01 : 0.1;

    // All pools in sweep direction — find the absolute deepest
    const allSweepPools = pools.filter(p =>
      dir === 'BUY' ? p.level < price : p.level > price
    );

    // ✅ FIX: `poolsInRange` was referenced below but never defined — it is the
    // same set as `allSweepPools` (every pool sitting between the current price
    // and the sweep direction). Aliasing here keeps the original return shape
    // and label intact while resolving the ReferenceError that caused
    // `predictSweepDepth error: poolsInRange is not defined`.
    const poolsInRange = allSweepPools;

    const deepestInRange = allSweepPools.length > 0
      ? (dir === 'BUY'
          ? Math.min(...allSweepPools.map(p => p.level))  // lowest pool for BUY
          : Math.max(...allSweepPools.map(p => p.level))) // highest pool for SELL
      : (dir === 'BUY' ? price * 0.97 : price * 1.03);   // fallback if no pools

    // Pre-calc entry: 1 tick beyond the deepest pool — fills AFTER all liquidity consumed
    const preCalcEntry = dir === 'BUY'
      ? Math.round((deepestInRange + tickSize) * 100000) / 100000
      : Math.round((deepestInRange - tickSize) * 100000) / 100000;

    // Compute stats for display
    const baseDepthPct = Math.abs(price - deepestInRange) / price * 100;
    const sweepTargetPrice = deepestInRange;

    const distanceFromPrice = Math.abs(price - preCalcEntry) / price * 100;

    return {
      baseDepthPct:      Math.round(baseDepthPct * 100) / 100,
      sweepTargetPrice:  Math.round(sweepTargetPrice * 100000) / 100000,
      preCalcEntry,
      deepestInRange:    Math.round(deepestInRange * 100000) / 100000,
      poolsInRange:      poolsInRange.length,
      distanceFromPrice: Math.round(distanceFromPrice * 100) / 100,
      atrZ:              Math.round(atrZ * 100) / 100,
      momentumPct:       Math.round(momentumPct * 100) / 100,
      factors: { atrZ, momentumPct, frIntensity, poolCount, strongPoolCount },
      label: `Predicted sweep: ${baseDepthPct.toFixed(2)}% → ${sweepTargetPrice.toFixed(5)} | Pre-calc entry: ${preCalcEntry} (${distanceFromPrice.toFixed(2)}% from price) | ${poolsInRange.length} pools in sweep range`,
    };
  } catch(e) {
    console.warn('predictSweepDepth error:', e.message);
    return null;
  }
}


/* ════════════════════════════════════════════════════════════════════════════
   ENGINE 3: REAL MOVE ENTRY ENGINE (RMEE)
   The ONLY engine that says "place your limit NOW — this is the real move."
   Combines full pool map + sweep completion + absorption + macro direction.

   Three entry modes:
   A. PRE-CALC MODE (before sweep starts):
      "Sweep predicted to reach X. Set limit at X NOW and wait."
   B. IN-SWEEP MODE (sweep in progress):
      "Sweep at Y% complete. Still Z pools remaining. DO NOT ENTER."
   C. POST-SWEEP CONFIRMATION (sweep complete, real move starting):
      "All pools consumed at X. Limit at X+1tick. THIS IS THE REAL MOVE."
   ════════════════════════════════════════════════════════════════════════════ */

async function getRealMoveEntry(symbol, candles, price, dir, instCtx) {
  const key = `rmee_${symbol}_${dir}`;
  const hit = RSDE_CACHE.get(key);
  if (hit && Date.now() - hit.ts < 30 * 1000) return hit.data; // 30s cache for RMEE

  try {
    const [liqMap, fundingData] = await Promise.allSettled([
      buildFullLiquidityMap(symbol, price, dir),
      fetchFundingRateAndOI(symbol).catch(() => null),
    ]);

    const map  = liqMap.status === 'fulfilled'  ? liqMap.value  : { pools: [], totalPools: 0 };
    const fund = fundingData.status === 'fulfilled' ? fundingData.value : null;
    const sweepPrediction = predictSweepDepth(candles, price, dir, fund, map);

    const allPools     = map.pools || [];
    const totalPools   = allPools.length;
    if (totalPools === 0) {
      const data = { mode: 'NO_POOLS', signal: 'WAIT', label: 'No liquidity pools mapped', preCalcEntry: null };
      RSDE_CACHE.set(key, { data, ts: Date.now() }); return data;
    }

    // Determine how many pools are already swept (wick touched)
    const recentLow  = Math.min(...candles.slice(-20).map(c => c.l));
    const recentHigh = Math.max(...candles.slice(-20).map(c => c.h));

    const poolsSwept   = allPools.filter(p => dir === 'BUY' ? recentLow  <= p.level * 1.002 : recentHigh >= p.level * 0.998);
    const poolsPending = allPools.filter(p => dir === 'BUY' ? recentLow  >  p.level * 1.002 : recentHigh <  p.level * 0.998);

    // Check absorption of deepest swept pool
    const deepestSwept = poolsSwept.length > 0
      ? (dir === 'BUY' ? poolsSwept.reduce((m, p) => p.level < m.level ? p : m) : poolsSwept.reduce((m, p) => p.level > m.level ? p : m))
      : null;

    // Absorption check: candle closed back beyond deepest swept pool
    const tickSize = price < 1 ? 0.0001 : price < 10 ? 0.001 : price < 100 ? 0.01 : price < 1000 ? 0.1 : 1.0;

    let absorptionCandle = null;
    if (deepestSwept) {
      for (let i = candles.length - 12; i < candles.length; i++) {
        const c = candles[i];
        if (!c) continue;
        if (dir === 'BUY' && c.l <= deepestSwept.level * 1.003 && c.c > deepestSwept.level) {
          const range = c.h - c.l;
          const bodyQuality = range > 0 ? (c.c - c.l) / range : 0;
          if (bodyQuality >= 0.50) { absorptionCandle = { ...c, bodyQuality, idx: i }; }
        }
        if (dir === 'SELL' && c.h >= deepestSwept.level * 0.997 && c.c < deepestSwept.level) {
          const range = c.h - c.l;
          const bodyQuality = range > 0 ? (c.h - c.c) / range : 0;
          if (bodyQuality >= 0.50) { absorptionCandle = { ...c, bodyQuality, idx: i }; }
        }
      }
    }

    // Post-sweep confirmation candles
    let confirmCandles = 0, maxConsec = 0, consec = 0;
    if (absorptionCandle) {
      const postSlice = candles.slice(absorptionCandle.idx + 1, absorptionCandle.idx + 7);
      for (const pc of postSlice) {
        const ok = dir === 'BUY' ? (pc.c > pc.o && pc.c > absorptionCandle.c) : (pc.c < pc.o && pc.c < absorptionCandle.c);
        if (ok) { confirmCandles++; consec++; maxConsec = Math.max(maxConsec, consec); }
        else consec = 0;
      }
    }

    // Volume exhaustion on absorption candle
    const avgVol20  = candles.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20 || 1;
    const absVol    = absorptionCandle?.v || 0;
    const post1Vol  = absorptionCandle ? (candles[absorptionCandle.idx + 1]?.v || 0) : 0;
    const volExhaust = absVol > avgVol20 * 1.5 && post1Vol < absVol * 0.55;

    // ── Determine entry mode ───────────────────────────────────────────────

    let mode, signal, certBoost, preCalcEntry, realEntry, label, waitFor;
    const pct = Math.round(poolsSwept.length / totalPools * 100);

    if (poolsSwept.length === 0) {
      // ── MODE A: PRE-CALC — sweep hasn't started yet ─────────────────────
      mode          = 'PRE_CALC';
      signal        = 'PREPARE';
      certBoost     = 0;
      preCalcEntry  = sweepPrediction?.preCalcEntry || null;
      realEntry     = null;
      waitFor       = `${totalPools} pool(s) ahead. Deepest: ${map.deepestPool?.toFixed(5)||'?'}`;
      // If no sweep prediction, use deepest pool directly as entry
      if (!preCalcEntry && map.deepestPool) {
        const tickSzPc = price < 1 ? 0.00001 : price < 10 ? 0.0001 : price < 100 ? 0.001 : price < 1000 ? 0.01 : 0.1;
        preCalcEntry = dir === 'BUY'
          ? Math.round((map.deepestPool + tickSzPc) * 100000) / 100000
          : Math.round((map.deepestPool - tickSzPc) * 100000) / 100000;
        realEntry = preCalcEntry;
      }
      const sweepPoolPath = allPools.slice(0, 8).map(p => p.level?.toFixed?.(5) || p.toFixed?.(5) || p).join(' → ');
      label         = preCalcEntry
        ? `🎯 SET ${dir} LIMIT NOW at <code>${preCalcEntry}</code> — end of ALL ${totalPools} mapped pools.\nSweep will consume: ${sweepPoolPath} → YOUR LIMIT\nSet it, walk away. Market will sweep to your level, fill you, then real move starts.`
        : `👁 ${totalPools} pool(s) mapped. Set limit at deepest pool: ${map.deepestPool?.toFixed(5)||'TBD'}.`;

    } else if (poolsPending.length > 0) {
      // ── MODE B: IN-SWEEP — sweep running, calculate FINAL limit at deepest pool
      // The deepest pending pool is where ALL liquidity ends.
      // Set limit THERE NOW — price will sweep to it and fill, then real move starts.
      mode          = 'IN_SWEEP';
      signal        = 'SET_LIMIT_DEEPEST';
      certBoost     = 2;  // positive — we know exactly where to set the limit
      const deepestPendingPool = dir === 'BUY'
        ? Math.min(...poolsPending.map(p => p.level))
        : Math.max(...poolsPending.map(p => p.level));
      const tickSzCalc = dir === 'BUY'
        ? (price < 1 ? 0.00001 : price < 10 ? 0.0001 : price < 100 ? 0.001 : price < 1000 ? 0.01 : 0.1)
        : (price < 1 ? 0.00001 : price < 10 ? 0.0001 : price < 100 ? 0.001 : price < 1000 ? 0.01 : 0.1);
      preCalcEntry  = dir === 'BUY'
        ? Math.round((deepestPendingPool + tickSzCalc) * 100000) / 100000
        : Math.round((deepestPendingPool - tickSzCalc) * 100000) / 100000;
      realEntry     = preCalcEntry;
      const pendingLevels = poolsPending.slice(0, 8).map(p => p.level.toFixed(5)).join(' → ');
      waitFor       = `Limit set at deepest pool ${preCalcEntry}. Waiting for price to sweep through: ${pendingLevels}`;
      label         = [
        `🎯 SWEEP ${pct}% — SET LIMIT AT DEEPEST POOL: <code>${preCalcEntry}</code>`,
        `${poolsSwept.length}/${totalPools} pools swept. ${poolsPending.length} still ahead.`,
        `Sweep path: ${pendingLevels}`,
        `✅ Your limit fills AFTER ALL liquidity is consumed. Real move starts at ${preCalcEntry}.`,
        `Set ${dir} LIMIT at <code>${preCalcEntry}</code> now — price will come to you.`,
      ].join('\n');

    } else if (!absorptionCandle) {
      // ── All pools swept by wick but no absorption close yet ──────────────
      mode          = 'SWEPT_AWAITING';
      signal        = 'ALMOST';
      certBoost     = 0;
      preCalcEntry  = sweepPrediction?.preCalcEntry || null;
      realEntry     = null;
      waitFor       = `All ${totalPools} pools swept. Waiting for strong absorption close at ${deepestSwept?.level?.toFixed(5)||'?'}`;
      label         = `⏳ ALL POOLS SWEPT — Waiting for absorption close.\nWick swept all ${totalPools} pools. Need candle to CLOSE BACK ${dir==='BUY'?'above':'below'} ${deepestSwept?.level?.toFixed(5)||'?'} with body ≥50% recovery.`;

    } else if (confirmCandles < 2) {
      // ── Absorption candle found but not enough confirmation yet ──────────
      mode          = 'CONFIRMING';
      signal        = 'NEAR';
      certBoost     = 5;
      realEntry     = dir === 'BUY'
        ? Math.round((absorptionCandle.c + tickSize) * 100000) / 100000
        : Math.round((absorptionCandle.c - tickSize) * 100000) / 100000;
      preCalcEntry  = realEntry;
      waitFor       = `Need ${2 - confirmCandles} more institutional candle(s) closing ${dir==='BUY'?'above':'below'} ${absorptionCandle.c}`;
      label         = `⚡ CONFIRMING — Absorption candle found, waiting for ${2 - confirmCandles} more confirm candles.\nPre-set limit at <code>${realEntry}</code> — fills if confirmation completes.`;

    } else {
      // ── MODE C: REAL MOVE CONFIRMED — place limit NOW ───────────────────
      mode      = 'REAL_MOVE_CONFIRMED';
      signal    = 'ENTER_NOW';
      realEntry = dir === 'BUY'
        ? Math.round((absorptionCandle.c + tickSize) * 100000) / 100000
        : Math.round((absorptionCandle.c - tickSize) * 100000) / 100000;
      preCalcEntry = realEntry;

      const confidence = Math.min(100, Math.round(
        60
        + (volExhaust ? 12 : 0)
        + confirmCandles * 6
        + maxConsec * 4
        + (absorptionCandle.bodyQuality >= 0.70 ? 8 : 0)
      ));
      certBoost = confidence >= 88 ? 20 : confidence >= 75 ? 14 : 8;

      label = [
        `🏆 REAL MOVE CONFIRMED — ALL ${totalPools} POOLS CONSUMED`,
        ``,
        `✅ ${poolsSwept.length}/${totalPools} pools swept | Absorption: body quality ${Math.round(absorptionCandle.bodyQuality * 100)}%`,
        `✅ ${confirmCandles} institutional confirm candles (${maxConsec} consecutive)`,
        volExhaust ? `✅ Volume fractal confirmed (spike → collapse)` : `⚠️ Volume pattern weak`,
        ``,
        `🎯 REAL MOVE ENTRY: <code>${realEntry}</code>`,
        `= Close of LAST liquidity candle + 1 tick`,
        `NO manipulation, NO liquidity, NO retail stops from here.`,
        `ONLY institutional real move remains.`,
      ].join('\n');
      waitFor = '';
    }

    const data = {
      mode, signal, certBoost,
      preCalcEntry, realEntry,
      label, waitFor,
      liqMap: map,
      sweepPrediction,
      poolsSwept:       poolsSwept.length,
      poolsPending:     poolsPending.length,
      totalPools,
      sweepPct:         pct,
      absorptionCandle: absorptionCandle ? {
        close:       absorptionCandle.c,
        bodyQuality: Math.round(absorptionCandle.bodyQuality * 100) / 100,
      } : null,
      confirmCandles,
      maxConsec,
      volExhaust,
      deepestPool: map.deepestPool,
      direction:   dir,
    };
    RSDE_CACHE.set(key, { data, ts: Date.now() });
    return data;
  } catch(e) {
    console.warn('getRealMoveEntry error:', e.message);
    return { mode: 'ERROR', signal: 'WAIT', certBoost: 0, label: 'RMEE error', preCalcEntry: null, realEntry: null };
  }
}


/* ════════════════════════════════════════════════════════════════════════════
   FORMAT + WIRE INTO PIPELINE
   ════════════════════════════════════════════════════════════════════════════ */

function formatRMEE(rmee, dir) {
  if (!rmee || rmee.mode === 'NO_POOLS' || rmee.mode === 'ERROR') return '';

  const L = ['\n━━━ 🔴 REAL SWEEP DEPTH ENGINE ━━━'];

  const modeIcon = {
    PRE_CALC:           '🎯 PRE-CALC — Set limit NOW',
    IN_SWEEP:           '🎯 SWEEP IN PROGRESS — Limit set at deepest pool',
    SET_LIMIT_DEEPEST:  '🎯 SET LIMIT AT END OF ALL LIQUIDITY',
    SWEPT_AWAITING:     '⏳ ALL POOLS SWEPT — awaiting absorption close',
    CONFIRMING:         '⚡ CONFIRMING — absorption found',
    REAL_MOVE_CONFIRMED:'🏆 REAL MOVE CONFIRMED',
  }[rmee.mode] || rmee.mode;

  L.push(`<b>${modeIcon}</b> | Pools: ${rmee.poolsSwept}/${rmee.totalPools} swept (${rmee.sweepPct}%)`);

  if (rmee.sweepPrediction) {
    L.push(`Predicted sweep depth: ${rmee.sweepPrediction.baseDepthPct}% → target ${rmee.sweepPrediction.sweepTargetPrice}`);
  }

  if (rmee.poolsPending > 0 && rmee.liqMap?.pools) {
    const pending = rmee.liqMap.pools
      .filter(p => dir === 'BUY' ? p.level < (rmee.liqMap.pools.find(x => rmee.poolsSwept > 0)?.level || Infinity) : true)
      .slice(0, 3)
      .map(p => `${p.level.toFixed(5)}[${p.sources}]`);
    if (pending.length) L.push(`⚠️ Unswept pools: ${pending.join(' → ')}`);
  }

  if (rmee.preCalcEntry) {
    L.push(`\n🎯 <b>${rmee.mode === 'REAL_MOVE_CONFIRMED' ? 'REAL MOVE' : 'PRE-CALC'} ENTRY: <code>${rmee.preCalcEntry}</code></b>`);
  }

  if (rmee.waitFor) {
    L.push(`⏳ Wait for: ${rmee.waitFor}`);
  }

  if (rmee.mode === 'IN_SWEEP') {
    L.push(`\n🚫 <b>SETTING A LIMIT NOW = ENTERING INSIDE LIQUIDITY</b>`);
    L.push(`The market will sweep through your limit to ${rmee.sweepPrediction?.sweepTargetPrice||'a lower level'} before reversing.`);
    L.push(`Set the pre-calc limit at <code>${rmee.preCalcEntry||'TBD'}</code> instead.`);
  }

  return L.join('\n');
}


/* ── Wire RMEE into buildInstitutionalContextFull ────────────────────────── */
const _origBuildInst_rmee = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function(symbol, price, dir) {
  const base = await _origBuildInst_rmee(symbol, price, dir);
  try {
    const candles = base?._sharedCandles || await fetchCandlesCached(symbol, '1h', 100).catch(() => null);
    if (candles && price && dir) {
      const rmee = await getRealMoveEntry(symbol, candles, price, dir, base).catch(() => null);
      if (base && rmee) {
        base.rmee  = rmee;
        base._rmee = true;
      }
    }
  } catch(e) { console.warn('RMEE wiring error:', e.message); }
  return base;
};


/* ── Wire RMEE into formatInstitutionalContext ───────────────────────────── */
const _origFormat_rmee = formatInstitutionalContext;
formatInstitutionalContext = function(ctx, dir) {
  let msg = '';
  try { msg = _origFormat_rmee(ctx, dir) || ''; }
  catch (e) { console.warn('inst-ctx[rmee-upstream] error:', e.message); msg = msg || ''; }
  try { if (ctx?.rmee) msg += formatRMEE(ctx.rmee, dir); }
  catch (e) { console.warn('inst-ctx[rmee] render error:', e.message); }
  return msg;
};


/* ── Wire RMEE into analyseSignalInternal — highest priority gate ─────────── */
const _origAnalyse_rmee = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  let result = _origAnalyse_rmee(consensus, instCtx, scored);
  if (!result) return result;

  const rmee = instCtx?.rmee;
  if (!rmee) return result;

  try {
    const dir = consensus?.consensusDirection || 'NEUTRAL';

    // ╔══════════════════════════════════════════════════════════════════════╗
    // ║ USER FIX: ALIGN RSDE LIMIT WITH CANONICAL SAFE LIMIT                 ║
    // ║ Original RSDE writes deep liquidity-pool limits that can sit 5–10%   ║
    // ║ from the current price. At Bybit 10x leverage that drawdown wipes    ║
    // ║ the position before the real move starts. We override its emitted    ║
    // ║ limit with the canonical max -3% pullback limit so AI Analyst, RSDE  ║
    // ║ and Recovery cards all show the same single price.                   ║
    // ╚══════════════════════════════════════════════════════════════════════╝
    try {
      let _rsdeCanon = consensus?._safeLimit || instCtx?._safeLimit || null;
      if (!_rsdeCanon) {
        const _refPx = safeNumber(consensus?.bestSig?.price || consensus?.bestSig?.entry || 0);
        // ✅ ARBITER: same single source the AI Analyst card used. If
        // AI Analyst stashed _safeLimit upstream we reuse it (no recompute);
        // otherwise we ask the arbiter ourselves so AI Analyst, RSDE,
        // and Recovery cards always agree on price + source.
        const _gCert = safeNumber(consensus?.certaintyScore || consensus?.certainty || 0);
        const _picked = selectBestLimitGuarded(_refPx, dir, { cert: _gCert, instCtx });
        if (_picked) {
          _rsdeCanon = _picked.price;
          consensus._safeLimit  = _picked.price;
          consensus._safeSource = _picked.source;
          consensus._safeLabel  = _picked.label;
        }
      }
      if (_rsdeCanon) {
        rmee.preCalcEntry = _rsdeCanon;
        if (rmee.realEntry) rmee.realEntry = _rsdeCanon;
        rmee._safeLimitOverridden = true;
      }
    } catch(_e) { /* non-fatal */ }

    if (rmee.mode === 'IN_SWEEP' || rmee.mode === 'SET_LIMIT_DEEPEST') {
      // Sweep in progress — show the deepest limit prominently
      const sweepBlock = [
        '━━━━━━━━━━━━━━━━━━━━━━',
        `🎯 <b>RSDE: SET LIMIT AT END OF ALL LIQUIDITY</b>`,
        ``,
        `Sweep ${rmee.sweepPct}%: ${rmee.poolsSwept}/${rmee.totalPools} pools consumed.`,
        rmee.poolsPending > 0 ? `${rmee.poolsPending} pool(s) remaining to be swept.` : '',
        ``,
        rmee.preCalcEntry
          ? `🎯 <b>Set ${dir} LIMIT at <code>${rmee.preCalcEntry}</code></b> — end of ALL liquidity`
          : `⏳ Calculating deepest limit level...`,
        rmee.waitFor ? `Sweep path: ${rmee.waitFor}` : '',
        ``,
        `✅ Your limit sits AFTER every pool is consumed.`,
        `✅ Price sweeps down to fill you, then real move starts immediately.`,
        `✅ Set it now — this is set and forget.`,
        '━━━━━━━━━━━━━━━━━━━━━━',
      ].filter(Boolean).join('\n');

      const firstSep = result.indexOf('━━━━━━━━━━━━━━━━━━━━━━');
      if (firstSep >= 0) result = result.slice(0, firstSep) + sweepBlock + '\n' + result.slice(firstSep);
      else result = sweepBlock + '\n' + result;

    } else if (rmee.mode === 'REAL_MOVE_CONFIRMED' && rmee.realEntry) {
      // HIGHEST SIGNAL — all pools consumed, real move confirmed
      const confirm = [
        '━━━━━━━━━━━━━━━━━━━━━━',
        `🏆 <b>RSDE: REAL MOVE ENTRY CONFIRMED</b>`,
        ``,
        `ALL ${rmee.totalPools} pools consumed across 1h + 4h + Daily timeframes.`,
        `${rmee.confirmCandles} institutional candles confirm direction.`,
        rmee.volExhaust ? `✅ Volume exhaustion confirmed — sweep energy depleted.` : '',
        ``,
        `🎯 <b>REAL MOVE ENTRY: <code>${rmee.realEntry}</code></b>`,
        `This is the close of the last liquidity candle + 1 tick.`,
        `From this price: NO pools, NO manipulation, NO retail stops.`,
        `Direction: ${dir} — institutional real move beginning.`,
        '━━━━━━━━━━━━━━━━━━━━━━',
      ].filter(Boolean).join('\n');

      const firstSep = result.indexOf('━━━━━━━━━━━━━━━━━━━━━━');
      if (firstSep >= 0) result = result.slice(0, firstSep) + confirm + '\n' + result.slice(firstSep);
      else result = confirm + '\n' + result;

    } else if (rmee.mode === 'PRE_CALC' && rmee.preCalcEntry) {
      // Show pre-calc entry before sweep starts
      const precalc = `\n📍 <b>RSDE PRE-CALC:</b> Set ${dir} LIMIT at <code>${rmee.preCalcEntry}</code> now.\nSweep predicted ${rmee.sweepPrediction?.baseDepthPct||'?'}% deep across ${rmee.totalPools} pools. Wait for fill.\n`;
      result += precalc;
    }

  } catch(e) { console.warn('RMEE analyseSignalInternal patch error:', e.message); }
  return result;
};


