/* ════════════════════════════════════════════════════════════════════════════
   PART 1: RECOVERY SIGNAL SYSTEM
   ─────────────────────────────────────────────────────────────────────────
   Tracks signals that fired but whose sweep was incomplete at signal time.
   Every scan cycle, checks if those signals have now completed their sweep.
   When sweep completes → re-sends full signal + AI analyst automatically.

   Also handles /recovery command: manually request any past signal resent.
   ════════════════════════════════════════════════════════════════════════════ */

const RECOVERY_STORE    = new Map(); // symbol → { signalTs, dir, entry, pools, sentAt }
const RECOVERY_SENT     = new Set(); // symbol_dir_ts to prevent duplicates
const MAX_RECOVERY_AGE  = 72 * 60 * 60 * 1000; // 72h — max age to track
const RECOVERY_FILE     = './recovery_signals.json';

// Load persisted recovery store on startup
try {
  if (fs.existsSync(RECOVERY_FILE)) {
    const saved = JSON.parse(fs.readFileSync(RECOVERY_FILE, 'utf8'));
    for (const [k, v] of Object.entries(saved)) {
      if (Date.now() - v.signalTs < MAX_RECOVERY_AGE) RECOVERY_STORE.set(k, v);
    }
    console.log(`🔄 Recovery store loaded: ${RECOVERY_STORE.size} tracked signals`);
  }
} catch(_) {}

function saveRecoveryStore() {
  try {
    const obj = Object.fromEntries(RECOVERY_STORE.entries());
    fs.writeFileSync(RECOVERY_FILE, JSON.stringify(obj, null, 2));
  } catch(_) {}
}

/**
 * registerSignalForRecovery(symbol, dir, entry, lepd, rmee)
 * Call this when a signal fires but sweep is still pending.
 * Tracks it so recovery system can resend when sweep completes.
 */
function registerSignalForRecovery(symbol, dir, entry, lepd, rmee) {
  try {
    const key = `${symbol}_${dir}`;
    const existing = RECOVERY_STORE.get(key);

    // Only register if sweep is incomplete
    const sweepIncomplete =
      lepd?.state === 'PRE_SWEEP'   ||
      lepd?.state === 'SWEEPING'    ||
      lepd?.state === 'DEEPER_POOLS_EXIST' ||
      rmee?.mode  === 'PRE_CALC'    ||
      rmee?.mode  === 'IN_SWEEP';

    if (!sweepIncomplete) return;

    const record = {
      symbol, dir, entry,
      signalTs:     Date.now(),
      lepdState:    lepd?.state     || 'UNKNOWN',
      allPools:     lepd?.allPools  || rmee?.liqMap?.pools?.map(p=>p.level) || [],
      poolsPending: lepd?.poolsPending || rmee?.poolsPending || 0,
      deepestPool:  lepd?.deepestPool  || rmee?.deepestPool  || null,
      preCalcEntry: rmee?.preCalcEntry || lepd?.precisionLimit || null,
      recovered:    false,
      sentAt:       null,
    };

    RECOVERY_STORE.set(key, record);
    saveRecoveryStore();
    console.log(`📌 Recovery tracked: ${symbol} ${dir} entry=${entry} deepest=${record.deepestPool}`);
  } catch(e) {
    console.warn('registerSignalForRecovery error:', e.message);
  }
}

/**
 * checkRecoverySignals(generator, chatId, tgSend)
 * Called every scan cycle. For each tracked signal, checks if sweep
 * has now completed. If yes, re-sends the full signal card + AI analyst.
 */
async function checkRecoverySignals(generator, chatId, tgSend) {
  if (!RECOVERY_STORE.size) return;

  for (const [key, record] of RECOVERY_STORE.entries()) {
    try {
      // Skip if too old
      if (Date.now() - record.signalTs > MAX_RECOVERY_AGE) {
        RECOVERY_STORE.delete(key);
        continue;
      }
      // Skip if already recovered
      if (record.recovered) continue;

      const { symbol, dir, deepestPool, preCalcEntry, signalTs } = record;
      const ageHours = Math.round((Date.now() - signalTs) / 36e5 * 10) / 10;

      // Fetch current price
      const price = await fetchLivePrice(symbol).catch(() => null);
      if (!price) continue;

      // Fetch candles for RMEE check
      const candles = await fetchCandlesCached(symbol, '1h', 100).catch(() => null);
      if (!candles) continue;

      // Check if sweep has progressed
      const rmee = await getRealMoveEntry(symbol, candles, price, dir, null).catch(() => null);
      const lepd = detectLiquidityExhaustion(candles, price, dir, null);

      const sweepComplete =
        rmee?.mode === 'REAL_MOVE_CONFIRMED' ||
        rmee?.mode === 'CONFIRMING' ||
        lepd?.state === 'PERFECT_EXHAUSTION' ||
        lepd?.state === 'STRONG_EXHAUSTION';

      if (!sweepComplete) continue;

      // Dedup check
      const dedupKey = `${symbol}_${dir}_${Math.floor(signalTs / 3600000)}`;
      if (RECOVERY_SENT.has(dedupKey)) continue;
      RECOVERY_SENT.add(dedupKey);

      // Re-build and send the full signal
      console.log(`🔄 RECOVERY TRIGGER: ${symbol} ${dir} — sweep complete after ${ageHours}h`);

      const consensus = await buildMTFConsensus(symbol, generator).catch(() => null);
      if (!consensus) continue;

      // Build context
      const instCtx = await buildInstitutionalContextFull(symbol, price, dir).catch(() => null);

      // Format recovery header
      // ✅ Clamp displayed limit prices to max -3% from current price
      const _recMaxP = parseFloat(process.env.MAX_LIMIT_PULLBACK_PCT || '3') / 100;
      const _recClamp = (lp) => {
        if (!lp || !price || price <= 0) return lp;
        const _n = Number(lp);
        if (dir === 'BUY'  && _n < price * (1 - _recMaxP)) return price * (1 - _recMaxP);
        if (dir === 'SELL' && _n > price * (1 + _recMaxP)) return price * (1 + _recMaxP);
        return _n;
      };
      const _recFmt = (v) => { if (!v || isNaN(v)) return null; const n = Number(v); return n > 1000 ? n.toFixed(2) : n > 1 ? n.toFixed(4) : n.toFixed(6); };
      const _rmeeDisp = _recFmt(_recClamp(rmee?.realEntry));
      const _lepdDisp = _recFmt(_recClamp(lepd?.precisionLimit));
      const recoveryHeader = [
        `━━━ 🔄 RECOVERY SIGNAL ━━━`,
        `⏰ Original signal: <b>${ageHours}h ago</b>`,
        `✅ Sweep completed — real move entry now available`,
        `📌 Original entry was: <code>${record.entry}</code>`,
        _rmeeDisp ? `🎯 <b>New precision entry: <code>${_rmeeDisp}</code></b>` : '',
        _lepdDisp ? `🎯 <b>LEPD precision: <code>${_lepdDisp}</code></b>` : '',
        ``,
      ].filter(Boolean).join('\n');

      // Send recovery header + signal card
      const recoveryMsg = recoveryHeader + '\n' + (formatMTFConsensusMessage(consensus) || '');
      const safeMsg = recoveryMsg.length > 4090 ? recoveryMsg.slice(0, 4090) + '<i>…</i>' : recoveryMsg;

      try {
        const r = await tgSend('sendMessage', {
          chat_id: chatId,
          text: safeMsg,
          parse_mode: 'HTML',
          disable_web_page_preview: true,
        });

        if (r?.ok) {
          // Send AI analyst
          await new Promise(res => setTimeout(res, 1500));
          const scored = scoreIntraSignal(consensus, instCtx);
          if (scored && instCtx) {
            await sendAIAnalysis(symbol, consensus, instCtx, scored).catch(() => {});
          }

          // Mark recovered
          record.recovered = true;
          record.sentAt    = Date.now();
          saveRecoveryStore();
          console.log(`✅ Recovery sent: ${symbol} ${dir}`);
        }
      } catch(sendErr) {
        console.warn('Recovery send error:', sendErr.message);
      }

      // Small delay between recovery signals
      await new Promise(res => setTimeout(res, 3000));

    } catch(e) {
      console.warn(`Recovery check error for ${key}:`, e.message);
    }
  }
}

/**
 * handleRecoveryCommand(chatId, tgSend, generator, args)
 * /recovery — lists all tracked signals with status
 * /recovery BTCUSDT BUY — manually re-send a specific signal
 * /recovery all — re-send all pending recovery signals
 */
async function handleRecoveryCommand(chatId, tgSend, generator, args) {
  try {
    const [symbolArg, dirArg] = (args || '').trim().toUpperCase().split(/\s+/);

    if (!symbolArg || symbolArg === '') {
      // List all tracked
      if (!RECOVERY_STORE.size) {
        await tgSend('sendMessage', { chat_id: chatId, text: '🔄 <b>Recovery Store</b>\n\nNo signals currently being tracked.', parse_mode: 'HTML' });
        return;
      }
      const lines = ['🔄 <b>Recovery Signal Tracker</b>', ''];
      for (const [k, r] of RECOVERY_STORE.entries()) {
        const age = Math.round((Date.now() - r.signalTs) / 36e5 * 10) / 10;
        const icon = r.recovered ? '✅' : '⏳';
        lines.push(`${icon} <b>${r.symbol}</b> ${r.dir} | ${age}h ago | deepest: <code>${r.deepestPool||'?'}</code> | ${r.recovered?'RECOVERED':'pending'}`);
      }
      lines.push('', 'Use /recovery SYMBOL DIR to force re-send any signal');
      await tgSend('sendMessage', { chat_id: chatId, text: lines.join('\n'), parse_mode: 'HTML' });
      return;
    }

    // Force re-send specific signal
    const key = symbolArg + (dirArg ? `_${dirArg}` : '');
    const match = dirArg ? RECOVERY_STORE.get(key) : Array.from(RECOVERY_STORE.values()).find(r => r.symbol === symbolArg);

    if (!match) {
      // Force a fresh scan for this symbol
      await tgSend('sendMessage', { chat_id: chatId, text: `🔍 Scanning <b>${symbolArg}</b> ${dirArg||''} for recovery signal...`, parse_mode: 'HTML' });
      const price = await fetchLivePrice(symbolArg).catch(() => null);
      if (!price) { await tgSend('sendMessage', { chat_id: chatId, text: `❌ Could not fetch price for ${symbolArg}`, parse_mode: 'HTML' }); return; }

      const candles = await fetchCandlesCached(symbolArg, '1h', 100).catch(() => null);
      const d = dirArg || 'BUY';
      const lepd = candles ? detectLiquidityExhaustion(candles, price, d, null) : null;
      const rmee = candles ? await getRealMoveEntry(symbolArg, candles, price, d, null).catch(() => null) : null;

      const infoLines = [
        `📊 <b>${symbolArg} ${d}</b> — Current status:`,
        lepd ? `LEPD: ${lepd.state} | conf ${lepd.confidence}% | ${lepd.poolsSwept||0}/${lepd.allPools?.length||0} pools swept` : 'LEPD: no data',
        rmee ? `RMEE: ${rmee.mode} | ${rmee.poolsSwept||0}/${rmee.totalPools||0} pools swept (${rmee.sweepPct||0}%)` : 'RMEE: no data',
        rmee?.preCalcEntry ? `Pre-calc entry: <code>${rmee.preCalcEntry}</code>` : '',
        lepd?.precisionLimit ? `LEPD limit: <code>${lepd.precisionLimit}</code>` : '',
      ].filter(Boolean);
      await tgSend('sendMessage', { chat_id: chatId, text: infoLines.join('\n'), parse_mode: 'HTML' });
      return;
    }

    // Force re-send
    match.recovered = false; // reset so it resends
    const dedupKey = `${match.symbol}_${match.dir}_force_${Date.now()}`;
    await checkRecoverySignals(generator, chatId, tgSend);
    await tgSend('sendMessage', { chat_id: chatId, text: `🔄 Recovery signal for <b>${match.symbol} ${match.dir}</b> queued.`, parse_mode: 'HTML' });

  } catch(e) {
    console.warn('handleRecoveryCommand error:', e.message);
  }
}

// Wire recovery registration into the signal pipeline
// Called after every signal fires in autoScanner
const _origAutoScanner = autoScanner;
autoScanner = async function() {
  await _origAutoScanner();
  // After each scan, check if any tracked signals have completed their sweep
  try {
    if (RECOVERY_STORE.size > 0) {
      const sys = global._tradingSystem;
      if (sys?.telegramInterface) {
        const chatId = TELEGRAM_CHAT_ID;
        await checkRecoverySignals(
          sys.signalGenerator,
          chatId,
          (method, params) => sys.telegramInterface.sendTelegramRequest(method, params)
        );
      }
    }
  } catch(_) {}
};


/* ════════════════════════════════════════════════════════════════════════════
   PART 2: APEX LIQUIDITY DETECTOR (ALD)
   ─────────────────────────────────────────────────────────────────────────
   Measures the TOTAL QUANTIFIED LIQUIDITY in an asset before the real
   institutional long-term move begins.

   What "total liquidity" means:
   Not just pool count — the VOLUME of stop orders sitting at each level.
   High liquidity concentration = institutions NEED to sweep this before moving.
   After they sweep it all = they have the fuel to move far in one direction.

   Components:
   1. STOP CLUSTER DENSITY — how many stops per price unit sit at each level
   2. OPEN INTEREST CONCENTRATION — where leveraged positions are clustered
   3. FUNDING RATE ACCUMULATION — how long has crowded positioning built up
   4. HISTORICAL REACTION STRENGTH — how violently has this level been swept before
   5. CROSS-ASSET LIQUIDITY CORRELATION — when BTC sweeps, how much follows

   Output: APEX_LIQUIDITY_SCORE 0-100
   > 75: Massive liquidity concentration → huge move incoming once swept
   > 50: Significant liquidity → reliable move
   < 30: Low liquidity → shallow move, skip

   APEX CONFLUENCE: When APEX score is high AND RMEE/LEPD confirm ALL liquidity
   consumed → this is the APEX ENTRY — the rarest, highest-conviction setup.
   ════════════════════════════════════════════════════════════════════════════ */

const ALD_CACHE     = new Map();
const ALD_CACHE_TTL = 5 * 60 * 1000; // 5min — liquidity concentration is stable

async function getApexLiquidityScore(symbol, price, dir, candles, fundingData) {
  const key = `ald_${symbol}_${dir}`;
  const hit = ALD_CACHE.get(key);
  if (hit && Date.now() - hit.ts < ALD_CACHE_TTL) return hit.data;

  try {
    if (!candles || candles.length < 20 || !price) return null;

    const atr = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    if (!atr || atr <= 0) return null;

    // ── Component 1: Stop Cluster Density ────────────────────────────────
    // Count how many swing points (stop clusters) exist in sweep direction
    // weighted by how many candles returned to the same level (= denser stop pool)
    let stopDensityScore = 0;
    const EQ = 0.002;
    const stopLevels = [];

    for (let i = 2; i < candles.length - 2; i++) {
      const level = dir === 'BUY' ? candles[i].l : candles[i].h;
      if (dir === 'BUY' && level >= price) continue;
      if (dir === 'SELL' && level <= price) continue;
      const isSwing = dir === 'BUY'
        ? candles[i].l < candles[i-1].l && candles[i].l < candles[i+1].l
        : candles[i].h > candles[i-1].h && candles[i].h > candles[i+1].h;
      if (!isSwing) continue;
      const retouches = candles.filter(c =>
        dir === 'BUY' ? Math.abs(c.l - level) / level < EQ : Math.abs(c.h - level) / level < EQ
      ).length;
      stopLevels.push({ level, retouches });
      stopDensityScore += retouches * 2;
    }

    const normalizedStopDensity = Math.min(100, stopDensityScore / 3);

    // ── Component 2: Open Interest Concentration ──────────────────────────
    // Use funding rate as OI proxy — higher absolute funding = more OI concentration
    const frPct = (fundingData?.fundingRate || 0) * 100;
    const oiScore = Math.min(100, Math.abs(frPct) / 0.15 * 100);

    // ── Component 3: Funding Rate Accumulation ────────────────────────────
    // How long has extreme funding persisted? (proxy: high |fr| = accumulated risk)
    const fundingAccum = Math.min(100, Math.abs(frPct) * 400);

    // ── Component 4: Historical Reaction Strength ────────────────────────
    // When sweep levels were last tested, how strongly did price react?
    let reactionScore = 0;
    for (const sl of stopLevels) {
      // Find the candle that last touched this level
      const touchIdx = candles.reduce((best, c, i) => {
        const dist = dir === 'BUY' ? Math.abs(c.l - sl.level) : Math.abs(c.h - sl.level);
        return dist < atr * 0.15 ? i : best;
      }, -1);
      if (touchIdx > 0 && touchIdx < candles.length - 1) {
        const nextCandle = candles[touchIdx + 1];
        const reaction = Math.abs(nextCandle.c - nextCandle.o) / atr;
        reactionScore += Math.min(25, reaction * 10);
      }
    }
    const normalizedReaction = Math.min(100, reactionScore);

    // ── Component 5: Volume Concentration at Stop Levels ─────────────────
    // High volume at stop levels = more real orders sitting there
    const avgVol = candles.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20 || 1;
    let volConcentration = 0;
    for (const sl of stopLevels) {
      const nearCandles = candles.filter(c =>
        dir === 'BUY' ? Math.abs(c.l - sl.level) / sl.level < 0.003 : Math.abs(c.h - sl.level) / sl.level < 0.003
      );
      const levelVol = nearCandles.reduce((s, c) => s + (c.v || 0), 0) / (nearCandles.length || 1);
      volConcentration += levelVol / avgVol;
    }
    const normalizedVolConc = Math.min(100, volConcentration * 15);

    // ── Composite APEX Score ──────────────────────────────────────────────
    // Weighted combination of all 5 components
    const apexScore = Math.round(
      normalizedStopDensity * 0.30 +   // stop clusters = 30%
      oiScore               * 0.20 +   // OI concentration = 20%
      fundingAccum          * 0.15 +   // funding accumulation = 15%
      normalizedReaction    * 0.20 +   // historical reaction = 20%
      normalizedVolConc     * 0.15     // volume concentration = 15%
    );

    // ── APEX interpretation ───────────────────────────────────────────────
    let apexTier, apexLabel, apexCertBoost;
    if (apexScore >= 75) {
      apexTier      = 'APEX';
      apexCertBoost = 20;
      apexLabel     = `🏔️ APEX LIQUIDITY — ${apexScore}/100: Massive institutional fuel. When swept, expect 8-20%+ sustained move.`;
    } else if (apexScore >= 55) {
      apexTier      = 'HIGH';
      apexCertBoost = 12;
      apexLabel     = `🔥 HIGH LIQUIDITY — ${apexScore}/100: Large fuel pool. Expected move 4-10% post-sweep.`;
    } else if (apexScore >= 35) {
      apexTier      = 'MODERATE';
      apexCertBoost = 6;
      apexLabel     = `📊 MODERATE LIQUIDITY — ${apexScore}/100: Decent fuel. Expected move 2-5% post-sweep.`;
    } else {
      apexTier      = 'LOW';
      apexCertBoost = 0;
      apexLabel     = `💧 LOW LIQUIDITY — ${apexScore}/100: Limited fuel. Short move expected, use smaller size.`;
    }

    // ── Expected move magnitude ───────────────────────────────────────────
    // Based on APEX score + ATR
    const expectedMovePct = Math.round(apexScore / 100 * 15 * 100) / 100; // 0-15% based on score
    const expectedMovePrice = dir === 'BUY'
      ? Math.round((price * (1 + expectedMovePct / 100)) * 100000) / 100000
      : Math.round((price * (1 - expectedMovePct / 100)) * 100000) / 100000;

    // ── Stop level map ────────────────────────────────────────────────────
    const topStopLevels = stopLevels
      .sort((a, b) => b.retouches - a.retouches)
      .slice(0, 4)
      .map(sl => ({ level: Math.round(sl.level * 100000) / 100000, strength: sl.retouches }));

    const data = {
      apexScore,
      apexTier,
      apexCertBoost,
      apexLabel,
      expectedMovePct,
      expectedMovePrice,
      stopLevelCount: stopLevels.length,
      topStopLevels,
      components: {
        stopDensity:    Math.round(normalizedStopDensity),
        oiConcentration: Math.round(oiScore),
        fundingAccum:   Math.round(fundingAccum),
        reactionStrength: Math.round(normalizedReaction),
        volConcentration: Math.round(normalizedVolConc),
      },
      frPct:    Math.round(frPct * 1000) / 1000,
      direction: dir,
    };

    ALD_CACHE.set(key, { data, ts: Date.now() });
    return data;
  } catch(e) {
    console.warn('getApexLiquidityScore error:', e.message);
    return null;
  }
}

function formatAPEX(apex, dir) {
  if (!apex) return '';
  const L = ['\n━━━ 🏔️ APEX LIQUIDITY DETECTOR ━━━'];
  L.push(`<b>${apex.apexLabel}</b>`);

  // Score bar
  const bars = Math.round(apex.apexScore / 10);
  const bar  = '█'.repeat(bars) + '░'.repeat(10 - bars);
  L.push(`[${bar}] ${apex.apexScore}/100`);

  // Components
  const { stopDensity, oiConcentration, fundingAccum, reactionStrength, volConcentration } = apex.components;
  L.push(`Stop density: ${stopDensity} | OI conc: ${oiConcentration} | Funding accum: ${fundingAccum}`);
  L.push(`Reaction str: ${reactionStrength} | Vol conc: ${volConcentration}`);

  // Top stop levels
  if (apex.topStopLevels?.length) {
    L.push(`Key sweep targets: ${apex.topStopLevels.map(s=>`<code>${s.level}</code>(${s.strength}×)`).join(' → ')}`);
  }

  // Expected move
  L.push(`Expected move post-sweep: <b>${dir==='BUY'?'+':'−'}${apex.expectedMovePct}%</b> → <code>${apex.expectedMovePrice}</code>`);

  if (apex.apexTier === 'APEX') {
    L.push(`\n🏔️ <b>APEX CONFLUENCE</b>: When RMEE/LEPD confirm all liquidity consumed + APEX tier = HIGHEST conviction entry in existence.`);
  }

  return L.join('\n');
}


/* ── Wire ALD into buildInstitutionalContextFull ─────────────────────────── */
const _origBuildInst_ald = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function(symbol, price, dir) {
  const base = await _origBuildInst_ald(symbol, price, dir);
  try {
    const candles     = base?._sharedCandles || await fetchCandlesCached(symbol, '1h', 80).catch(() => null);
    const fundingData = await fetchFundingRateAndOI(symbol).catch(() => null);
    const apex = candles ? await getApexLiquidityScore(symbol, price, dir, candles, fundingData).catch(() => null) : null;
    if (base && apex) {
      base.apex  = apex;
      base._apex = true;
    }
  } catch(e) { console.warn('ALD wiring error:', e.message); }
  return base;
};

/* ── Wire ALD into formatInstitutionalContext ────────────────────────────── */
const _origFormat_ald = formatInstitutionalContext;
formatInstitutionalContext = function(ctx, dir) {
  let msg = '';
  try { msg = _origFormat_ald(ctx, dir) || ''; }
  catch (e) { console.warn('inst-ctx[ald-upstream] error:', e.message); }
  try { if (ctx?.apex) msg += formatAPEX(ctx.apex, dir); }
  catch (e) { console.warn('inst-ctx[apex] render error:', e.message); }
  return msg;
};

/* ── Wire ALD into analyseSignalInternal pos/neg + certBoost ─────────────── */
const _origAnalyse_ald = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  let result = _origAnalyse_ald(consensus, instCtx, scored);
  if (!result) return result;

  const apex = instCtx?.apex;
  if (apex?.apexTier === 'APEX' || apex?.apexTier === 'HIGH') {
    const apexBlock = [
      '',
      `🏔️ <b>APEX LIQUIDITY: ${apex.apexScore}/100 — ${apex.apexTier} TIER</b>`,
      apex.apexLabel,
      `Expected move: ${apex.expectedMovePct}% → <code>${apex.expectedMovePrice}</code>`,
      '',
    ].join('\n');

    const firstSep = result.indexOf('━━━━━━━━━━━━━━━━━━━━━━');
    if (firstSep >= 0) result = result.slice(0, firstSep) + apexBlock + result.slice(firstSep);
    else result += apexBlock;
  }
  return result;
};

/* APEX certBoost flows via instCtx.clge.certBoost into the scoring section above */


/* ── Wire RECOVERY registration into signal pipeline ────────────────────── */
// Register signals for recovery tracking in the main autoScanner
// This is called inside the signal card send block
const _origFormatMTF = formatMTFConsensusMessage;
formatMTFConsensusMessage = function(consensus) {
  const result = _origFormatMTF(consensus);
  // Register for recovery if LEPD/RMEE show incomplete sweep
  try {
    const ctx  = consensus?._instCtx;
    const sym  = consensus?.symbol || consensus?.bestSig?.symbol;
    const dir  = consensus?.consensusDirection;
    const entry = consensus?.bestSig?.entry;
    if (sym && dir && entry && ctx) {
      registerSignalForRecovery(sym, dir, entry, ctx.lepd, ctx.rmee);
    }
  } catch(_) {}
  return result;
};


/* ── Add /recovery command to Telegram handler ───────────────────────────── */
EnhancedQuantumTradingSystem.prototype.handleLegacyCommand = (function(_prev_hlc_recovery) { return async function(message) {
  const text = (message?.text || '').trim();
  const chatId = message?.chat?.id;

  if (text.toLowerCase().startsWith('/recovery')) {
    const args = text.slice('/recovery'.length).trim();
    await handleRecoveryCommand(
      chatId,
      (method, params) => this.telegramInterface.sendTelegramRequest(method, params),
      this.signalGenerator,
      args
    );
    return;
  }

  if (text.toLowerCase() === '/apex' || text.toLowerCase().startsWith('/apex ')) {
    const parts  = text.split(/\s+/);
    const sym    = (parts[1] || 'BTCUSDT').toUpperCase();
    const dir    = (parts[2] || 'BUY').toUpperCase();
    const price  = await fetchLivePrice(sym).catch(() => null);
    const candles = await fetchCandlesCached(sym, '1h', 80).catch(() => null);
    const fund   = await fetchFundingRateAndOI(sym).catch(() => null);
    const apex   = price && candles ? await getApexLiquidityScore(sym, price, dir, candles, fund) : null;
    if (!apex) {
      await this.sendMessage(chatId, `❌ Could not compute APEX for ${sym}`);
      return;
    }
    const lines = [
      `🏔️ <b>APEX LIQUIDITY — ${sym} ${dir}</b>`,
      ``,
      apex.apexLabel,
      `Score: ${apex.apexScore}/100 | Tier: <b>${apex.apexTier}</b> | Cert boost: +${apex.apexCertBoost}%`,
      `Expected move: ${apex.expectedMovePct}% → <code>${apex.expectedMovePrice}</code>`,
      ``,
      `Components:`,
      `  Stop density: ${apex.components.stopDensity} | OI: ${apex.components.oiConcentration} | Funding: ${apex.components.fundingAccum}`,
      `  Reaction: ${apex.components.reactionStrength} | Vol conc: ${apex.components.volConcentration}`,
      ``,
      `Key sweep levels: ${apex.topStopLevels?.map(s=>`${s.level}(${s.strength}×)`).join(' → ')||'none'}`,
    ];
    await this.sendMessage(chatId, lines.join('\n'));
    return;
  }

  return _prev_hlc_recovery.call(this, message);
}; })(EnhancedQuantumTradingSystem.prototype.handleLegacyCommand);

