/* ████████████████████████████████████████████████████████████████████████████
   SECTION A: RECOVERY SIGNAL ENGINE
   ─────────────────────────────────────────────────────────────────────────
   When signals are sent by the scanner but you miss them (asleep, away),
   this engine recovers ALL assets where liquidity has been swept in the
   past N hours. It re-runs the full signal card + AI analyst for each one.

   Commands:
   /recovery          — show all assets with swept liquidity in last 12h
   /recovery 6h       — last 6 hours
   /recovery 24h      — last 24 hours
   /missed            — alias for /recovery
   /postliq           — show assets where LEPD = PERFECT or STRONG EXHAUSTION
   ████████████████████████████████████████████████████████████████████████████ */

const RECOVERY_SCAN_CACHE = new Map();

async function runRecoveryScan(hoursBack = 12) {
  const cacheKey = `recovery_${hoursBack}`;
  const hit      = RECOVERY_SCAN_CACHE.get(cacheKey);
  if (hit && Date.now() - hit.ts < 3 * 60 * 1000) return hit.data;

  const results = [];
  const symbols = Array.from(WATCH.keys());
  const cutoff  = Date.now() - hoursBack * 3600 * 1000;

  // Scan every symbol for post-liquidity states
  for (const symbol of symbols) {
    try {
      const price = await fetchLivePrice(symbol).catch(() => null);
      if (!price) continue;

      // Run quick LEPD check on both directions
      for (const dir of ['BUY', 'SELL']) {
        const candles = await fetchCandlesCached(symbol, '1h', 60).catch(() => null);
        if (!candles || candles.length < 15) continue;

        const lepd = detectLiquidityExhaustion(candles, price, dir, null);
        if (!lepd) continue;

        // Only recover if exhaustion was recently confirmed
        const isRecoverable = ['PERFECT_EXHAUSTION', 'STRONG_EXHAUSTION', 'SWEPT_NO_ABSORPTION']
          .includes(lepd.state);
        if (!isRecoverable) continue;

        // Check RMEE state
        const rmee = await getRealMoveEntry(symbol, candles, price, dir, null).catch(() => null);

        // Only include if all pools swept or confirming
        const worthRecovering = lepd.state === 'PERFECT_EXHAUSTION' ||
          lepd.state === 'STRONG_EXHAUSTION' ||
          (rmee?.mode === 'REAL_MOVE_CONFIRMED') ||
          (rmee?.mode === 'CONFIRMING');

        if (!worthRecovering) continue;

        results.push({
          symbol, dir, price,
          lepdState:     lepd.state,
          confidence:    lepd.confidence,
          precisionLimit: lepd.precisionLimit,
          rmeeMode:      rmee?.mode || 'UNKNOWN',
          preCalcEntry:  rmee?.preCalcEntry || lepd.precisionLimit,
          poolsSwept:    lepd.poolsSwept,
          totalPools:    lepd.allPools?.length || 0,
          timestamp:     Date.now(),
        });
        break; // one direction per symbol
      }
    } catch(_) { /* skip errors */ }
  }

  // Sort by confidence descending
  results.sort((a, b) => b.confidence - a.confidence);

  const data = { results, scannedAt: Date.now(), hoursBack };
  RECOVERY_SCAN_CACHE.set(cacheKey, { data, ts: Date.now() });
  return data;
}

async function sendRecoverySignals(chatId, tgFn, hoursBack = 12) {
  await tgFn('sendMessage', { chat_id: chatId,
    text: `🔍 <b>Recovery Scan — Last ${hoursBack}h</b>\nScanning ${WATCH.size} assets for swept liquidity...`,
    parse_mode: 'HTML' }).catch(() => {});

  const scan = await runRecoveryScan(hoursBack);

  if (!scan.results.length) {
    await tgFn('sendMessage', { chat_id: chatId,
      text: `📭 <b>No recovery signals</b>\nNo assets found with swept liquidity in the last ${hoursBack}h.`,
      parse_mode: 'HTML' }).catch(() => {});
    return;
  }

  // Send summary first
  const summaryLines = [
    `♻️ <b>Recovery Signals — ${scan.results.length} assets</b>`,
    `Scanned: last ${hoursBack}h | Found: ${scan.results.length} post-liquidity setups`,
    '',
  ];
  for (const r of scan.results.slice(0, 8)) {
    const stateIcon = r.lepdState === 'PERFECT_EXHAUSTION' ? '🏆'
      : r.lepdState === 'STRONG_EXHAUSTION' ? '✅'
      : r.rmeeMode === 'REAL_MOVE_CONFIRMED' ? '🎯'
      : r.rmeeMode === 'CONFIRMING' ? '⚡' : '⏳';
    const entryStr = r.preCalcEntry ? ` | Entry: <code>${r.preCalcEntry}</code>` : '';
    summaryLines.push(`${stateIcon} <b>${r.symbol}</b> ${r.dir} @ <code>${r.price}</code>${entryStr} — ${r.confidence}% conf`);
  }
  summaryLines.push('', `<i>Sending full signal cards below...</i>`);

  await tgFn('sendMessage', {
    chat_id: chatId, text: summaryLines.join('\n'), parse_mode: 'HTML'
  }).catch(() => {});

  // Send full signal card + AI analyst for top results
  for (const r of scan.results.slice(0, 5)) {
    try {
      await sleep(1000);

      const candles = await fetchCandlesCached(r.symbol, '1h', 100).catch(() => null);
      if (!candles) continue;

      const [htfConsensus] = await Promise.allSettled([
        buildMTFConsensus(r.symbol, null).catch(() => null),
      ]);
      const consensus = htfConsensus.status === 'fulfilled' ? htfConsensus.value : null;
      if (!consensus) continue;

      // Build instCtx
      let instCtx = null;
      try { instCtx = await buildInstitutionalContextFull(r.symbol, r.price, r.dir); } catch(_) {}
      if (instCtx) consensus._instCtx = instCtx;

      const scored = autoScoreSignal(consensus, consensus?.bestSig);

      // Build signal card
      const cardText = formatMTFConsensusMessage(consensus);
      const safeCard = cardText.length > 4090 ? cardText.slice(0, 4090) + '<i>…</i>' : cardText;

      await tgFn('sendMessage', {
        chat_id: chatId, text: `♻️ <b>RECOVERY SIGNAL — ${r.symbol}</b>\n\n` + safeCard,
        parse_mode: 'HTML', disable_web_page_preview: true,
      }).catch(() => {});

      // Send AI analyst
      await sleep(1500);
      await sendAIAnalysis(r.symbol, consensus, instCtx, scored).catch(() => {});

    } catch(e) {
      console.warn(`Recovery signal error for ${r.symbol}:`, e.message);
    }
  }

  await tgFn('sendMessage', { chat_id: chatId,
    text: `✅ <b>Recovery scan complete</b>\n${scan.results.length} setups found. Top ${Math.min(5, scan.results.length)} sent above.`,
    parse_mode: 'HTML' }).catch(() => {});
}


/* ████████████████████████████████████████████████████████████████████████████
   SECTION B: APEX UPGRADE — CUMULATIVE LIQUIDITY GRAVITY ENGINE (CLGE)
   ─────────────────────────────────────────────────────────────────────────
   MORE SOPHISTICATED THAN STANDARD LIQUIDITY DETECTION.

   Standard liquidity: finds WHERE pools are.
   CLGE: measures the TOTAL GRAVITATIONAL MASS of all liquidity in a direction
   and computes the INSTITUTIONAL CONVICTION required to move price past it.

   Physics model: Gravitational attraction between price and liquidity mass.
   F = G × (M1 × M2) / d²
   Where:
     M1 = current price × volume (market momentum)
     M2 = pool size × age weight × timeframe weight (liquidity mass)
     d  = distance from price to pool
     G  = market gravity constant (calibrated per asset class)

   When the CUMULATIVE GRAVITY pulling price toward a direction exceeds
   the INSTITUTIONAL CONVICTION threshold:
   → Price MUST visit that liquidity before any sustained move away from it
   → The larger the gravity, the larger the eventual move after consumption

   New signals produced:
   1. GRAVITY_VECTOR:       Direction + magnitude of pull
   2. GRAVITY_THRESHOLD:    Price level where gravity becomes irresistible
   3. CONVICTION_INDEX:     How much institutional force is behind the move
   4. ABSORPTION_PREDICTION: Estimated price where ALL gravity is resolved
   5. LONG_TERM_TARGET:     Post-absorption target based on gravity magnitude
   ████████████████████████████████████████████████████████████████████████████ */

const CLGE_CACHE     = new Map();
const CLGE_CACHE_TTL = 5 * 60 * 1000;

const GRAVITY_CONSTANT = 0.0042; // market gravity constant (calibrated for crypto)

async function computeLiquidityGravity(symbol, candles, price, dir) {
  const cacheKey = `clge_${symbol}_${dir}`;
  const hit      = CLGE_CACHE.get(cacheKey);
  if (hit && Date.now() - hit.ts < CLGE_CACHE_TTL) return hit.data;

  try {
    if (!candles || candles.length < 20 || !price) return null;

    const atr    = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    const avgVol = candles.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20 || 1;
    const currentMomentum = candles.slice(-5).reduce((s, c) => s + (c.c > c.o ? c.v : -c.v), 0);

    // Get full liquidity map
    const liqMap = await buildFullLiquidityMap(symbol, price, dir).catch(() => null);
    if (!liqMap || !liqMap.pools.length) return null;

    const pools = liqMap.pools;

    // ── Compute gravitational force from each pool ────────────────────────
    let totalGravity = 0;
    const poolGravities = [];

    for (const pool of pools) {
      const distance   = Math.abs(price - pool.level);
      const distNorm   = distance / price; // as % of price
      if (distNorm <= 0) continue;

      // Pool mass = size weight × timeframe weight × touch count
      const poolMass = pool.weight * pool.count * (1 + pool.strength / 100);

      // Market momentum mass = volume × price
      const momentumMass = Math.abs(currentMomentum) / avgVol;

      // Gravitational force: F = G × (M1 × M2) / d²
      const force = GRAVITY_CONSTANT * (momentumMass * poolMass) / (distNorm * distNorm);

      totalGravity += force;
      poolGravities.push({
        level:    pool.level,
        force:    Math.round(force * 1000) / 1000,
        mass:     Math.round(poolMass * 100) / 100,
        distPct:  Math.round(distNorm * 10000) / 100,
        sources:  pool.sources,
      });
    }

    // Normalise to conviction index 0-100
    const convictionIndex = Math.round(Math.min(100, totalGravity * 8));

    // ── Gravity threshold: price level where gravity becomes irresistible ──
    // This is the weighted centre of gravity of all pools
    const totalMass = pools.reduce((s, p) => s + p.weight * p.count, 0) || 1;
    const gravityCenter = pools.reduce((s, p) => s + p.level * p.weight * p.count, 0) / totalMass;

    // ── Absorption prediction: where does gravity resolve? ──────────────────
    // The deepest pool with significant mass = final absorption level
    const significantPools = poolGravities.filter(p => p.mass >= 3.0);
    const deepest = significantPools.length > 0
      ? (dir === 'BUY'
          ? significantPools.reduce((m, p) => p.level < m.level ? p : m)
          : significantPools.reduce((m, p) => p.level > m.level ? p : m))
      : poolGravities[poolGravities.length - 1];

    const absorptionPrice = deepest?.level || gravityCenter;

    // ── Long-term target: post-absorption institutional move ────────────────
    // After gravity is resolved, price moves by the magnitude of the absorbed mass
    // Target = absorption level ± (totalGravity × ATR × conviction multiplier)
    const moveMultiplier = Math.min(8, totalGravity * 1.5);
    const longTermTarget = dir === 'BUY'
      ? Math.round((absorptionPrice + atr * moveMultiplier) * 100000) / 100000
      : Math.round((absorptionPrice - atr * moveMultiplier) * 100000) / 100000;

    // ── Signal classification ──────────────────────────────────────────────
    let gravitySignal, gravityLabel, certBoost = 0;

    if (convictionIndex >= 75) {
      gravitySignal = 'IRRESISTIBLE';
      certBoost     = 16;
      gravityLabel  = `🌑 IRRESISTIBLE GRAVITY — ${convictionIndex} conviction. Price WILL visit ${absorptionPrice.toFixed(5)} before any sustained move away.`;
    } else if (convictionIndex >= 50) {
      gravitySignal = 'STRONG';
      certBoost     = 10;
      gravityLabel  = `⚫ STRONG GRAVITY — ${convictionIndex} conviction. High probability sweep to ${absorptionPrice.toFixed(5)}.`;
    } else if (convictionIndex >= 30) {
      gravitySignal = 'MODERATE';
      certBoost     = 5;
      gravityLabel  = `🔵 MODERATE GRAVITY — ${convictionIndex} conviction. Likely sweep to ${absorptionPrice.toFixed(5)}.`;
    } else {
      gravitySignal = 'WEAK';
      certBoost     = 0;
      gravityLabel  = `⚪ WEAK GRAVITY — ${convictionIndex} conviction. Pools present but insufficient mass for forced sweep.`;
    }

    // certBoost direction: if gravity aligns with signal dir → positive, else negative
    // (gravity always pulls toward liquidity, so if we're waiting for sweep then
    //  high gravity = good = confirms our setup)

    const data = {
      gravitySignal,
      convictionIndex,
      totalGravity:      Math.round(totalGravity * 1000) / 1000,
      gravityCenter:     Math.round(gravityCenter * 100000) / 100000,
      absorptionPrice:   Math.round(absorptionPrice * 100000) / 100000,
      longTermTarget:    Math.round(longTermTarget * 100000) / 100000,
      moveMultiplier:    Math.round(moveMultiplier * 100) / 100,
      poolGravities:     poolGravities.slice(0, 5),
      significantPools:  significantPools.length,
      certBoost,
      direction:         dir,
      label:             gravityLabel,
    };

    CLGE_CACHE.set(cacheKey, { data, ts: Date.now() });
    return data;
  } catch(e) {
    console.warn('computeLiquidityGravity error:', e.message);
    return null;
  }
}

function formatCLGE(clge, dir) {
  if (!clge || clge.gravitySignal === 'WEAK') return '';

  const L = ['\n━━━ 🌑 APEX: LIQUIDITY GRAVITY ENGINE ━━━'];

  const icon = { IRRESISTIBLE: '🌑', STRONG: '⚫', MODERATE: '🔵', WEAK: '⚪' }[clge.gravitySignal] || '⚪';
  L.push(`${icon} <b>${clge.gravitySignal} GRAVITY</b> — Conviction: ${clge.convictionIndex}/100`);
  L.push(`Gravity center: <code>${clge.gravityCenter}</code> | Absorption: <code>${clge.absorptionPrice}</code>`);
  L.push(`Post-absorption target: <code>${clge.longTermTarget}</code> (${clge.moveMultiplier}× ATR from absorption)`);

  if (clge.poolGravities?.length) {
    const topPools = clge.poolGravities.slice(0, 3)
      .map(p => `${p.level}[F:${p.force}]`)
      .join(' → ');
    L.push(`Top gravity pools: ${topPools}`);
  }

  L.push(`\n<i>${clge.label}</i>`);
  return L.join('\n');
}


/* ── Wire CLGE into buildInstitutionalContextFull ────────────────────────── */
const _origBuildInst_clge = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function(symbol, price, dir) {
  const base = await _origBuildInst_clge(symbol, price, dir);
  try {
    const candles = base?._sharedCandles || await fetchCandlesCached(symbol, '1h', 80).catch(() => null);
    if (candles && price && dir) {
      const clge = await computeLiquidityGravity(symbol, candles, price, dir).catch(() => null);
      if (base && clge) {
        base.clge  = clge;
        base._clge = true;
      }
    }
  } catch(e) { console.warn('CLGE wiring error:', e.message); }
  return base;
};

/* ── Wire CLGE into formatInstitutionalContext ───────────────────────────── */
