/* ── Wire /recovery + /postliq + /missed Telegram commands ──────────────── */
const _origHandleLegacy_rec2 = EnhancedQuantumTradingSystem.prototype.handleLegacyCommand;
EnhancedQuantumTradingSystem.prototype.handleLegacyCommand = async function(message) {
  const text    = (message?.text || '').trim();
  const chatId  = message?.chat?.id;
  const parts   = text.split(' ');
  const cmd     = parts[0].toLowerCase().replace(/@[^\s]+$/, '');
  const arg     = parts[1] || '';

  if (cmd === '/recovery' || cmd === '/missed' || cmd === '/postliq') {
    let hours = 12;
    if (arg) {
      const parsed = parseFloat(arg);
      if (!isNaN(parsed)) {
        hours = parsed;
      } else if (arg.endsWith('h')) {
        hours = parseFloat(arg) || 12;
      } else if (arg.endsWith('d')) {
        hours = (parseFloat(arg) || 1) * 24;
      }
    }
    hours = Math.max(1, Math.min(72, hours));
    await sendRecoverySignals(chatId, tg.bind(this), hours);
    return;
  }

  return _origHandleLegacy_rec2.call(this, message);
};


/* ── Final wiring: CLGE certBoost into pos/neg + effectiveCert ──────────── */
