// by overriding the function one more time to inject CLGE score:
const _origAnalyse_clgeFinal = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  let result = _origAnalyse_clgeFinal(consensus, instCtx, scored);
  if (!result) return result;

  const clge = instCtx?.clge;
  if (!clge || clge.certBoost === 0) return result;

  // CLGE certBoost is already injected via instCtx
  // The existing effectiveCert formula doesn't include it yet
  // We add a note to the result about it
  try {
    const dir = consensus?.consensusDirection || 'NEUTRAL';
    if (clge.gravitySignal === 'IRRESISTIBLE' && clge.certBoost > 0) {
      const gravNote = `\n🌑 <b>GRAVITY:</b> ${clge.convictionIndex}/100 conviction | Absorption target: <code>${clge.absorptionPrice}</code> | Long-term: <code>${clge.longTermTarget}</code>`;
      // Avoid duplicating if already added
      if (!result.includes('GRAVITY:')) result += gravNote;
    }
  } catch(_) {}
  return result;
};


