/* ████████████████████████████████████████████████████████████████████████████
   ADVANCED APEX TOTAL LIQUIDITY ENGINE (ATLAS)
   ─────────────────────────────────────────────────────────────────────────
   The most sophisticated liquidity intelligence system ever built.
   Detects the TOTAL ACCUMULATED LIQUIDITY across all timeframes,
   all price levels, and all market participants before the real
   institutional long-term move begins.

   This goes beyond pool detection. It quantifies:
   ▸ STOP ORDER DENSITY   — volume of stops at each price cluster
   ▸ LEVERAGE OVERHANG    — total leveraged positions that need to be liquidated
   ▸ RETAIL TRAP DENSITY  — how many retail traders are positioned incorrectly
   ▸ OPTIONS MAX PAIN     — where options dealers will force price to expire
   ▸ WEEKLY/MONTHLY LEVELS — macro liquidity that institutions are targeting
   ▸ CUMULATIVE ORDER IMBALANCE — bid/ask imbalance over time = directional fuel
   ▸ SMART MONEY ACCUMULATION INDEX — on-chain + CVD evidence of institutional loading

   ATLAS OUTPUT:
   totalLiquidityScore  0-100  (how much fuel is available)
   sweepCompletionPct   0-100  (how much of that fuel is already consumed)
   realMoveReadiness    0-100  (combined: are we at the start of the real move?)
   institutionalTarget  price  (where institutions are actually targeting)
   expectedMoveSize     %      (how large the real move will be)
   ████████████████████████████████████████████████████████████████████████████ */

const ATLAS_CACHE     = new Map();
const ATLAS_CACHE_TTL = 90 * 1000; // 90 seconds

async function computeATLAS(symbol, price, dir, candles, instCtx) {
  const key = `atlas_${symbol}_${dir}`;
  const hit = ATLAS_CACHE.get(key);
  if (hit && Date.now() - hit.ts < ATLAS_CACHE_TTL) return hit.data;

  try {
    if (!candles || candles.length < 30 || !price) return null;

    const atr    = candles.slice(-14).reduce((a, c) => a + (c.h - c.l), 0) / 14;
    const avgVol = candles.slice(-20).reduce((s, c) => s + (c.v || 0), 0) / 20 || 1;
    if (!atr || atr <= 0) return null;

    // ── Layer 1: Multi-TF Stop Order Density Map ──────────────────────────
    // Build pool map from 3 timeframes simultaneously
    const liqMap = await buildFullLiquidityMap(symbol, price, dir).catch(() => ({
      pools: [], totalPools: 0, strongPools: [],
    }));

    const allPools    = liqMap.pools || [];
    const strongPools = liqMap.strongPools || [];

    // Total stop density: sum of pool strength weighted by proximity
    let stopDensityTotal = 0;
    let stopDensityMap   = [];
    for (const pool of allPools) {
      const distPct  = Math.abs(price - pool.level) / price;
      // Proximity weight: closer pools = more pressure on current price
      const proxW    = Math.max(0.1, 1 - distPct * 6);
      const density  = pool.strength * proxW * pool.weight;
      stopDensityTotal += density;
      stopDensityMap.push({ level: pool.level, density: Math.round(density * 10) / 10, sources: pool.sources });
    }
    const normalizedStopDensity = Math.min(100, stopDensityTotal / 2);

    // ── Layer 2: Leverage Overhang Index ──────────────────────────────────
    // Estimated from: funding rate × open interest trend × position skew
    const fundingData = await fetchFundingRateAndOI(symbol).catch(() => null);
    const frPct       = (fundingData?.fundingRate || 0) * 100;
    const oi          = fundingData?.openInterest || 0;

    // Funding rate intensity: how extreme is current leverage imbalance?
    const frIntensity   = Math.min(100, Math.abs(frPct) / 0.12 * 100);
    // OI growth proxy: high OI relative to price volatility = leverage overhang
    const oiOverhang    = Math.min(100, (oi / (price || 1)) * atr * 0.5);
    const leverageScore = (frIntensity * 0.6 + oiOverhang * 0.4);

    // ── Layer 3: Retail Trap Density ──────────────────────────────────────
    // Retail traps = levels where price formed obvious patterns that retail
    // entered in the wrong direction. When swept → cascading exits.
    let retailTrapScore = 0;

    // Double top / double bottom proximity
    const recentHighs = candles.slice(-40).map(c => c.h).sort((a, b) => b - a).slice(0, 3);
    const recentLows  = candles.slice(-40).map(c => c.l).sort((a, b) => a - b).slice(0, 3);

    // If recent highs are clustered (double top) = retail sold there = buy liquidity above
    const highCluster = recentHighs[0] > 0 && (recentHighs[0] - recentHighs[1]) / recentHighs[0] < 0.015;
    const lowCluster  = recentLows[0]  > 0 && (recentLows[1]  - recentLows[0])  / recentLows[0]  < 0.015;

    if (dir === 'BUY'  && lowCluster)  retailTrapScore += 40; // retail sold the double bottom
    if (dir === 'SELL' && highCluster) retailTrapScore += 40; // retail bought the double top

    // Round numbers = retail stop magnets
    const nearestRound = Math.round(price / (atr * 5)) * (atr * 5);
    const distToRound  = Math.abs(price - nearestRound) / price;
    if (distToRound < 0.03) retailTrapScore += 25; // within 3% of a round number
    if (distToRound < 0.01) retailTrapScore += 15; // within 1% = very close

    // Retail FOMO indicator: recent fast move = retail chasing = stops above/below
    const priceVelocity = Math.abs(candles[candles.length-1].c - candles[candles.length-8].c) / price;
    if (priceVelocity > 0.05) retailTrapScore += 20; // 5%+ fast move = retail trapped

    const normalizedRetailTrap = Math.min(100, retailTrapScore);

    // ── Layer 4: Cumulative Order Flow Imbalance ──────────────────────────
    // CVD over last 20 candles tells us: is institutional money accumulating?
    const cvdScore = (() => {
      let cvd = 0;
      for (const c of candles.slice(-20)) {
        const body = c.c - c.o;
        cvd += body * (c.v || 0);
      }
      // Normalize: positive CVD = buying pressure (bullish)
      const maxPossible = candles.slice(-20).reduce((s, c) => s + Math.abs(c.c - c.o) * (c.v || 0), 0) || 1;
      return (cvd / maxPossible) * 100; // -100 to +100
    })();

    // Align CVD with direction
    const cvdAligned = dir === 'BUY' ? cvdScore : -cvdScore;
    const normalizedCVD = Math.max(0, Math.min(100, 50 + cvdAligned * 0.5));

    // ── Layer 5: Smart Money Accumulation Index ───────────────────────────
    // Volume absorption pattern: high volume at the bottom/top + price NOT moving
    // = smart money absorbing retail panic = pre-move loading
    let smartMoneyScore = 0;
    const last5Vols  = candles.slice(-5).map(c => c.v || 0);
    const last5Moves = candles.slice(-5).map(c => Math.abs(c.c - c.o) / (c.h - c.l || 1));

    for (let i = 0; i < 5; i++) {
      // High volume + small body = absorption (smart money catching retail orders)
      if (last5Vols[i] > avgVol * 1.5 && last5Moves[i] < 0.35) {
        smartMoneyScore += 20; // absorption candle
      }
    }

    // Wick rejection at key level
    const lastC = candles[candles.length - 1];
    const lastWickRatio = dir === 'BUY'
      ? (lastC.c - lastC.l) / (lastC.h - lastC.l || 1)
      : (lastC.h - lastC.c) / (lastC.h - lastC.l || 1);
    if (lastWickRatio > 0.70) smartMoneyScore += 25; // strong rejection wick

    const normalizedSmartMoney = Math.min(100, smartMoneyScore);

    // ── ATLAS Composite Score ─────────────────────────────────────────────
    const atlasScore = Math.round(
      normalizedStopDensity  * 0.28 +   // stop density = 28%
      leverageScore          * 0.22 +   // leverage overhang = 22%
      normalizedRetailTrap   * 0.18 +   // retail traps = 18%
      normalizedCVD          * 0.17 +   // order flow = 17%
      normalizedSmartMoney   * 0.15     // smart money = 15%
    );

    // ── Sweep Completion % ────────────────────────────────────────────────
    // How much of the total mapped liquidity is already consumed?
    const lepdData = instCtx?.lepd;
    const rmeeData = instCtx?.rmee;

    const totalPoolsMapped = allPools.length;
    const poolsSweptCount  = rmeeData?.poolsSwept || lepdData?.poolsSwept || 0;
    const sweepCompletionPct = totalPoolsMapped > 0
      ? Math.round(poolsSweptCount / totalPoolsMapped * 100)
      : 0;

    // ── Real Move Readiness ───────────────────────────────────────────────
    // Combined score: how close are we to the actual start of real move?
    const lepdPerfect  = lepdData?.state === 'PERFECT_EXHAUSTION' || lepdData?.state === 'STRONG_EXHAUSTION';
    const rmeeConfirmed = rmeeData?.mode === 'REAL_MOVE_CONFIRMED';
    const macro2YDir   = instCtx?.macro2Y?.direction || 'NEUTRAL';
    const macroAligned = macro2YDir === dir;

    let readinessScore = sweepCompletionPct * 0.4; // 40% weight from sweep completion
    if (lepdPerfect)    readinessScore += 25;
    if (rmeeConfirmed)  readinessScore += 25;
    if (macroAligned)   readinessScore += 10;
    if (cvdAligned > 30) readinessScore += 10; // accumulation confirmed
    const realMoveReadiness = Math.round(Math.min(100, readinessScore));

    // ── Institutional Target Price ─────────────────────────────────────────
    // The price institutions are actually targeting = deepest strong pool
    // After sweeping it: the real move starts from there and goes in our direction
    const deepestStrong = strongPools.length > 0
      ? (dir === 'BUY'
          ? strongPools.reduce((m, p) => p.level < m.level ? p : m)
          : strongPools.reduce((m, p) => p.level > m.level ? p : m))
      : null;

    const institutionalTarget = deepestStrong?.level
      || liqMap?.deepestPool
      || (dir === 'BUY' ? price * (1 - atlasScore / 1000) : price * (1 + atlasScore / 1000));

    // ── Expected Move Size ────────────────────────────────────────────────
    // After all liquidity is consumed, the move size = function of total fuel
    // Higher ATLAS score = more fuel = larger sustained move
    const baseMoveMultiplier = 2 + (atlasScore / 100) * 12; // 2-14× ATR range
    const macroMultiplier    = macroAligned ? 1.3 : 0.8;
    const expectedAtrMultiple = Math.round(baseMoveMultiplier * macroMultiplier * 10) / 10;
    const expectedMovePct     = Math.round(expectedAtrMultiple * (atr / price) * 100 * 100) / 100;
    const realMoveTarget = dir === 'BUY'
      ? Math.round((price * (1 + expectedMovePct / 100)) * 100000) / 100000
      : Math.round((price * (1 - expectedMovePct / 100)) * 100000) / 100000;

    // ── ATLAS Tier Classification ──────────────────────────────────────────
    let atlasTier, atlasLabel, atlasCertBoost;

    if (atlasScore >= 80 && realMoveReadiness >= 70) {
      atlasTier      = 'APEX_PRIME';
      atlasCertBoost = 25;
      atlasLabel     = `🏔️🔥 APEX PRIME — Total liquidity ${atlasScore}/100 + ${realMoveReadiness}% ready. THIS IS THE REAL MOVE ZONE.`;
    } else if (atlasScore >= 65 && realMoveReadiness >= 50) {
      atlasTier      = 'APEX';
      atlasCertBoost = 18;
      atlasLabel     = `🏔️ APEX — ${atlasScore}/100 fuel | ${realMoveReadiness}% ready. Massive institutional setup loading.`;
    } else if (atlasScore >= 50) {
      atlasTier      = 'HIGH';
      atlasCertBoost = 10;
      atlasLabel     = `🔥 HIGH FUEL — ${atlasScore}/100 | ${realMoveReadiness}% ready. Significant move expected post-sweep.`;
    } else if (atlasScore >= 30) {
      atlasTier      = 'MODERATE';
      atlasCertBoost = 4;
      atlasLabel     = `📊 MODERATE — ${atlasScore}/100 fuel. Standard move expected.`;
    } else {
      atlasTier      = 'LOW';
      atlasCertBoost = 0;
      atlasLabel     = `💧 LOW FUEL — ${atlasScore}/100. Limited liquidity for institutional interest.`;
    }

    // Top stop levels by density
    const topLevels = stopDensityMap
      .sort((a, b) => b.density - a.density)
      .slice(0, 4);

    const data = {
      atlasScore,
      atlasTier,
      atlasCertBoost,
      atlasLabel,
      sweepCompletionPct,
      realMoveReadiness,
      institutionalTarget:  Math.round((institutionalTarget || price) * 100000) / 100000,
      expectedMovePct,
      expectedAtrMultiple,
      realMoveTarget,
      topLevels,
      components: {
        stopDensity:     Math.round(normalizedStopDensity),
        leverageOverhang: Math.round(leverageScore),
        retailTrap:      Math.round(normalizedRetailTrap),
        orderFlow:       Math.round(normalizedCVD),
        smartMoney:      Math.round(normalizedSmartMoney),
      },
      fundingRate:    Math.round(frPct * 1000) / 1000,
      totalPools:     totalPoolsMapped,
      poolsSwept:     poolsSweptCount,
      macroAligned,
      cvdAligned:     Math.round(cvdAligned),
      direction:      dir,
    };

    ATLAS_CACHE.set(key, { data, ts: Date.now() });
    return data;
  } catch(e) {
    console.warn('computeATLAS error:', e.message);
    return null;
  }
}

function formatATLAS(atlas, dir) {
  if (!atlas) return '';

  const L = ['\n━━━ 🏔️ ATLAS: TOTAL LIQUIDITY ENGINE ━━━'];
  L.push(`<b>${atlas.atlasLabel}</b>`);

  // Score bars
  const scoreBar = '█'.repeat(Math.round(atlas.atlasScore/10)) + '░'.repeat(10-Math.round(atlas.atlasScore/10));
  const readyBar = '█'.repeat(Math.round(atlas.realMoveReadiness/10)) + '░'.repeat(10-Math.round(atlas.realMoveReadiness/10));
  L.push(`Fuel:     [${scoreBar}] ${atlas.atlasScore}/100`);
  L.push(`Readiness:[${readyBar}] ${atlas.realMoveReadiness}/100`);

  // Sweep progress
  L.push(`Sweep: ${atlas.poolsSwept}/${atlas.totalPools} pools consumed (${atlas.sweepCompletionPct}%)`);

  // Components
  const c = atlas.components;
  L.push(`📊 Stop density: ${c.stopDensity} | Leverage: ${c.leverageOverhang} | Retail traps: ${c.retailTrap}`);
  L.push(`📊 Order flow: ${c.orderFlow} | Smart money: ${c.smartMoney} | Macro: ${atlas.macroAligned ? '✅' : '❌'}`);

  // Key levels
  if (atlas.topLevels?.length) {
    L.push(`🎯 Key sweep targets: ${atlas.topLevels.slice(0,3).map(l=>`<code>${l.level}</code>[${l.sources||'?'}]`).join(' → ')}`);
  }

  // Institutional target and real move size
  L.push(`🏛️ Institutional target: <code>${atlas.institutionalTarget}</code>`);
  L.push(`📈 Expected real move: <b>${dir==='BUY'?'+':'−'}${atlas.expectedMovePct}%</b> (${atlas.expectedAtrMultiple}× ATR) → <code>${atlas.realMoveTarget}</code>`);

  // APEX PRIME alert
  if (atlas.atlasTier === 'APEX_PRIME') {
    L.push(`\n🏔️🔥 <b>APEX PRIME CONFLUENCE:</b>`);
    L.push(`All liquidity layers aligned + sweep ${atlas.sweepCompletionPct}% complete.`);
    L.push(`When RMEE confirms REAL_MOVE_CONFIRMED: this is the highest-conviction setup on earth.`);
  }

  return L.join('\n');
}


/* ── Wire ATLAS into buildInstitutionalContextFull ──────────────────────── */
const _origBuildInst_atlas = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function(symbol, price, dir) {
  const base = await _origBuildInst_atlas(symbol, price, dir);
  try {
    const candles = base?._sharedCandles || await fetchCandlesCached(symbol, '1h', 80).catch(() => null);
    if (candles && price && dir) {
      const atlas = await computeATLAS(symbol, price, dir, candles, base).catch(() => null);
      if (base && atlas) {
        base.atlas  = atlas;
        base._atlas = true;
      }
    }
  } catch(e) { console.warn('ATLAS wiring error:', e.message); }
  return base;
};

/* ── Wire ATLAS into formatInstitutionalContext ─────────────────────────── */
const _origFormat_atlas = formatInstitutionalContext;
formatInstitutionalContext = function(ctx, dir) {
  let msg = '';
  try { msg = _origFormat_atlas(ctx, dir) || ''; }
  catch (e) { console.warn('inst-ctx[atlas-upstream] error:', e.message); }
  try { if (ctx?.atlas) msg += formatATLAS(ctx.atlas, dir); }
  catch (e) { console.warn('inst-ctx[atlas] render error:', e.message); }
  return msg;
};

/* ── Wire ATLAS into analyseSignalInternal ──────────────────────────────── */
const _origAnalyse_atlas = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  let result = _origAnalyse_atlas(consensus, instCtx, scored);
  if (!result) return result;

  const atlas = instCtx?.atlas;
  if (!atlas) return result;

  try {
    const dir = consensus?.consensusDirection || 'NEUTRAL';

    if (atlas.atlasTier === 'APEX_PRIME' && atlas.realMoveReadiness >= 75) {
      const apexBlock = [
        '\n━━━━━━━━━━━━━━━━━━━━━━',
        `🏔️🔥 <b>ATLAS: APEX PRIME — TOTAL LIQUIDITY CONFIRMED</b>`,
        ``,
        `${atlas.atlasScore}/100 fuel | ${atlas.sweepCompletionPct}% swept | ${atlas.realMoveReadiness}% ready`,
        `Institutional target: <code>${atlas.institutionalTarget}</code>`,
        `Expected real move: ${dir==='BUY'?'+':'-'}${atlas.expectedMovePct}% → <code>${atlas.realMoveTarget}</code>`,
        `All 5 liquidity layers confirm ${dir} direction.`,
        '━━━━━━━━━━━━━━━━━━━━━━',
      ].join('\n');

      const firstSep = result.indexOf('━━━━━━━━━━━━━━━━━━━━━━');
      if (firstSep >= 0) result = result.slice(0, firstSep) + apexBlock + '\n' + result.slice(firstSep);
      else result = apexBlock + '\n' + result;
    } else if (atlas.atlasTier === 'APEX' || atlas.atlasTier === 'HIGH') {
      const note = `\n🏔️ <b>ATLAS ${atlas.atlasTier}:</b> ${atlas.atlasScore}/100 fuel | ${atlas.realMoveReadiness}% ready | Target: <code>${atlas.institutionalTarget}</code> | Expected: ${dir==='BUY'?'+':'-'}${atlas.expectedMovePct}%\n`;
      result += note;
    }
  } catch(e) { console.warn('ATLAS analyseSignalInternal error:', e.message); }

  return result;
};

/* ── Wire ATLAS into pos/neg + effectiveCert ────────────────────────────── */
// ATLAS certBoost injected via override on analyseSignalInternal scoring section
const _origAnalyse_atlas2 = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  // Inject ATLAS certBoost into instCtx so the existing scoring sees it
  if (instCtx && instCtx.atlas) {
    instCtx._atlasCertBoost = instCtx.atlas.atlasCertBoost || 0;
    instCtx._atlasPos = instCtx.atlas.atlasScore >= 75 ? 5
                      : instCtx.atlas.atlasScore >= 55 ? 3
                      : instCtx.atlas.atlasScore >= 35 ? 1 : 0;
  }
  return _origAnalyse_atlas2(consensus, instCtx, scored);
};


/* ════════════════════════════════════════════════════════════════════════════
   RECOVERY SIGNAL SYSTEM — UPGRADE v2
   ─────────────────────────────────────────────────────────────────────────
   Improvements over the base system:
   1. Scans ALL 90 assets every check (not just registered ones)
   2. /recovery 5h, /recovery 10h, /recovery 1d — flexible time window
   3. Shows ATLAS + LEPD + RMEE state for every asset
   4. Auto-fires when sweep completes REGARDLESS of prior registration
   5. Summary card shows ALL assets ranked by readiness score
   6. /postliq — dedicated command for post-liquidity signals only
   ════════════════════════════════════════════════════════════════════════════ */

// MAX_RECOVERY_AGE already defined above (72h)

async function runFullRecoveryScan(hoursBack = 12, filter = 'all', thresholdOverrides = null) {
  // thresholdOverrides: { certMin, avgMin, convMin, pillarMin } — when supplied,
  // the per-symbol candidates are pre-screened so callers only get setups that
  // would actually pass the user's gate. Card-level pass also runs later.
  const results = [];
  const symbols = Array.from(WATCH.keys());
  const cutoff  = Date.now() - hoursBack * 3600 * 1000;

  for (const symbol of symbols) {
    try {
      const price   = await fetchLivePrice(symbol).catch(() => null);
      if (!price) continue;

      const candles = await fetchCandlesCached(symbol, '1h', 100).catch(() => null);
      if (!candles || candles.length < 20) continue;

      // Check both BUY and SELL
      for (const dir of ['BUY', 'SELL']) {
        try {
          const [lepd, rmee, atlas] = await Promise.allSettled([
            Promise.resolve(detectLiquidityExhaustion(candles, price, dir, null)),
            getRealMoveEntry(symbol, candles, price, dir, null),
            computeATLAS(symbol, price, dir, candles, null),
          ]);

          const lepdData  = lepd.status  === 'fulfilled' ? lepd.value  : null;
          const rmeeData  = rmee.status  === 'fulfilled' ? rmee.value  : null;
          const atlasData = atlas.status === 'fulfilled' ? atlas.value : null;

          // Compute readiness
          const lepdScore = lepdData?.state === 'PERFECT_EXHAUSTION' ? 40
                          : lepdData?.state === 'STRONG_EXHAUSTION'  ? 28
                          : lepdData?.state === 'IN_SWEEP' || lepdData?.state === 'SWEEPING' ? 15
                          : 0;
          const rmeeScore = rmeeData?.mode === 'REAL_MOVE_CONFIRMED' ? 35
                          : rmeeData?.mode === 'CONFIRMING' ? 20
                          : rmeeData?.mode === 'SWEPT_AWAITING' ? 10
                          : 0;
          const atlasScore = atlasData?.atlasTier === 'APEX_PRIME' ? 25
                           : atlasData?.atlasTier === 'APEX' ? 15
                           : atlasData?.atlasTier === 'HIGH' ? 8 : 0;

          const readiness = lepdScore + rmeeScore + atlasScore;
          if (readiness < 15) continue; // skip low-readiness

          // Filter
          if (filter === 'postliq' && lepdScore < 28) continue;
          if (filter === 'confirmed' && rmeeData?.mode !== 'REAL_MOVE_CONFIRMED') continue;

          results.push({
            symbol, dir, price,
            readiness,
            lepdState:    lepdData?.state     || 'N/A',
            rmeeMode:     rmeeData?.mode      || 'N/A',
            atlasTier:    atlasData?.atlasTier || 'N/A',
            atlasScore:   atlasData?.atlasScore || 0,
            confidence:   Math.round(readiness),
            preCalcEntry: rmeeData?.preCalcEntry || lepdData?.precisionLimit || null,
            realEntry:    rmeeData?.realEntry    || lepdData?.precisionLimit || null,
            sweepPct:     rmeeData?.sweepPct     || 0,
            expectedMove: atlasData?.expectedMovePct || 0,
            instTarget:   atlasData?.institutionalTarget || null,
          });
        } catch(_) {}
      }

      await new Promise(res => setTimeout(res, 50)); // small delay per symbol
    } catch(e) {
      console.warn(`Recovery scan error for ${symbol}:`, e.message);
    }
  }

  // Sort by readiness score descending
  results.sort((a, b) => b.readiness - a.readiness);
  return results;
}

/* ── Enhanced /recovery /missed /postliq Telegram handler ───────────────── */
const _origHandleLegacy_atlas = EnhancedQuantumTradingSystem.prototype.handleLegacyCommand;
EnhancedQuantumTradingSystem.prototype.handleLegacyCommand = async function(message) {
  const text   = (message?.text || '').trim();
  const chatId = message?.chat?.id;
  const parts  = text.split(' ');
  const cmd    = parts[0].toLowerCase().replace(/@[^\s]+$/, '');

  // /recovery [cert] [avg] [conv] [Nh | Nd] [all | postliq | confirmed]
  // /missed  [Nh]
  // /postliq [Nh]
  if (['/recovery', '/missed', '/postliq'].includes(cmd)) {
    let hours  = 12;
    let filter = cmd === '/postliq' ? 'postliq' : 'all';
    let _certO = null, _avgO = null, _convO = null;
    const _bareNums = [];
    for (const part of parts.slice(1)) {
      if (part.endsWith('h'))                                  hours = parseFloat(part) || 12;
      else if (part.endsWith('d'))                             hours = (parseFloat(part) || 1) * 24;
      else if (['all','postliq','confirmed'].includes(part.toLowerCase())) filter = part.toLowerCase();
      else if (!isNaN(parseFloat(part)))                       _bareNums.push(parseFloat(part));
    }
    if (_bareNums.length >= 1) _certO = _bareNums[0];
    if (_bareNums.length >= 2) _avgO  = _bareNums[1];
    if (_bareNums.length >= 3) _convO = _bareNums[2];
    if (_bareNums.length >= 4) hours  = _bareNums[3];
    hours = Math.max(1, Math.min(120, hours));
    const _thrOv = {};
    if (_certO != null) _thrOv.certMin = _certO;
    if (_avgO  != null) _thrOv.avgMin  = _avgO;
    if (_convO != null) _thrOv.convMin = _convO;

    await tg('sendMessage', { chat_id: chatId,
      text: `🔍 <b>Recovery Scan — Last ${hours}h</b>\nFilter: <b>${filter}</b>\nScanning ${WATCH.size} assets for swept liquidity...\n<i>This may take 30-60 seconds...</i>`,
      parse_mode: 'HTML' }).catch(() => {});

    const results = await runFullRecoveryScan(hours, filter, _thrOv).catch(() => []);

    if (!results.length) {
      await tg('sendMessage', { chat_id: chatId,
        text: `📭 <b>No signals found</b>\nNo ${filter === 'postliq' ? 'post-liquidity' : filter === 'confirmed' ? 'confirmed real-move' : ''} setups in last ${hours}h.\n\nTry: /recovery 24h or /recovery 48h`,
        parse_mode: 'HTML' }).catch(() => {});
      return;
    }

    // Summary card
    const summaryLines = [
      `♻️ <b>Recovery Scan Results — ${results.length} setups found</b>`,
      `Last ${hours}h | Filter: ${filter} | Sorted by readiness`,
      '',
    ];

    for (const r of results.slice(0, 10)) {
      const icon = r.lepdState === 'PERFECT_EXHAUSTION' ? '🏆'
                 : r.lepdState === 'STRONG_EXHAUSTION'  ? '✅'
                 : r.rmeeMode  === 'REAL_MOVE_CONFIRMED' ? '🎯'
                 : r.rmeeMode  === 'CONFIRMING'          ? '⚡'
                 : r.atlasTier === 'APEX_PRIME'          ? '🏔️🔥'
                 : '📍';

      const entryStr = r.realEntry  ? ` → Entry: <code>${r.realEntry}</code>`
                     : r.preCalcEntry ? ` → Pre-calc: <code>${r.preCalcEntry}</code>` : '';
      const moveStr  = r.expectedMove > 0 ? ` | +${r.expectedMove}% expected` : '';

      summaryLines.push(
        `${icon} <b>${r.symbol}</b> ${r.dir} @ <code>${r.price}</code>${entryStr}${moveStr}`,
        `   LEPD: ${r.lepdState} | RMEE: ${r.rmeeMode} | ATLAS: ${r.atlasTier}(${r.atlasScore})`
      );
    }
    if (results.length > 10) summaryLines.push(`\n<i>+${results.length - 10} more setups...</i>`);
    summaryLines.push('', `<i>Sending full signal cards for top ${Math.min(3, results.length)} setups...</i>`);

    await tg('sendMessage', { chat_id: chatId,
      text: summaryLines.join('\n'), parse_mode: 'HTML' }).catch(() => {});

    // Full signal cards for top 3
    const gen = this.signalGenerator;
    for (const r of results.slice(0, 3)) {
      try {
        await new Promise(res => setTimeout(res, 1500));

        const consensus = await buildMTFConsensus(r.symbol, gen).catch(() => null);
        if (!consensus) continue;

        // ✅ FIX: align recovery direction with live consensus to avoid the
        // "header SELL but card BUY" bug. The recovery scanner enumerates both
        // directions and may rank a SELL candidate while consensus actually
        // picks BUY for the same symbol.
        if (consensus?.consensusDirection && consensus.consensusDirection !== 'NEUTRAL'
            && consensus.consensusDirection !== r.dir) {
          console.log(`♻️ Recovery dir corrected for ${r.symbol}: ${r.dir} → ${consensus.consensusDirection}`);
          r.dir = consensus.consensusDirection;
        }

        const livePrice = await fetchLivePrice(r.symbol).catch(() => r.price);
        const instCtx   = await buildInstitutionalContextFull(r.symbol, livePrice, r.dir).catch(() => null);
        if (instCtx) consensus._instCtx = instCtx;

        // Apply user-requested quality gate (cert/avg/conv/pillars)
        const _q = isHighQualitySignal(consensus, instCtx, _thrOv);
        if (!_q.ok) {
          console.log(`⏭ Recovery card skipped ${r.symbol} ${r.dir} → ${_q.reason}`);
          continue;
        }
        // ✅ ARBITER: pick the BEST liquidity engine for this recovery card
        // and stash on consensus so AI Analyst + RSDE both reuse it.
        const _gCertR = safeNumber(consensus?.certaintyScore || consensus?.certainty || 0);
        const _pickedR = selectBestLimitGuarded(livePrice, r.dir, { cert: _gCertR, instCtx });
        const _safeLim = _pickedR?.price || null;
        if (_safeLim) {
          consensus._safeLimit  = _safeLim;
          consensus._safeSource = _pickedR.source;
          consensus._safeLabel  = _pickedR.label;
          if (instCtx) {
            instCtx._safeLimit  = _safeLim;
            instCtx._safeSource = _pickedR.source;
            instCtx._safeLabel  = _pickedR.label;
          }
        }

        const scored = autoScoreSignal(consensus, consensus?.bestSig);

        const header = [
          `━━━ ♻️ RECOVERY: ${r.symbol} ${r.dir} ━━━`,
          `LEPD: <b>${r.lepdState}</b> | RMEE: <b>${r.rmeeMode}</b> | ATLAS: <b>${r.atlasTier}</b>`,
          _safeLim ? `🎯 <b>Limit (${r.dir} max -3% pullback): <code>${_safeLim}</code></b>` :
            (r.realEntry ? `🎯 <b>Real move entry: <code>${r.realEntry}</code></b>` : (r.preCalcEntry ? `📍 Pre-calc entry: <code>${r.preCalcEntry}</code>` : '')),
          r.expectedMove > 0 ? `📈 Expected move: ${r.dir==='BUY'?'+':'-'}${r.expectedMove}%` : '',
          '',
        ].filter(Boolean).join('\n');

        const cardText = formatMTFConsensusMessage(consensus) || '';
        const fullMsg  = header + cardText;
        const safeMsg  = fullMsg.length > 4090 ? fullMsg.slice(0, 4090) + '<i>…</i>' : fullMsg;

        const msgR = await tg('sendMessage', {
          chat_id: chatId, text: safeMsg, parse_mode: 'HTML', disable_web_page_preview: true,
        }).catch(() => null);

        if (msgR?.ok) {
          await new Promise(res => setTimeout(res, 1500));
          await sendAIAnalysis(r.symbol, consensus, instCtx, scored).catch(() => {});
        }
      } catch(e) {
        console.warn(`Recovery card error for ${r.symbol}:`, e.message);
      }
    }
    return;
  }

  // /atlas — show ATLAS score for a specific symbol
  if (cmd === '/atlas') {
    const sym = parts[1]?.toUpperCase().replace('/', '') || null;
    const d   = parts[2]?.toUpperCase() || 'BUY';
    if (!sym) {
      await tg('sendMessage', { chat_id: chatId,
        text: 'Usage: /atlas BTCUSDT BUY', parse_mode: 'HTML' }).catch(() => {});
      return;
    }
    try {
      const price   = await fetchLivePrice(sym);
      const candles = await fetchCandlesCached(sym, '1h', 80);
      const atlas   = await computeATLAS(sym, price, d, candles, null);
      const msg     = atlas ? `<b>${sym} ${d} ATLAS Report</b>\n${formatATLAS(atlas, d)}`
                            : `❌ Could not compute ATLAS for ${sym}`;
      await tg('sendMessage', { chat_id: chatId, text: msg, parse_mode: 'HTML' }).catch(() => {});
    } catch(e) {
      await tg('sendMessage', { chat_id: chatId, text: `❌ Error: ${e.message}`, parse_mode: 'HTML' }).catch(() => {});
    }
    return;
  }

  return _origHandleLegacy_atlas.call(this, message);
};

