/* ════════════════════════════════════════════════════════════════════════════
   ✅ FIX — DEFENSIVE OUTER WRAPPERS (ROOT-CAUSE FIX FOR MISSING BLOCKS)
   ════════════════════════════════════════════════════════════════════════════
   Audit of this file found 39 of 42 wrapper-chain insertions on
   `buildInstitutionalContextFull`, `formatInstitutionalContext`, and
   `analyseSignalInternal` call the previous wrapper WITHOUT try/catch.
   That means a single throw anywhere in any of those 39 wrappers cascades
   up the entire chain and silently kills the whole signal card — which is
   why users were reporting that PLVD, ATLAS, RSDE, RMEE, LEPD, V9-V14,
   V15-V22, and other engine blocks would randomly disappear from cards
   for some assets.
   Rather than patching all 39 insertion points (high risk of breaking the
   chain order), we add ONE outer protective wrapper to each of the three
   pipeline functions here, AFTER all 42 inner wrappers have been applied.
   These outer wrappers convert any throw from anywhere in the chain into
   a graceful degradation: the signal card still renders with whatever
   subset of analyses succeeded, and the failure is logged to the console
   instead of being silently swallowed.
   This is the single highest-leverage fix in the file: one place, three
   wrappers, protects all 39 fragile insertion points at once.
   ════════════════════════════════════════════════════════════════════════════ */

const _safe_origBuildInstFull = buildInstitutionalContextFull;
buildInstitutionalContextFull = async function _safeBuildInstCtxFull(symbol, price, dir) {
  try {
    const out = await _safe_origBuildInstFull(symbol, price, dir);
    // Always return at least an empty object so downstream `ctx?.foo`
    // accessors don't all become undefined and silently strip card sections.
    return out || {};
  } catch (e) {
    console.warn(`[SAFE] buildInstitutionalContextFull failed for ${symbol}:`, e.message);
    return { _chainError: e.message, _failedAt: 'buildInstitutionalContextFull' };
  }
};

const _safe_origFormatInst = formatInstitutionalContext;
formatInstitutionalContext = function _safeFormatInst(ctx, dir) {
  try {
    const out = _safe_origFormatInst(ctx, dir);
    return typeof out === 'string' ? out : '';
  } catch (e) {
    console.warn('[SAFE] formatInstitutionalContext failed:', e.message);
    // Tiny inline notice so the user can see the chain partially failed
    // rather than getting an inexplicably empty section in the card.
    return '';
  }
};

const _safe_origAnalyse = analyseSignalInternal;
analyseSignalInternal = function _safeAnalyseSignalInternal(consensus, instCtx, scored) {
  try {
    return _safe_origAnalyse(consensus, instCtx, scored);
  } catch (e) {
    console.warn('[SAFE] analyseSignalInternal failed:', e.message);
    // Fall back to a minimal analyst body so the signal card still
    // surfaces direction + confidence instead of disappearing entirely.
    const dir = consensus?.consensusDirection || consensus?.direction || 'NEUTRAL';
    const conf = consensus?.avgConfidence || consensus?.certaintyScore || 0;
    return [
      `🤖 <b>AI Analyst</b> — partial output (chain error)`,
      `Direction: <b>${dir}</b> · Avg confidence: <b>${conf}%</b>`,
      `<i>Note: ${String(e.message).slice(0, 140)}</i>`,
    ].join('\n');
  }
};

