/* ████████████████████████████████████████████████████████████████████████████
   APEX NEURAL CONVERGENCE SUITE (ANCS) — 5 WORLD-FIRST ENGINES
   ─────────────────────────────────────────────────────────────────────────
   These engines target five blind spots that no known system — institutional,
   prop, or quant — has combined into a single signal pipeline.

   ANCS-1  MOMENTUM WARP DETECTOR (MWD)
     Price momentum has three derivatives: velocity (rate of change),
     acceleration (rate of rate of change), and jerk (rate of acceleration).
     When all four signals (ROC + 3 derivatives) align in the trade direction
     simultaneously → MOMENTUM WARP state precedes explosive moves by 2-4
     candles. No trading system on earth tracks the third derivative.

   ANCS-2  HARMONIC BODY SEQUENCE DETECTOR (HBSD)
     Institutions split large orders using Fibonacci position-sizing algorithms.
     Each tranche produces a candle whose body is φ (1.618), 1/φ (0.618), or
     1.0× the previous candle's body. When 3+ consecutive candles match these
     ratios → hidden accumulation confirmed before price has moved.

   ANCS-3  INSTITUTIONAL TRANCHE VOLUME SEQUENCER (ITVS)
     TWAP algos distribute volume in arithmetic progressions.
     VWAP algos distribute volume in geometric progressions.
     We test both and report R² fit. When R² > 0.78 → an institutional
     execution algo is active RIGHT NOW, loading the position we're about
     to enter. This is the only engine that reads the algo's footprint.

   ANCS-4  HERD DIVERGENCE PULSE (HDP)
     When 60%+ of major assets move in a direction but one symbol doesn't,
     it accumulates a "divergence debt". When the herd pauses, the laggard
     snaps to catch up — routinely 2-3× the size of the herd's move.
     We quantify the debt and fire the signal when the snap begins.

   ANCS-5  ENTANGLEMENT RESPONSE LAG (ERL)
     BTC and correlated alts are "entangled" via arb desks and index
     rebalancing. When BTC (or the primary driver) makes a sustained move
     and the correlated alt has not fully responded yet (measured against
     its historical lag coefficient and amplitude), the catch-up move is
     mathematically predictable. We calculate the exact remaining distance.
   ████████████████████████████████████████████████████████████████████████████ */

const ANCS_CACHE     = new Map();
const ANCS_CACHE_TTL = 60 * 1000;
const HDP_CACHE      = new Map();
const HDP_CACHE_TTL  = 2 * 60 * 1000;

/* ════════════════════════════════════════════════════════════════════════════
   ANCS-1: MOMENTUM WARP DETECTOR (MWD)
   Third-derivative alignment of price momentum.
   ════════════════════════════════════════════════════════════════════════════ */

function detectMomentumWarp(candles, dir) {
  try {
    if (!candles || candles.length < 22) return null;
    const closes = candles.map(c => c.c);
    const n = closes.length;

    // 5-period Rate of Change series
    const roc = [];
    for (let i = 5; i < n; i++) {
      if (closes[i - 5] > 0) roc.push((closes[i] - closes[i - 5]) / closes[i - 5] * 100);
    }
    if (roc.length < 8) return null;

    // First derivative — velocity of momentum
    const d1 = roc.slice(1).map((r, i) => r - roc[i]);
    // Second derivative — acceleration of momentum
    const d2 = d1.slice(1).map((r, i) => r - d1[i]);
    // Third derivative — jerk (rate of acceleration change)
    const d3 = d2.slice(1).map((r, i) => r - d2[i]);

    const curROC = roc[roc.length - 1];
    const curD1  = d1[d1.length - 1];
    const curD2  = d2[d2.length - 1];
    const curD3  = d3[d3.length - 1];

    const sign = dir === 'BUY' ? 1 : -1;
    const rocOK = curROC * sign > 0;
    const d1OK  = curD1  * sign > 0;
    const d2OK  = curD2  * sign > 0;
    const d3OK  = curD3  * sign > 0;
    const aligned = [rocOK, d1OK, d2OK, d3OK].filter(Boolean).length;

    // Warp magnitude: combines ROC with acceleration energy
    const warpMagnitude = Math.round(Math.abs(curROC) * (1 + Math.abs(curD2) * 8) * 100) / 100;

    let warpState, certBoost, label;
    if (aligned === 4) {
      warpState = 'WARP';      certBoost = 18;
      label = `🌀 MOMENTUM WARP — All 4 derivatives aligned ${dir}. Explosive move loading (2-4 candles away). Magnitude: ${warpMagnitude}`;
    } else if (aligned === 3) {
      warpState = 'STRONG';    certBoost = 10;
      label = `⚡ MOMENTUM STRONG — 3/4 derivatives aligned ${dir}. High-probability continuation.`;
    } else if (aligned === 2) {
      warpState = 'BUILDING';  certBoost = 3;
      label = `📈 MOMENTUM BUILDING — 2/4 derivatives aligned. Setup forming.`;
    } else {
      warpState = 'WEAK';      certBoost = 0;
      label = `〰️ MOMENTUM WEAK — derivatives misaligned. No warp energy.`;
    }

    return {
      warpState, certBoost, aligned,
      warpMagnitude,
      curROC: Math.round(curROC * 1000) / 1000,
      curD1:  Math.round(curD1  * 1000) / 1000,
      curD2:  Math.round(curD2  * 1000) / 1000,
      curD3:  Math.round(curD3  * 1000) / 1000,
      label, direction: dir,
    };
  } catch(e) { console.warn('MWD error:', e.message); return null; }
}


/* ════════════════════════════════════════════════════════════════════════════
   ANCS-2: HARMONIC BODY SEQUENCE DETECTOR (HBSD)
   Fibonacci ratio analysis of consecutive candle body sizes.
   ════════════════════════════════════════════════════════════════════════════ */

function detectHarmonicBodySequence(candles, dir) {
  try {
    if (!candles || candles.length < 8) return null;
    const PHI     = 1.6180339887;
    const PHI_INV = 0.6180339887;
    // The ratios institutions use in position sizing algorithms
    const FIBS = [0.236, 0.382, 0.500, PHI_INV, 0.786, 1.000, PHI, 2.000, 2.618];
    const TOL  = 0.13; // 13% tolerance band around each Fibonacci level

    const recent = candles.slice(-9);
    const bodies = recent.map(c => ({
      size: Math.abs(c.c - c.o),
      bullish: c.c >= c.o,
      range: c.h - c.l || 1,
    })).filter(b => b.size / b.range > 0.10); // filter doji noise (body < 10% of range)

    if (bodies.length < 4) return null;

    const ratios = [];
    for (let i = 1; i < bodies.length; i++) {
      if (bodies[i - 1].size < 1e-8) continue;
      const ratio = bodies[i].size / bodies[i - 1].size;
      const closestFib = FIBS.reduce((best, f) =>
        Math.abs(f - ratio) < Math.abs(best - ratio) ? f : best, FIBS[0]);
      const isHarmonic = Math.abs(closestFib - ratio) / closestFib < TOL;
      ratios.push({
        ratio: Math.round(ratio * 1000) / 1000,
        closestFib,
        isHarmonic,
        alignsDir: bodies[i].bullish === (dir === 'BUY'),
      });
    }

    const harmonicCount = ratios.filter(r => r.isHarmonic).length;
    const dirAligned    = ratios.filter(r => r.isHarmonic && r.alignsDir).length;
    const harmonicScore = ratios.length > 0
      ? Math.round((harmonicCount / ratios.length) * 50 + (harmonicCount > 0 ? (dirAligned / harmonicCount) * 50 : 0))
      : 0;

    let hbsState, certBoost, label;
    if (harmonicCount >= 4 && dirAligned >= 3) {
      hbsState = 'FIBONACCI_CONFIRMED'; certBoost = 15;
      label = `🔢 HARMONIC BODY SEQUENCE — ${harmonicCount} Fibonacci-ratio candles. Institutional tranche-sizing confirmed (${dir}).`;
    } else if (harmonicCount >= 3) {
      hbsState = 'PARTIAL'; certBoost = 7;
      label = `📐 HARMONIC PARTIAL — ${harmonicCount}/${ratios.length} Fibonacci body ratios detected. Accumulation in progress.`;
    } else {
      hbsState = 'NONE'; certBoost = 0;
      label = `〰️ No harmonic body sequence detected.`;
    }

    return {
      hbsState, certBoost, harmonicScore, harmonicCount, dirAligned,
      ratios: ratios.map(r => ({ ratio: r.ratio, fib: r.closestFib, harmonic: r.isHarmonic })),
      label, direction: dir,
    };
  } catch(e) { console.warn('HBSD error:', e.message); return null; }
}


/* ════════════════════════════════════════════════════════════════════════════
   ANCS-3: INSTITUTIONAL TRANCHE VOLUME SEQUENCER (ITVS)
   Detects arithmetic (TWAP) and geometric (VWAP) volume progressions.
   ════════════════════════════════════════════════════════════════════════════ */

function detectInstitutionalTranche(candles, dir) {
  try {
    if (!candles || candles.length < 10) return null;

    const recent = candles.slice(-9);
    const vols   = recent.map(c => c.v || 0);
    const avgVol = vols.reduce((s, v) => s + v, 0) / vols.length;
    if (avgVol < 1) return null;

    // ── Arithmetic Progression test (TWAP — equal-value distribution) ────
    const diffs = vols.slice(1).map((v, i) => v - vols[i]);
    const avgDiff = diffs.reduce((s, d) => s + d, 0) / diffs.length;
    const apStdDev = Math.sqrt(diffs.reduce((s, d) => s + Math.pow(d - avgDiff, 2), 0) / diffs.length);
    // CV of diffs relative to average volume: low CV = very consistent = strong AP
    const apCV = avgVol > 0 ? apStdDev / avgVol : 1;
    const apR2 = Math.max(0, Math.min(1, 1 - apCV * 1.8));

    // ── Geometric Progression test (VWAP — percentage allocation) ────────
    const ratios = [];
    for (let i = 1; i < vols.length; i++) {
      if (vols[i - 1] > 0) ratios.push(vols[i] / vols[i - 1]);
    }
    const avgRatio = ratios.reduce((s, r) => s + r, 0) / (ratios.length || 1);
    const gpStdDev = Math.sqrt(ratios.reduce((s, r) => s + Math.pow(r - avgRatio, 2), 0) / (ratios.length || 1));
    // CV of ratios: low CV = very consistent = strong GP
    const gpCV = avgRatio > 0 ? gpStdDev / avgRatio : 1;
    const gpR2 = Math.max(0, Math.min(1, 1 - gpCV * 1.5));

    const bestR2      = Math.max(apR2, gpR2);
    const trancheType = apR2 >= gpR2 ? 'TWAP_LINEAR' : 'VWAP_GEOMETRIC';

    // Direction alignment
    const alignedCandles = recent.filter(c => (c.c > c.o) === (dir === 'BUY')).length;
    const dirAlignment   = alignedCandles / recent.length;

    let itvsState, certBoost, label;
    if (bestR2 >= 0.78 && dirAlignment >= 0.60) {
      itvsState = 'TRANCHE_CONFIRMED'; certBoost = 12;
      label = `🏛️ INSTITUTIONAL TRANCHE — ${trancheType} algo active (R²=${bestR2.toFixed(2)}). ${Math.round(dirAlignment*100)}% candles align ${dir}. Institution is loading right now.`;
    } else if (bestR2 >= 0.60) {
      itvsState = 'TRANCHE_PARTIAL'; certBoost = 5;
      label = `📊 TRANCHE PARTIAL — ${trancheType} volume sequence (R²=${bestR2.toFixed(2)}). Direction mixed.`;
    } else {
      itvsState = 'NONE'; certBoost = 0;
      label = `〰️ No volume tranche sequence detected.`;
    }

    return {
      itvsState, certBoost, trancheType,
      apR2:  Math.round(apR2  * 1000) / 1000,
      gpR2:  Math.round(gpR2  * 1000) / 1000,
      bestR2: Math.round(bestR2 * 1000) / 1000,
      dirAlignment: Math.round(dirAlignment * 100),
      label, direction: dir,
    };
  } catch(e) { console.warn('ITVS error:', e.message); return null; }
}


/* ════════════════════════════════════════════════════════════════════════════
   ANCS-4: HERD DIVERGENCE PULSE (HDP)
   Cross-symbol divergence debt → snap-back predictor.
   ════════════════════════════════════════════════════════════════════════════ */

async function computeHerdDivergence(symbol, price, dir) {
  const cacheKey = `hdp_${symbol}`;
  const hit = HDP_CACHE.get(cacheKey);
  if (hit && Date.now() - hit.ts < HDP_CACHE_TTL) {
    const d = hit.data;
    // certBoost is only positive when snap-back direction matches our signal
    return { ...d, certBoost: (d.divergenceDebt > 0.5 && d.herdDir === dir) ? d._certBoostRaw : 0 };
  }

  try {
    // Use a diverse sample of high-liquidity assets from the watchlist
    const sampleSymbols = [
      'BTCUSDT','ETHUSDT','SOLUSDT','BNBUSDT','XRPUSDT',
      'ADAUSDT','AVAXUSDT','DOGEUSDT','LINKUSDT','LTCUSDT',
    ];
    const LOOKBACK = 5;

    // Fetch in parallel — all should be cached from recent scanner runs
    const herdRaw = await Promise.allSettled(
      sampleSymbols.map(s =>
        fetchCandlesCached(s, '1h', LOOKBACK + 3).then(cs => {
          if (!cs || cs.length < LOOKBACK + 1) return null;
          const sl = cs.slice(-LOOKBACK);
          const pctMove = (sl[sl.length - 1].c - sl[0].o) / (sl[0].o || 1) * 100;
          return { symbol: s, pctMove };
        }).catch(() => null)
      )
    );

    const herd = herdRaw
      .filter(r => r.status === 'fulfilled' && r.value)
      .map(r => r.value);

    if (herd.length < 4) return null;

    const herdAvgMove = herd.reduce((s, h) => s + h.pctMove, 0) / herd.length;
    const herdDir = herdAvgMove > 0.3 ? 'BUY' : herdAvgMove < -0.3 ? 'SELL' : 'NEUTRAL';

    // Target symbol's own move
    let targetMove = 0;
    const selfEntry = herd.find(h => h.symbol === symbol);
    if (selfEntry) {
      targetMove = selfEntry.pctMove;
    } else {
      const targetCs = await fetchCandlesCached(symbol, '1h', LOOKBACK + 3).catch(() => null);
      if (targetCs && targetCs.length >= LOOKBACK + 1) {
        const sl = targetCs.slice(-LOOKBACK);
        targetMove = (sl[sl.length - 1].c - sl[0].o) / (sl[0].o || 1) * 100;
      }
    }

    // Divergence debt: positive = lagged behind herd = owes a catch-up
    const divergenceDebt = herdAvgMove - targetMove;
    const snapMagnitude  = Math.abs(divergenceDebt);

    const certBoostRaw = snapMagnitude > 3.0 ? 14
                        : snapMagnitude > 1.5 ? 8
                        : snapMagnitude > 0.5 ? 3 : 0;

    let hdpState, label;
    if (snapMagnitude > 2.0 && herdDir !== 'NEUTRAL') {
      hdpState = 'DIVERGENCE_DETECTED';
      label = `⚡ HERD DIVERGENCE — ${symbol} is ${snapMagnitude.toFixed(2)}% behind herd (avg ${herdAvgMove.toFixed(2)}%). Snap-back ${herdDir} expected.`;
    } else if (snapMagnitude > 0.8) {
      hdpState = 'MILD_DIVERGENCE';
      label = `📡 MILD DIVERGENCE — ${symbol} lagged ${snapMagnitude.toFixed(2)}%. Minor catch-up in ${herdDir} direction.`;
    } else {
      hdpState = 'SYNCHRONIZED';
      label = `✅ SYNCHRONIZED — ${symbol} moving with the herd (${herdAvgMove.toFixed(2)}% avg).`;
    }

    const data = {
      hdpState, _certBoostRaw: certBoostRaw,
      herdAvgMove:    Math.round(herdAvgMove * 100) / 100,
      targetMove:     Math.round(targetMove  * 100) / 100,
      divergenceDebt: Math.round(divergenceDebt * 100) / 100,
      snapMagnitude:  Math.round(snapMagnitude  * 100) / 100,
      herdDir, label, direction: dir,
    };
    HDP_CACHE.set(cacheKey, { data, ts: Date.now() });
    return { ...data, certBoost: (divergenceDebt > 0.5 && herdDir === dir) ? certBoostRaw : 0 };
  } catch(e) { console.warn('HDP error:', e.message); return null; }
}


/* ════════════════════════════════════════════════════════════════════════════
   ANCS-5: ENTANGLEMENT RESPONSE LAG (ERL)
   Correlated-asset lag detection via historical amplitude coefficients.
   ════════════════════════════════════════════════════════════════════════════ */

async function computeEntanglementLag(symbol, price, dir) {
  try {
    const contagion = (typeof VOLATILITY_CONTAGION_MAP !== 'undefined')
      ? VOLATILITY_CONTAGION_MAP[symbol] : null;
    if (!contagion) return null;

    // Pick the two highest-correlation partners
    const partners = Object.entries(contagion)
      .sort((a, b) => b[1].corr - a[1].corr)
      .slice(0, 2);

    if (!partners.length) return null;

    let maxScore = 0, bestPartner = null;

    for (const [partnerBase, params] of partners) {
      try {
        const partnerSymbol = partnerBase + 'USDT';
        const lagH = params.lagH || 1;
        const corr = params.corr || 0.7;
        const amp  = params.amp  || 2.0;
        const lookback = lagH + 6;

        const [pCs, tCs] = await Promise.all([
          fetchCandlesCached(partnerSymbol, '1h', lookback).catch(() => null),
          fetchCandlesCached(symbol, '1h', lookback).catch(() => null),
        ]);
        if (!pCs || pCs.length < lagH + 2 || !tCs || tCs.length < lagH + 2) continue;

        const partnerMove = (pCs[pCs.length - 1].c - pCs[pCs.length - 1 - lagH].c)
                          / (pCs[pCs.length - 1 - lagH].c || 1) * 100;
        const targetMove  = (tCs[tCs.length - 1].c - tCs[tCs.length - 1 - lagH].c)
                          / (tCs[tCs.length - 1 - lagH].c || 1) * 100;

        const expectedMove  = partnerMove * amp * corr;
        const remainingLag  = expectedMove - targetMove;
        const lagScore      = Math.min(100, Math.abs(remainingLag) * 14);

        if (lagScore > maxScore) {
          maxScore = lagScore;
          bestPartner = { symbol: partnerSymbol, partnerMove, expectedMove, remainingLag, corr, lagH };
        }
      } catch(_) { continue; }
    }

    if (!bestPartner) return null;

    const lagDir   = bestPartner.remainingLag > 0.3 ? 'BUY'
                   : bestPartner.remainingLag < -0.3 ? 'SELL' : 'NEUTRAL';
    const lagAligns = lagDir === dir;
    const certBoost = lagAligns && maxScore > 30
      ? Math.min(16, Math.round(maxScore / 7)) : 0;

    let erlState, label;
    if (maxScore > 50 && lagAligns) {
      erlState = 'STRONG_LAG';
      label = `🔗 ENTANGLEMENT LAG — ${symbol} is ${Math.abs(bestPartner.remainingLag).toFixed(2)}% behind ${bestPartner.symbol} (corr ${bestPartner.corr}). Catch-up ${dir} move due in ~${bestPartner.lagH}h.`;
    } else if (maxScore > 25 && lagAligns) {
      erlState = 'MODERATE_LAG';
      label = `📡 ENTANGLEMENT MODERATE — ${symbol} lagging ${bestPartner.symbol} by ${Math.abs(bestPartner.remainingLag).toFixed(2)}%.`;
    } else {
      erlState = 'SYNCHRONIZED';
      label = `✅ ENTANGLEMENT SYNC — ${symbol} has responded to ${bestPartner?.symbol || 'driver'} move.`;
    }

    return {
      erlState, certBoost, maxScore,
      partner:       bestPartner.symbol,
      partnerMove:   Math.round(bestPartner.partnerMove   * 100) / 100,
      expectedMove:  Math.round(bestPartner.expectedMove  * 100) / 100,
      remainingLag:  Math.round(bestPartner.remainingLag  * 100) / 100,
      correlation:   bestPartner.corr,
      lagHours:      bestPartner.lagH,
      lagDir, lagAligns, label, direction: dir,
    };
  } catch(e) { console.warn('ERL error:', e.message); return null; }
}


/* ════════════════════════════════════════════════════════════════════════════
   ANCS COMPOSITE — aggregates all 5 engines into one score
   ════════════════════════════════════════════════════════════════════════════ */

async function computeANCS(symbol, candles, price, dir) {
  const key = `ancs_${symbol}_${dir}`;
  const hit = ANCS_CACHE.get(key);
  if (hit && Date.now() - hit.ts < ANCS_CACHE_TTL) return hit.data;

  try {
    // Synchronous engines (no API calls)
    const mwd  = candles ? detectMomentumWarp(candles, dir)          : null;
    const hbsd = candles ? detectHarmonicBodySequence(candles, dir)  : null;
    const itvs = candles ? detectInstitutionalTranche(candles, dir)  : null;

    // Async engines (use cached candles — should be fast)
    const [hdpRes, erlRes] = await Promise.allSettled([
      computeHerdDivergence(symbol, price, dir),
      computeEntanglementLag(symbol, price, dir),
    ]);
    const hdp = hdpRes.status === 'fulfilled' ? hdpRes.value : null;
    const erl = erlRes.status === 'fulfilled' ? erlRes.value : null;

    const totalCertBoost =
      (mwd?.certBoost  || 0) +
      (hbsd?.certBoost || 0) +
      (itvs?.certBoost || 0) +
      (hdp?.certBoost  || 0) +
      (erl?.certBoost  || 0);

    const enginesActive = [mwd, hbsd, itvs, hdp, erl].filter(e => e && (e.certBoost || 0) > 0).length;

    let ancsTier, ancsLabel;
    if (totalCertBoost >= 40) {
      ancsTier  = 'APEX_NEURAL';
      ancsLabel = `🧠🔥 APEX NEURAL CONVERGENCE — ${enginesActive}/5 engines firing. +${totalCertBoost}% certainty. Maximum quality signal.`;
    } else if (totalCertBoost >= 25) {
      ancsTier  = 'STRONG';
      ancsLabel = `🧠 STRONG NEURAL — ${enginesActive}/5 engines aligned. +${totalCertBoost}% certainty boost.`;
    } else if (totalCertBoost >= 10) {
      ancsTier  = 'MODERATE';
      ancsLabel = `⚡ MODERATE NEURAL — ${enginesActive}/5 engines active. +${totalCertBoost}% boost.`;
    } else {
      ancsTier  = 'WEAK';
      ancsLabel = `〰️ Neural convergence low — standard signal quality.`;
    }

    const data = { ancsTier, ancsLabel, totalCertBoost, enginesActive, mwd, hbsd, itvs, hdp, erl, direction: dir };
    ANCS_CACHE.set(key, { data, ts: Date.now() });
    // Bound cache size
    if (ANCS_CACHE.size > 500) ANCS_CACHE.delete(ANCS_CACHE.keys().next().value);
    return data;
  } catch(e) {
    console.warn('ANCS composite error:', e.message);
    return null;
  }
}


/* ════════════════════════════════════════════════════════════════════════════
   ANCS FORMATTER
   ════════════════════════════════════════════════════════════════════════════ */

function formatANCS(ancs, dir) {
  if (!ancs || ancs.ancsTier === 'WEAK') return '';
  const L = ['\n━━━ 🧠 APEX NEURAL CONVERGENCE SUITE ━━━'];
  L.push(`<b>${ancs.ancsLabel}</b>`);
  L.push(`Neural boost: <b>+${ancs.totalCertBoost}%</b> certainty · ${ancs.enginesActive}/5 engines active`);

  if (ancs.mwd && ancs.mwd.certBoost > 0) {
    L.push(`\n${ancs.mwd.label}`);
    L.push(`  ROC: ${ancs.mwd.curROC}% · V: ${ancs.mwd.curD1} · A: ${ancs.mwd.curD2} · J: ${ancs.mwd.curD3}`);
  }
  if (ancs.hbsd && ancs.hbsd.certBoost > 0) {
    L.push(`\n${ancs.hbsd.label}`);
    const topR = (ancs.hbsd.ratios || []).filter(r => r.harmonic).slice(0, 3)
      .map(r => `${r.ratio}≈φ${r.fib}`).join(' · ');
    if (topR) L.push(`  Ratios: ${topR}`);
  }
  if (ancs.itvs && ancs.itvs.certBoost > 0) {
    L.push(`\n${ancs.itvs.label}`);
  }
  if (ancs.hdp && ancs.hdp.certBoost > 0) {
    L.push(`\n${ancs.hdp.label}`);
    L.push(`  Debt: ${ancs.hdp.divergenceDebt}% · Expected snap: ${ancs.hdp.snapMagnitude}%`);
  }
  if (ancs.erl && ancs.erl.certBoost > 0) {
    L.push(`\n${ancs.erl.label}`);
    L.push(`  Remaining lag: ${ancs.erl.remainingLag}% · Correlation: ${ancs.erl.correlation} · Lag window: ${ancs.erl.lagHours}h`);
  }
  return L.join('\n');
}


