buildInstitutionalContextFull = async function(symbol, price, dir) {
  const base = await _origBuildInst_ancs(symbol, price, dir);
  try {
    const candles = base?._sharedCandles || await fetchCandlesCached(symbol, '1h', 60).catch(() => null);
    if (price && dir) {
      const ancs = await computeANCS(symbol, candles, price, dir).catch(() => null);
      if (base && ancs) { base.ancs = ancs; base._ancs = true; }
    }
  } catch(e) { console.warn('ANCS wiring error:', e.message); }
  return base;
};

