/* ── Wire into analyseSignalInternal — inject block at top of AI analyst ── */
const _origAnalyse_ancs = analyseSignalInternal;
analyseSignalInternal = function(consensus, instCtx, scored) {
  let result = _origAnalyse_ancs(consensus, instCtx, scored);
  if (!result) return result;

  const ancs = instCtx?.ancs;
  const dir  = consensus?.consensusDirection || 'NEUTRAL';
  if (!ancs || ancs.totalCertBoost < 10) return result;

  try {
    const lines = [
      '\n━━━━━━━━━━━━━━━━━━━━━━',
      `🧠 <b>ANCS: ${ancs.ancsTier} — +${ancs.totalCertBoost}% NEURAL BOOST (${ancs.enginesActive}/5 engines)</b>`,
    ];

    if (ancs.mwd?.certBoost > 0)
      lines.push(`🌀 Momentum Warp: ${ancs.mwd.aligned}/4 derivatives aligned · Magnitude ${ancs.mwd.warpMagnitude}`);
    if (ancs.hbsd?.certBoost > 0)
      lines.push(`🔢 Harmonic Sequence: ${ancs.hbsd.harmonicCount} Fibonacci body ratios (${ancs.hbsd.dirAligned} dir-aligned)`);
    if (ancs.itvs?.certBoost > 0)
      lines.push(`🏛️ Tranche: ${ancs.itvs.trancheType} algo active (R²=${ancs.itvs.bestR2}) · ${ancs.itvs.dirAlignment}% candles ${dir}`);
    if (ancs.hdp?.certBoost > 0)
      lines.push(`⚡ Herd Divergence: ${ancs.hdp.snapMagnitude}% debt · Snap-back ${ancs.hdp.herdDir}`);
    if (ancs.erl?.certBoost > 0)
      lines.push(`🔗 Entanglement Lag: ${ancs.erl.remainingLag}% behind ${ancs.erl.partner} · +${ancs.erl.certBoost}% boost`);

    if (ancs.ancsTier === 'APEX_NEURAL') {
      lines.push('');
      lines.push(`🧠🔥 <b>ALL NEURAL ENGINES FIRING — Signal quality at maximum. This is the convergence point.</b>`);
    }
    lines.push('━━━━━━━━━━━━━━━━━━━━━━');

    const block = lines.join('\n');
    const firstSep = result.indexOf('━━━━━━━━━━━━━━━━━━━━━━');
    if (firstSep >= 0) result = result.slice(0, firstSep) + block + '\n' + result.slice(firstSep);
    else result = block + '\n' + result;
  } catch(e) { console.warn('ANCS analyst error:', e.message); }

  return result;
};

