/* ████████████████████████████████████████████████████████████████████████████
   DEEP LIQUIDITY EXHAUSTION ENGINE (DLEE)
   ─────────────────────────────────────────────────────────────────────────
   Unlike /cascade which only scans within 3.5× ATR of current price,
   DLEE scans the FULL historical price structure across 1h + 4h + Daily
   with NO distance cap. It finds:

   1. Every significant liquidity pool from current price to the absolute
      deepest swing low (BUY sweep) or swing high (SELL sweep) in history.
   2. The TRUE exhaustion zone — the deepest MEGA/LARGE pool beyond which
      a vacuum exists (no significant orders).
   3. The ideal deep limit entry price AFTER all pools are consumed.
   4. The expected reversal magnitude from the deepest exhaustion point.

   Command: /deep SYMBOL BUY|SELL
   ████████████████████████████████████████████████████████████████████████████ */

const DLEE_CACHE     = new Map();
const DLEE_CACHE_TTL = 4 * 60 * 1000;

async function computeDLEE(symbol, price, dir, targetPrice = null) {
  const cacheKey = `dlee_${symbol}_${dir}_${targetPrice || 'auto'}`;
  const hit = DLEE_CACHE.get(cacheKey);
  if (hit && Date.now() - hit.ts < DLEE_CACHE_TTL) return hit.data;

  try {
    if (!price || price <= 0) return null;

    // Fetch deep history across all three timeframes — no ATR cap
    const [r1h, r4h, r1d] = await Promise.allSettled([
      fetchCandlesCached(symbol, '1h',   300).catch(() => null),
      fetchCandlesCached(symbol, '4h',   150).catch(() => null),
      fetchCandlesCached(symbol, '1day',  90).catch(() => null),
    ]);

    const c1h = r1h.status === 'fulfilled' && r1h.value ? r1h.value : [];
    const c4h = r4h.status === 'fulfilled' && r4h.value ? r4h.value : [];
    const c1d = r1d.status === 'fulfilled' && r1d.value ? r1d.value : [];

    if (c1h.length < 10 && c4h.length < 5) return null;

    // ATR(14) for mass classification
    const atrSrc = c1h.length >= 14 ? c1h : c4h;
    const atr14  = atrSrc.slice(-14).reduce((s, c) => s + ((c.h || 0) - (c.l || 0)), 0) / 14 || price * 0.01;

    // Deep pool scanner — scans full history with no distance cap
    const rawPools = new Map();
    const EQ = 0.0020; // 0.20% cluster tolerance

    function scanTF(candles, tfWeight, tfName) {
      if (!candles || candles.length < 3) return;
      for (let i = 1; i < candles.length - 1; i++) {
        const c = candles[i], prev = candles[i - 1], next = candles[i + 1];
        if (!c || !prev || !next) continue;

        const level = dir === 'BUY' ? (c.l || 0) : (c.h || 0);
        if (!level || level <= 0) continue;

        // Only pools in the sweep direction
        if (dir === 'BUY'  && level >= price * 0.9998) continue;
        if (dir === 'SELL' && level <= price * 1.0002) continue;

        // Swing structure check
        const isSwing = dir === 'BUY'
          ? (c.l || 0) < (prev.l || Infinity) && (c.l || 0) < (next.l || Infinity)
          : (c.h || 0) > (prev.h || 0)        && (c.h || 0) > (next.h || 0);

        const touches = candles.filter(cc => {
          const lvl = dir === 'BUY' ? (cc.l || 0) : (cc.h || 0);
          return lvl > 0 && Math.abs(lvl - level) / level < EQ;
        }).length;

        const volAtLevel = candles
          .filter(cc => {
            const lvl = dir === 'BUY' ? (cc.l || 0) : (cc.h || 0);
            return lvl > 0 && Math.abs(lvl - level) / level < EQ;
          })
          .reduce((s, cc) => s + (cc.v || 0), 0);

        if (!isSwing && touches < 2) continue;

        let merged = false;
        for (const [k, v] of rawPools.entries()) {
          if (Math.abs(k - level) / level < EQ * 2) {
            v.count  += touches;
            v.weight += tfWeight;
            v.volSum += volAtLevel;
            v.sources += `,${tfName}`;
            merged = true;
            break;
          }
        }
        if (!merged) rawPools.set(level, { level, count: touches, weight: tfWeight, volSum: volAtLevel, sources: tfName });
      }
    }

    scanTF(c1h, 1.0, '1h');
    scanTF(c4h, 2.5, '4h');
    scanTF(c1d, 5.0, '1d');

    if (rawPools.size === 0) return null;

    // Build sorted pool list with mass classification
    const pools = Array.from(rawPools.values()).map(p => {
      const distPct   = Math.abs(price - p.level) / price * 100;
      const massScore = p.weight * 1.5 + p.count * 1.2 + (p.volSum > 0 ? Math.log1p(p.volSum) * 0.3 : 0);
      const mass      = massScore >= 20 ? 'MEGA' : massScore >= 10 ? 'LARGE' : massScore >= 5 ? 'MEDIUM' : 'SMALL';
      const prob      = Math.max(5, Math.round(95 * Math.exp(-distPct * 0.18)));
      return {
        level:     Math.round(p.level * 100000) / 100000,
        weight:    p.weight, count: p.count,
        strength:  Math.min(200, Math.round(p.weight * p.count * 8)),
        sources:   p.sources,
        distPct:   Math.round(distPct * 100) / 100,
        mass, prob,
        massScore: Math.round(massScore * 10) / 10,
      };
    })
    .filter(p => dir === 'BUY' ? p.level < price : p.level > price)
    .sort((a, b) => dir === 'BUY' ? b.level - a.level : a.level - b.level);

    if (pools.length === 0) return null;

    // Deduplicate: keep strongest within 0.3%
    const deduped = [];
    for (const p of pools) {
      const ex = deduped.find(d => Math.abs(d.level - p.level) / p.level < 0.003);
      if (!ex) deduped.push(p);
      else if (p.massScore > ex.massScore) Object.assign(ex, p);
    }

    // Find TRUE exhaustion zone: deepest LARGE/MEGA pool with vacuum beyond it
    let exhaustionPool = null;
    let vacuumStart    = null;
    let vacuumEnd      = null;

    for (let i = 0; i < deduped.length; i++) {
      const cur  = deduped[i];
      const next = deduped[i + 1];
      const gapToNext = next ? Math.abs(cur.level - next.level) : atr14 * 3;
      const isVacuum  = gapToNext > atr14 * 1.5;
      if ((cur.mass === 'LARGE' || cur.mass === 'MEGA') && isVacuum) {
        exhaustionPool = cur;
        vacuumStart    = cur.level;
        vacuumEnd      = next ? next.level : cur.level * (dir === 'BUY' ? 0.97 : 1.03);
        break;
      }
    }

    // Fallback: deepest LARGE/MEGA, or last pool
    if (!exhaustionPool) {
      exhaustionPool = [...deduped].reverse().find(p => p.mass === 'LARGE' || p.mass === 'MEGA')
        || deduped[deduped.length - 1];
    }
    if (!exhaustionPool) return null;

    const slipBuffer = atr14 * 0.15;

    let idealDeepEntry;
    let expectedReversal;
    let reversalMagPct;
    let targetPriceLocked = false;
    let targetProfitPct   = null;
    let sweepDepthPct;

    if (targetPrice !== null && Number.isFinite(targetPrice) && targetPrice > 0) {
      // ── TARGET PRICE MODE ─────────────────────────────────────────────────
      // The user locked the exit. We back-calculate the required sweep bottom.
      //
      // Logic:
      //   For BUY:  price sweeps DOWN to entry, then reverses UP to targetPrice.
      //             recoveryFactor = targetPrice / entry  → entry = targetPrice / recoveryFactor
      //             But we don't use a fixed factor — we use the pool mass of the
      //             best exhaustion candidate closest to the required entry.
      //
      // Step 1: estimate the required entry from the target using mass factors
      //   recovery magnitudes by mass: MEGA=78%, LARGE=65%, MEDIUM=52%, SMALL=40%
      //   For BUY:  entry = targetPrice / (1 + recoveryPct/100)
      //   For SELL: entry = targetPrice / (1 - recoveryPct/100)
      //
      // Step 2: among all scanned pools, find the one whose level is closest
      //         to that required entry — this becomes the TRUE exhaustion pool.
      //
      // Step 3: ideal entry = that pool level ± slipBuffer (just past the sweep)
      //
      // This guarantees the sweep ends exactly where needed for the reversal
      // to reach targetPrice — no probability guessing.

      // Try each mass tier from most to least powerful to find which pool
      // in the deduped list is closest to the required entry for that tier.
      const massTiers = [
        { mass: 'MEGA',   factor: 0.78 },
        { mass: 'LARGE',  factor: 0.65 },
        { mass: 'MEDIUM', factor: 0.52 },
        { mass: 'SMALL',  factor: 0.40 },
      ];

      let bestPool      = null;
      let bestEntry     = null;
      let bestFactor    = null;
      let bestDist      = Infinity;

      for (const tier of massTiers) {
        // Required entry so that reversal from entry reaches targetPrice
        const requiredEntry = dir === 'BUY'
          ? targetPrice / (1 + tier.factor)
          : targetPrice / (1 - tier.factor);

        // Find the pool in deduped closest to this required entry
        for (const p of deduped) {
          const dist = Math.abs(p.level - requiredEntry);
          if (dist < bestDist) {
            bestDist   = dist;
            bestPool   = p;
            bestEntry  = requiredEntry;
            bestFactor = tier.factor;
          }
        }
      }

      // Use the best matching pool as the exhaustion point
      if (bestPool) exhaustionPool = bestPool;

      // Ideal entry = just past the exhaustion pool level (slip beyond it)
      idealDeepEntry = dir === 'BUY'
        ? Math.round((exhaustionPool.level - slipBuffer) * 100000) / 100000
        : Math.round((exhaustionPool.level + slipBuffer) * 100000) / 100000;

      // Reversal is locked to exactly the user's target price
      expectedReversal  = Math.round(targetPrice * 100000) / 100000;
      reversalMagPct    = Math.round(Math.abs(targetPrice - idealDeepEntry) / idealDeepEntry * 10000) / 100;
      targetPriceLocked = true;
      targetProfitPct   = reversalMagPct;
      sweepDepthPct     = Math.round(Math.abs(price - idealDeepEntry) / price * 10000) / 100;

      // Update vacuum markers to reflect the new exhaustion pool
      vacuumStart = exhaustionPool.level;
      const nextAfterExhaustion = deduped.find(p =>
        dir === 'BUY' ? p.level < exhaustionPool.level : p.level > exhaustionPool.level
      );
      vacuumEnd = nextAfterExhaustion
        ? nextAfterExhaustion.level
        : exhaustionPool.level * (dir === 'BUY' ? 0.97 : 1.03);

    } else {
      // ── AUTO MODE ─────────────────────────────────────────────────────────
      // No target given — compute entry from pool scanner, reversal from mass factor
      idealDeepEntry = dir === 'BUY'
        ? Math.round((exhaustionPool.level - slipBuffer) * 100000) / 100000
        : Math.round((exhaustionPool.level + slipBuffer) * 100000) / 100000;

      sweepDepthPct = Math.round(Math.abs(price - exhaustionPool.level) / price * 10000) / 100;

      const recoveryFactor = exhaustionPool.mass === 'MEGA'   ? 0.78
                           : exhaustionPool.mass === 'LARGE'  ? 0.65
                           : exhaustionPool.mass === 'MEDIUM' ? 0.52
                           : 0.40;
      reversalMagPct   = Math.round(sweepDepthPct * recoveryFactor * 100) / 100;
      expectedReversal = dir === 'BUY'
        ? Math.round(idealDeepEntry * (1 + reversalMagPct / 100) * 100000) / 100000
        : Math.round(idealDeepEntry * (1 - reversalMagPct / 100) * 100000) / 100000;
    }

    // ── Pools that must be swept before entry is valid ──────────────────────
    const poolsToSweep = deduped.filter(p =>
      dir === 'BUY'
        ? p.level >= exhaustionPool.level && p.level < price
        : p.level <= exhaustionPool.level && p.level > price
    );

    const vacuumDepthPct = vacuumStart && vacuumEnd
      ? Math.round(Math.abs(vacuumStart - vacuumEnd) / price * 10000) / 100
      : 0;

    // Sweep path — mark the correct exhaustion pool
    const sweepPath = deduped.slice(0, 12).map((p, i) => ({
      seq: i + 1, level: p.level, mass: p.mass,
      // In target-price mode: show CERTAIN (100%) for exhaustion, SWEPT for pools above it
      // In auto mode: keep probability decay
      prob: targetPriceLocked
        ? (p.level === exhaustionPool.level ? 100
           : (dir === 'BUY' ? p.level > exhaustionPool.level : p.level < exhaustionPool.level) ? 100 : p.prob)
        : p.prob,
      sources: p.sources, distPct: p.distPct,
      isExhaustion: p.level === exhaustionPool.level,
      // In target mode: pools between price and exhaustion are MUST-SWEEP (certain)
      mustSweep: targetPriceLocked && (
        dir === 'BUY'
          ? p.level > exhaustionPool.level && p.level < price
          : p.level < exhaustionPool.level && p.level > price
      ),
    }));

    const result = {
      symbol, dir, currentPrice: price,
      targetPrice,
      targetPriceLocked,
      targetProfitPct,
      totalPools:           deduped.length,
      poolsToSweep:         poolsToSweep.length,
      sweepPath,
      exhaustionPool,
      idealDeepEntry,
      expectedReversal,
      reversalMagnitudePct: reversalMagPct,
      totalSweepDepthPct:   sweepDepthPct,
      vacuumStart, vacuumEnd, vacuumDepthPct,
      nearestPool:  deduped[0]?.level || null,
      deepestPool:  deduped[deduped.length - 1]?.level || null,
      atr14:        Math.round(atr14 * 100000) / 100000,
      computedAt:   Date.now(),
    };

    DLEE_CACHE.set(cacheKey, { data: result, ts: Date.now() });
    // Bound cache size
    if (DLEE_CACHE.size > 200) DLEE_CACHE.delete(DLEE_CACHE.keys().next().value);
    return result;

  } catch (e) {
    console.warn('computeDLEE error:', e.message);
    return null;
  }
}

function formatDLEE(d) {
  if (!d) return '❌ No DLEE data available.';

  // Smart formatter: use 5dp for small prices, 2dp for large
  const fmt = v => {
    const n = Number(v);
    if (!Number.isFinite(n)) return '?';
    return n >= 100 ? n.toFixed(2) : n >= 1 ? n.toFixed(4) : n.toFixed(5);
  };

  const arrow     = d.dir === 'BUY'  ? '⬇️' : '⬆️';
  const sweepWord = d.dir === 'BUY'  ? 'DOWN' : 'UP';
  const entryWord = d.dir === 'BUY'  ? 'BUY'  : 'SELL';
  const massEmoji = m => m === 'MEGA' ? '🔴' : m === 'LARGE' ? '🟠' : m === 'MEDIUM' ? '🟡' : '⚪';

  const lines = [];

  // ── Header ────────────────────────────────────────────────────────────────
  lines.push(`━━━ 💎 DEEP LIQUIDITY EXHAUSTION ENGINE ━━━`);
  lines.push(`<b>${d.symbol} — ${d.dir} SETUP | Sweep ${sweepWord}</b>`);
  if (d.targetPriceLocked) {
    lines.push(`🎯 <b>Target locked: <code>${fmt(d.targetPrice)}</code></b>`);
  }
  lines.push(``);
  lines.push(`📍 Current price:      <code>${fmt(d.currentPrice)}</code>`);
  lines.push(`🗺️  Total pools mapped: <b>${d.totalPools}</b> (1h + 4h + Daily)`);
  lines.push(`📏 ATR(14):            <code>${fmt(d.atr14)}</code>`);
  lines.push(``);

  // ── Sweep path ────────────────────────────────────────────────────────────
  lines.push(`${arrow} <b>SWEEP PATH — near → deep:</b>`);
  for (const p of d.sweepPath) {
    const exTag   = p.isExhaustion ? '  ← 🎯 EXHAUSTION — BUY HERE' : '';
    const probTag = d.targetPriceLocked
      ? (p.isExhaustion  ? '✅ CERTAIN'
         : p.mustSweep   ? '⚡ MUST SWEEP'
         : `${p.prob}% prob`)
      : `${p.prob}% prob`;
    lines.push(`  ${p.seq}. <code>${fmt(p.level)}</code> ${massEmoji(p.mass)}[${p.mass}] ${probTag} — ${p.distPct}% from price${exTag}`);
  }
  if (d.totalPools > d.sweepPath.length) {
    lines.push(`  ... +${d.totalPools - d.sweepPath.length} more pools beyond`);
  }

  // ── Exhaustion zone ───────────────────────────────────────────────────────
  lines.push(``);
  lines.push(`━━━ 🎯 DEEP EXHAUSTION ZONE ━━━`);
  lines.push(`${massEmoji(d.exhaustionPool.mass)} Exhaustion pool:   <code>${fmt(d.exhaustionPool.level)}</code> [${d.exhaustionPool.mass}]`);
  lines.push(`   TF sources: ${d.exhaustionPool.sources}`);
  lines.push(`   Touches: ${d.exhaustionPool.count} | Strength: ${d.exhaustionPool.strength}`);
  lines.push(`   Depth from current price: <b>${d.totalSweepDepthPct}%</b>`);
  lines.push(`   Pools that must sweep before entry: <b>${d.poolsToSweep}</b>`);

  if (d.vacuumDepthPct > 0) {
    lines.push(``);
    lines.push(`🌌 <b>Vacuum zone beyond exhaustion:</b>`);
    lines.push(`   <code>${fmt(d.vacuumStart)}</code> → <code>${fmt(d.vacuumEnd)}</code>`);
    lines.push(`   ${d.vacuumDepthPct}% gap — zero orders in this zone`);
    lines.push(`   Price moves 3-5× faster through vacuum`);
  }

  // ── Entry & reversal ──────────────────────────────────────────────────────
  lines.push(``);
  lines.push(`━━━ 📍 TRADE PLAN ━━━`);
  lines.push(`✅ <b>STEP 1 — Deep ${entryWord} entry:</b>`);
  lines.push(`   Limit: <code>${fmt(d.idealDeepEntry)}</code>`);
  lines.push(`   Place this order NOW — fills only after ALL pools swept`);
  lines.push(``);

  if (d.targetPriceLocked) {
    // TARGET PRICE MODE — show full locked trade plan
    const profitPct = Math.round(Math.abs(d.targetPrice - d.idealDeepEntry) / d.idealDeepEntry * 10000) / 100;
    const profitDir = d.dir === 'BUY' ? 'up' : 'down';
    lines.push(`🔄 <b>STEP 2 — Reversal target (your exit):</b>`);
    lines.push(`   Target: <code>${fmt(d.targetPrice)}</code> 🎯 LOCKED`);
    lines.push(`   Move needed: price goes <b>${profitDir} ${profitPct}%</b> from entry`);
    lines.push(``);
    lines.push(`💰 <b>TRADE SUMMARY:</b>`);
    lines.push(`   ${entryWord} at:  <code>${fmt(d.idealDeepEntry)}</code>`);
    lines.push(`   Sell at: <code>${fmt(d.targetPrice)}</code>`);
    lines.push(`   Profit:  <b>+${profitPct}%</b> on the reversal`);
    lines.push(`   Sweep depth: <b>${d.totalSweepDepthPct}%</b> before your fill`);
    // Risk/reward
    const rr = d.totalSweepDepthPct > 0
      ? Math.round(profitPct / d.totalSweepDepthPct * 10) / 10
      : '?';
    lines.push(`   R:R ratio:  <b>1 : ${rr}</b>  (risk sweep depth, reward = target)`);
  } else {
    // AUTO MODE
    lines.push(`🔄 <b>STEP 2 — Expected reversal from deep:</b>`);
    lines.push(`   Target: <code>${fmt(d.expectedReversal)}</code>`);
    lines.push(`   Magnitude: <b>+${d.reversalMagnitudePct}%</b> from entry`);
    lines.push(`   (Auto-calculated from pool mass recovery model)`);
    lines.push(``);
    lines.push(`💡 <i>Tip: add your TP price to lock the reversal target:</i>`);
    lines.push(`   <code>/deep ${d.symbol} ${d.dir} [your_target_price]</code>`);
  }

  return lines.join('\n');
}

console.log('✅ DEEP LIQUIDITY EXHAUSTION ENGINE (DLEE) loaded');
console.log('   Full history scan: 300×1h + 150×4h + 90×Daily — no ATR cap');
console.log('   Finds: deep exhaustion zone, ideal limit entry, expected reversal');
console.log('   Command: /deep SYMBOL BUY|SELL — wired directly into switch router');


/* ████████████████████████████████████████████████████████████████████████████
   SWEEP DIRECTION DETECTOR ENGINE
   ─────────────────────────────────────────────────────────────────────────
   Command: /sweep SYMBOL

   Runs BOTH BUY-sweep and SELL-sweep analyses simultaneously, then
   determines which sweep is actually in progress (or which is imminent)
   using 7 confluence factors:

   1. CVD (Cumulative Volume Delta)        — buy/sell pressure imbalance
   2. Pool asymmetry                       — more pools above vs below
   3. Nearest pool distance                — which side is closest to price
   4. EMA slope (7 vs 28)                 — trend direction
   5. ATR-normalised momentum              — candle velocity direction
   6. Funding-rate proxy (OI imbalance)   — leverage bias
   7. Candle close bias (last 8 candles)  — recent directional pressure

   Scores BUY-sweep and SELL-sweep 0–100 each.
   Winner = the active sweep. Entry = sweep's ideal limit. Exit = reversal.
   ████████████████████████████████████████████████████████████████████████████ */

const SWEEP_CACHE     = new Map();
const SWEEP_CACHE_TTL = 3 * 60 * 1000; // 3 min

async function computeSweepDirection(symbol, price) {
  const cacheKey = `sweep_${symbol}`;
  const hit = SWEEP_CACHE.get(cacheKey);
  if (hit && Date.now() - hit.ts < SWEEP_CACHE_TTL) return hit.data;

  try {
    if (!price || price <= 0) return null;

    // ── Fetch all 3 timeframes independently — one failure never kills the rest ──
    let c1h = [], c4h = [], c1d = [];
    try { const r = await fetchCandlesCached(symbol, '1h',  100); c1h = Array.isArray(r) ? r.filter(c => c && c.h && c.l && c.c) : []; } catch(e) { c1h = []; }
    try { const r = await fetchCandlesCached(symbol, '4h',   90); c4h = Array.isArray(r) ? r.filter(c => c && c.h && c.l && c.c) : []; } catch(e) { c4h = []; }
    try { const r = await fetchCandlesCached(symbol, '1day', 60); c1d = Array.isArray(r) ? r.filter(c => c && c.h && c.l && c.c) : []; } catch(e) { c1d = []; }

    const candles = c1h.length >= 10 ? c1h : c4h.length >= 5 ? c4h : c1d;

    // ATR — safe fallback to 1% of price
    const atrSlice = candles.slice(-14);
    const atr = Math.max(price * 0.005,
      atrSlice.length > 0
        ? atrSlice.reduce((s, c) => s + ((c.h || 0) - (c.l || 0)), 0) / atrSlice.length
        : price * 0.01
    );

    // ── Pool scanner — tags every pool with its source timeframe ─────────────
    // Daily = highest authority (weight 5.0), 4h = medium (2.5), 1h = lowest (1.0)
    // This mirrors institutional top-down analysis: HTF structure dominates,
    // LTF only refines the exact entry within that HTF zone.
    const EQ = 0.0018;
    const rawAbove = new Map();
    const rawBelow = new Map();

    function scanTF(tfC, tfW, tfLabel) {
      if (!tfC || tfC.length < 3) return;
      for (let i = 1; i < tfC.length - 1; i++) {
        const c = tfC[i], prev = tfC[i-1], next = tfC[i+1];
        if (!c || !prev || !next) continue;

        // Pools ABOVE price (resistance / buy-side liquidity)
        const hi = c.h || 0;
        if (hi > price * 1.001) {
          const isHiSwing = hi > (prev.h||0) && hi > (next.h||0);
          const hiTouches = tfC.filter(x => x && Math.abs((x.h||0)-hi)/hi < EQ).length;
          if (isHiSwing || hiTouches >= 2) {
            let m = false;
            for (const [k,v] of rawAbove.entries()) {
              if (Math.abs(k-hi)/hi < EQ*2.5) {
                v.weight += tfW; v.count += hiTouches;
                if (!v.tfs.includes(tfLabel)) v.tfs.push(tfLabel);
                m = true; break;
              }
            }
            if (!m) rawAbove.set(hi, { level:hi, weight:tfW, count:hiTouches, tfs:[tfLabel] });
          }
        }

        // Pools BELOW price (support / sell-side liquidity)
        const lo = c.l || 0;
        if (lo > 0 && lo < price * 0.999) {
          const isLoSwing = lo < (prev.l||Infinity) && lo < (next.l||Infinity);
          const loTouches = tfC.filter(x => x && Math.abs((x.l||0)-lo)/lo < EQ).length;
          if (isLoSwing || loTouches >= 2) {
            let m = false;
            for (const [k,v] of rawBelow.entries()) {
              if (Math.abs(k-lo)/lo < EQ*2.5) {
                v.weight += tfW; v.count += loTouches;
                if (!v.tfs.includes(tfLabel)) v.tfs.push(tfLabel);
                m = true; break;
              }
            }
            if (!m) rawBelow.set(lo, { level:lo, weight:tfW, count:loTouches, tfs:[tfLabel] });
          }
        }
      }
    }

    // Scan HTF → LTF order (Daily first, establishes the dominant zones)
    scanTF(c1d, 5.0, '1D');
    scanTF(c4h, 2.5, '4h');
    scanTF(c1h, 1.0, '1h');

    const poolsAbove = Array.from(rawAbove.values()).sort((a,b) => a.level - b.level).slice(0, 12);
    const poolsBelow = Array.from(rawBelow.values()).sort((a,b) => b.level - a.level).slice(0, 12);
    const nearAbove  = poolsAbove[0]?.level || null;
    const nearBelow  = poolsBelow[0]?.level || null;

    // ── Per-timeframe pool counts (for full transparency, no discrimination) ──
    const countByTF = (pools, tf) => pools.filter(p => p.tfs.includes(tf)).length;
    const tfBreakdown = {
      above: { '1D': countByTF(poolsAbove, '1D'), '4h': countByTF(poolsAbove, '4h'), '1h': countByTF(poolsAbove, '1h') },
      below: { '1D': countByTF(poolsBelow, '1D'), '4h': countByTF(poolsBelow, '4h'), '1h': countByTF(poolsBelow, '1h') },
    };

    // ── Per-timeframe directional bias (HTF → LTF weighted) ──────────────────
    // Each timeframe votes BUY or SELL based on its own EMA + candle structure.
    // Daily vote counts most, 4h second, 1h least — true top-down institutional logic.
    function tfDirectionalBias(tfC) {
      if (!tfC || tfC.length < 8) return 0; // neutral if insufficient data
      const cl = tfC.map(c => c.c || 0).filter(v => v > 0);
      if (cl.length < 8) return 0;
      const calcEMA = (arr, len) => { const k=2/(len+1); return arr.reduce((e,v,i) => i===0?v:e*(1-k)+v*k, arr[0]||price); };
      const fastLen = Math.min(7, Math.floor(cl.length/3));
      const slowLen = Math.min(21, Math.floor(cl.length*0.8));
      const emaFast = calcEMA(cl.slice(-fastLen), fastLen);
      const emaSlow = calcEMA(cl.slice(-slowLen), slowLen);
      const emaVote = emaFast > emaSlow ? 1 : -1;

      const lastN = tfC.slice(-Math.min(8, tfC.length));
      const bulls = lastN.filter(c => (c.c||0) >= (c.o||0)).length;
      const candleVote = bulls > lastN.length/2 ? 1 : bulls < lastN.length/2 ? -1 : 0;

      return emaVote * 0.6 + candleVote * 0.4; // -1..+1 range
    }

    const dailyBias = tfDirectionalBias(c1d); // weight 5
    const h4Bias    = tfDirectionalBias(c4h); // weight 2.5
    const h1Bias    = tfDirectionalBias(c1h); // weight 1
    const htfWeightedBias = (dailyBias*5 + h4Bias*2.5 + h1Bias*1) / 8.5; // -1..+1, HTF dominant

    // ── 8-factor composite scoring (now includes HTF-weighted MTF bias) ───────
    const poolGravityBuy  = poolsAbove.length - poolsBelow.length;
    const distAbove       = nearAbove ? Math.abs(price - nearAbove) / price * 100 : 999;
    const distBelow       = nearBelow ? Math.abs(price - nearBelow) / price * 100 : 999;
    const nearestBias     = distBelow < distAbove ? -1 : 1;
    const strengthAbove   = poolsAbove.reduce((s,p) => s+(p.weight||1), 0);
    const strengthBelow   = poolsBelow.reduce((s,p) => s+(p.weight||1), 0);
    const strengthBias    = strengthAbove > strengthBelow ? 1 : strengthBelow > strengthAbove ? -1 : 0;

    const cvdSlice  = candles.slice(-20);
    const cvdRaw    = cvdSlice.reduce((s,c) => s + ((c.c||0) >= (c.o||0) ? (c.v||0) : -(c.v||0)), 0);
    const cvdTotal  = cvdSlice.reduce((s,c) => s+(c.v||0), 0) || 1;
    const cvdScore  = Math.max(-100, Math.min(100, (cvdRaw/cvdTotal)*100));

    const momNew  = candles.slice(-3).reduce((s,c) => s+(c.c||0), 0)/3 || price;
    const momOld  = candles.slice(-6,-3).reduce((s,c) => s+(c.c||0), 0)/3 || price;
    const momBias = atr > 0 ? ((momNew-momOld)/atr > 0.3 ? 1 : (momNew-momOld)/atr < -0.3 ? -1 : 0) : 0;

    const last10    = candles.slice(-10);
    const bullCount = last10.filter(c => (c.c||0) >= (c.o||0)).length;
    const bearCount = 10 - bullCount;
    const closeBias = bullCount > bearCount ? 1 : bullCount < bearCount ? -1 : 0;
    const avgUW = last10.reduce((s,c) => s+Math.max(0,(c.h||0)-Math.max(c.o||0,c.c||0)), 0)/10;
    const avgLW = last10.reduce((s,c) => s+Math.max(0,Math.min(c.o||0,c.c||0)-(c.l||0)), 0)/10;
    const wickBias = avgLW > avgUW*1.3 ? 1 : avgUW > avgLW*1.3 ? -1 : 0;

    // Composite: pool structure (mechanical) + HTF-weighted trend (directional) + micro factors
    const buyScore  = Math.max(0, Math.min(100, 50
      + poolGravityBuy * 4
      + nearestBias    * 12
      + strengthBias   * 9
      + htfWeightedBias* 16     // NEW — HTF (1D→4h→1h weighted) directional vote
      + cvdScore       * 0.20
      + momBias        * 5
      + closeBias       * 3
      + wickBias        * 2
    ));
    const sellScore = Math.max(0, Math.min(100, 100 - buyScore));
    const sweepDir  = buyScore >= sellScore ? 'BUY' : 'SELL';
    const confidence = Math.round(Math.max(buyScore, sellScore));

    // ── MTF Alignment Check — do all 3 timeframes agree? ──────────────────────
    const dailyDir = dailyBias > 0.1 ? 'BUY' : dailyBias < -0.1 ? 'SELL' : 'NEUTRAL';
    const h4Dir    = h4Bias    > 0.1 ? 'BUY' : h4Bias    < -0.1 ? 'SELL' : 'NEUTRAL';
    const h1Dir    = h1Bias    > 0.1 ? 'BUY' : h1Bias    < -0.1 ? 'SELL' : 'NEUTRAL';
    const tfVotes  = [dailyDir, h4Dir, h1Dir].filter(v => v !== 'NEUTRAL');
    const allAgree = tfVotes.length >= 2 && tfVotes.every(v => v === tfVotes[0]);
    const mtfAlignment = allAgree
      ? `✅ ALL TIMEFRAMES ALIGNED — ${tfVotes[0]} confirmed on 1D + 4h + 1h`
      : `⚠️ Mixed signals — 1D:${dailyDir} | 4h:${h4Dir} | 1h:${h1Dir}`;

    // Boost confidence if all timeframes agree with the final verdict
    const finalConfidence = allAgree && tfVotes[0] === sweepDir
      ? Math.min(99, confidence + 12)
      : confidence;

    // ── Entry / Exit / Stop ────────────────────────────────────────────────────
    const p5 = v => { const n=Number(v); return !Number.isFinite(n)?'?':n>=100?n.toFixed(2):n>=1?n.toFixed(4):n.toFixed(5); };
    let sweepEntry, sweepExit, sweepStop, entryNote, exitNote, stopNote;

    if (sweepDir === 'SELL') {
      sweepEntry = Math.round((price - atr*0.08)*100000)/100000;
      sweepExit  = nearBelow ? Math.round((nearBelow + atr*0.05)*100000)/100000 : Math.round(price*0.94*100000)/100000;
      sweepStop  = Math.round((price + atr*0.5)*100000)/100000;
      entryNote  = `SHORT — price sweeping DOWN into ${poolsBelow.length} pool${poolsBelow.length!==1?'s':''} below`;
      exitNote   = nearBelow ? `Nearest pool below ${p5(nearBelow)} — sweep exhausts here` : 'ATR-based exit';
      stopNote   = 'Stop above sweep origin';
    } else {
      sweepEntry = Math.round((price + atr*0.08)*100000)/100000;
      sweepExit  = nearAbove ? Math.round((nearAbove - atr*0.05)*100000)/100000 : Math.round(price*1.06*100000)/100000;
      sweepStop  = Math.round((price - atr*0.5)*100000)/100000;
      entryNote  = `LONG — price sweeping UP into ${poolsAbove.length} pool${poolsAbove.length!==1?'s':''} above`;
      exitNote   = nearAbove ? `Nearest pool above ${p5(nearAbove)} — sweep exhausts here` : 'ATR-based exit';
      stopNote   = 'Stop below sweep origin';
    }

    const profitPct = Math.round(Math.abs(sweepExit-sweepEntry)/sweepEntry*10000)/100;
    const riskPct   = Math.round(Math.abs(sweepEntry-sweepStop)/sweepEntry*10000)/100;
    const rr        = riskPct > 0 ? Math.round(profitPct/riskPct*10)/10 : '?';

    // Display pool lists — tagged with source timeframe(s), no discrimination
    const dispAboveList = poolsAbove.slice(0,10).map((p,i) => ({
      seq:i+1, level:Math.round(p.level*100000)/100000,
      dist:Math.round(Math.abs(price-p.level)/price*10000)/100,
      tfs: p.tfs.join('+'),
    }));
    const dispBelowList = poolsBelow.slice(0,10).map((p,i) => ({
      seq:i+1, level:Math.round(p.level*100000)/100000,
      dist:Math.round(Math.abs(price-p.level)/price*10000)/100,
      tfs: p.tfs.join('+'),
    }));

    const result = {
      symbol, price, sweepDir,
      confidence: finalConfidence,
      buyScore: Math.round(buyScore), sellScore: Math.round(sellScore),
      sweepEntry, sweepExit, sweepStop,
      entryNote, exitNote, stopNote,
      profitPct, riskPct, rr,
      poolsBelow: dispBelowList, poolsAbove: dispAboveList,
      totalBelow: poolsBelow.length, totalAbove: poolsAbove.length,
      totalPoolsAll: poolsBelow.length + poolsAbove.length,
      nearBelow, nearAbove,
      tfBreakdown,
      mtfAlignment,
      dailyDir, h4Dir, h1Dir, allAgree,
      candleCounts: { '1D': c1d.length, '4h': c4h.length, '1h': c1h.length },
      factors: {
        poolGravity:  poolGravityBuy>0 ? `${poolsAbove.length} above vs ${poolsBelow.length} below -> BUY pull` : poolGravityBuy<0 ? `${poolsBelow.length} below vs ${poolsAbove.length} above -> SELL pull` : 'balanced',
        nearestPool:  distBelow<distAbove && nearBelow ? `BELOW closer (${p5(nearBelow)} - ${distBelow.toFixed(2)}% away)` : nearAbove ? `ABOVE closer (${p5(nearAbove)} - ${distAbove.toFixed(2)}% away)` : 'none detected',
        poolStrength: strengthBias>0 ? 'ABOVE heavier' : strengthBias<0 ? 'BELOW heavier' : 'balanced',
        cvdScore:     Math.round(cvdScore),
        htfBias:      htfWeightedBias > 0.1 ? `Bullish (${(htfWeightedBias*100).toFixed(0)}% HTF-weighted)` : htfWeightedBias < -0.1 ? `Bearish (${(htfWeightedBias*100).toFixed(0)}% HTF-weighted)` : 'Neutral',
        momentum:     momBias>0 ? 'Upward' : momBias<0 ? 'Downward' : 'Neutral',
        candleBias:   `${bullCount}/10 bull, ${bearCount}/10 bear`,
        wickBias:     wickBias>0 ? 'Lower wicks - buy pressure' : wickBias<0 ? 'Upper wicks - sell pressure' : 'Balanced',
      },
      atr: Math.round(atr*100000)/100000,
      computedAt: Date.now(),
    };

    SWEEP_CACHE.set(cacheKey, { data: result, ts: Date.now() });
    if (SWEEP_CACHE.size > 200) SWEEP_CACHE.delete(SWEEP_CACHE.keys().next().value);
    return result;

  } catch (e) {
    console.warn('computeSweepDirection error:', symbol, e.message);
    const fallbackAtr = price * 0.01;
    return {
      symbol, price, sweepDir: 'BUY', confidence: 40,
      buyScore: 55, sellScore: 45,
      sweepEntry: price,
      sweepExit:  Math.round(price*1.05*100000)/100000,
      sweepStop:  Math.round(price*0.97*100000)/100000,
      entryNote: 'Estimate only - candle fetch error',
      exitNote:  'ATR-based estimate (5% target)',
      stopNote:  'ATR-based estimate (3% stop)',
      profitPct: 5, riskPct: 3, rr: 1.7,
      poolsBelow: [], poolsAbove: [], totalBelow: 0, totalAbove: 0, totalPoolsAll: 0,
      nearBelow: null, nearAbove: null,
      tfBreakdown: { above:{'1D':0,'4h':0,'1h':0}, below:{'1D':0,'4h':0,'1h':0} },
      mtfAlignment: 'Unable to compute - data error',
      dailyDir:'NEUTRAL', h4Dir:'NEUTRAL', h1Dir:'NEUTRAL', allAgree:false,
      candleCounts: { '1D':0, '4h':0, '1h':0 },
      factors: { poolGravity:'fetch error', nearestPool:'fetch error', poolStrength:'fetch error',
        cvdScore:0, htfBias:'fetch error', momentum:'fetch error', candleBias:'fetch error', wickBias:'fetch error' },
      atr: fallbackAtr, computedAt: Date.now(), lowConfidence: true, error: e.message,
    };
  }
}



function formatSweepDirection(d) {
  if (!d) return '❌ No sweep data available.';

  const fmt = v => {
    const n = Number(v);
    if (!Number.isFinite(n)) return '?';
    return n >= 100 ? n.toFixed(2) : n >= 1 ? n.toFixed(4) : n.toFixed(5);
  };

  const isBuy     = d.sweepDir === 'BUY';
  const dirEmoji  = isBuy ? '⬆️' : '⬇️';
  const sweepWord = isBuy ? 'BUY SWEEP (price going UP)' : 'SELL SWEEP (price going DOWN)';
  const confBar   = '█'.repeat(Math.round(d.confidence / 10)) + '░'.repeat(10 - Math.round(d.confidence / 10));
  const confLabel = d.confidence >= 85 ? '🔥🔥 VERY HIGH CONFIDENCE'
                  : d.confidence >= 75 ? '🔥 HIGH CONFIDENCE'
                  : d.confidence >= 60 ? '✅ MODERATE CONFIDENCE'
                  : '⚠️ LOW CONFIDENCE — wait for more confluence';

  const lines = [];

  // ── Header ────────────────────────────────────────────────────────────────
  lines.push(`━━━ 🌊 SWEEP DIRECTION DETECTOR (3-TF) ━━━`);
  lines.push(`<b>${d.symbol}</b> @ <code>${fmt(d.price)}</code>`);
  lines.push(``);

  // ── Verdict ───────────────────────────────────────────────────────────────
  lines.push(`${dirEmoji} <b>ACTIVE SWEEP: ${sweepWord}</b>`);
  lines.push(`${confLabel}`);
  lines.push(`[${confBar}] ${d.confidence}%`);
  lines.push(`BUY score: <b>${d.buyScore}/100</b>  |  SELL score: <b>${d.sellScore}/100</b>`);
  lines.push(``);

  // ── Multi-Timeframe Alignment (1D + 4h + 1h — no discrimination) ──────────
  lines.push(`━━━ 🕐 MULTI-TIMEFRAME ALIGNMENT ━━━`);
  lines.push(`${d.mtfAlignment}`);
  lines.push(`  📅 1D:  <b>${d.dailyDir}</b>  (${d.candleCounts['1D']} candles)`);
  lines.push(`  🕓 4h:  <b>${d.h4Dir}</b>  (${d.candleCounts['4h']} candles)`);
  lines.push(`  🕐 1h:  <b>${d.h1Dir}</b>  (${d.candleCounts['1h']} candles)`);
  lines.push(`  ${d.allAgree ? '✅ All timeframes agree — maximum certainty' : '⚠️ Not all timeframes agree — trade with caution'}`);
  lines.push(``);

  // ── Trade plan ────────────────────────────────────────────────────────────
  lines.push(`━━━ 📍 TRADE PLAN ━━━`);
  lines.push(isBuy
    ? `✅ <b>ENTER LONG:  <code>${fmt(d.sweepEntry)}</code></b>`
    : `✅ <b>ENTER SHORT: <code>${fmt(d.sweepEntry)}</code></b>`
  );
  lines.push(`   ${d.entryNote}`);
  lines.push(``);
  lines.push(isBuy
    ? `🎯 <b>EXIT LONG:   <code>${fmt(d.sweepExit)}</code></b>`
    : `🎯 <b>EXIT SHORT:  <code>${fmt(d.sweepExit)}</code></b>`
  );
  lines.push(`   ${d.exitNote}`);
  lines.push(``);
  lines.push(`🛑 <b>STOP LOSS:   <code>${fmt(d.sweepStop)}</code></b>`);
  lines.push(`   ${d.stopNote}`);
  lines.push(``);
  lines.push(`💰 Sweep profit: <b>+${d.profitPct}%</b>  |  Risk: <b>${d.riskPct}%</b>  |  R:R <b>1:${d.rr}</b>`);
  lines.push(``);

  // ── Pool map — TOTAL pools across all 3 timeframes, no discrimination ─────
  lines.push(`━━━ 🗺️ COMPLETE POOL MAP — ${d.totalPoolsAll} TOTAL POOLS (1D+4h+1h) ━━━`);
  lines.push(`Pool breakdown ABOVE: 1D=${d.tfBreakdown.above['1D']} | 4h=${d.tfBreakdown.above['4h']} | 1h=${d.tfBreakdown.above['1h']}`);
  lines.push(`Pool breakdown BELOW: 1D=${d.tfBreakdown.below['1D']} | 4h=${d.tfBreakdown.below['4h']} | 1h=${d.tfBreakdown.below['1h']}`);
  lines.push(``);

  if (d.poolsAbove.length > 0) {
    lines.push(`<b>⬆️ Pools ABOVE (${d.totalAbove} total${isBuy ? ' — SWEEP TARGETS' : ' — resistance'}):</b>`);
    for (const p of d.poolsAbove) {
      const tag = isBuy && p.seq === 1 ? '  ← 🎯 EXIT HERE' : '';
      lines.push(`  ${p.seq}. <code>${fmt(p.level)}</code> [${p.tfs}] — ${p.dist}% away${tag}`);
    }
  } else {
    lines.push(`⬆️ Pools above: none detected`);
  }
  lines.push(``);
  if (d.poolsBelow.length > 0) {
    lines.push(`<b>⬇️ Pools BELOW (${d.totalBelow} total${!isBuy ? ' — SWEEP TARGETS' : ' — support'}):</b>`);
    for (const p of d.poolsBelow) {
      const tag = !isBuy && p.seq === 1 ? '  ← 🎯 EXIT HERE' : '';
      lines.push(`  ${p.seq}. <code>${fmt(p.level)}</code> [${p.tfs}] — ${p.dist}% away${tag}`);
    }
  } else {
    lines.push(`⬇️ Pools below: none detected`);
  }
  lines.push(``);

  // ── Confluence breakdown ───────────────────────────────────────────────────
  lines.push(`━━━ 📊 WHY ${d.sweepDir} SWEEP ━━━`);
  const f = d.factors;
  lines.push(`Pool gravity:    <b>${f.poolGravity}</b>`);
  lines.push(`Nearest pool:    <b>${f.nearestPool}</b>`);
  lines.push(`Pool strength:   <b>${f.poolStrength}</b>`);
  lines.push(`HTF bias (1D→1h):<b>${f.htfBias}</b>`);
  lines.push(`CVD pressure:    <b>${f.cvdScore > 0 ? '+' : ''}${f.cvdScore}</b> ${f.cvdScore > 15 ? '(strong buy)' : f.cvdScore < -15 ? '(strong sell)' : '(neutral)'}`);
  lines.push(`Momentum:        <b>${f.momentum}</b>`);
  lines.push(`Candles:         <b>${f.candleBias}</b>`);
  lines.push(`Wicks:           <b>${f.wickBias}</b>`);
  lines.push(``);
  lines.push(`<i>💡 Confirm with: /atlas ${d.symbol} ${d.sweepDir}</i>`);

  return lines.join('\n');
}

